-- Poems batch 14
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('8a43df9d-01dc-4b80-8e23-8753b717b151','送殷華之洪州','陳羽','唐','唐诗','tang','','[]','離堂悲楚調，君奏豫章行。',48,'全唐诗/poet.tang.18000.json','["離堂悲楚調，君奏豫章行。", "愁處雪花白，夢中江水清。", "扣船歌月色，避浪宿猨聲。", "還作經年別，相思湖草生。"]'),
('4ae70026-7725-46c4-b055-52e65929534d','春日晴原野望','陳羽','唐','唐诗','tang','','[]','東風吹煖氣，消散入晴天。',48,'全唐诗/poet.tang.18000.json','["東風吹煖氣，消散入晴天。", "漸變池塘色，欲生楊柳煙。", "蒙茸花向月，潦倒客經年。", "鄉思應愁望，江湖春水連。"]'),
('56cf6555-4f70-4397-a1eb-237e0c3ce4f6','湘妃怨','陳羽','唐','唐诗','tang','','[]','舜欲省蠻陬，南巡非逸游。',48,'全唐诗/poet.tang.18000.json','["舜欲省蠻陬，南巡非逸游。", "九山沈白日，二女泣滄洲。", "目極楚雲斷，恨連湘水流。", "至今聞鼓瑟，咽絕不勝愁。"]'),
('22efc969-6c59-4708-a2f7-3d91fd7a9ab6','冬晚送友人使西蕃','陳羽','唐','唐诗','tang','','[]','驛使向天西，巡羌復入氐。',48,'全唐诗/poet.tang.18000.json','["驛使向天西，巡羌復入氐。", "玉關晴有雪，砂磧雨無泥。", "落淚軍中笛，驚眠塞上雞。", "逢春鄉思苦，萬里草萋萋。"]'),
('d8063912-f95b-43d2-b92a-4940991cac94','春園即事','陳羽','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','水隔羣物遠，夜深風起頻。',48,'全唐诗/poet.tang.18000.json','["水隔羣物遠，夜深風起頻。", "霜中千樹橘，月下五湖人。", "聽鶴忽忘寢，見山如得鄰。", "明年還到此，共看洞庭春。"]'),
('79290dfd-c53b-4dae-8064-9b94a007ddae','送友人及第歸江東','陳羽','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','五陵春色泛花枝，心醉花前遠別離。',64,'全唐诗/poet.tang.18000.json','["五陵春色泛花枝，心醉花前遠別離。", "落羽耻爲關右客，成名空羨里中兒。", "都門雨歇愁分處，山店燈殘夢到時。", "家住洞庭多釣伴，因來相賀話相思。"]'),
('b0c4819b-d884-485c-b1fa-03d5717c8d9a','梓州與溫商夜別','陳羽','唐','唐诗','tang','','[]','鳳皇城裏花時別，客舍莫辭先買酒，相門曾忝共登龍。',56,'全唐诗/poet.tang.18000.json','["鳳皇城裏花時別，客舍莫辭先買酒，相門曾忝共登龍。", "迎風騷屑千家竹，隔水悠揚午夜鐘。", "明日又行西蜀路，不堪天際遠山重。"]'),
('d4b5b719-f5cd-49f1-b533-6d28299b3534','長安臥病秋夜言懷','陳羽','唐','唐诗','tang','','[]','九重門鎖禁城秋，月過南宮漸映樓。',64,'全唐诗/poet.tang.18000.json','["九重門鎖禁城秋，月過南宮漸映樓。", "紫陌夜深槐露滴，碧空雲盡火星流。", "風清刻漏傳三殿，甲第歌鐘樂五侯。", "楚客病來鄉思苦，寂寥燈下不勝愁。"]'),
('17b9e9b5-d633-40f2-b865-9c5cbb339550','喜雪上竇相公','陳羽','唐','唐诗','tang','','[]','千門萬戶雪花浮，點點無聲落瓦溝。',56,'全唐诗/poet.tang.18000.json','["千門萬戶雪花浮，點點無聲落瓦溝。", "全似玉塵銷更積，半成冰水結還流。", "光添曙色連天遠，平地已沾盈尺潤，年豐須荷富人侯。"]'),
('b3fed01c-2525-4489-a7c4-dd9739239efb','宴楊駙馬山亭','陳羽','唐','唐诗','tang','','[]','垂楊拂岸草茸茸，繡戶窗前花影重。',64,'全唐诗/poet.tang.18000.json','["垂楊拂岸草茸茸，繡戶窗前花影重。", "鱠下玉盤紅縷細，酒開金甕綠醅醲。", "中朝附馬何平叔，南國詞人陸士龍。", "落日泛舟同醉處，迴潭百丈映千峯。"]'),
('c9bf1fcf-9377-47b0-b837-81e9c1d1c0f7','西蜀送許中庸歸秦赴舉','陳羽','唐','唐诗','tang','','[]','春色華陽國，秦人此別離。',96,'全唐诗/poet.tang.18000.json','["春色華陽國，秦人此別離。", "驛樓橫水影，鄉路入花枝。", "日暖鶯飛好，山晴馬去遲。", "劒門當石隘，棧閣入雲危。", "獨鶴心千里，貧交酒一巵。", "桂條攀偃蹇，蘭葉藉參差。", "旅夢驚蝴蝶，殘芳怨子規。", "碧霄今夜月，惆悵上峨嵋。"]'),
('bb7bd85f-5a12-4ede-9bcf-12fe909e7405','小苑春望宮池柳色','陳羽','唐','唐诗','tang','','[]','宛宛如絲柳，含黃一望新。',72,'全唐诗/poet.tang.18000.json','["宛宛如絲柳，含黃一望新。", "未成溝上暗，且向日邊春。", "嫋娜方遮水，低迷欲醉人。", "託空芳鬱鬱，逐溜影鱗鱗。", "弄水滋宵露，垂枝染夕塵。", "夾堤連太液，還似映天津。"]'),
('7db8d3e0-6dba-4d3f-93e1-5597b9c971b1','中秋夜臨鏡湖望月','陳羽','唐','唐诗','tang','','[]','鏡裏秋宵望，湖平月彩深。',72,'全唐诗/poet.tang.18000.json','["鏡裏秋宵望，湖平月彩深。", "圓光珠入浦，浮照鵲驚林。", "澹動光還碎，嬋娟影不沈。", "遠時生岸曲，空處落波心。", "逈徹輪初滿，孤明魄未侵。", "桂枝如可折，何惜夜登臨。"]'),
('5a953cb5-26cf-4e66-847b-c3b1e867afdc','江上愁思二首 一','陳羽','唐','唐诗','tang','','[]','江上翁開門，開門向衰草。',24,'全唐诗/poet.tang.18000.json','["江上翁開門，開門向衰草。", "只知愁子孫，不覺生涯老。"]'),
('665ce408-8b52-4d03-babc-416e522be0fd','江上愁思二首 二','陳羽','唐','唐诗','tang','','[]','江上草莖枯，莖枯葉復焦。',24,'全唐诗/poet.tang.18000.json','["江上草莖枯，莖枯葉復焦。", "那堪芳意盡，夜夜沒寒潮。"]'),
('b0e03011-2685-4e63-89f6-df489e1fca0f','梁城老人怨','陳羽','唐','唐诗','tang','','[]','朝爲耕種人，暮作刀槍鬼。',24,'全唐诗/poet.tang.18000.json','["朝爲耕種人，暮作刀槍鬼。", "相看父子血，共染城濠水。"]'),
('81408fc9-9fb4-42c8-a956-b8a5ac3ea9b0','送靈一上人','陳羽','唐','唐诗','tang','','[]','十年勞遠別，一笑喜相逢。',24,'全唐诗/poet.tang.18000.json','["十年勞遠別，一笑喜相逢。", "又上青山去，青山千萬重。"]'),
('5f03c2e9-b5da-4437-9db7-6d93d9fb104f','經夫差廟','陳羽','唐','唐诗','tang','','[]','姑蘇城畔千年木，刻作夫差廟裏神。',32,'全唐诗/poet.tang.18000.json','["姑蘇城畔千年木，刻作夫差廟裏神。", "冠蓋寂寥塵滿室，不知簫鼓樂何人。"]'),
('1258066e-c005-43f1-807c-91c5de1cce61','九月十日即事','陳羽','唐','唐诗','tang','','[]','漢江天外東流去，巴塞連山萬里秋。',32,'全唐诗/poet.tang.18000.json','["漢江天外東流去，巴塞連山萬里秋。", "節過重陽人病起，一枝殘菊不勝愁。"]'),
('a194cf22-2ec6-4dae-80d1-369fd2cf83b4','夏日讌九華池贈主人','陳羽','唐','唐诗','tang','','[]','池上涼臺五月涼，百花開盡水芝香。',32,'全唐诗/poet.tang.18000.json','["池上涼臺五月涼，百花開盡水芝香。", "黃金買酒邀詩客，醉倒檐前青玉牀。"]'),
('5a94796e-39fc-4799-a98c-0070900ac25b','長安早春言志','陳羽','唐','唐诗','tang','','[]','九衢日暖樹蒼蒼，萬里吳人憶水鄉。',32,'全唐诗/poet.tang.18000.json','["九衢日暖樹蒼蒼，萬里吳人憶水鄉。", "漢主未曾親羽獵，不知將底諫君王。"]'),
('230d114f-9f9d-4993-b1bb-affb2f1a0941','讀蘇屬國傳','陳羽','唐','唐诗','tang','','[]','天山西北居延海，沙塞重重不見春。',32,'全唐诗/poet.tang.18000.json','["天山西北居延海，沙塞重重不見春。", "腸斷帝鄉遙望日，節旄零落漢家臣。"]'),
('48100fde-672c-4a27-a6ef-ee8461a1a907','吳城覽古','陳羽','唐','唐诗','tang','','[]','吳王舊國水煙空，香徑無人蘭葉紅。',32,'全唐诗/poet.tang.18000.json','["吳王舊國水煙空，香徑無人蘭葉紅。", "春色似憐歌舞地，年年先發館娃宮。"]'),
('aa02b064-d182-4403-b0bc-18dda2fc0a8a','犍爲城下夜泊聞夷歌','陳羽','唐','唐诗','tang','','[]','犍爲城下牂牁路，空冢灘西賈客舟。',32,'全唐诗/poet.tang.18000.json','["犍爲城下牂牁路，空冢灘西賈客舟。", "此夜可憐江上月，夷歌銅鼓不勝愁。"]'),
('8ee2518c-583b-4124-abe9-9ff8b9f708d2','和王中丞使君春日過高評事幽居','陳羽','唐','唐诗','tang','','[]','風光滿路旗旛出，林下高人待使君。',32,'全唐诗/poet.tang.18000.json','["風光滿路旗旛出，林下高人待使君。", "笑藉紫蘭相向醉，野花千樹落紛紛。"]'),
('081fd5e7-8e05-4fe8-ad1e-82857bc17613','和王中丞中和日','陳羽','唐','唐诗','tang','','[]','節應中和天地晴，繁弦疊鼓動高城。',32,'全唐诗/poet.tang.18000.json','["節應中和天地晴，繁弦疊鼓動高城。", "漢家分刺諸侯貴，一曲陽春江水清。"]'),
('67715f49-df41-4375-b1f1-148780e32e07','同韋中丞花下夜飲贈歌人','陳羽','唐','唐诗','tang','','[]','銀燭煌煌半醉人，嬌歌宛轉動朱脣。',32,'全唐诗/poet.tang.18000.json','["銀燭煌煌半醉人，嬌歌宛轉動朱脣。", "繁花落盡春風裏，繡被郎官不負春。"]'),
('401da5a6-f506-4a31-86f5-8ac780cd84d6','若耶溪逢陸澧','陳羽','唐','唐诗','tang','','[]','溪上春晴聊看竹，誰言驛使此相逢。',32,'全唐诗/poet.tang.18000.json','["溪上春晴聊看竹，誰言驛使此相逢。", "擔簦躡屐仍多病，笑殺雲間陸士龍。"]'),
('3fdddde1-10b7-4ead-9c84-649bf6bb3bdc','夜泊荆溪','陳羽','唐','唐诗','tang','','[]','小雪已晴蘆葉暗，長波乍急鶴聲嘶。',32,'全唐诗/poet.tang.18000.json','["小雪已晴蘆葉暗，長波乍急鶴聲嘶。", "孤舟一夜宿流水，眼看山頭月落溪。"]'),
('39d53cea-56b6-4fec-9798-3b88133562b5','南山別僧','陳羽','唐','唐诗','tang','','[]','惆悵人間多別離，梅花滿眼獨行時。',32,'全唐诗/poet.tang.18000.json','["惆悵人間多別離，梅花滿眼獨行時。", "無家度日多爲客，欲共山僧何處期。"]'),
('dece1bbc-2959-43a1-93e2-cb34a168865e','戲題山居二首 一','陳羽','唐','唐诗','tang','','[]','雲蓋秋松幽洞近，水穿危石亂山深。',32,'全唐诗/poet.tang.18000.json','["雲蓋秋松幽洞近，水穿危石亂山深。", "門前自有千竿竹，免向人家看竹林。"]'),
('81d4891b-ebb7-45c4-aa7c-2ae11329e972','戲題山居二首 二','陳羽','唐','唐诗','tang','','[]','雖有柴門長不關，片雲高木共身閑。',32,'全唐诗/poet.tang.18000.json','["雖有柴門長不關，片雲高木共身閑。", "猶嫌住久人知處，見欲移居更上山。"]'),
('b9853d70-f4eb-4b7a-9f01-23903dcbb5c5','山中秋夜喜周士閑見過','陳羽','唐','唐诗','tang','','[]','青山高處上不易，白雲深處行亦難。',32,'全唐诗/poet.tang.18000.json','["青山高處上不易，白雲深處行亦難。", "留君不宿對秋月，莫厭山空泉石寒。"]'),
('18f98f94-f282-40b1-89a9-3518493fd3de','過櫟陽山谿','陳羽','唐','唐诗','tang','','[]','衆草穿沙芳色齊，蹋莎行草過春谿。',32,'全唐诗/poet.tang.18000.json','["衆草穿沙芳色齊，蹋莎行草過春谿。", "閑雲相引上山去，人到山頭雲却低。"]'),
('6fb8b33d-fcba-425b-bc93-30668dfd2836','姑蘇臺懷古','陳羽','唐','唐诗','tang','','[]','憶昔吳王爭霸日，歌鐘滿地上高臺。',32,'全唐诗/poet.tang.18000.json','["憶昔吳王爭霸日，歌鐘滿地上高臺。", "三千宮女看花處，人盡臺崩花自開。"]'),
('8017660e-e1f1-401a-9821-9bf18198c29a','將歸舊山留別','陳羽','唐','唐诗','tang','','[]','相共遊梁今獨還，異鄉搖落憶空山。',32,'全唐诗/poet.tang.18000.json','["相共遊梁今獨還，異鄉搖落憶空山。", "信陵死後無公子，徒向夷門學抱關。"]'),
('4c979a6c-3eba-42d1-96a7-940be7220b77','遊洞靈觀','陳羽','唐','唐诗','tang','','[]','初訪西城禮少君，獨行深入洞天雲。',32,'全唐诗/poet.tang.18000.json','["初訪西城禮少君，獨行深入洞天雲。", "風吹青桂寒花落，香繞仙壇處處聞。"]'),
('80d520e6-37ab-4d6f-a027-6cc092080c5d','旅次沔陽聞克復而用師者窮兵黷武因書簡之','陳羽','唐','唐诗','tang','','[]','江上煙消漢水清，王師大破綠林兵。',32,'全唐诗/poet.tang.18000.json','["江上煙消漢水清，王師大破綠林兵。", "干戈用盡人成血，韓信空傳壯士名。"]'),
('403fbd38-35c0-4c27-828a-bf6d8185ca4d','湘君祠','陳羽','唐','唐诗','tang','','[]','二妃怨處雲沈沈，二妃哭處湘水深。',32,'全唐诗/poet.tang.18000.json','["二妃怨處雲沈沈，二妃哭處湘水深。", "商人酒滴廟前草，蕭索風生斑竹林。"]'),
('1692c313-e03e-4371-a5ce-29d96d95eed0','送辛吉甫常州覲省','陳羽','唐','唐诗','tang','','[]','西去蘭陵家不遠，到家還及採蘭時。',32,'全唐诗/poet.tang.18000.json','["西去蘭陵家不遠，到家還及採蘭時。", "新年送客我爲客，惆悵門前黃柳絲。"]'),
('a8300d33-c1ec-4f8b-82c2-2b700aa3e8ba','題舞花山大師遺居','陳羽','唐','唐诗','tang','','[]','西過流沙歸路長，一生遺迹在東方。',32,'全唐诗/poet.tang.18000.json','["西過流沙歸路長，一生遺迹在東方。", "空堂寂寞閉燈影，風動四山松柏香。"]'),
('3806408c-e43f-4f4f-8fc2-8a539d74e807','廣陵秋夜對月即事','陳羽','唐','唐诗','tang','','[]','霜落寒空月上樓，月中歌吹滿揚州。',32,'全唐诗/poet.tang.18000.json','["霜落寒空月上樓，月中歌吹滿揚州。", "相看醉舞倡樓月，不覺隋家陵樹秋。"]'),
('d61e274f-b073-4b6a-a725-ce6072c15c95','早秋滻水送人歸越','陳羽','唐','唐诗','tang','','[]','涼葉蕭蕭生遠風，曉鵶飛度望春宮。',32,'全唐诗/poet.tang.18000.json','["涼葉蕭蕭生遠風，曉鵶飛度望春宮。", "越人歸去一搖首，腸斷馬嘶秋水東。"]'),
('84a642b1-e1a8-488a-9ac3-32b20223be4d','小江驛送陸侍御歸湖上山','陳羽','唐','唐诗','tang','','[]','鶴唳天邊秋水空，荻花蘆葉起西風。',32,'全唐诗/poet.tang.18000.json','["鶴唳天邊秋水空，荻花蘆葉起西風。", "今夜渡江何處宿，會稽山在月明中。"]'),
('edd88f76-3872-4096-9f64-6da254cb8884','送李德輿歸穿石洞山居','陳羽','唐','唐诗','tang','','[]','烏巾年少歸何處，一片綵霞仙洞中。',32,'全唐诗/poet.tang.18000.json','["烏巾年少歸何處，一片綵霞仙洞中。", "惆悵別時花似雪，行人不肯醉春風。"]'),
('cbb68b3c-4906-4031-953f-750c2e5cc628','酬幽居閑上人喜及第後見贈','陳羽','唐','唐诗','tang','','[]','九霄心在勞相問，四十年間豈足驚。',32,'全唐诗/poet.tang.18000.json','["九霄心在勞相問，四十年間豈足驚。", "風動自然雲出岫，高僧不用笑浮生。"]'),
('2736836a-f50b-4d37-a606-2b30d5a9a9fe','洛下贈徹公','陳羽','唐','唐诗','tang','','[]','天竺沙門洛下逢，請爲同社笑相容。',32,'全唐诗/poet.tang.18000.json','["天竺沙門洛下逢，請爲同社笑相容。", "支頤忽望碧雲裏，心愛嵩山第幾重。"]'),
('595c57cc-e61d-4076-8ead-42dad5de4670','觀朱舍人歸葬吳中','陳羽','唐','唐诗','tang','','[]','翩翩絳旐寒流上，行引東歸萬里魂。',32,'全唐诗/poet.tang.18000.json','["翩翩絳旐寒流上，行引東歸萬里魂。", "幾處州人臨水哭，共看遺草有王言。"]'),
('b54bf578-45b3-4473-8512-a08804c9e63c','題清鏡寺留別','陳羽','唐','唐诗','tang','','[]','路入千山愁自知，雪花撩亂壓松枝。',32,'全唐诗/poet.tang.18000.json','["路入千山愁自知，雪花撩亂壓松枝。", "世人並道離別苦，誰信山僧輕別離。"]'),
('7481bb63-1d8b-4a09-9057-cbeccc070239','從軍行','陳羽','唐','唐诗','tang','','["\u884c\u519b", "\u8fb9\u585e"]','海畔風吹凍泥裂，枯桐葉落枝梢折。',32,'全唐诗/poet.tang.18000.json','["海畔風吹凍泥裂，枯桐葉落枝梢折。", "橫笛聞聲不見人，紅旗直上天山雪。"]'),
('19e3b3ab-d7eb-4363-aad5-3e0f3197be84','宿淮陰作','陳羽','唐','唐诗','tang','','[]','秋燈點點淮陰市，楚客聯檣宿淮水。',32,'全唐诗/poet.tang.18000.json','["秋燈點點淮陰市，楚客聯檣宿淮水。", "夜深風起魚鼈腥，韓信祠堂明月裏。"]'),
('c8f4ef3d-dfd7-4d77-8d4c-df0e8575eeef','春日南山行','陳羽','唐','唐诗','tang','','[]','處處看山不可行，野花相向笑無成。',32,'全唐诗/poet.tang.18000.json','["處處看山不可行，野花相向笑無成。", "長嫌爲客過州縣，漸被時人識姓名。"]'),
('46de16bf-9cba-40d2-8cab-92888b89d657','步虛詞二首 一','陳羽','唐','唐诗','tang','','[]','漢武青齋讀鼎書，太官扶上畫雲車。',32,'全唐诗/poet.tang.18000.json','["漢武青齋讀鼎書，太官扶上畫雲車。", "壇上月明宮殿閉，仰看星斗禮空虛。"]'),
('fe5870e3-82e9-4f97-9b2e-fb212a5afa96','步虛詞二首 二','陳羽','唐','唐诗','tang','','[]','樓殿層層阿母家，崑崙山頂駐紅霞。',32,'全唐诗/poet.tang.18000.json','["樓殿層層阿母家，崑崙山頂駐紅霞。", "笙歌出見穆天子，相引笑看琪樹花。"]'),
('32c6fd71-0813-4060-ad07-8fa827806409','襄陽過孟浩然舊居','陳羽','唐','唐诗','tang','','[]','襄陽城郭春風起，漢水東流去不還。',32,'全唐诗/poet.tang.18000.json','["襄陽城郭春風起，漢水東流去不還。", "孟子死來江樹老，煙霞猶在鹿門山。"]'),
('e7c36b33-eab1-47ec-adb3-2a9ea0bb26e2','送友人遊嵩山','陳羽','唐','唐诗','tang','','[]','嵩山歸路繞天壇，雪影松聲滿谷寒。',32,'全唐诗/poet.tang.18000.json','["嵩山歸路繞天壇，雪影松聲滿谷寒。", "君見九龍潭上月，莫辭清夜訪袁安。"]'),
('ea01e257-27d4-48cb-82a6-0bf168b8544d','伏翼西洞送夏方慶','陳羽','唐','唐诗','tang','','[]','洞裏春晴花正開，看花出洞幾時迴。',32,'全唐诗/poet.tang.18000.json','["洞裏春晴花正開，看花出洞幾時迴。", "殷勤好去武陵客，莫引世人相逐來。"]'),
('c211d043-f534-4ad0-b293-5a9c791e8c36','贈人','陳羽','唐','唐诗','tang','','[]','或櫂孤舟或杖藜，尋常適意釣長溪。',32,'全唐诗/poet.tang.18000.json','["或櫂孤舟或杖藜，尋常適意釣長溪。", "草堂竹徑在何處，落日孤煙寒渚西。"]'),
('8dc1b019-ffb1-4cb1-ab29-ed77ac718cd5','句','陳羽','唐','唐诗','tang','','[]','稚子新能編筍笠，山妻舊解補荷衣。',32,'全唐诗/poet.tang.18000.json','["稚子新能編筍笠，山妻舊解補荷衣。", "秋山隔岸清猨叫，湖水當門白鳥飛。"]'),
('0a3c3f84-9946-4c55-aaa7-ad22bcab3779','東風二章 一','歐陽詹','唐','唐诗','tang','','[]','東風叶時，匪沃匪飄。',73,'全唐诗/poet.tang.18000.json','["東風叶時，匪沃匪飄。", "莫雪凝川，莫陰沍郊。", "朝不徯夕乃銷，東風之行地上兮。", "上德臨慝，匪戮匪梟。", "莫暴在野，莫醜在階。", "以踣以殲，夕不徯朝，隴西公來浚都兮。"]'),
('b850806a-2014-49d4-870c-cc97b0fc26ad','東風二章 二','歐陽詹','唐','唐诗','tang','','[]','東風叶時，匪鑿匪[穮]。',75,'全唐诗/poet.tang.18000.json','["東風叶時，匪鑿匪[穮]。", "莫蟄在泉，莫枯在條。", "宵不徯晨乃繇，東風之行地上兮。", "上德爲政，匪食匪招。", "莫顧於家，莫流於遼。", "以飽以迴，晨不徯霄，隴西公來浚都兮。"]'),
('49243050-ebfa-4e56-a695-493e61d65601','有所恨二章 一','歐陽詹','唐','唐诗','tang','','[]','相思君子，吁嗟萬里。',46,'全唐诗/poet.tang.18000.json','["相思君子，吁嗟萬里。", "亦既至止，曷不覯止。", "本不信巫，謂巫言是履。", "在門五日，如待之死，有所恨兮。"]'),
('adf4050a-da16-4038-81fc-302ce657db02','有所恨二章 二','歐陽詹','唐','唐诗','tang','','[]','相思遺衣，爲憶以貽。',46,'全唐诗/poet.tang.18000.json','["相思遺衣，爲憶以貽。", "亦既受止，曷不保持。", "本不欺友，謂友情是違。", "隔生之贈，造次亡之，有所恨兮。"]'),
('879a3a26-c1d4-4e47-bda6-b6e98481547d','玩月','歐陽詹','唐','唐诗','tang','','[]','八月十五夕，舊嘉蟾兔光。',96,'全唐诗/poet.tang.18000.json','["八月十五夕，舊嘉蟾兔光。", "斯從古人好，共下今宵堂。", "素魄皎孤凝，芳輝紛四揚。", "裴回林上頭，泛灧天中央。", "皓露助流華，輕風佐浮涼。", "清冷到肌骨，潔白盈衣裳。", "惜此苦宜玩，攬之非可將。", "含情顧廣庭，願勿沈西方。"]'),
('358b69bc-760b-4274-9fd6-1a2251eb9699','詠德上韋檢察','歐陽詹','唐','唐诗','tang','','[]','少華類太華，太室似少室。',96,'全唐诗/poet.tang.18000.json','["少華類太華，太室似少室。", "亞相與丞相，亦復無異質。", "渟如月臨水，肅若松照日。", "輝影互光澄，陰森兩蔥鬱。", "連城鸞鳳分，同氣龜龍出。", "併力革夷心，通籌整師律。", "英豪願迴席，蠻貊皆屈膝。", "中外行分途，寰瀛待清謐。"]'),
('39504689-a531-4837-96ff-43ed29ace50a','寓興','歐陽詹','唐','唐诗','tang','','[]','桃李有奇質，樗櫟無妙姿。',48,'全唐诗/poet.tang.18000.json','["桃李有奇質，樗櫟無妙姿。", "皆承慶雲沃，一種春風吹。", "美惡苟同歸，喧囂徒爾爲。", "相將任玄造，聊醉手中巵。"]'),
('e4d037ba-589c-4cda-af55-98f2cf5ad48f','荅韓十八駑驥吟','歐陽詹','唐','唐诗','tang','','[]','故人舒其憤，昨示駑驥篇。',204,'全唐诗/poet.tang.18000.json','["故人舒其憤，昨示駑驥篇。", "駑以易售陳，驥以難知言。", "委曲感既深，咨嗟詞亦殷。", "伊情有遠瀾，余志遜其源。", "室在周孔堂，道通堯舜門。", "調雅聲寡同，途遐勢難翻。", "顧茲萬恨來，假彼二物云。", "賤貴而貴賤，世人良共然。", "巴蕉一葉妖，茙葵一花妍。", "畢無才實資，手植堦墀前。", "楩柟十圍瑰，松柏百尺堅。", "罔念梁棟功，野長丘墟邊。", "傷哉昌黎韓，焉得不迍邅。", "上帝本厚生，大君方建元。", "寶將庇羣甿，庶此規崇軒。", "班爾圖永安，掄擇期精專。", "君看廣廈中，豈有樹庭萱。"]'),
('dc03f335-ced6-4cb0-bd9e-e24151c01b6e','益昌行','歐陽詹','唐','唐诗','tang','','[]','驅馬至益昌，倍驚風俗和。',156,'全唐诗/poet.tang.18000.json','["驅馬至益昌，倍驚風俗和。", "耕夫隴上謠，負者途中歌。", "處處川復原，重重山與河。", "人煙遍餘田，時稼無閑坡。", "問業一何脩，太守德化加。", "問身一何安，太守恩懷多。", "賢哉我太守，在古無以過。", "愛人甚愛身，治郡如治家。", "雲雷既奮騰，草木遂萌芽。", "乃知良二千，德足爲國華。", "今時固精求，漢帝非徒嗟。", "四海有青春，衆植佇揚葩。", "期當作說霖，天下同雱𩃱。"]'),
('455b1c96-7b63-4d5e-88c0-ee32154c68d4','自淮中却赴洛途中作','歐陽詹','唐','唐诗','tang','','[]','惆悵策疲馬，孤蓬被風吹。',48,'全唐诗/poet.tang.18000.json','["惆悵策疲馬，孤蓬被風吹。", "昨東今又西，冉冉長路岐。", "歲晚樹無葉，夜寒霜滿枝。", "旅人恒苦辛，冥寞天何知。"]'),
('77c91cec-5b68-4b9b-9984-eecb94006d7b','晨裝行','歐陽詹','唐','唐诗','tang','','[]','村店月西出，山林鵯鵊聲。',48,'全唐诗/poet.tang.18000.json','["村店月西出，山林鵯鵊聲。", "旅燈徹夜席，束囊事晨征。", "寂寂人尚眠，悠悠天未明。", "豈無偃息心，所務前有程。"]'),
('1eefb001-0b7b-435f-bd3a-61837433a2e9','新都行','歐陽詹','唐','唐诗','tang','','[]','縹緲空中絲，蒙籠道傍樹。',48,'全唐诗/poet.tang.18000.json','["縹緲空中絲，蒙籠道傍樹。", "翻茲葉間吹，惹破花上露。", "悠揚絲意去，苒蒻花枝住。", "何計脫纏綿，天長春日暮。"]'),
('c7693fd9-1b59-4478-844b-91bfc6d5a29d','銅雀妓','歐陽詹','唐','唐诗','tang','','[]','蕭條登古臺，迴首黃金屋。',48,'全唐诗/poet.tang.18000.json','["蕭條登古臺，迴首黃金屋。", "落葉不歸林，高陵永爲谷。", "妝容徒自麗，舞態閱誰目。", "惆悵繐帷空，歌聲苦於哭。"]'),
('fafc09ae-0b35-448d-8acb-6d5202c5180a','太原旅懷呈薛十八侍御齊十二奉禮','歐陽詹','唐','唐诗','tang','','[]','前來稱英雋，有食主人魚。',96,'全唐诗/poet.tang.18000.json','["前來稱英雋，有食主人魚。", "後來曰賢才，又受主人車。", "伊予亦投刺，恩煦胡凋疎。", "既覩主人面，復見主人書。", "餬口百家周，賃廡三月餘。", "眼見寒序臻，坐送秋光除。", "西日惄飢腸，北風疾絺裾。", "升堂有知音，此意當何如。"]'),
('d786a412-340b-4aed-b485-3b45bf6efc61','李評事公進示文集因贈之','歐陽詹','唐','唐诗','tang','','[]','風雅不墜地，五言始君先。',156,'全唐诗/poet.tang.18000.json','["風雅不墜地，五言始君先。", "希微嘉會章，杳冥河梁篇。", "理蔓語無枝，言一意則千。", "往來更後人，澆蕩醨前源。", "傾筐實不收，樸樕華爭繁。", "大教護微旨，哲人生令孫。", "高飆激頹波，坐使橫流翻。", "昔日越重阻，側聆滄海傳。", "逮茲覿清揚，幸覩青琅編。", "泠泠中山醇，片片崑丘璠。", "一杯有餘味，再覽增光鮮。", "對寶人皆鑒，握鞶良自妍。", "吾其告先師，六義今還全。"]'),
('bee2cbb1-71a9-4702-91dc-cce9446269ff','徐十八晦落第','歐陽詹','唐','唐诗','tang','','[]','嘉穀不夏熟，大器當晚成。',48,'全唐诗/poet.tang.18000.json','["嘉穀不夏熟，大器當晚成。", "徐生異凡鳥，安得非時鳴。", "汲汲有所爲，驅驅無本情。", "懿哉蒼梧鳳，終見排雲征。"]'),
('9e52799f-5182-4e6f-ae2e-f411c4af69f2','春日途中寄故園所親','歐陽詹','唐','唐诗','tang','','[]','客路度年華，故園云未返。',48,'全唐诗/poet.tang.18000.json','["客路度年華，故園云未返。", "悠悠去源水，日日只有遠。", "始歎秋葉零，又看春草晚。", "寄書南飛鴻，相憶劇鄉縣。"]'),
('2c05f2b1-902f-49dd-a9ff-bc4fae236a7b','蜀中將歸留辭韓相公貫之','歐陽詹','唐','唐诗','tang','','[]','寧體即雲構，方前恒玉食。',48,'全唐诗/poet.tang.18000.json','["寧體即雲構，方前恒玉食。", "貧居豈及此，要自懷歸憶。", "在夢關山遠，如流歲華逼。", "明晨首鄉路，迢遰孤飛翼。"]'),
('a9f11723-8c05-4402-8ecb-9282de704534','江夏留別華二','歐陽詹','唐','唐诗','tang','','[]','弭棹已傷別，不堪離緒催。',48,'全唐诗/poet.tang.18000.json','["弭棹已傷別，不堪離緒催。", "十年一心人，千里同舟來。", "鄉路我尚遙，客遊君未回。", "將何慰兩端，互勉臨岐杯。"]'),
('f4d7c131-d44a-4feb-845b-f55e47bcfb60','送潭州陸戶曹之任','歐陽詹','唐','唐诗','tang','','[]','三語又爲掾，大家聞屈聲。',48,'全唐诗/poet.tang.18000.json','["三語又爲掾，大家聞屈聲。", "多年名下人，四姓江南英。", "衡嶽半天秀，湘潭無底清。", "何言驅車遠，去有蒙莊情。"]'),
('c19d180f-2283-4d4c-9adf-65d1dbdc129b','福州送鄭楚材赴京時監察劉公亮有感激鄭意','歐陽詹','唐','唐诗','tang','','[]','美人河嶽靈，家本滎水濆。',120,'全唐诗/poet.tang.18000.json','["美人河嶽靈，家本滎水濆。", "門承若蘭族，身蘊如瓊文。", "早折青桂枝，俯窺鴻鵠羣。", "邇來丹霄姿，遠逐蒼梧雲。", "有伊光鑒人，惜茲瑤蕙薰。", "中酣前激昂，四座同氛氳。", "海郡梅霪晴，山郵炎景曛。", "迴翔罷南遊，鳴唳期西聞。", "秦塞鸞鳳征，越江雲雨分。", "從茲一別離，佇致如堯君。"]'),
('7b18f8d4-7e91-4311-910f-83687f2092aa','初發太原途中寄太原所思','歐陽詹','唐','唐诗','tang','','[]','驅馬覺漸遠，迴頭長路塵。',72,'全唐诗/poet.tang.18000.json','["驅馬覺漸遠，迴頭長路塵。", "高城已不見，況復城中人。", "去意自未甘，居情諒猶辛。", "五原東北晉，千里西南秦。", "一屨不出門，一車無停輪。", "流萍與繫匏，早晚期相親。"]'),
('c544c727-c17f-486e-a2d2-dd00027319bc','汝川行','歐陽詹','唐','唐诗','tang','','[]','汝墳春女蠶忙月，朝起採桑日西沒。',64,'全唐诗/poet.tang.18000.json','["汝墳春女蠶忙月，朝起採桑日西沒。", "輕綃裙露紅羅襪，半蹋金梯倚枝歇。", "垂空玉腕若無骨，映葉朱唇似花發。", "相歡誰是遊冶郎，蠶休不得岐路旁。"]'),
('84f71b83-837d-45ff-9cc4-3d4a788aa232','智達上人水精念珠歌','歐陽詹','唐','唐诗','tang','','[]','水已清，清中不易當其精。',216,'全唐诗/poet.tang.18000.json','["水已清，清中不易當其精。", "精華極，何宜更復加磨拭。", "良工磨拭成貫珠，泓澄洞澈看如無。", "星輝月耀莫之逾，駭雞照乘徒稱殊。", "上人念佛泛貞諦，一佛一珠以爲計。", "既指其珠當佛身，亦欲珠明佛像智。", "咨董母，訪朱公。", "得之玓瓅羣奇中，龍龕鷲嶺長隨躬。", "朝自守持纖掌透，夜來月照紅條空。", "窮川極陸難爲寶，孰說軖璖將瑪瑙。", "連連寒溜下陰軒，熒熒泫露垂秋草。", "皎晶晶，彰煌煌。", "陸離電烻紛不常，凌眸暈目生光芒。", "我來借問修行術，數日殷勤美茲物。", "上人視日授微言，心靜如斯即諸佛。"]'),
('084bd5ac-df4b-4dfe-b1b7-2b313031f1c9','許州途中','歐陽詹','唐','唐诗','tang','','[]','秦川行盡潁川長，吳江越嶺已同方。',64,'全唐诗/poet.tang.18000.json','["秦川行盡潁川長，吳江越嶺已同方。", "征途渺渺煙茫茫，未得還鄉傷近鄉。", "隨萍逐梗見春光，行樂登臺鬬在旁。", "林間啼鳥野中芳，有似故園皆斷腸。"]'),
('07a036a1-fe61-431c-acf2-31af1c614832','賦得秋河曙耿耿送郭秀才應舉','歐陽詹','唐','唐诗','tang','','[]','月沒天欲明，秋河尚凝白。',164,'全唐诗/poet.tang.18000.json','["月沒天欲明，秋河尚凝白。", "皚皚積光素，耿耿橫虛碧。", "南斗接，北辰連，空濛鴻洞浮高天。", "蕩蕩漫漫皆晶然，實類平蕪流大川。", "星爲潭底珠，雲是波中煙。", "雞唱漏盡東方作，曲渚蒼蒼曉霜落。", "鴈叫疑從清淺驚，鳧聲似在沿洄泊。", "幷州細侯直下孫，才應秋賦懷金門。", "念排雲漢將飛翻，仰之踴躍當華軒。", "夜來陪餞歐陽子，偶坐通宵見深旨。", "心知慷慨日昭然，前程心在青雲裏。"]'),
('2fd9de74-3cf1-458a-b466-3b200a4f02ec','送袁秀才下第歸毘陵','歐陽詹','唐','唐诗','tang','','[]','羸馬出都門，修途指江東。',48,'全唐诗/poet.tang.18000.json','["羸馬出都門，修途指江東。", "關河昨夜雨，草木非春風。", "矢捨雖未中，璞全終待攻。", "層霄秋可翔，豈不隨高鴻。"]'),
('ce55dfbe-58f4-4c3e-989e-87eea0afc301','聞鄰舍唱涼州有所思','歐陽詹','唐','唐诗','tang','','[]','有善伊涼曲，離別在天涯。',48,'全唐诗/poet.tang.18000.json','["有善伊涼曲，離別在天涯。", "虛堂正相思，所妙發鄰家。", "聲音雖類聞，形影終以遐。", "因之增遠懷，惆悵菖蒲花。"]'),
('6be58134-7437-4e69-96c4-79b5d56a2e40','陪太原鄭行軍中丞登汾上閣中丞詩曰汾樓秋水闊宛似到閶門惆悵江湖思惟將南客論南客即詹也輒書即事上荅','歐陽詹','唐','唐诗','tang','','[]','幷州汾上閣，登望似吳閶。',48,'全唐诗/poet.tang.18000.json','["幷州汾上閣，登望似吳閶。", "貫郭河通路，縈村水逼鄉。", "城槐臨枉渚，巷市接飛梁。", "莫論江湖思，南人正斷腸。"]'),
('30726e0d-5d2b-4fbe-8665-cab35288179d','送少微上人歸德峯','歐陽詹','唐','唐诗','tang','','[]','不負人間累，棲身任所從。',48,'全唐诗/poet.tang.18000.json','["不負人間累，棲身任所從。", "灰心聞密行，菜色見羸容。", "幻世方同悟，深居願繼踪。", "孤雲與禪誦，到後在何峯。"]'),
('4d84619b-2065-42ec-81e4-fdc19b5c7b93','荆南夏夜水樓懷昭丘直上人雲夢李莘','歐陽詹','唐','唐诗','tang','','["\u5b64\u72ec", "\u5199\u666f", "\u6292\u60c5", "\u6c34"]','無機成旅逸，中夜上江樓。',48,'全唐诗/poet.tang.18000.json','["無機成旅逸，中夜上江樓。", "雲盡月如練，水涼風似秋。", "鳧聲聞夢澤，黛色上昭丘。", "不遠人情在，良宵恨獨遊。"]'),
('a52a19f0-ead1-4794-b251-81d26a38ce12','酬裴十二秀才孩子詠','歐陽詹','唐','唐诗','tang','','[]','算日未成年，英姿已[襃]然。',50,'全唐诗/poet.tang.18000.json','["算日未成年，英姿已[襃]然。", "王家千里後，荀氏八龍先。", "蔥蒨松猶嫩，清明月漸圓。", "將何一枝桂，容易賞名賢。"]'),
('1fdf6645-69a1-40fc-8a38-29f170bc949f','旅次舟中對月寄姜公','歐陽詹','唐','唐诗','tang','','[]','中宵天色淨，片月出滄洲。',48,'全唐诗/poet.tang.18000.json','["中宵天色淨，片月出滄洲。", "皎潔臨孤島，嬋娟入亂流。", "應同故園夜，獨起異鄉愁。", "那得修蓬轉，從君上庾樓。"]'),
('60d3b99d-99a2-4d2a-94fe-67ad3005be16','除夜長安客舍','歐陽詹','唐','唐诗','tang','','["\u601d\u4e61", "\u6625\u8282"]','十上書仍寢，如流歲又遷。',48,'全唐诗/poet.tang.18000.json','["十上書仍寢，如流歲又遷。", "望家思獻壽，算甲恨長年。", "虛牖傳寒柝，孤燈照絕編。", "誰應問窮轍，泣盡更潸然。"]'),
('8340c35c-e614-442b-88ee-953777780df5','早秋登慈恩寺塔','歐陽詹','唐','唐诗','tang','','[]','寶塔過千仞，登臨盡四維。',48,'全唐诗/poet.tang.18000.json','["寶塔過千仞，登臨盡四維。", "毫端分馬頰，墨點辨蛾眉。", "地逈風彌緊，天長日久遲。", "因高欲有賦，遠意慘生悲。"]'),
('e2227f88-0595-46df-8a7f-6cf8ad77a2d6','太原和嚴長官八月十五日夜西山童子上方玩月寄中丞少尹','歐陽詹','唐','唐诗','tang','','[]','西寺碧雲端，東溟白雪團。',48,'全唐诗/poet.tang.18000.json','["西寺碧雲端，東溟白雪團。", "年來一夜玩，君在半天看。", "素魄當懷上，清光在下寒。", "宜裁濟江什，有阻惠連歡。"]'),
('e0403532-fc3c-4599-9a51-28e131f578a1','九日廣陵同陳十五先輩登高懷林十二先輩','歐陽詹','唐','唐诗','tang','','[]','客路重陽日，登高寄上樓。',48,'全唐诗/poet.tang.18000.json','["客路重陽日，登高寄上樓。", "風煙今令節，臺閣古雄州。", "泛菊聊斟酒，持萸嬾插頭。", "情人共惆悵，良久不同遊。"]'),
('994c7472-17c8-45aa-b66f-6d15bb892e27','題嚴光釣臺','歐陽詹','唐','唐诗','tang','','[]','弭棹歷塵跡，悄然關我情。',48,'全唐诗/poet.tang.18000.json','["弭棹歷塵跡，悄然關我情。", "伊無昔時節，豈有今日名。", "辭貴不辭賤，是心誰復行。", "欽哉此溪曲，永獨古風清。"]'),
('69588c99-4ab4-4da8-a846-bc0f2729d506','送高士安下第歸岷南寧覲','歐陽詹','唐','唐诗','tang','','[]','偕隱有賢親，岷南四十春。',48,'全唐诗/poet.tang.18000.json','["偕隱有賢親，岷南四十春。", "棲雲自匪石，觀國暫同塵。", "就養思兒戲，延年愛鳥伸。", "還看謝時去，有類潁陽人。"]'),
('ef860c48-a517-48a8-8aa1-826f47bfafba','述德上興元嚴僕射','歐陽詹','唐','唐诗','tang','','[]','山橫碧立並雄岷，大阜洪川共降神。',64,'全唐诗/poet.tang.18000.json','["山橫碧立並雄岷，大阜洪川共降神。", "心合雲雷清禍亂，力迴天地作陽春。", "非熊德媿當周輔，稱傑叨慙首漢臣。", "何幸腐儒無一藝，得爲門下食魚人。"]'),
('1989e242-9e27-44c6-9413-7ca68e470f9f','及第後酬故園親故','歐陽詹','唐','唐诗','tang','','[]','才非天授學非師，以此成名曩豈期。',64,'全唐诗/poet.tang.18000.json','["才非天授學非師，以此成名曩豈期。", "楊葉射頻因偶中，桂枝材美敢當之。", "稱文作藝方慙德，相賀投篇料媿詞。", "猶著褐衣何足羨，如君即是載鳴時。"]'),
('855d8967-d433-4ec4-8968-cb53bec512b0','題華十二判官汝州宅內亭','歐陽詹','唐','唐诗','tang','','[]','高居勝景誰能有，佳意幽情共可歡。',64,'全唐诗/poet.tang.18000.json','["高居勝景誰能有，佳意幽情共可歡。", "新柳遶門青翡翠，修篁浮徑碧琅玕。", "步兵阮籍空除屏，彭澤陶潛謾挂冠。", "只在城隍也趨府，豈如吾子道斯安。"]'),
('01cc00ab-b96f-4f24-aedd-8e3f0981fdbe','薛舍人使君觀察韓判官侍御許雨晴到所居既霽先呈即事','歐陽詹','唐','唐诗','tang','','[]','江臯昨夜雨收梅，寂寂衡門與釣臺。',64,'全唐诗/poet.tang.18000.json','["江臯昨夜雨收梅，寂寂衡門與釣臺。", "西島落花隨水至，前山飛鳥出雲來。", "觀風駟馬能言駐，行縣雙旌許蹔迴。", "豈不偶然聊爲竹，空令石逕掃莓苔。"]'),
('ff32e672-5b8e-45e2-b1dd-c14d0ad909ee','元日陪早朝','歐陽詹','唐','唐诗','tang','','[]','斗柄東迴歲又新，邃旒南面挹來賓。',64,'全唐诗/poet.tang.18000.json','["斗柄東迴歲又新，邃旒南面挹來賓。", "和光髣髴樓臺曉，休氣氛氳天地春。", "儀籥不唯丹穴鳥，稱觴半是越裳人。", "江臯腐草今何幸，亦與恒星拱北辰。"]'),
('5689f7b8-86c8-4a2d-91e2-2d192f8818ef','和太原鄭中丞登龍興寺閣','歐陽詹','唐','唐诗','tang','','["\u9ec4\u6cb3"]','青窗朱戶半天開，極目凝神望幾迴。',64,'全唐诗/poet.tang.18000.json','["青窗朱戶半天開，極目凝神望幾迴。", "晉國頹墉生草樹，皇家瑞氣在樓臺。", "千條水入黃河去，萬點山從紫塞來。", "獨恨侍遊違長者，不知高意是誰陪。"]'),
('91ae8451-d75e-4354-9ffa-5a93b3e50c78','詠德上太原李尚書','歐陽詹','唐','唐诗','tang','','[]','那以公方郭細侯，幷州非復舊幷州。',64,'全唐诗/poet.tang.18000.json','["那以公方郭細侯，幷州非復舊幷州。", "九重帝宅司丹地，十萬兵樞擁碧油。", "鏘玉半爲趨閤吏，腰金皆是走庭流。", "王襃見德空知頌，身在三千最上頭。"]'),
('d35e86d0-1748-4524-b21a-7e0f05d410a2','和嚴長官秋日登太原龍興寺閣野望','歐陽詹','唐','唐诗','tang','','[]','百丈化城樓，君登最上頭。',96,'全唐诗/poet.tang.18000.json','["百丈化城樓，君登最上頭。", "九霄回棧路，八到視幷州。", "煙火遺堯庶，山河啓聖猷。", "短垣齊介嶺，片白指分流。", "清鐸中天籟，哀鳴下界秋。", "境閑知道勝，心遠見名浮。", "豈念乘肥馬，方應駕大牛。", "自憐蓬逐吹，不得與良遊。"]'),
('c38a63bc-bf26-4379-8a83-eaebcab303b6','小苑春望宮池柳色','歐陽詹','唐','唐诗','tang','','[]','東風韶景至，垂柳御溝新。',72,'全唐诗/poet.tang.18000.json','["東風韶景至，垂柳御溝新。", "媚作千門秀，連爲一道春。", "柔荑生女指，嫩葉長龍鱗。", "舞絮迴青岸，翻煙拂綠蘋。", "王孫初命賞，佳客欲傷神。", "芳意堪相贈，一枝先遠人。"]'),
('97fa05d3-e555-40af-aa33-ac4bb3750bf0','蜀門與林藴分路後屢有山川似閩中因寄林藴藴亦閩人也','歐陽詹','唐','唐诗','tang','','[]','村步如延壽，川原似福平。',24,'全唐诗/poet.tang.18000.json','["村步如延壽，川原似福平。", "無人相共識，獨自故鄉情。"]'),
('8a794755-ce81-4b97-a3d2-48cbdb28ae9e','讀周太公傳','歐陽詹','唐','唐诗','tang','','[]','論兵去商虐，講德興周道。',24,'全唐诗/poet.tang.18000.json','["論兵去商虐，講德興周道。", "屠沽未遇時，豈異茲川老。"]'),
('5eda2e48-d0fb-418a-8b38-84d705bd4cde','樂津店北陂','歐陽詹','唐','唐诗','tang','','[]','嬋娟有麗玉如也，美笑當予繫予馬。',32,'全唐诗/poet.tang.18000.json','["嬋娟有麗玉如也，美笑當予繫予馬。", "羅幃碧簟豈相容，行到山頭憶山下。"]'),
('d7cddc61-5ae5-4032-a44e-43c6e1da0566','出蜀門','歐陽詹','唐','唐诗','tang','','[]','北客今朝出蜀門，翛然領得入時魂。',32,'全唐诗/poet.tang.18000.json','["北客今朝出蜀門，翛然領得入時魂。", "遊人莫道歸來易，三不曾聞古老言。"]'),
('5ec74fde-5b02-4481-88f7-07670a452d04','題第五司戶侍御','歐陽詹','唐','唐诗','tang','','[]','曾稱野鶴比羣公，忽作長松向府中。',32,'全唐诗/poet.tang.18000.json','["曾稱野鶴比羣公，忽作長松向府中。", "驄馬不騎人不識，冷然三尺別生風。"]'),
('d7c69883-1ef7-4791-aad3-a5f030d5eed0','建溪行待陳詡','歐陽詹','唐','唐诗','tang','','[]','偕行那得會心期，先者貪前後者遲。',32,'全唐诗/poet.tang.18000.json','["偕行那得會心期，先者貪前後者遲。", "空憶麗詞能狀物，每看奇異但相思。"]'),
('7070422c-8945-4916-baa0-31ab2febfb20','述德上興元嚴僕射','歐陽詹','唐','唐诗','tang','','[]','推車閫外主恩新，今日梁川草遍春。',32,'全唐诗/poet.tang.18000.json','["推車閫外主恩新，今日梁川草遍春。", "玉色據鞍雙節下，揚兵百萬路無塵。"]'),
('2cb358f3-1e3d-4422-b218-56eb2d719e8b','許州送張中丞出臨潁鎮','歐陽詹','唐','唐诗','tang','','[]','心誦陰符口不言，風驅千騎出轅門。',32,'全唐诗/poet.tang.18000.json','["心誦陰符口不言，風驅千騎出轅門。", "孫吳去後無長策，誰敵留侯直下孫。"]'),
('f05df1de-4fe9-47c8-82c3-1dc42796bc22','覩亡友題詩處','歐陽詹','唐','唐诗','tang','','[]','舊友親題壁上詩，傷看緣跡不緣詞。',32,'全唐诗/poet.tang.18000.json','["舊友親題壁上詩，傷看緣跡不緣詞。", "門前猶是長安道，無復迴車下筆時。"]'),
('66255388-5cf2-427f-861f-7809a38dde30','題秦嶺','歐陽詹','唐','唐诗','tang','','[]','南下斯須隔帝鄉，北行一步掩南方。',32,'全唐诗/poet.tang.18000.json','["南下斯須隔帝鄉，北行一步掩南方。", "悠悠煙景兩邊意，蜀客秦人各斷腸。"]'),
('80ae0056-53e2-4922-9a5d-aa6822753297','自南山却赴京師石臼嶺頭即事寄嚴僕射','歐陽詹','唐','唐诗','tang','','[]','鳥企蛇盤地半天，下窺千仞到浮煙。',32,'全唐诗/poet.tang.18000.json','["鳥企蛇盤地半天，下窺千仞到浮煙。", "因高回望沾恩處，認得梁州落日邊。"]'),
('bed5209b-488b-44e0-b075-3a9d5c10a43b','與洪孺卿自梁州迴途中經駱谷見野果有閩中懸壺子即同採摘因呈之洪亦閩人','歐陽詹','唐','唐诗','tang','','[]','青苞朱實忽離離，摘得盈筐淚更垂。',32,'全唐诗/poet.tang.18000.json','["青苞朱實忽離離，摘得盈筐淚更垂。", "上德同之豈無意，故園山路一枝枝。"]'),
('cb341afc-6306-4758-9cc0-48d26463dd66','韋晤宅聽歌','歐陽詹','唐','唐诗','tang','','[]','服製虹霓鬢似雲，蕭郎屋裏上清人。',32,'全唐诗/poet.tang.18000.json','["服製虹霓鬢似雲，蕭郎屋裏上清人。", "等閑逐酒傾杯樂，飛盡虹梁一夜塵。"]'),
('ef440ea8-c82e-480f-a12a-c0bb31f8c8ca','與林藴同之蜀途次嘉陵江認得越鳥聲呈林林亦閩中人也','歐陽詹','唐','唐诗','tang','','[]','正是閩中越鳥聲，幾回留聽暗沾纓。',32,'全唐诗/poet.tang.18000.json','["正是閩中越鳥聲，幾回留聽暗沾纓。", "傷心激念君深淺，共有離鄉萬里情。"]'),
('8b8e247e-6bcc-476b-94d8-1cdff649e142','送聞上人遊嵩山','歐陽詹','唐','唐诗','tang','','[]','二室峯峯昔願遊，從雲從鶴思悠悠。',32,'全唐诗/poet.tang.18000.json','["二室峯峯昔願遊，從雲從鶴思悠悠。", "丹梯石路君先去，爲上青冥最上頭。"]'),
('58a44419-4efb-4b61-b76c-2f8c54a9e852','永安寺照上人房','歐陽詹','唐','唐诗','tang','','[]','草席蒲團不掃塵，松閑石上似無人。',32,'全唐诗/poet.tang.18000.json','["草席蒲團不掃塵，松閑石上似無人。", "羣陰欲午鐘聲動，自煮溪蔬養幻身。"]'),
('f14cd215-be6a-4661-80b6-ebfbca36c438','山中老僧','歐陽詹','唐','唐诗','tang','','[]','笑向來人話古時，繩牀竹杖自扶持。',32,'全唐诗/poet.tang.18000.json','["笑向來人話古時，繩牀竹杖自扶持。", "秋深頭冷不能剃，白黑蒼然髪到眉。"]'),
('ee3a748c-e210-472d-99bb-71831799d10d','贈魯山李明府','歐陽詹','唐','唐诗','tang','','[]','外戶通宵不閉關，抱孫弄子萬家閑。',32,'全唐诗/poet.tang.18000.json','["外戶通宵不閉關，抱孫弄子萬家閑。", "若將邑號稱賢宰，又是皇唐李魯山。"]'),
('9ca644ee-c880-47fa-a80b-ed18ae8d973d','泉州赴上都留別舍弟及故人','歐陽詹','唐','唐诗','tang','','[]','天長地闊多岐路，身即飛蓬共水萍。',32,'全唐诗/poet.tang.18000.json','["天長地闊多岐路，身即飛蓬共水萍。", "匹馬將驅豈容易，弟兄親故滿離亭。"]'),
('8931a16d-73b3-48c5-bb27-b856f92a700d','送張驃騎邠寧行營','歐陽詹','唐','唐诗','tang','','[]','寶馬琱弓金僕姑，龍驤虎視出皇都。',32,'全唐诗/poet.tang.18000.json','["寶馬琱弓金僕姑，龍驤虎視出皇都。", "揚鞭莫怪輕胡虜，曾在漁陽敵萬夫。"]'),
('4f1f1858-9efe-4e97-b679-db52d06f08e1','題棃嶺','歐陽詹','唐','唐诗','tang','','[]','南北風煙即異方，連峯危棧倚蒼蒼。',32,'全唐诗/poet.tang.18000.json','["南北風煙即異方，連峯危棧倚蒼蒼。", "哀猨咽水偏高處，誰不沾衣望故鄉。"]'),
('e7b91849-3907-488f-ba7f-e3e758b5cccd','秋夜寄僧','歐陽詹','唐','唐诗','tang','','[]','尚被浮名誘此身，今時誰與德爲鄰。',32,'全唐诗/poet.tang.18000.json','["尚被浮名誘此身，今時誰與德爲鄰。", "遙知是夜檀溪上，月照千峯爲一人。"]'),
('8caeacee-deaf-4bd0-8239-0e17328c4d13','觀送葬','歐陽詹','唐','唐诗','tang','','[]','何事悲酸淚滿巾，浮生共是北邙塵。',32,'全唐诗/poet.tang.18000.json','["何事悲酸淚滿巾，浮生共是北邙塵。", "他時不見北山路，死者還曾哭送人。"]'),
('f0a09c3b-54ff-48e6-b5e6-371387278537','宿建溪中宵即事','歐陽詹','唐','唐诗','tang','','[]','𥳌{𥫗/窮}一席眠還坐，蛙噪螢飛夜未央。',36,'全唐诗/poet.tang.18000.json','["𥳌{𥫗/窮}一席眠還坐，蛙噪螢飛夜未央。", "僮僕舟人空寂寂，隔簾微月入中倉。"]'),
('c55d61ca-f437-40dd-b84d-92fda8e2a83f','題王明府郊亭','歐陽詹','唐','唐诗','tang','','[]','日日郊亭啓竹扉，論桑勸穡是常機。',32,'全唐诗/poet.tang.18000.json','["日日郊亭啓竹扉，論桑勸穡是常機。", "山城要得牛羊下，方與農人分背歸。"]'),
('0fbde34e-6692-4e18-bd4c-71ad7b3dbbac','塞上行','歐陽詹','唐','唐诗','tang','','[]','聞說胡兵欲利秋，昨來投筆到營州。',32,'全唐诗/poet.tang.18000.json','["聞說胡兵欲利秋，昨來投筆到營州。", "驍雄已許將軍用，邊塞無勞天子憂。"]'),
('af215778-668a-4186-bf55-d25cc6791ec9','題別業','歐陽詹','唐','唐诗','tang','','[]','千山江上背斜暉，一徑中峯見所歸。',32,'全唐诗/poet.tang.18000.json','["千山江上背斜暉，一徑中峯見所歸。", "不信扁舟迴在晚，宿雲先已到柴扉。"]'),
('8ee4a403-4578-4bde-bb43-b5e7e5f296ed','九日廣陵登高懷邵二先輩','歐陽詹','唐','唐诗','tang','','[]','簪萸泛菊俯平阡，飲過三杯却惘然。',32,'全唐诗/poet.tang.18000.json','["簪萸泛菊俯平阡，飲過三杯却惘然。", "十歲此辰同醉友，登高各處已三年。"]'),
('4001fe9b-8bc2-44f7-9b23-9436708a523b','題延平劒潭','歐陽詹','唐','唐诗','tang','','[]','想象精靈欲見難，通津一去水漫漫。',32,'全唐诗/poet.tang.18000.json','["想象精靈欲見難，通津一去水漫漫。", "空餘昔日凌霜色，長與澄潭生晝寒。"]'),
('27114f2b-7cd1-4aea-8020-c80155a8885e','晚泊漳州營頭亭','歐陽詹','唐','唐诗','tang','','[]','迴峯疊嶂遶庭隅，散點煙霞勝畫圖。',32,'全唐诗/poet.tang.18000.json','["迴峯疊嶂遶庭隅，散點煙霞勝畫圖。", "日暮華軒卷長箔，太清雲上對蓬壺。"]'),
('85864d15-6ae3-468a-9559-08a310507242','贈山南嚴兵馬使','歐陽詹','唐','唐诗','tang','','[]','爲鴈爲鴻弟與兄，如雕如鶚傑連英。',32,'全唐诗/poet.tang.18000.json','["爲鴈爲鴻弟與兄，如雕如鶚傑連英。", "天旋地轉煙雲黑，共鼓長風六合清。"]'),
('68479c4e-2461-4f27-8810-95565529446b','除夜侍酒呈諸兄示舍弟','歐陽詹','唐','唐诗','tang','','[]','莫歎明朝又一春，相看堪共貴茲身。',32,'全唐诗/poet.tang.18000.json','["莫歎明朝又一春，相看堪共貴茲身。", "悠悠寰宇同今夜，膝下傳杯有幾人。"]'),
('506593fa-4613-495c-99df-9cc35ac6e058','皇武 一','柳宗元','唐','唐诗','tang','','[]','皇耆其武，于溵于淮。',40,'全唐诗/poet.tang.18000.json','["皇耆其武，于溵于淮。", "既巾乃車，環蔡具來。", "狡衆昏嚚，甚毒于酲。", "狂奔呌呶，以干大刑。"]'),
('b7300491-6061-4e49-980c-76ca3da9882d','皇武 二','柳宗元','唐','唐诗','tang','','[]','皇咨于度，惟汝一德。',40,'全唐诗/poet.tang.18000.json','["皇咨于度，惟汝一德。", "曠誅四紀，其徯汝克。", "錫汝斧鉞，其往視師。", "師是蔡人，以宥以釐。"]'),
('301414a1-bb58-41cb-94e3-c80b09371490','皇武 三','柳宗元','唐','唐诗','tang','','[]','度拜稽首，廟于元龜。',40,'全唐诗/poet.tang.18000.json','["度拜稽首，廟于元龜。", "既禡既類，于社是宜。", "金節煌煌，錫盾雕戈。", "犀甲熊旂，威命是荷。"]'),
('25d55e99-63e4-49b3-b303-45e00cd6baa6','皇武 四','柳宗元','唐','唐诗','tang','','[]','度拜稽首，出次于東。',40,'全唐诗/poet.tang.18000.json','["度拜稽首，出次于東。", "天子餞之，罍斝是崇。", "鼎臑俎胾，五獻百籩。", "凡百卿士，班以周旋。"]'),
('3f9780ae-224e-4f08-9238-354c2fbdb3e3','皇武 五','柳宗元','唐','唐诗','tang','','[]','既涉于滻，乃翼乃前。',40,'全唐诗/poet.tang.18000.json','["既涉于滻，乃翼乃前。", "孰圖厥猶，其佐多賢。", "宛宛周道，于山于川。", "遠揚邇昭，陟降連連。"]'),
('67c391a9-e57e-46f3-a213-27338f012939','皇武 六','柳宗元','唐','唐诗','tang','','[]','我斾我旗，于道于陌。',40,'全唐诗/poet.tang.18000.json','["我斾我旗，于道于陌。", "訓于羣帥，拳勇來格。", "公曰徐之，無恃頟頟。", "式和爾容，惟義之宅。"]'),
('7823b47b-9a7a-41e8-b6b8-859b4c9e039e','皇武 七','柳宗元','唐','唐诗','tang','','[]','進次于郾，彼昏卒狂。',40,'全唐诗/poet.tang.18000.json','["進次于郾，彼昏卒狂。", "裒兇鞠頑，鋒蝟斧螗。", "赤子匍匐，厥父是亢。", "怒其萌芽，以悖太陽。"]'),
('5c311edd-164b-446a-a252-c938fb7ea498','皇武 八','柳宗元','唐','唐诗','tang','','[]','王旅渾渾，是佚是怙。',40,'全唐诗/poet.tang.18000.json','["王旅渾渾，是佚是怙。", "既獲敵師，若飢得餔。", "蔡兇伊窘，悉起來聚。", "左擣其虛，靡愆厥慮。"]'),
('088bc124-269b-4db3-8529-582b48e9964c','皇武 九','柳宗元','唐','唐诗','tang','','[]','載闢載袚，丞相是臨。',40,'全唐诗/poet.tang.18000.json','["載闢載袚，丞相是臨。", "弛其武刑，諭我德心。", "其危既安，有長如林。", "曾是讙譊，化爲謳吟。"]'),
('dc0557d9-6129-43d9-a338-783f33ca8cc2','皇武 十','柳宗元','唐','唐诗','tang','','[]','皇曰來歸，汝復相予。',40,'全唐诗/poet.tang.18000.json','["皇曰來歸，汝復相予。", "爵之成國，胙以夏區。", "度拜稽首，天子聖神。", "度拜稽首，皇祐下人。"]'),
('5df4d53a-2b2b-43ea-939c-40b4b751b22f','皇武 十一','柳宗元','唐','唐诗','tang','','[]','淮夷既平，震是朔南。',40,'全唐诗/poet.tang.18000.json','["淮夷既平，震是朔南。", "宜廟宜郊，以告德音。", "歸牛休馬，豐稼于埜。", "我武惟皇，永保無疆。"]'),
('03d78bae-f4c6-409f-b13b-93818f3af0ed','方城 一','柳宗元','唐','唐诗','tang','','[]','方城臨臨，王卒峙之。',40,'全唐诗/poet.tang.18000.json','["方城臨臨，王卒峙之。", "匪徼匪競，皇有正命。", "皇命于愬，往舒余仁。", "踣彼艱頑，柔惠是馴。"]'),
('8a4cf46c-0a8a-4a6a-b73f-58816987dc24','方城 二','柳宗元','唐','唐诗','tang','','[]','愬拜即命，于皇之訓。',40,'全唐诗/poet.tang.18000.json','["愬拜即命，于皇之訓。", "既礪既攻，以後厥刃。", "王師嶷嶷，熊羆是式。", "銜勇韜力，日思予殛。"]'),
('a0a54d7f-1aba-417d-b1c8-1ca7d6720816','方城 三','柳宗元','唐','唐诗','tang','','[]','寇昏以狂，敢蹈愬疆。',40,'全唐诗/poet.tang.18000.json','["寇昏以狂，敢蹈愬疆。", "士獲厥心，大袒高驤。", "長戟酋矛，粲其綏章。", "右翦左屠，聿禽其良。"]'),
('6c897bd8-5e07-4329-b856-820eeefb9d9a','方城 四','柳宗元','唐','唐诗','tang','','[]','其良既宥，告以父母。',39,'全唐诗/poet.tang.18000.json','["其良既宥，告以父母。", "恩柔于肌，卒貢爾有。", "維彼攸恃，乃偵乃誘維彼攸宅，乃發乃守。"]'),
('60ec9b1a-f3d4-4b7f-bdcb-f8e140012d97','方城 五','柳宗元','唐','唐诗','tang','','[]','其恃爰獲，我功我多。',40,'全唐诗/poet.tang.18000.json','["其恃爰獲，我功我多。", "陰諜厥圖，以究爾訛。", "雨雪洋洋，大風來加。", "于燠其寒，于邇其遐。"]'),
('82cd4938-3373-4c37-b947-bb908cd2d306','方城 六','柳宗元','唐','唐诗','tang','','[]','汝陰之茫，懸瓠之峨。',40,'全唐诗/poet.tang.18000.json','["汝陰之茫，懸瓠之峨。", "是震是拔，大殲厥家。", "狡虜既縻，輸于國都。", "示之市人，即社行誅。"]'),
('101f6bee-402d-4a35-971d-367297b35963','方城 七','柳宗元','唐','唐诗','tang','','[]','乃諭乃止，蔡有厚喜。',40,'全唐诗/poet.tang.18000.json','["乃諭乃止，蔡有厚喜。", "完其室家，仰父俯子。", "汝水沄沄，既清而瀰。", "蔡人行歌，我步逶遲。"]'),
('b80e7522-fde3-4d6f-88cf-7681955a0aac','方城 八','柳宗元','唐','唐诗','tang','','[]','蔡人歌矣，蔡風和矣。',40,'全唐诗/poet.tang.18000.json','["蔡人歌矣，蔡風和矣。", "孰颣蔡初，胡甈爾居。", "式慕以康，爲愿有餘。", "是究是咨，皇德既舒。"]'),
('fd9c37f9-68e7-4ff9-85bd-0c77906e91a2','方城 九','柳宗元','唐','唐诗','tang','','[]','皇曰咨愬，裕乃父功。',41,'全唐诗/poet.tang.18000.json','["皇曰咨愬，裕乃父功。", "昔我文祖，惟西平是庸。", "內誨于家，外刑于邦。", "孰是蔡人，而不率從。"]'),
('8e27f410-6881-456b-b383-588a75931af9','方城 十','柳宗元','唐','唐诗','tang','','[]','蔡人率止，惟西平有子。',41,'全唐诗/poet.tang.18000.json','["蔡人率止，惟西平有子。", "西平有子，惟我有臣。", "疇允大邦，俾惠我人。", "于廟告功，以顧萬方。"]'),
('f5dd74de-3d63-4970-b23d-1374ed88ad76','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','晉陽武，奮義威。',104,'全唐诗/poet.tang.18000.json','["晉陽武，奮義威。", "煬之渝，德焉歸。", "氓畢屠，綏者誰。", "皇烈烈，專天機。", "號以仁，揚其旗。", "日之昇，九土晞。", "斥田坼，流洪輝。", "有其二，翼餘隋。", "斮梟鷔，連熊螭。", "枯以肉，勍者羸。", "后土蕩，玄穹彌。", "合之育，莾然施。", "惟德輔，慶無期。"]'),
('b54e6d4e-5c99-4e41-84b0-1be53f3c3da9','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','獸之窮，奔大麓。',92,'全唐诗/poet.tang.18000.json','["獸之窮，奔大麓。", "天厚黃德，狙獷服。", "甲之櫜，弓弭矢箙。", "皇旅靖，敵逾蹙。", "自亡其徒，匪予戮。", "屈𧸾猛，虔慄慄。", "縻以尺組，噉以秩。", "黎之陽，土茫茫。", "富兵戎，盈倉箱。", "乏者德，莫能享。", "驅豺兕，授我疆。"]'),
('ccc2ad15-c3f4-4611-9460-b9890b904aca','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','戰武牢，動河朔。',74,'全唐诗/poet.tang.18000.json','["戰武牢，動河朔。", "逆之助，圖掎角。", "怒鷇麛，抗喬嶽。", "翹萌牙，傲霜雹。", "王謀內定，申掌握。", "鋪施芟夷，二主縛。", "憚華戎，廓封略。", "命之瞢，卑以斮。", "歸有德，唯先覺。"]'),
('1a6b9cdc-85a0-4ec8-aae6-f2e9c7ab3348','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','["\u548f\u53f2", "\u6c34"]','涇水黃，隴野茫。',105,'全唐诗/poet.tang.18000.json','["涇水黃，隴野茫。", "負太白，騰天狼。", "有鳥鷙立，羽翼張。", "鈎喙決前，鉅趯傍。", "怒飛飢嘯，翾不可當。", "老雄死，子復良。", "巢岐飲渭，肆翱翔。", "頓地紘，提天綱。", "列缺掉幟，招搖耀鋩。", "鬼神來助，夢嘉祥。", "腦塗原野，魄飛揚。", "星辰復，恢一方。"]'),
('75ddf192-9207-4c1a-96b7-782817cc3c51','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','奔鯨沛，盪海垠。',80,'全唐诗/poet.tang.18000.json','["奔鯨沛，盪海垠。", "吐霓翳日，腥浮雲。", "帝怒下顧，哀墊昏。", "授以神柄，推元臣。", "手援天矛，截脩鱗。", "披攘蒙霿，開海門。", "地平水靜，浮天根。", "羲和顯耀，乘清氛。", "赫炎溥暢，融大鈞。"]'),
('cc95ff9b-7918-4588-9624-6dbe9678c325','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','苞枿𪒶矣，惟根之蟠。',136,'全唐诗/poet.tang.18000.json','["苞枿𪒶矣，惟根之蟠。", "彌巴蔽荆，負南極以安。", "[冃]我舊梁氏，緝綏艱難。", "江漢之阻，都邑固以完。", "聖人作，神武用。", "有臣勇智，奮不以衆。", "投跡死地，謀猷縱。", "化敵爲家，慮則中。", "浩浩海裔，不威而同。", "係縲降王，定厥功。", "澶漫萬里，宣唐風。", "蠻夷九譯，咸來從。", "凱旋金奏，象形容。", "震赫萬國，罔不龔。"]'),
('95d51064-c607-44b7-96ee-11b063501b4f','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','河右澶漫，頑爲之魁。',93,'全唐诗/poet.tang.18000.json','["河右澶漫，頑爲之魁。", "王師如雷震，崑崙以頹。", "上聾下聰，驁不可廻。", "助讎抗有德，惟人之災。", "乃潰乃奮，執縛歸厥命。", "萬室蒙其仁，一夫則病。", "濡以鴻澤，皇之聖。", "威畏德懷，功以定。", "順之于理，物咸遂厥性。"]'),
('dca1e577-5542-42ce-bb3c-51e641e8be32','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','鐵山碎，大漠舒。',101,'全唐诗/poet.tang.18000.json','["鐵山碎，大漠舒。", "二虜勁，連穹廬。", "背北海，專坤隅。", "歲來侵邊，或傅于都。", "天子命元帥，奮其雄圖。", "破定襄，降魁渠。", "窮竟窟宅，斥余吾。", "百蠻破膽，邊氓蘇。", "威武輝耀，明鬼區。", "利澤彌萬祀，功不可踰。", "官臣拜手，惟帝之暮。"]'),
('4a1008e6-8028-4155-9d26-0df2cd3a9fbf','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','本邦伊晉，惟時不靖。',70,'全唐诗/poet.tang.18000.json','["本邦伊晉，惟時不靖。", "根柢之搖，枯葉攸病。", "守臣不任，勩于神聖。", "惟越之興，翦焉則定。", "洪惟我理，式和以敬。", "羣頑既夷，庶績咸正。", "皇謩載大，惟人之慶。"]'),
('623937c4-d618-4c10-b326-b8324ce70bd4','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','吐谷渾盛彊，背西海以夸。',156,'全唐诗/poet.tang.18000.json','["吐谷渾盛彊，背西海以夸。", "歲侵擾我疆，退匿險且遐。", "帝謂神武師。", "往征靖皇家。", "烈烈斾其旗，熊虎雜龍蛇。", "王旅千萬人，銜枚默無譁。", "束刃踰山徼，張翼縱漠沙。", "一舉刈羶腥，尸骸積如麻。", "除惡務本根，況敢遺萌芽。", "洋洋西海水，威命窮天涯。", "係虜來王都，犒樂窮休嘉。", "登高望還師，竟野如春華。", "行者靡不歸，親戚勸要遮。", "凱旋獻清廟，萬國思無邪。"]'),
('e689817f-e0cc-4a57-9464-c6c7de3df9bc','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','麴氏雄西北，別絕臣外區。',132,'全唐诗/poet.tang.18000.json','["麴氏雄西北，別絕臣外區。", "既恃遠且險，縱傲不我虞。", "烈烈王者師，熊螭以爲徒。", "龍旂翻海浪，馹騎馳坤隅。", "賁育搏嬰兒，一掃不復餘。", "平沙際天極，但見黃雲驅。", "臣靖執長纓，智勇伏囚拘。", "文皇南面坐，夷狄千羣趨。", "咸稱天子神，往古不得俱。", "獻號天可汗，以覆我國都。", "兵戎不交害，各保性與軀。"]'),
('3d9fe521-fbe8-4d7d-9734-5f611bc276b6','唐鐃歌妓吹曲十二篇','柳宗元','唐','唐诗','tang','','[]','東蠻有謝氏，冠帶理海中。',132,'全唐诗/poet.tang.18000.json','["東蠻有謝氏，冠帶理海中。", "自言我異世，雖聖莫能通。", "王卒如飛翰，鵬鶱駭羣龍。", "轟然自天墜，乃信神武功。", "繫虜君臣人，累累來自東。", "無思不服從，唐業如山崇。", "百辟拜稽首，咸願圖形容。", "如周王會書，永永傳無窮。", "睢盱萬狀乖，咿嗢九譯重。", "廣輪撫四海，浩浩知皇風。", "歌詩鐃鼓閒，以壯我元戎。"]'),
('95e30faf-c17c-4627-8fca-c189788361ee','貞符','柳宗元','唐','唐诗','tang','','[]','於穆敬德，黎人皇之。',242,'全唐诗/poet.tang.18000.json','["於穆敬德，黎人皇之。", "惟貞厥符，浩浩將之。", "仁函于膚，刃莫畢屠。", "澤熯于爨，𩰾炎以澣。", "殄厥兇德，乃敺乃夷。", "懿其休風，是喣是吹。", "父子熙熙，相寧以嬉。", "賦徹而藏，厚我糗粻。", "刑輕以清，我肌靡傷。", "貽我子孫，百代是康。", "十聖嗣于理，仁后之子。", "子思孝父，易患于已。", "拱之戴之，神具爾宜。", "載揚于雅，承天之嘏。", "天之誠神，宜鑒于仁。", "神之曷依，宜仁之歸。", "濮沿于北，祝栗于南。", "幅員西東，祗一乃心。", "祝唐之紀，後天罔墜。", "祝皇之壽，與地咸久。", "曷徒祝之，心誠篤之。", "神協人同，道以告之。", "俾彌億萬年，不震不危。", "我代之延，永永毗之。"]'),
('de76d823-85a2-459b-b16c-8340efcb915f','眎民詩','柳宗元','唐','唐诗','tang','','[]','帝眎民情，匪幽匪明。',244,'全唐诗/poet.tang.18000.json','["帝眎民情，匪幽匪明。", "慘或在腹，已如色聲。", "亦無動威，亦無止力。", "弗動弗止，惟民之極。", "帝懷民眎，乃降明德。", "乃生明翼，明翼者何。", "迺房迺杜，惟房與杜。", "實爲民路，迺定天子。", "迺開萬國，萬國既分。", "迺釋蠹民，迺學與仕。", "迺播與食，迺器與用。", "迺貨與通，有作有遷。", "無遷無作，士實蕩蕩。", "農實董董，工實蒙蒙。", "賈實融融，左右惟一。", "出入惟同，攝儀以引。", "以遵以肆，其風既流。", "品物載休，惟天子守。", "乃二公之久，惟天子明。", "乃二公之成，惟百辟正。", "乃二公之令，惟百辟穀。", "乃二公之祿，二公行矣。", "弗敢憂縱，是獲憂共。", "二公居矣，弗敢泰止。"]'),
('37d48834-7fd0-4ce2-b952-e10dc7fc983c','同劉二十八院長述舊言懷感時書事奉寄澧州張員外使君五十二韻之作因其韻增至八十通贈二君子','柳宗元','唐','唐诗','tang','','[]','弱歲游玄圃，先容幸棄瑕。',288,'全唐诗/poet.tang.18000.json','["弱歲游玄圃，先容幸棄瑕。", "名勞長者記，文許後生誇。", "鷃翼嘗披隼，蓬心類倚麻。", "繼酬天祿署，俱尉甸侯家。", "憲府初收迹，丹墀共拜嘉。", "分行參瑞獸，傳點亂宮鴉。", "執簡寧循枉，持書每去邪。", "鸞鳳標魏闕，熊武負崇牙。", "辨色宜相顧，傾心自不譁。", "金爐仄流月，紫殿啓晨赮。", "未竟遷喬樂，俄成失路嗟。", "還如渡遼水，更似謫長沙。", "別怨秦城暮，途窮越嶺斜。", "訟庭閒枳棘，候吏逐麋䴥。", "三載皇恩暢，千年聖曆遐。", "朝宗延駕海，師役罷梁溠。", "京邑搜貞幹，南宮步渥洼。", "世惟材是梓，人仰驥中驊。", "歘刺苗人地，仍逾贛石崖。", "禮容垂珌琫，戍備響錏鍜。", "寵即郎官舊，威從太守加。", "建旟翻鷙鳥，負弩繞文蛇。", "冊府榮八命，中闈盛六珈。", "肯隨胡質矯，方惡馬融奢。"]'),
('2a6e14a5-ee60-480f-8a82-38b2c5210833','弘農公以碩德偉材屈於誣枉左官三歲復爲大僚天監昭明人心感悅宗元竄伏湘浦拜賀末由謹獻詩五十韻以畢微志','柳宗元','唐','唐诗','tang','','[]','知命儒爲貴，時中聖所臧。',288,'全唐诗/poet.tang.18000.json','["知命儒爲貴，時中聖所臧。", "處心齊寵辱，遇物任行藏。", "關識新安地，封傳臨晉鄉。", "挺生推豹蔚，遐步仰龍驤。", "幹有千尋竦，精聞百鍊鋼。", "茂功期舜禹，高韻狀羲黃。", "足逸詩書囿，鋒搖翰墨場。", "雅歌張仲德，頌祝魯侯昌。", "憲府初騰價，神州轉耀鋩。", "右言盈簡策，左轄備條綱。", "響切晨趨佩，煙濃近侍香。", "司儀六禮洽，論將七兵揚。", "合樂來儀鳳，尊祠重餼羊。", "卿材優柱石，公器擅巖廊。", "峻節臨衡嶠，和風滿豫章。", "人歸父母育，郡得股肱良。", "細故誰留念，煩言肯過防。", "璧非真盜客，金有誤持郎。", "龜虎休前寄，貂蟬冠舊行。", "訓刑方命呂，理劇復推張。", "直用明銷惡，還將道勝剛。", "敬逾齊國社，恩比召南棠。", "希怨猶逢怒，多容競忤彊。", "火炎侵琬琰，鷹擊謬鸞凰。"]'),
('f7a459f1-85fa-46c8-aac4-c23cc89c6d48','酬韶州裴曹長使君寄道州呂八大使以見示二十韻一首','柳宗元','唐','唐诗','tang','','[]','金馬嘗齊入，銅魚亦共頒。',240,'全唐诗/poet.tang.18000.json','["金馬嘗齊入，銅魚亦共頒。", "疑山看積翠，湞水想澄灣。", "標牓同驚俗，清明兩照姦。", "乘軺參孔僅，按節服侯狦。", "賈傅辭寧切，虞童髪未䰔。", "秉心方的的，騰口任㘖㘖。", "聖理高懸象，爰書降罰鍰。", "德風流海外，和氣滿人寰。", "禦魅恩猶貸，思賢淚自潸。", "在亡均寂寞，零落間惸鰥。", "夙志隨憂盡，殘肌觸瘴𤸷。", "月光搖淺瀨，風韻碎枯菅。", "海俗衣猶卉，山夷髻不鬟。", "泥沙潛虺蜮，榛莽鬬豺獌。", "循省誠知懼，安排秖自𢢀。", "食貧甘莽鹵，被褐謝斕斒。", "遠物裁青罽，時珍饌白鷴。", "長捐楚客佩，未賜大夫環。", "異政徒云仰，高蹤不可攀。", "空勞慰顦顇，妍唱劇妖㛠。"]'),
('44cea862-5bd3-4705-aeae-2a7b899a201a','酬婁秀才將之淮南見贈之什','柳宗元','唐','唐诗','tang','','[]','遠棄甘幽獨，誰云值故人。',144,'全唐诗/poet.tang.18000.json','["遠棄甘幽獨，誰云值故人。", "好音憐鎩羽，濡沫慰窮鱗。", "困志情惟舊，相知樂更新。", "浪遊輕費日，醉舞詎傷春。", "風月歡寧間，星霜分益親。", "已將名是患，還用道爲鄰。", "機事齊飄瓦，嫌猜比拾塵。", "高冠余肯賦，長鋏子忘貧。", "晼晚驚移律，睽攜忽此辰。", "開顏時不再，絆足去何因。", "海上銷魂別，天邊弔影身。", "秖應西澗水，寂寞但垂綸。"]'),
('df70911c-bbed-45b7-919f-e381838d6961','酬婁秀才寓居開元寺早秋月夜病中見寄','柳宗元','唐','唐诗','tang','','[]','客有故園思，瀟湘生夜愁。',72,'全唐诗/poet.tang.18000.json','["客有故園思，瀟湘生夜愁。", "病依居士室，夢繞羽人丘。", "味道憐知止，遺名得自求。", "壁空殘月曙，門掩候蟲秋。", "謬委雙金重，難徵雜佩酬。", "碧霄無枉路，徒此助離憂。"]'),
('96314951-671b-423f-a172-4f10ec08a6f2','初秋夜坐贈吳武陵','柳宗元','唐','唐诗','tang','','["\u540c\u60c5", "\u5fe7\u6124", "\u79cb\u5929", "\u6000\u53cb", "\u591c\u665a"]','稍稍雨侵竹，翻翻鵲驚叢。',96,'全唐诗/poet.tang.18000.json','["稍稍雨侵竹，翻翻鵲驚叢。", "美人隔湘浦，一夕生秋風。", "積霧杳難極，滄波浩無窮。", "相思豈云遠，即席莫與同。", "若人抱奇音，朱弦緪枯桐。", "清商激西顥，泛灧凌長空。", "自得本無作，天成諒非功。", "希聲閟大樸，聾俗何由聰。"]'),
('2954ddd2-f1c7-41b1-8c9e-42058398cde0','晨詣超師院讀禪經','柳宗元','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e94\u8a00\u53e4\u8bd7", "\u6292\u60c5", "\u8d2c\u8c2a"]','汲井漱寒齒，清心拂塵服。',84,'全唐诗/poet.tang.18000.json','["汲井漱寒齒，清心拂塵服。", "閒持貝葉書，步出東齋讀。", "真源了無取，妄跡世所逐。", "遺言冀可冥，繕性何由熟。", "道人庭宇靜，苔色連深竹。", "日出霧露餘，青松如膏沐。", "澹然離言說，悟悅心自足。"]'),
('a5f1a8ad-737d-4f10-bd3a-782747054253','贈江華長老','柳宗元','唐','唐诗','tang','','["\u5199\u4eba", "\u751f\u6d3b", "\u5199\u4eba\u8bd7"]','老僧道機熟，默語心皆寂。',72,'全唐诗/poet.tang.18000.json','["老僧道機熟，默語心皆寂。", "去歲別舂陵，沿流此投跡。", "室空無侍者，巾履唯掛壁。", "一飯不願餘，跏趺便終夕。", "風牕疎竹響，露井寒松滴。", "偶地即安居，滿庭芳草積。"]'),
('b060055f-cb85-4656-8297-035e68b380ed','巽上人以竹閒自採新茶見贈酬之以詩','柳宗元','唐','唐诗','tang','','[]','芳叢翳湘竹，零露凝清華。',96,'全唐诗/poet.tang.18000.json','["芳叢翳湘竹，零露凝清華。", "復此雪山客，晨朝掇靈芽。", "蒸煙俯石瀨，咫尺凌丹崖。", "圓方麗奇色，圭璧無纖瑕。", "呼兒爨金鼎，餘馥延幽遐。", "滌慮發真照，還源蕩昏邪。", "猶同甘露飯，佛事薰毗耶。", "咄此蓬瀛侶，無乃貴流霞。"]'),
('e387aad0-cefb-4e70-b299-855d181a36ab','零陵贈李卿元侍御簡吳武陵','柳宗元','唐','唐诗','tang','','[]','理世固輕士，棄捐湘之湄。',96,'全唐诗/poet.tang.18000.json','["理世固輕士，棄捐湘之湄。", "陽光競四溟，敲石安所施。", "鎩羽集枯幹，低昂互鳴悲。", "朔雲吐風寒，寂歷窮秋時。", "君子尚容與，小人守兢危。", "慘悽日相視，離憂坐自滋。", "尊酒聊可酌，放歌諒徒爲。", "惜無協律者，窈眇絃吾詩。"]'),
('88d529e0-7481-45fa-8568-bf134ec06a59','界圍巖水簾','柳宗元','唐','唐诗','tang','','["\u559c\u60a6", "\u6292\u60c5", "\u5199\u666f", "\u5fc3\u60c5"]','界圍匯湘曲，青壁環澄流。',120,'全唐诗/poet.tang.18000.json','["界圍匯湘曲，青壁環澄流。", "懸泉粲成簾，羅注無時休。", "韻磬叩凝碧，鏘鏘徹巖幽。", "丹霞冠其巔，想像凌虛遊。", "靈境不可狀，鬼工諒難求。", "忽如朝玉皇，天冕垂前旒。", "楚臣昔南逐，有意仍丹丘。", "今我始北旋，新詔釋縲囚。", "采真誠眷戀，許國無淹留。", "再來寄幽夢，遺貯催行舟。"]'),
('8bdc2c58-e651-49d0-9142-85ab23847cf3','古東門行','柳宗元','唐','唐诗','tang','','[]','漢家三十六將軍，東方雷動橫陣雲。',144,'全唐诗/poet.tang.18000.json','["漢家三十六將軍，東方雷動橫陣雲。", "雞鳴函谷客如霧，貌同心異不可數。", "赤丸夜語飛電光，徼巡司隸眠如羊。", "當街一叱百吏走，馮敬胷中函匕首。", "兇徒側耳潛愜心，悍臣破膽皆杜口。", "魏王臥內藏兵符，子西掩袂真無辜。", "羗胡轂下一朝起，敵國舟中非所擬。", "安陵誰辨削礪功，韓國詎明深井里。", "絕臙斷骨那下補，萬金寵贈不如土。"]'),
('37fce2eb-8608-4641-9ee8-3e367d534cf9','寄韋珩','柳宗元','唐','唐诗','tang','','[]','初拜柳州出東郊，道旁相送皆賢豪。',240,'全唐诗/poet.tang.18000.json','["初拜柳州出東郊，道旁相送皆賢豪。", "廻眸炫晃別羣玉，獨赴異域穿蓬蒿。", "炎煙六月咽口鼻，胷鳴肩舉不可逃。", "桂州西南又千里，灕水鬬石麻蘭高。", "陰森野葛交蔽日，懸蛇結虺如蒲萄。", "到官數宿賊滿野，縛壯殺老啼且號。", "饑行夜坐設方略，籠銅枹鼓手所操。", "奇瘡釘骨狀如箭，鬼手脫命爭纖毫。", "今年噬毒得霍疾，支心攪腹戟與刀。", "邇來氣少筋骨露，蒼白瀄汩盈顛毛。", "君今矻矻又竄逐，辭賦已復窮詩騷。", "神兵廟略頻破虜，四溟不日清風濤。", "聖恩倘忽念行葦，十年踐蹈久已勞。", "幸因解網入鳥獸，畢命江海終遊遨。", "願言未果身益老，起望東北心滔滔。"]'),
('4020eb95-6f63-4c86-bdcb-34ec37b63cfa','奉和楊尚書郴州追和故李中書夏日登北樓十韻之作依本詩韻次用','柳宗元','唐','唐诗','tang','','[]','郡樓有遺唱，新和敵南金。',120,'全唐诗/poet.tang.18000.json','["郡樓有遺唱，新和敵南金。", "境以道情得，人期幽夢尋。", "層軒隔炎暑，迥野恣窺臨。", "鳳去徽音續，芝焚芳意深。", "游鱗出陷浦，唳鶴繞仙岑。", "風起三湘浪，雲生萬里陰。", "宏規齊德宇，麗藻競詞林。", "靜契分憂術，閑同遲客心。", "驊騮當遠步，鶗鴂莫相侵。", "今日登高處，還聞梁父吟。"]'),
('1ad733c4-5502-4869-80b9-07e3ab4129d6','楊尚書寄郴筆知是小生本樣令更商榷使盡其功輙獻長句','柳宗元','唐','唐诗','tang','','[]','截玉銛錐作妙形，貯雲含霧到南溟。',64,'全唐诗/poet.tang.18000.json','["截玉銛錐作妙形，貯雲含霧到南溟。", "尚書舊用裁天詔，內史新將寫道經。", "曲藝豈能裨損益，微辭秖欲播芳馨。", "桂陽卿月光輝徧，毫末應傳顧兔靈。"]'),
('604ee73f-05ea-4201-80bd-c068e47ed590','南省轉牒欲具江國圖令盡通風俗故事','柳宗元','唐','唐诗','tang','','[]','聖代提封盡海壖，狼荒猶得紀山川。',64,'全唐诗/poet.tang.18000.json','["聖代提封盡海壖，狼荒猶得紀山川。", "華夷圖上應初錄，風土記中殊未傳。", "椎髻老人難借問，黃茆深峒敢留連。", "南宮有意求遺俗，試檢周書王會篇。"]'),
('65d61708-16c4-4937-9f25-ddc2656a532d','與浩初上人同看山寄京華親故','柳宗元','唐','唐诗','tang','','["\u601d\u5ff5", "\u5c71", "\u63cf\u5199\u5c71", "\u5199\u5c71"]','海畔尖山似劒鋩，秋來處處割愁腸。',32,'全唐诗/poet.tang.18000.json','["海畔尖山似劒鋩，秋來處處割愁腸。", "若爲化得身千億，散上峰頭望故鄉。"]'),
('ac2f736a-0a3d-4ec1-a855-374f26faff25','再至界圍巖水簾遂宿巖下','柳宗元','唐','唐诗','tang','','[]','發春念長違，中夏欣再覩。',108,'全唐诗/poet.tang.18000.json','["發春念長違，中夏欣再覩。", "是時植物秀，杳若臨懸圃。", "歊陽訝垂冰，白日驚雷雨。", "笙簧潭際起，鸛鶴雲間舞。", "古苔凝青枝，陰草濕翠羽。", "蔽空素彩列，激浪寒光聚。", "的皪沈珠淵，鏘鳴捐佩浦。", "幽巖畫屏倚，新月玉鈎吐。", "夜涼星滿川，忽疑眠洞府。"]'),
('80751d99-7945-44a5-925b-21fdd94a79f2','詔追赴都廻寄零陵親故','柳宗元','唐','唐诗','tang','','[]','每憶纖鱗遊尺澤，翻愁弱羽上丹霄。',32,'全唐诗/poet.tang.18000.json','["每憶纖鱗遊尺澤，翻愁弱羽上丹霄。", "岸傍古堠應無數，次第行看別路遙。"]'),
('f40f6ab5-543f-4405-818e-3a2603d82151','過衡山見新花開却寄弟','柳宗元','唐','唐诗','tang','','["\u8861\u5c71"]','故國名園久別離，今朝楚樹發南枝。',32,'全唐诗/poet.tang.18000.json','["故國名園久別離，今朝楚樹發南枝。", "晴天歸路好相逐，正是峰前廻雁時。"]'),
('194a53e4-d7f8-49a6-92eb-3e36d41fd32c','汨羅遇風','柳宗元','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u6292\u60c5", "\u7f81\u65c5", "\u62b1\u8d1f"]','南來不作楚臣悲，重入脩門自有期。',32,'全唐诗/poet.tang.18000.json','["南來不作楚臣悲，重入脩門自有期。", "爲報春風汨羅道，莫將波浪枉明時。"]'),
('134e6050-0242-4e9c-92cb-b6a4e6412581','朗州竇常員外寄劉二十八詩見促行騎走筆酬贈','柳宗元','唐','唐诗','tang','','[]','投荒垂一紀，新詔下荆扉。',48,'全唐诗/poet.tang.18000.json','["投荒垂一紀，新詔下荆扉。", "疑比莊周夢，情如蘇武歸。", "賜環留逸響，五馬助征騑。", "不羨衡陽雁，春來前後飛。"]'),
('e52b13f4-9bb3-477c-952e-64a36965d159','離觴不醉至驛却寄相送諸公','柳宗元','唐','唐诗','tang','','["\u6292\u60c5", "\u9001\u522b", "\u6101\u7eea"]','無限居人送獨醒，可憐寂寞到長亭。',32,'全唐诗/poet.tang.18000.json','["無限居人送獨醒，可憐寂寞到長亭。", "荆州不遇高陽侶，一夜春寒滿下廳。"]'),
('c2a912f4-d7b3-4b92-a25b-8d87e3ac47c3','北還登漢陽北原題臨川驛','柳宗元','唐','唐诗','tang','','[]','驅車方向闕，廻首一臨川。',48,'全唐诗/poet.tang.18000.json','["驅車方向闕，廻首一臨川。", "多壘非余耻，無謀終自憐。", "亂松知野寺，餘雪記山田。", "惆悵樵漁事，今還又落然。"]'),
('c6a022f3-1760-4dd6-863a-60aa5fc68d26','善謔驛和劉夢得酹淳于先生','柳宗元','唐','唐诗','tang','','[]','水上鵠已去，亭中鳥又鳴。',48,'全唐诗/poet.tang.18000.json','["水上鵠已去，亭中鳥又鳴。", "辭因使楚重，名爲救齊成。", "荒壠遽千古，羽觴難再傾。", "劉伶今日意，異代是同聲。"]'),
('5be6ce26-fcc6-494d-a684-c3c3bafce78d','詔追赴都二月至灞亭上','柳宗元','唐','唐诗','tang','','["\u559c\u60a6", "\u6292\u60c5", "\u611f\u6168"]','十一年前南渡客，四千里外北歸人。',32,'全唐诗/poet.tang.18000.json','["十一年前南渡客，四千里外北歸人。", "詔書許逐陽和至，驛路開花處處新。"]'),
('f6cccae4-2e01-4f12-ad32-efc5fe5c5dd7','李西川薦琴石','柳宗元','唐','唐诗','tang','','[]','遠師騶忌鼓鳴琴，去和南風愜舜心。',32,'全唐诗/poet.tang.18000.json','["遠師騶忌鼓鳴琴，去和南風愜舜心。", "從此他山千古重，殷勤曾是奉徽音。"]'),
('9dd7d4eb-5662-4dae-ab12-25882cd10835','同劉二十八哭呂衡州兼寄江陵李元二侍御','柳宗元','唐','唐诗','tang','','[]','衡岳新摧天柱峰，士林顦顇泣相逢。',64,'全唐诗/poet.tang.18000.json','["衡岳新摧天柱峰，士林顦顇泣相逢。", "祗令文字傳青簡，不使功名上景鐘。", "三畝空留懸磬室，九原猶寄若堂封。", "遙想荆州人物論，幾回中夜惜元龍。"]'),
('22e86cb8-863c-4c69-8dd1-b843de7de4c7','奉酬楊侍郎丈因送八叔拾遺戲贈詔追南來諸賓二首 一','柳宗元','唐','唐诗','tang','','[]','貞一來時送彩牋，一行歸雁慰驚弦。',32,'全唐诗/poet.tang.18000.json','["貞一來時送彩牋，一行歸雁慰驚弦。", "翰林寂寞誰爲主，鳴鳳應須早上天。"]'),
('34a154bb-90c1-4527-aa74-deae218dc562','奉酬楊侍郎丈因送八叔拾遺戲贈詔追南來諸賓二首 二','柳宗元','唐','唐诗','tang','','[]','一生判却歸休，謂著南冠到頭。',28,'全唐诗/poet.tang.18000.json','["一生判却歸休，謂著南冠到頭。", "冶長雖解縲絏，無由得見東周。"]'),
('a3b573aa-58b9-41ef-b21c-4799f3c98a56','商山臨路有孤松往來斫以爲明好事者憐之編竹成楥遂其生植感而賦詩','柳宗元','唐','唐诗','tang','','[]','孤松停翠蓋，託根臨廣路。',48,'全唐诗/poet.tang.18000.json','["孤松停翠蓋，託根臨廣路。", "不以險自防，遂爲明所誤。", "幸逢仁惠意，重此藩籬護。", "猶有半心存，時將承雨露。"]'),
('7d475032-daa2-4ee7-bbaa-dbd8d0bc2dca','衡陽與夢得分路贈別','柳宗元','唐','唐诗','tang','','["\u8d60\u522b", "\u53cb\u60c5"]','十年顦顇到秦京，誰料翻爲嶺外行。',64,'全唐诗/poet.tang.18000.json','["十年顦顇到秦京，誰料翻爲嶺外行。", "伏波故道風煙在，翁仲遺墟草樹平。", "直以慵疎招物議，休將文字占時名。", "今朝不用臨河別，垂淚千行便濯纓。"]'),
('fe6a4fdb-7d32-47ad-b976-da9d50df4368','重別夢得','柳宗元','唐','唐诗','tang','','["\u79bb\u522b", "\u6292\u60c5", "\u6101\u7eea"]','二十年來萬事同，今朝岐路忽西東。',32,'全唐诗/poet.tang.18000.json','["二十年來萬事同，今朝岐路忽西東。", "皇恩若許歸田去，晚歲當爲鄰舍翁。"]'),
('d28f7fa2-d327-44a2-9d39-c432e24ccb15','三贈劉員外','柳宗元','唐','唐诗','tang','','[]','信書成自誤，經事漸知非。',24,'全唐诗/poet.tang.18000.json','["信書成自誤，經事漸知非。", "今日臨岐別，何年待汝歸。"]'),
('d60160ba-08f7-45a8-85c5-a96ed2c09449','再上湘江','柳宗元','唐','唐诗','tang','','[]','好在湘江水，今朝又上來。',24,'全唐诗/poet.tang.18000.json','["好在湘江水，今朝又上來。", "不知從此去，更遣幾年迴。"]'),
('dd6aa460-87be-4520-94c6-ccdfc93d1431','清水驛叢竹天水趙云余手種一十二莖','柳宗元','唐','唐诗','tang','','[]','簷下疎篁十二莖，襄陽從事寄幽情。',32,'全唐诗/poet.tang.18000.json','["簷下疎篁十二莖，襄陽從事寄幽情。", "祗應更指伶倫見，寫盡雌雄雙鳳鳴。"]'),
('3779cd3c-8ef9-4259-8f2a-f3110b4aac09','長沙驛前南樓感舊','柳宗元','唐','唐诗','tang','','[]','海鶴一爲別，存亡三十秋。',24,'全唐诗/poet.tang.18000.json','["海鶴一爲別，存亡三十秋。", "今來數行淚，獨上驛南樓。"]'),
('d1165e3b-828f-4c97-8494-e9347cbb61f9','桂州北望秦驛手開竹徑至釣磯留待徐容州','柳宗元','唐','唐诗','tang','','[]','幽徑爲誰開，美人城北來。',24,'全唐诗/poet.tang.18000.json','["幽徑爲誰開，美人城北來。", "王程倘餘暇，一上子陵臺。"]'),
('3d26433c-a673-4094-8c83-cadb1b08412a','登柳州城樓寄漳汀封連四州','柳宗元','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u6292\u60c5", "\u6000\u4eba"]','城上高樓接大荒，海天愁思正茫茫。',64,'全唐诗/poet.tang.18000.json','["城上高樓接大荒，海天愁思正茫茫。", "驚風亂颭芙蓉水，密雨斜侵薜荔牆。", "嶺樹重遮千里目，江流曲似九廻腸。", "共來百越文身地，猶自音書滯一鄉。"]'),
('424c1536-61e0-48ae-8333-1eec727f5eb6','柳州寄丈人周韶州','柳宗元','唐','唐诗','tang','','[]','越絕孤城千萬峰，空齋不語坐高舂。',64,'全唐诗/poet.tang.18000.json','["越絕孤城千萬峰，空齋不語坐高舂。", "印文生綠經旬合，硯匣留塵盡日封。", "梅嶺寒煙藏翡翠，桂江秋水露鰅鳙。", "丈人本自忘機事，爲想年來憔悴容。"]'),
('d41a204e-f263-4b55-aa31-5b92bc8e3c78','登柳州峨山','柳宗元','唐','唐诗','tang','','[]','荒山秋日午，獨上意悠悠。',24,'全唐诗/poet.tang.18000.json','["荒山秋日午，獨上意悠悠。", "如何望鄉處，西北是融州。"]'),
('212bf7ea-f6b1-4e8e-a98f-695166f02597','得盧衡州書因以詩寄','柳宗元','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u82e6\u95f7"]','臨蒸且莫歎炎方，爲報秋來雁幾行。',64,'全唐诗/poet.tang.18000.json','["臨蒸且莫歎炎方，爲報秋來雁幾行。", "林邑東廻山似戟，牂牁南下水如湯。", "蒹葭浙瀝含秋霧，橘柚玲瓏透夕陽。", "非是白蘋洲畔客，還將遠意問瀟湘。"]'),
('5d153ce7-5125-419a-bec6-72bc18d34967','答劉連州邦字','柳宗元','唐','唐诗','tang','','[]','連璧本難雙，分符刺小邦。',48,'全唐诗/poet.tang.18000.json','["連璧本難雙，分符刺小邦。", "崩雲下灕水，劈箭上潯江。", "負弩啼寒狖，鳴枹驚夜狵。", "遙憐郡山好，謝守但臨窗。"]'),
('382c265b-130c-43b1-b500-f49215b85f2e','嶺南江行','柳宗元','唐','唐诗','tang','','["\u52b1\u5fd7"]','瘴江南去入雲煙，望盡黃茆是海邊。',64,'全唐诗/poet.tang.18000.json','["瘴江南去入雲煙，望盡黃茆是海邊。", "山腹雨晴添象跡，潭心日暖長蛟涎。", "射工巧伺遊人影，颶母偏驚旅客船。", "從此憂來非一事，豈容華髪待流年。"]'),
('4219b728-27b9-41d8-93bb-504ae1465338','柳州峒氓','柳宗元','唐','唐诗','tang','','["\u751f\u6d3b", "\u5199\u4eba", "\u6292\u6000", "\u5199\u4eba\u8bd7"]','郡城南下接通津，異服殊音不可親。',64,'全唐诗/poet.tang.18000.json','["郡城南下接通津，異服殊音不可親。", "青箬裹鹽歸峒客，綠荷包飯趂虛人。", "鵝毛禦臘縫山罽，雞骨占年拜水神。", "愁向公庭問重譯，欲投章甫作文身。"]'),
('959dee20-a6ce-46d5-87a5-b2c84bd68332','酬徐二中丞普寧郡內池館即事見寄','柳宗元','唐','唐诗','tang','','[]','鵷鴻念舊行，虛館對芳塘。',48,'全唐诗/poet.tang.18000.json','["鵷鴻念舊行，虛館對芳塘。", "落日明朱檻，繁花照羽觴。", "泉歸滄海近，樹入楚山長。", "榮賤俱爲累，相期在故鄉。"]'),
('79a30dfa-4ed0-4d45-98d3-1ac80b0defc1','酬賈鵬山人郡內新栽松寓興見贈二首 一','柳宗元','唐','唐诗','tang','','[]','芳巧自爲別，無心乃玄功。',60,'全唐诗/poet.tang.18000.json','["芳巧自爲別，無心乃玄功。", "夭夭日放花，榮耀將安窮。", "青松遺澗底，擢蒔茲庭中。", "積雪表明秀，寒花助葱蘢。", "貞幽夙有慕，持以延清風。"]'),
('87b71056-e4f5-4cc5-b42b-63d2ee7fa562','酬賈鵬山人郡內新栽松寓興見贈二首 二','柳宗元','唐','唐诗','tang','','[]','無能常閉閣，偶以靜見名。',60,'全唐诗/poet.tang.18000.json','["無能常閉閣，偶以靜見名。", "奇姿來遠山，忽似人家生。", "勁色不改舊，芳心與誰榮。", "喧卑豈所安，任物非我情。", "清韻動竽瑟，諧此風中聲。"]'),
('6bc9518f-6506-4720-89f8-b49b2958a855','種柳戲題','柳宗元','唐','唐诗','tang','','["\u67f3\u6811", "\u613f\u671b"]','柳州柳刺史，種柳柳江邊。',48,'全唐诗/poet.tang.18000.json','["柳州柳刺史，種柳柳江邊。", "談笑爲故事，推移成昔年。", "垂陰當覆地，聳幹會參天。", "好作思人樹，慚無惠化傳。"]'),
('5679526b-d077-4f1f-a67e-fc430e4643a9','柳州二月榕葉落盡偶題','柳宗元','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f", "\u6292\u60c5"]','宦情羈思共悽悽，春半如秋意轉迷。',32,'全唐诗/poet.tang.18000.json','["宦情羈思共悽悽，春半如秋意轉迷。", "山城過雨百花盡，榕葉滿庭鶯亂啼。"]'),
('354d1430-5c88-4520-9397-3e7d5ceaa076','浩初上人見貽絕句欲登仙人山因以酬之','柳宗元','唐','唐诗','tang','','[]','珠樹玲瓏隔翠微，病來方外事多違。',32,'全唐诗/poet.tang.18000.json','["珠樹玲瓏隔翠微，病來方外事多違。", "仙山不屬分符客，一任凌空錫杖飛。"]'),
('1fb004f1-ffec-441c-8a85-0e022d75f293','雨中贈仙人山賈山人','柳宗元','唐','唐诗','tang','','[]','寒江夜雨聲潺潺，曉雲遮盡仙人山。',32,'全唐诗/poet.tang.18000.json','["寒江夜雨聲潺潺，曉雲遮盡仙人山。", "遙知玄豹在深處，下笑羈絆泥塗間。"]'),
('cf3a0ecd-c2dd-468d-adf6-26b1e3d92f76','別舍弟宗一','柳宗元','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u6292\u60c5", "\u9001\u522b", "\u8fc1\u8c2a", "\u5199\u666f"]','零落殘紅倍黯然，雙垂別淚越江邊。',64,'全唐诗/poet.tang.18000.json','["零落殘紅倍黯然，雙垂別淚越江邊。", "一身去國六千里，萬死投荒十二年。", "桂嶺瘴來雲似墨，洞庭春盡水如天。", "欲知此後相思夢，長在荆門郢樹煙。"]'),
('7bd52da1-5075-49d7-bcde-6680d97e5441','奉和周二十丈酬郴州侍郎衡江夜泊得韶州書幷附當州生黃茶一封率然成篇代意之作','柳宗元','唐','唐诗','tang','','[]','丘山仰德耀，天路下征騑。',48,'全唐诗/poet.tang.18000.json','["丘山仰德耀，天路下征騑。", "夢喜三刀近，書嫌五載違。", "凝情江月落，屬思嶺雲飛。", "會入司徒府，還邀周掾歸。"]'),
('cd90f31a-75b7-4f67-b707-f8a21fd135bc','殷賢戲批書後寄劉連州幷示孟崙二童','柳宗元','唐','唐诗','tang','','[]','書成欲寄庾安西，紙背應勞手自題。',32,'全唐诗/poet.tang.18000.json','["書成欲寄庾安西，紙背應勞手自題。", "聞到盡來諸子弟，臨池尋已厭家雞。"]'),
('eeeaecf4-1f4f-4809-81f3-13040acb9e04','重贈二首 一','柳宗元','唐','唐诗','tang','','[]','聞道將雛向墨池，劉家還有異同詞。',32,'全唐诗/poet.tang.18000.json','["聞道將雛向墨池，劉家還有異同詞。", "如今試遣隈牆問，已道世人那得知。"]'),
('c75f28d6-1e45-4499-89cd-ce3224eb9043','重贈二首 二','柳宗元','唐','唐诗','tang','','[]','世上悠悠不識真，薑芽盡是捧心人。',32,'全唐诗/poet.tang.18000.json','["世上悠悠不識真，薑芽盡是捧心人。", "若道柳家無子弟，往年何事乞西賓。"]'),
('e752c7ea-b896-4dd1-881c-1ae06f7951d3','疊前','柳宗元','唐','唐诗','tang','','[]','小學新翻墨沼波，羨君瓊樹散枝柯。',32,'全唐诗/poet.tang.18000.json','["小學新翻墨沼波，羨君瓊樹散枝柯。", "左家弄玉唯嬌女，空覺庭前鳥跡多。"]'),
('dc1afe59-acba-49a3-ac70-655752a51636','疊後','柳宗元','唐','唐诗','tang','','[]','事業無成耻藝成，南宮起草舊連名。',32,'全唐诗/poet.tang.18000.json','["事業無成耻藝成，南宮起草舊連名。", "勸君火急添功用，趂取當時二妙聲。"]'),
('9765ae66-ebe0-4cc1-9114-84514dcb0c94','銅魚使赴都寄親友','柳宗元','唐','唐诗','tang','','[]','行盡關山萬里餘，到時閭井是荒墟。',32,'全唐诗/poet.tang.18000.json','["行盡關山萬里餘，到時閭井是荒墟。", "附庸唯有銅魚使，此後無因寄遠書。"]'),
('8266d738-14bb-4717-a174-470b71253311','韓漳州書報徹上人亡因寄二絕 一','柳宗元','唐','唐诗','tang','','[]','早歲京華聽越吟，聞君江海分逾深。',32,'全唐诗/poet.tang.18000.json','["早歲京華聽越吟，聞君江海分逾深。", "他時若寫蘭亭會，莫畫高僧支道林。"]'),
('d6705464-4bc5-4f1b-944b-ed96dc055204','韓漳州書報徹上人亡因寄二絕 二','柳宗元','唐','唐诗','tang','','[]','頻把瓊書出袖中，獨吟遺句立秋風。',32,'全唐诗/poet.tang.18000.json','["頻把瓊書出袖中，獨吟遺句立秋風。", "桂江日夜流千里，揮淚何時到甬東。"]'),
('67d3c773-4fd0-410c-8f19-d2ffd45b8934','柳州城西北隅種柑樹','柳宗元','唐','唐诗','tang','','[]','手種黃柑二百株，春來新葉徧城隅。',64,'全唐诗/poet.tang.18000.json','["手種黃柑二百株，春來新葉徧城隅。", "方同楚客憐皇樹，不學荆州利木奴。", "幾歲開花聞噴雪，何人摘實見垂珠。", "若教坐待成林日，滋味還堪養老夫。"]'),
('a09b5f48-59f0-4139-9efa-1a97582dbc9e','聞徹上人亡寄侍郎楊丈','柳宗元','唐','唐诗','tang','','[]','東越高僧還姓湯，幾時瓊佩觸鳴璫。',32,'全唐诗/poet.tang.18000.json','["東越高僧還姓湯，幾時瓊佩觸鳴璫。", "空花一散不知處，誰采金英與侍郎。"]'),
('d29596db-d8ae-4411-ac71-3e408a2f3801','段九秀才處見亡友呂衡州書迹','柳宗元','唐','唐诗','tang','','[]','交侶平生意最親，衡陽往事似分身。',32,'全唐诗/poet.tang.18000.json','["交侶平生意最親，衡陽往事似分身。", "袖中忽見三行字，拭淚相看是故人。"]'),
('e2af1834-05f0-4b2b-abee-1fa3116c5ea0','柳州寄京中親故','柳宗元','唐','唐诗','tang','','[]','林邑山連瘴海秋，牂牁水向郡前流。',32,'全唐诗/poet.tang.18000.json','["林邑山連瘴海秋，牂牁水向郡前流。", "勞君遠問龍城地，正北三千到錦州。"]'),
('40932cc3-cb8e-4e0f-ba48-9bd1bd6ca4f7','種木槲花','柳宗元','唐','唐诗','tang','','[]','上苑年年占物華，飄零今日在天涯。',32,'全唐诗/poet.tang.18000.json','["上苑年年占物華，飄零今日在天涯。", "祗因長作龍城守，剩種庭前木槲花。"]'),
('5a8f448f-d34b-4f01-95ca-4c0111970197','摘櫻桃贈元居士時在望仙亭南樓與朱道士同處','柳宗元','唐','唐诗','tang','','[]','海上朱櫻贈所思，樓居況是望仙時。',32,'全唐诗/poet.tang.18000.json','["海上朱櫻贈所思，樓居況是望仙時。", "蓬萊羽客如相訪，不是偷桃一小兒。"]'),
('79c4501d-99f2-4e89-86a2-93f3a8636022','酬曹侍御過象縣見寄','柳宗元','唐','唐诗','tang','','[]','破額山前碧玉流，騷人遙駐木蘭舟。',32,'全唐诗/poet.tang.18000.json','["破額山前碧玉流，騷人遙駐木蘭舟。", "春風無限瀟湘意，欲採蘋花不自由。"]'),
('2298ea36-2160-44bf-9c71-7149e2d34dfa','法華寺石門精舍三十韻','柳宗元','唐','唐诗','tang','','[]','拘情病幽鬱，曠志寄高爽。',288,'全唐诗/poet.tang.18000.json','["拘情病幽鬱，曠志寄高爽。", "願言懷名緇，東峰旦夕仰。", "始欣雲雨霽，尤悅草木長。", "道同有愛弟，披拂恣心賞。", "松谿𥦖窱入，石棧夤緣上。", "蘿葛綿層甍，莓苔侵標牓。", "密林互對聳，絕壁儼雙敞。", "塹峭出蒙籠，墟險臨滉瀁。", "稍疑地脉斷，悠若天梯往。", "結構罩羣崖，廻環驅萬象。", "小劫不逾瞬，大千若在掌。", "體空得化元，觀有遺細想。", "喧煩困蠛蠓，跼蹐疲魍魎。", "寸進諒何營，尋直非所枉。", "探奇極遙矚，窮妙閟清響。", "理會方在今，神開庶殊曩。", "茲遊苟不嗣，浩氣竟誰養。", "道異誠所希，名賓匪余仗。", "超攄藉外獎，俯默有內朗。", "鑑爾揖古風，終焉乃吾黨。", "潛軀委韁鎖，高步謝塵坱。", "蓄志徒爲勞，追縱將焉倣。", "淹留值頹暮，眷戀睇遐壤。", "映日雁聯軒，翻雲波泱漭。"]'),
('653e7422-5ea4-4ab0-b23b-6f457b9a54f3','遊朝陽巖遂登西亭二十韻','柳宗元','唐','唐诗','tang','','["\u6292\u60c5", "\u601d\u4e61", "\u5c71\u6c34", "\u5199\u666f", "\u6124\u61d1"]','謫棄殊隱淪，登陟非遠郊。',240,'全唐诗/poet.tang.18000.json','["謫棄殊隱淪，登陟非遠郊。", "所懷緩伊鬱，詎欲肩夷巢。", "高巖瞰清江，幽窟潛神蛟。", "開曠延陽景，廻薄攢林梢。", "西亭搆其巓，反字臨呀庨。", "背瞻星辰興，下見雲雨交。", "惜非吾鄉土，得以蔭菁茆。", "羈貫去江介，世仕尚函崤。", "故墅即灃川，數畝均肥磽。", "臺館葺荒丘，池塘疏沈坳。", "會有圭組戀，遂貽山林嘲。", "薄軀信無庸，瑣屑劇斗筲。", "囚居固其宜，厚羞久已包。", "庭除植蓬艾，隟牖懸蠨蛸。", "所賴山川客，扁舟枉長梢。", "挹流敵清觴，掇野代嘉肴。", "適道有高言，取樂非絃匏。", "逍遙屏幽昧，淡薄辭喧呶。", "晨雞不余欺，風雨聞嘐嘐。", "再期永日閒，提挈移中庖。"]'),
('a6338edb-f09e-4d88-adcd-f1752a9195a6','湘口館瀟湘二水所會','柳宗元','唐','唐诗','tang','','["\u5c71\u6c34", "\u5199\u666f", "\u6292\u60c5", "\u6c34"]','九疑濬傾奔，臨源委縈廻。',108,'全唐诗/poet.tang.18000.json','["九疑濬傾奔，臨源委縈廻。", "會合屬空曠，泓澄停風雷。", "高館軒霞表，危樓臨山隈。", "茲辰始澂霽，纖雲盡褰開。", "天秋日正中，水碧無塵埃。", "杳杳漁父吟，呌呌羈鴻哀。", "境勝豈不豫，慮分固難裁。", "升高欲自舒，彌使遠念來。", "歸流駛且廣，汎舟絕沿洄。"]'),
('20491a26-8ddd-490c-bc26-c8d48929d779','登蒲州石磯望橫江口潭島深逈斜對香零山','柳宗元','唐','唐诗','tang','','[]','隱憂倦永夜，凌霧臨江津。',132,'全唐诗/poet.tang.18000.json','["隱憂倦永夜，凌霧臨江津。", "猿鳴稍已疎，登石娛清淪。", "日出洲渚靜，澄明皛無垠。", "浮暉翻高禽，沈景照文鱗。", "雙江匯西奔，詭怪潛坤珍。", "孤山乃北峙，森爽棲靈神。", "洄潭或動容，島嶼疑搖振。", "陶埴茲擇土，蒲魚相與鄰。", "信美非所安，羈心屢逡巡。", "糺結良可解，紆鬱亦已伸。", "高歌返故室，自誷非所欣。"]'),
('e20e81c8-9fb7-47ee-adf9-b6cf3d62ed56','南磵中題','柳宗元','唐','唐诗','tang','','["\u5199\u666f", "\u6101\u82e6", "\u6292\u60c5", "\u79cb\u5929", "\u5b64\u5bc2"]','秋氣集南磵，獨遊亭午時。',96,'全唐诗/poet.tang.18000.json','["秋氣集南磵，獨遊亭午時。", "廻風一蕭瑟，林影久參差。", "始至若有得，稍深遂忘疲。", "羈禽響幽谷，寒藻舞淪漪。", "去國魂已遠，懷人淚空垂。", "孤生易爲感，失路少所宜。", "索寞竟何事，徘徊秖自知。", "誰爲後來者，當與此心期。"]'),
('25d5785e-b764-498d-b08a-887987b2513c','遊石角過小嶺至長烏村','柳宗元','唐','唐诗','tang','','[]','志適不期貴，道存豈偷生。',168,'全唐诗/poet.tang.18000.json','["志適不期貴，道存豈偷生。", "久忘上封事，復笑昇天行。", "竄逐宦湘浦，搖心劇懸旌。", "始驚陷世議，終欲逃天刑。", "歲月殺憂慄，慵疎寡將迎。", "追遊疑所愛，且復舒吾情。", "石角恣幽步，長烏遂遐征。", "磴廻茂樹斷，景晏寒川明。", "曠望少行人，時聞田鸛鳴。", "風篁冒水遠，霜稻侵山平。", "稍與人事閒，益知身世輕。", "爲農信可樂，居寵真虛榮。", "喬木餘故國，願言果丹誠。", "四支反田畝，釋至東臯耕。"]'),
('7ef0fcb1-5259-4a80-a64e-9bba53c50f36','與崔策登西山','柳宗元','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','鶴鳴楚山靜，露白秋江曉。',144,'全唐诗/poet.tang.18000.json','["鶴鳴楚山靜，露白秋江曉。", "連袂度危橋，縈廻出林杪。", "西岑極遠目，毫末皆可了。", "重疊九疑高，微茫洞庭小。", "逈窮兩儀際，高出萬象表。", "馳景泛頹波，遙風遞寒篠。", "謫居安所習，稍厭從紛擾。", "生同胥靡遺，壽比彭鏗夭。", "蹇連困顛踣，愚蒙怯幽眇。", "非令親愛疎，誰使心神悄。", "偶茲遁山水，得以觀魚鳥。", "吾子幸淹留，緩我愁腸繞。"]'),
('c328476f-ca1d-4e6f-b9db-19075cb5c39a','構法華寺西亭','柳宗元','唐','唐诗','tang','','["\u7eaa\u6e38", "\u6292\u6000", "\u590f\u5929", "\u6101\u82e6"]','竄身楚南極，山水窮險艱。',168,'全唐诗/poet.tang.18000.json','["竄身楚南極，山水窮險艱。", "步登最高寺，蕭散任疎頑。", "西垂下斗絕，欲似窺人寰。", "反如在幽谷，榛翳不可攀。", "命童恣披翦，葺宇橫斷山。", "割如判清濁，飄若升雲間。", "遠岫攢衆頂，澄江抱清灣。", "夕照臨軒墮，棲鳥當我還。", "菡萏溢嘉色，篔簹遺清斑。", "神舒屏羈鎖，志適忘幽孱。", "棄逐久枯槁，迨今始開顏。", "賞心難久留，離念來相關。", "北望間親愛，南瞻雜夷蠻。", "置之勿復道，且寄須臾閑。"]'),
('812dcc1c-9da1-41ae-9b8a-734c021c631f','夏夜苦熱登西樓','柳宗元','唐','唐诗','tang','','["\u590f\u5929", "\u5fe7\u56fd\u5fe7\u6c11", "\u591c\u665a", "\u6292\u60c5"]','苦熱中夜起，登樓獨褰衣。',84,'全唐诗/poet.tang.18000.json','["苦熱中夜起，登樓獨褰衣。", "山澤凝暑氣，星漢湛光輝。", "火晶燥露滋，野靜停風威。", "探湯汲陰井，煬竈開重扉。", "憑闌久彷徨，流汗不可揮。", "莫辯亭毒意，仰訴璿與璣。", "諒非姑射子，靜勝安能希。"]'),
('47e1560e-42f1-4da5-9900-cf0b820e975d','覺衰','柳宗元','唐','唐诗','tang','','[]','久知老會至，不謂便見侵。',132,'全唐诗/poet.tang.18000.json','["久知老會至，不謂便見侵。", "今年宜未衰，稍已來相尋。", "齒疎髪就種，奔走力不任。", "咄此可奈何，未必傷我心。", "彭聃安在哉？周孔亦已沈。", "古稱壽聖人，曾不留至今。", "但願得美酒，朋友常共酙。", "是時春向暮，桃李生繁陰。", "日照天正綠，杳杳歸鴻吟。", "出門呼所親，扶杖登西林。", "高歌足自快，商頌有遺音。"]'),
('dc7a8ce9-52d5-4b83-9a3c-8018aa5bab36','遊南亭夜還敘志七十韻','柳宗元','唐','唐诗','tang','','[]','夙抱丘壑尚，率性恣遊遨。',288,'全唐诗/poet.tang.18000.json','["夙抱丘壑尚，率性恣遊遨。", "中爲吏役牽，十祀空悁勞。", "外曲徇塵轍，私心寄英髦。", "進乏廓廟器，退非鄉曲豪。", "天命斯不易，鬼責將安逃。", "屯難果見凌，剝喪宜所遭。", "神明固浩浩，衆口徒嗷嗷。", "投跡山水地，放情詠離騷。", "再懷曩歲期，容與馳輕舠。", "虛館背山郭，前軒面江臯。", "重疊間浦溆，邐迤驅巖㟼。", "積翠浮澹灧，始疑負靈鼇。", "叢林留衝飆，石礫迎飛濤。", "曠朗天景霽，樵蘇遠相號。", "澄潭涌沈鷗，半壁跳懸猱。", "鹿鳴驗食埜，魚樂知觀濠。", "孤賞誠所悼，暫欣良足襃。", "留連俯櫺檻，注我壺中醪。", "朵頤進芰實，擢手持蟹螯。", "炊稻視爨鼎，膾鮮聞操刀。", "埜蔬盈傾筐，頗雜池沼芼。", "緬慕鼓枻翁，嘯詠哺其糟。", "退想於陵子，三咽資李螬。", "斯道難爲偕，沈憂安所韜。"]'),
('8fc1b3da-3ed1-4d9b-96ad-d17f5ecb4225','韋道安','柳宗元','唐','唐诗','tang','','[]','道安本儒士，頗擅弓劒名。',288,'全唐诗/poet.tang.18000.json','["道安本儒士，頗擅弓劒名。", "二十遊太行，暮聞號哭聲。", "疾驅前致問，有叟垂華纓。", "言我故刺史，失職還西京。", "偶爲羣盜得，毫縷無餘贏。", "貨財足非恡，二女皆娉婷。", "蒼黃見驅逐，誰識死與生。", "便當此殞命，休復事晨征。", "一聞激高義，眥裂肝膽橫。", "挂弓問所在，趫捷超崢嶸。", "見盜寒磵陰，羅列方忿爭。", "一矢斃酋帥，餘黨號且驚。", "麾令遞束縛，纆索相拄撐。", "彼姝久褫魄，刃下俟誅刑。", "却立不親授，諭以從父行。", "捃收自擔肩，轉道趨前程。", "夜發敲石火，山林如晝明。", "父子更抱持，涕血紛交零。", "頓首願歸貨，納女稱舅甥。", "道安舊衣去，義重利固輕。", "師婚古所病，合姓非用兵。", "朅來事儒術，十載所能逞。", "慷慨張徐州，朱邸揚前旌。", "投區獲所願，前馬出王城。"]'),
('ca80ebc1-d68e-4ba3-9a03-1df39d1fd7a2','哭連州凌員外司馬','柳宗元','唐','唐诗','tang','','[]','廢逐人所棄，遂爲鬼神欺。',288,'全唐诗/poet.tang.18000.json','["廢逐人所棄，遂爲鬼神欺。", "才難不其然，卒與大患期。", "凌人古受氏，吳世夸雄姿。", "寂寞富春水，英氣方在斯。", "六學誠一貫，精義窮發揮。", "著書逾十年，幽頥靡不推。", "天庭掞高文，萬字若波馳。", "記室征西府，宏謀耀其奇。", "輶軒下東越，列郡蘇疲羸。", "宛宛凌江羽，來棲翰林枝。", "孝文留弓劒，中外方危疑。", "抗聲促遺詔，定命由陳辭。", "徒隸肅曹官，征賦參有司。", "出守烏江滸，老遷湟水湄。", "高堂傾故國，葬祭限囚羈。", "仲叔繼幽淪，狂呌唯童兒。", "一門既無主，焉用徒生爲。", "舉聲但呼天，孰知神者誰。", "泣盡目無見，腎傷足不持。", "溘死委炎荒，臧獲守靈帷。", "平生負國譴，骸骨非敢私。", "蓋棺未塞責，孤旐凝寒颸。", "念昔始相遇，腑腸爲君知。", "進身齊選擇，失路同瑕疵。"]'),
('9d839121-570a-4a3b-a7ec-123ef750b664','旦攜謝山人至愚池','柳宗元','唐','唐诗','tang','','[]','新沐換輕幘，曉池風露清。',48,'全唐诗/poet.tang.18000.json','["新沐換輕幘，曉池風露清。", "自諧塵外意，況與幽人行。", "霞散衆山逈，天高數雁鳴。", "機心付當路，聊適羲皇情。"]'),
('8ff00086-6ece-4a0d-ad85-3ee36fb24f77','獨覺','柳宗元','唐','唐诗','tang','','[]','覺來窗牖空，寥落雨聲曉。',36,'全唐诗/poet.tang.18000.json','["覺來窗牖空，寥落雨聲曉。", "良遊怨遲暮，末事驚紛擾。", "爲問經世心，古人難盡了。"]'),
('62f80556-3154-4531-8866-26abd2553f1e','首春逢耕者','柳宗元','唐','唐诗','tang','','["\u6625\u5929", "\u7530\u56ed", "\u601d\u4e61"]','南楚春候早，餘寒已滋榮。',108,'全唐诗/poet.tang.18000.json','["南楚春候早，餘寒已滋榮。", "土膏釋原埜，百蟄競所營。", "綴景未及郊，穡人先耦耕。", "園林幽鳥囀，渚澤新泉清。", "農事誠素務，羈囚阻平生。", "故池想蕪沒，遺畝當榛荆。", "慕隱既有繫，圖功遂無成。", "聊從田父言，款曲陳此情。", "眷然撫耒耜，回首煙雲橫。"]'),
('469dec8b-ba5e-4faf-b52f-2ad203e38d81','溪居','柳宗元','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5b64\u72ec", "\u4e94\u8a00\u53e4\u8bd7", "\u751f\u6d3b"]','久爲簪組累，幸此南夷謫。',48,'全唐诗/poet.tang.18000.json','["久爲簪組累，幸此南夷謫。", "閑依農圃鄰，偶似山林客。", "曉耕翻露草，夜榜響溪石。", "來往不逢人，長歌楚天碧。"]'),
('7f361785-7997-4aa1-9a4f-e0068085f49f','夏初雨後尋愚溪','柳宗元','唐','唐诗','tang','','["\u4e50\u89c2", "\u6292\u60c5", "\u5199\u666f"]','悠悠雨初霽，獨繞清溪曲。',48,'全唐诗/poet.tang.18000.json','["悠悠雨初霽，獨繞清溪曲。", "引杖試荒泉，解帶圍新竹。", "沈吟亦何事，寂寞固所欲。", "幸此息營營，嘯歌靜炎燠。"]'),
('260bc544-c174-4872-b312-831142afb9b0','入黃溪聞猿','柳宗元','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f", "\u4f24\u6000"]','溪路千里曲，哀猿何處鳴。',24,'全唐诗/poet.tang.18000.json','["溪路千里曲，哀猿何處鳴。", "孤臣淚已盡，虛作斷腸聲。"]'),
('5906e6f6-f3a8-468b-8e7e-1cbe696c239c','韋使君黃溪祈雨見召從行至祠下口號','柳宗元','唐','唐诗','tang','','[]','驕陽愆歲事，良牧念菑畬。',96,'全唐诗/poet.tang.18000.json','["驕陽愆歲事，良牧念菑畬。", "列騎低殘月，鳴笳度碧虛。", "稍窮樵客路，遙駐野人居。", "谷口寒流淨，叢祠古木疎。", "焚香秋霧濕，奠玉曉光初。", "肸蠁巫言報，精誠禮物餘。", "惠風仍偃草，靈雨會隨車。", "俟罪非真吏，翻慚奉簡書。"]'),
('7906dd95-6598-4cae-9297-58ac173f8713','郊居歲暮','柳宗元','唐','唐诗','tang','','[]','屏居負山郭，歲暮驚離索。',48,'全唐诗/poet.tang.18000.json','["屏居負山郭，歲暮驚離索。", "野逈樵唱來，庭空燒燼落。", "世紛因事遠，心賞隨年薄。", "默默諒何爲，徒成今與昨。"]'),
('3cfb1372-3aec-4131-ab6f-2ac73a29e2f8','秋曉行南谷經荒村','柳宗元','唐','唐诗','tang','','["\u7eaa\u884c", "\u79cb\u5929"]','杪秋霜露重，晨起行幽谷。',48,'全唐诗/poet.tang.18000.json','["杪秋霜露重，晨起行幽谷。", "黃葉覆溪橋，荒村唯古木。", "寒花疎寂歷，幽泉微斷續。", "機心久已忘，何事驚麋鹿。"]'),
('360ea23a-2963-4444-91b6-1ee5d44e6669','雨後曉行獨至愚溪北池','柳宗元','唐','唐诗','tang','','[]','宿雲散洲渚，曉日明村塢。',36,'全唐诗/poet.tang.18000.json','["宿雲散洲渚，曉日明村塢。", "高樹臨清池，風驚夜來雨。", "予心適無事，偶此成賓主。"]'),
('22b36a7a-dc90-47d9-b5cb-0f1fcef619c0','中夜起望西園值月上','柳宗元','唐','唐诗','tang','','["\u6292\u60c5", "\u8d2c\u8c2a", "\u751f\u6d3b", "\u5199\u666f"]','覺聞繁露墜，開戶臨西園。',48,'全唐诗/poet.tang.18000.json','["覺聞繁露墜，開戶臨西園。", "寒月上東嶺，泠泠疎竹根。", "石泉遠逾響，山鳥時一喧。", "倚楹遂至旦，寂寞將何言。"]'),
('2f72f173-5cf6-4fef-a8e8-eb6f9b68044c','零陵春望','柳宗元','唐','唐诗','tang','','["\u6625\u5929", "\u6292\u6000", "\u5199\u666f", "\u58ee\u5fd7\u672a\u916c"]','平埜春草綠，曉鶯啼遠林。',48,'全唐诗/poet.tang.18000.json','["平埜春草綠，曉鶯啼遠林。", "日晴瀟湘渚，雲斷岣嶁岑。", "仙駕不可望，世途非所任。", "凝情空景慕，萬里蒼梧陰。"]'),
('869a83a3-d57f-420b-a67f-45bc55c74e4e','從崔中丞過盧少尹郊居','柳宗元','唐','唐诗','tang','','[]','寓居湘岸四無鄰，世網難嬰每自珍。',64,'全唐诗/poet.tang.18000.json','["寓居湘岸四無鄰，世網難嬰每自珍。", "蒔藥閑庭延國老，開罇虛室值賢人。", "泉迴淺石依高柳，逕轉垂藤閒綠筠。", "聞道偏爲五禽戲，出門鷗鳥更相親。"]'),
('0944daf0-fb7e-4fdf-a2d4-e827e672356a','夏晝偶作','柳宗元','唐','唐诗','tang','','["\u751f\u6d3b", "\u590f\u5929", "\u95f2\u9002"]','南州溽暑醉如酒，隱几熟眠開北牖。',32,'全唐诗/poet.tang.18000.json','["南州溽暑醉如酒，隱几熟眠開北牖。", "日午獨覺無餘聲，山童隔竹敲茶臼。"]'),
('dff12ec8-f20f-4b87-94af-d7c845d40b95','雨晴至江渡','柳宗元','唐','唐诗','tang','','[]','江雨初晴思遠步，日西獨向愚溪渡。',32,'全唐诗/poet.tang.18000.json','["江雨初晴思遠步，日西獨向愚溪渡。", "渡頭水落村逕成，撩亂浮槎在高樹。"]'),
('1f92134b-bca9-46eb-b2fe-87b30413041a','江雪','柳宗元','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u96ea", "\u5c71\u6c34", "\u51ac\u5929", "\u96ea", "\u51ac"]','千山鳥飛絕，萬逕人蹤滅。',24,'全唐诗/poet.tang.18000.json','["千山鳥飛絕，萬逕人蹤滅。", "孤舟蓑笠翁，獨釣寒江雪。"]'),
('fa268e1e-5c77-4914-b549-609cf2c647f6','冉溪','柳宗元','唐','唐诗','tang','','[]','少時陳力希公侯，許國不復爲身謀。',64,'全唐诗/poet.tang.18000.json','["少時陳力希公侯，許國不復爲身謀。", "風波一跌逝萬里，壯心瓦解空縲囚。", "縲囚終老無餘事，願卜湘西冉溪地。", "却學壽張樊敬侯，種漆南園待成器。"]'),
('10be461a-6b02-4e28-9c7a-28c27abb5838','法華寺西亭夜飲','柳宗元','唐','唐诗','tang','','[]','[祇]樹夕陽亭，共傾三昧酒。',38,'全唐诗/poet.tang.18000.json','["[祇]樹夕陽亭，共傾三昧酒。", "霧暗水連堦，月明花復牖。", "莫厭尊前醉，相看未白首。"]'),
('9ccd8d2d-59c0-4dc8-a7c2-555fcbc7322e','戲題石門長老東軒','柳宗元','唐','唐诗','tang','','[]','石門長老身如夢，旃檀成林手所種。',64,'全唐诗/poet.tang.18000.json','["石門長老身如夢，旃檀成林手所種。", "坐來念念非昔人，萬徧蓮花爲誰用。", "如今七十自忘機，貪愛都忘筋力微。", "莫向東軒春埜望，花開日出雉皆飛。"]'),
('f9eb3661-12d0-4bab-bbbd-443609889a30','茅簷下始栽竹','柳宗元','唐','唐诗','tang','','[]','瘴茅葺爲宇，溽暑常侵肌。',180,'全唐诗/poet.tang.18000.json','["瘴茅葺爲宇，溽暑常侵肌。", "適有重膇疾，蒸鬱寧所宜。", "東鄰幸導我，樹竹邀涼颸。", "欣然愜吾志，荷鍤西巖垂。", "楚壤多怪石，墾鑿力已疲。", "江風忽云暮，輿曳還相追。", "蕭瑟過極浦，旖旎附幽墀。", "貞根期永固，貽爾寒泉滋。", "夜牕遂不掩，羽扇寧復持。", "清泠集濃露，枕簟淒已知。", "網蟲依密葉，曉禽棲逈枝。", "豈伊紛囂閒，重以心慮怡。", "嘉爾亭亭質，自遠棄幽期。", "不見野蔓草，蓊蔚有華姿。", "諒無淩寒色，豈與青山辭。"]'),
('3c7ef80d-0348-48c2-b3ad-43d4d8d164a8','種仙靈毗','柳宗元','唐','唐诗','tang','','[]','窮陋闕自養，癘氣劇囂煩。',204,'全唐诗/poet.tang.18000.json','["窮陋闕自養，癘氣劇囂煩。", "隆冬乏霜霰，日夕南風溫。", "杖藜下庭際，曳踵不及門。", "門有野田吏，慰我飄零魂。", "及言有靈藥，近在湘西原。", "服之不盈旬，蹩𨇨皆騰鶱。", "笑忭前即吏，爲我擢其根。", "蔚蔚遂充庭，英翹忽已繁。", "晨起自採曝，杵臼通夜喧。", "靈和理內藏，攻疾貴自源。", "擁覆逃積霧，伸舒委餘暄。", "奇功苟可徵，寧復資蘭蓀。", "我聞畸人術，一氣中夜存。", "能令深深息，呼吸還歸跟。", "疎放固難效，且以藥餌論。", "痿者不忘起，窮者寧復言。", "神哉輔吾足，幸及兒女奔。"]'),
('fe3c260c-affc-4234-87e6-2615321980a0','種朮','柳宗元','唐','唐诗','tang','','[]','守閒事服餌，採朮東山阿。',144,'全唐诗/poet.tang.18000.json','["守閒事服餌，採朮東山阿。", "東山幽且阻，疲苶煩經過。", "戒徒斸靈根，封植閟天和。", "違爾澗底石，徹我庭中莎。", "土膏滋玄液，松露墜繁柯。", "南東自成畝，繚繞紛相羅。", "晨步佳色媚，夜眠幽氣多。", "離憂苟可怡，孰能知其他。", "爨竹茹芳葉，寧慮瘵與瘥。", "留連樹蕙辭，婉娩採薇歌。", "悟拙甘自足，激清媿同波。", "單豹且理內，高門復如何。"]'),
('202641be-8d53-4de4-b477-fcbef11c89bf','種白蘘荷','柳宗元','唐','唐诗','tang','','["\u6292\u60c5", "\u8a00\u5fd7", "\u8bbd\u523a"]','血蟲化爲癘，夷俗多所神。',132,'全唐诗/poet.tang.18000.json','["血蟲化爲癘，夷俗多所神。", "銜猜每腊毒，謀富不爲仁。", "蔬果自遠至，盃酒盈肆陳。", "言甘中必苦，何用知其真。", "華潔事外飾，尤病中州人。", "錢刀恐賈害，飢至益逡巡。", "竄伏常戰慄，懷故逾悲辛。", "庶氏有嘉草，攻禬事久泯。", "炎帝垂靈編，言此殊足珍。", "崎嶇乃有得，託以全余身。", "紛敷碧樹陰，眄睞心所親。"]'),
('2cb983f0-34c5-40ff-89e0-dbdd4da26eb2','新植海石榴','柳宗元','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u8a00\u5fd7", "\u548f\u7269"]','弱植不盈尺，遠意駐蓬瀛。',48,'全唐诗/poet.tang.18000.json','["弱植不盈尺，遠意駐蓬瀛。", "月寒空堦曙，幽夢綵雲生。", "糞壤擢珠樹，莓苔插瓊英。", "芳根閟顏色，徂歲爲誰榮。"]'),
('b2b75195-273f-4dbf-af3d-7306de9d55d6','戲題堦前芍藥','柳宗元','唐','唐诗','tang','','["\u7261\u4e39", "\u9690\u55bb", "\u548f\u7269\u8bd7", "\u548f\u7269"]','凡卉與時謝，妍華麗茲晨。',60,'全唐诗/poet.tang.18000.json','["凡卉與時謝，妍華麗茲晨。", "欹紅醉濃露，窈窕留餘春。", "孤賞白日暮，暄風動搖頻。", "夜牕藹芳氣，幽臥知相親。", "願致溱洧贈，悠悠南國人。"]'),
('31aff727-0102-427a-a1e0-21966f5509ff','始見白髪題所植海石榴','柳宗元','唐','唐诗','tang','','[]','幾年封植愛芳叢，韶豔朱顏竟不同。',32,'全唐诗/poet.tang.18000.json','["幾年封植愛芳叢，韶豔朱顏竟不同。", "從此休論上春事，看成古木對衰翁。"]'),
('e9138d2a-488e-4d70-8bb4-d0e3aac0d1fa','植靈壽木','柳宗元','唐','唐诗','tang','','[]','白華照寒水，怡我適野情。',96,'全唐诗/poet.tang.18000.json','["白華照寒水，怡我適野情。", "前趨問長老，重復欣嘉名。", "蹇連易衰朽，方剛謝經營。", "敢期齒杖賜，聊且移孤莖。", "叢萼中競秀，分房外舒英。", "柔條乍反植，勁節常對生。", "循翫足忘疲，稍覺步武輕。", "安能事翦伐，持用資徒行。"]'),
('39115c15-994b-43ec-b1e5-388a495629f1','自衡陽移桂十餘本植零陵所住精舍','柳宗元','唐','唐诗','tang','','[]','謫官去南裔，清湘繞靈岳。',108,'全唐诗/poet.tang.18000.json','["謫官去南裔，清湘繞靈岳。", "晨登蒹葭岸，霜景霽紛濁。", "離披得幽桂，芳本欣盈握。", "火耕困煙燼，薪採久摧剝。", "道旁且不願，岑嶺況悠邈。", "傾筐壅故壤，棲息期鸞鷟。", "路遠清涼宮，一雨悟無學。", "南人始珍重，微我誰先覺。", "芳意不可傳，丹心徒自渥。"]'),
('12c990df-c417-480a-aa17-39836764b4ef','湘岸移木芙蓉植龍興精舍','柳宗元','唐','唐诗','tang','','["\u6101\u82e6", "\u6292\u60c5", "\u5b64\u5bc2", "\u82b1", "\u5199\u82b1"]','有美不自蔽，安能守孤根。',48,'全唐诗/poet.tang.18000.json','["有美不自蔽，安能守孤根。", "盈盈湘西岸，秋至風露繁。", "麗影別寒水，穠芳委前軒。", "芰荷諒難雜，反此生高原。"]'),
('68ae20e0-130a-43ef-b672-8ce0d95abb8b','早梅','柳宗元','唐','唐诗','tang','','["\u548f\u7269", "\u6885\u82b1", "\u6292\u6000", "\u548f\u7269\u8bd7"]','早梅發高樹，逈映楚天碧。',48,'全唐诗/poet.tang.18000.json','["早梅發高樹，逈映楚天碧。", "朔吹飄夜香，繁霜滋曉白。", "欲爲萬里贈，杳杳山水隔。", "寒英坐銷落，何用慰遠客。"]'),
('5c3dbac0-97ae-499a-9161-50f86235aa6c','南中榮橘柚','柳宗元','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u548f\u7269", "\u8d5e\u7f8e", "\u611f\u6168"]','橘柚懷貞質，受命此炎方。',48,'全唐诗/poet.tang.18000.json','["橘柚懷貞質，受命此炎方。", "密林耀朱綠，晚歲有餘芳。", "殊風限清漢，飛雪滯故鄉。", "攀條何所歎，北望熊與湘。"]'),
('cddea3a9-a11d-4fdb-8faf-e4d2bbeb68f8','紅蕉','柳宗元','唐','唐诗','tang','','[]','晚英值窮節，綠潤含朱光。',48,'全唐诗/poet.tang.18000.json','["晚英值窮節，綠潤含朱光。", "以茲正陽色，窈窕凌清霜。", "遠物世所重，旅人心獨傷。", "回暉眺林際，摵摵無遺芳。"]'),
('45949e82-08fb-4b8e-94b1-9c2e0f5e541e','巽公院五詠 淨土堂','柳宗元','唐','唐诗','tang','','[]','結習自無始，淪溺窮苦源。',60,'全唐诗/poet.tang.18000.json','["結習自無始，淪溺窮苦源。", "流形及茲世，始悟三空門。", "華堂開淨域，圖像煥且繁。", "清冷焚衆香，微妙歌法言。", "稽首媿導師，超遙謝塵昏。"]'),
('c9ad6fd9-f748-4df2-a5e7-3a188cf5198b','巽公院五詠 曲講堂','柳宗元','唐','唐诗','tang','','[]','寂滅本非斷，文字安可離。',60,'全唐诗/poet.tang.18000.json','["寂滅本非斷，文字安可離。", "曲堂何爲設，高士方在斯。", "聖默寄言宣，分別乃無知。", "趣中即空假，名相與誰期。", "願言絕聞得，忘意聊思惟。"]'),
('1d057127-c006-4a03-932b-1b0f3839e9d7','巽公院五詠 禪堂','柳宗元','唐','唐诗','tang','','[]','發地結菁茅，團團抱虛白。',60,'全唐诗/poet.tang.18000.json','["發地結菁茅，團團抱虛白。", "山花落幽戶，中有忘機客。", "涉有本非取，照空不待析。", "萬籟俱緣生，窅然喧中寂。", "心境本洞如，鳥飛無遺跡。"]'),
('599ff2eb-7a17-414b-bae8-6b537724eec2','巽公院五詠 芙蓉亭','柳宗元','唐','唐诗','tang','','[]','新亭俯朱檻，嘉木開芙蓉。',60,'全唐诗/poet.tang.18000.json','["新亭俯朱檻，嘉木開芙蓉。", "清香晨風遠，溽彩寒露濃。", "瀟灑出人世，低昂多異容。", "嘗聞色空喻，造物誰爲工。", "留連秋月晏，迢遞來山鐘。"]'),
('9e26e57f-c6df-4f7a-81d3-538b04cc4dac','巽公院五詠 苦竹橋','柳宗元','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u7af9\u5b50", "\u6000\u624d\u4e0d\u9047", "\u548f\u7269"]','危橋屬幽徑，繚繞穿疎林。',61,'全唐诗/poet.tang.18000.json','["危橋屬幽徑，繚繞穿疎林。", "迸籜分苦節，輕筠抱虛心。", "俯瞰涓涓流，仰聆蕭蕭吟。", "差池下煙日，嘲异常鳴山禽。", "諒無要津用，棲息有餘陰。"]'),
('6ecbed64-2409-4f6d-ade3-ccfec85ff92c','梅雨','柳宗元','唐','唐诗','tang','','["\u5199\u96e8", "\u96e8"]','梅實迎時雨，蒼茫值晚春。',48,'全唐诗/poet.tang.18000.json','["梅實迎時雨，蒼茫值晚春。", "愁深楚猿夜，夢斷越雞晨。", "海霧連南極，江雲暗北津。", "素衣今盡化，非爲帝京塵。"]'),
('b1534d3f-c9c2-4eb1-872a-1bb24ea99cb7','零陵早春','柳宗元','唐','唐诗','tang','','["\u601d\u4e61", "\u6028\u6124"]','問春從此去，幾日到秦原。',24,'全唐诗/poet.tang.18000.json','["問春從此去，幾日到秦原。", "憑寄還鄉夢，殷勤入故園。"]'),
('28d14ca6-9080-4341-9945-1a6a8ff01622','田家三首 一','柳宗元','唐','唐诗','tang','','[]','蓐食徇所務，驅牛向東阡。',72,'全唐诗/poet.tang.18000.json','["蓐食徇所務，驅牛向東阡。", "雞鳴村巷白，夜色歸暮田。", "札札耒耜聲，飛飛來烏鳶。", "竭茲筋力事，持用窮歲年。", "盡輸助徭役，聊就空自眠。", "子孫日已長，世世還復然。"]'),
('19eddc03-4ac4-4c71-b850-2d2ff638428e','田家三首 二','柳宗元','唐','唐诗','tang','','[]','籬落隔煙火，農談四鄰夕。',108,'全唐诗/poet.tang.18000.json','["籬落隔煙火，農談四鄰夕。", "庭際秋蟲鳴，疎麻方寂歷。", "蠶絲盡輸稅，機杼空倚壁。", "里胥夜經過，雞黍事筵席。", "各言官長峻，文字多督責。", "東鄉後租期，車轂陷泥澤。", "公門少推恕，鞭朴恣狼籍。", "努力慎經營，肌膚真可惜。", "迎新在此歲，唯恐踵前跡。"]'),
('97465f06-fe21-4b2c-901d-9483805fa85b','田家三首 三','柳宗元','唐','唐诗','tang','','[]','古道饒蒺藜，縈迴古城曲。',84,'全唐诗/poet.tang.18000.json','["古道饒蒺藜，縈迴古城曲。", "蓼花被堤岸，陂水寒更綠。", "是時收穫竟，落日多樵牧。", "風高榆柳疎，霜重棃棗熟。", "行人迷去住，野鳥競棲宿。", "田翁笑相念，昏黑慎原陸。", "今年幸少豐，無厭饘與粥。"]'),
('31ac5443-ea10-4e3f-8762-d65aec27490b','行路難三首 一','柳宗元','唐','唐诗','tang','','[]','君不見夸父逐日窺虞淵，跳踉北海超崑崙。',99,'全唐诗/poet.tang.18000.json','["君不見夸父逐日窺虞淵，跳踉北海超崑崙。", "披霄決漢出沆漭，瞥裂左右遺星辰。", "須臾力盡道渴死，狐鼠蜂蟻爭噬吞。", "北方竫人長九寸，開口抵掌更笑喧。", "啾啾飲食滴與粒，生死亦足終天年。", "睢盱大志小成遂，坐使兒女相悲憐。"]'),
('f017dd9b-1d9c-465f-a7da-7e6b1ad28aa7','行路難三首 二','柳宗元','唐','唐诗','tang','','[]','虞衡斤斧羅千山，工命采斫杙與椽。',115,'全唐诗/poet.tang.18000.json','["虞衡斤斧羅千山，工命采斫杙與椽。", "深林土剪十取一，百牛連鞅摧雙轅。", "萬圍千尋妨道路，東西蹶倒山火焚。", "遺餘毫末不見保，躪躒磵壑何當存。", "羣材未成質已夭，突兀哮豁空巖巒。", "柏梁天災武庫火，匠石狼顧相愁冤。", "君不見南山棟梁益稀少，愛材養育誰復論。"]'),
('918ea01d-553d-44cb-ad8d-b508452b8ab6','行路難三首 三','柳宗元','唐','唐诗','tang','','[]','飛雪斷道冰成梁，侯家熾炭雕玉房。',112,'全唐诗/poet.tang.18000.json','["飛雪斷道冰成梁，侯家熾炭雕玉房。", "蟠龍吐耀虎喙張，熊蹲豹躑爭低昂。", "攢巒叢㟧射朱光，丹霞翠霧飄奇香。", "美人四向迴明璫，雪山冰谷晞太陽。", "星躔奔走不得止，奄忽雙燕棲虹梁。", "風臺露榭生光飾，死灰棄置參與商。", "盛時一去貴反賤，桃笙葵扇安可當。"]'),
('1682a191-1a61-4cb4-b5a7-ac1aea1d71c7','聞籍田有感','柳宗元','唐','唐诗','tang','','[]','天田不日降皇輿，留滯長沙歲又除。',32,'全唐诗/poet.tang.18000.json','["天田不日降皇輿，留滯長沙歲又除。", "宣室無由問釐事，周南何處託成書。"]'),
('d0453ea5-ee4e-46ad-85c2-36d2d5a301c1','跂烏詞','柳宗元','唐','唐诗','tang','','[]','城上日出羣烏飛，鵶鵶爭赴朝陽枝。',128,'全唐诗/poet.tang.18000.json','["城上日出羣烏飛，鵶鵶爭赴朝陽枝。", "刷毛伸翼和且樂，爾獨落魄今何爲。", "無乃慕高近白日，三足妬爾令爾疾。", "無乃飢啼走道旁，貪鮮攫肉人所傷。", "翹肖獨足下叢薄，口銜低枝始能躍。", "還顧泥涂備螻蟻，仰看棟梁防燕雀。", "左右六翮利如刀，踊身失勢不得高。", "支離無趾猶自免，努力低飛逃後患。"]'),
('0c3dc50a-50fb-4b40-8e05-9bbee262aeb1','籠鷹詞','柳宗元','唐','唐诗','tang','','[]','淒風淅瀝飛嚴霜，蒼鷹上擊翻曙光。',112,'全唐诗/poet.tang.18000.json','["淒風淅瀝飛嚴霜，蒼鷹上擊翻曙光。", "雲披霧裂虹蜺斷，霹靂掣電捎平岡。", "砉然勁翮翦荆棘，下攫狐兔騰蒼茫。", "爪毛吻血百鳥逝，獨立四顧時激昂。", "炎風溽暑忽然至，羽翼脫落自摧藏。", "草中狸鼠足爲患，一夕十顧驚且傷。", "但願清商復爲假，拔去萬累雲間翔。"]'),
('f873e56a-180a-4ee6-ab81-a78c6dd98021','放鷓鴣詞','柳宗元','唐','唐诗','tang','','[]','楚越有鳥甘且腴，嘲嘲自名爲鷓鴣。',112,'全唐诗/poet.tang.18000.json','["楚越有鳥甘且腴，嘲嘲自名爲鷓鴣。", "徇媒得食不復慮，機械潛發罹罝罦。", "羽毛摧折觸籠籞，煙火煽赫驚庖廚。", "鼎前芍藥調五味，膳夫攘腕左右視。", "齊王不忍觳觫牛，簡子亦放邯鄲鳩。", "二子得意猶念此，況我萬里爲孤囚。", "破籠展翅當遠去，同類相呼莫相顧。"]'),
('34730a4b-0b2f-489b-b33e-129117aa2622','龜背戲','柳宗元','唐','唐诗','tang','','[]','長安新技出宮掖，喧喧初徧王侯宅。',160,'全唐诗/poet.tang.18000.json','["長安新技出宮掖，喧喧初徧王侯宅。", "玉盤滴瀝黃金錢，皎如文龜麗秋天。", "八方定位開神卦，六甲離離齊上下。", "投變轉動玄機卑，星流霞破相參差。", "四分五裂勢未已，出無入有誰能知。", "乍驚散漫無處所，須臾羅列已如故。", "徒言萬事有盈虛，終朝一擲知勝負。", "脩門象棋不復貴，魏宮妝奩世所棄。", "豈如瑞質耀奇文，願持千歲壽吾君。", "廟堂巾笥非余慕，錢刀兒女徒紛紛。"]'),
('617121d0-e2bb-4f15-8062-2cf925e33f57','聞黃鸝','柳宗元','唐','唐诗','tang','','["\u6292\u6000", "\u601d\u4e61", "\u5199\u9e1f", "\u9e1f"]','倦聞子規嘲暮聲，不意忽有黃鸝鳴。',144,'全唐诗/poet.tang.18000.json','["倦聞子規嘲暮聲，不意忽有黃鸝鳴。", "一聲夢斷楚江曲，滿眼故園春意生。", "目極千里無山河，麥芒際天搖清波。", "王畿優本少賦役，務閑酒熟饒經過。", "此時晴煙最深處，舍南巷北遙相語。", "翻日迥度昆明飛，凌風邪看細柳翥。", "我今誤落千萬山，身同傖人不思還。", "鄉禽何事亦來此，令我生心憶桑梓。", "閉聲迴翅歸務速，西林紫椹行當熟。"]'),
('26e0cd7b-3bd0-4c1f-a7b4-105bb299106a','渾鴻臚宅聞歌效白紵','柳宗元','唐','唐诗','tang','','[]','翠帷雙卷出傾城，龍劒破匣霜月明。',56,'全唐诗/poet.tang.18000.json','["翠帷雙卷出傾城，龍劒破匣霜月明。", "朱脣掩仰悄無聲，金簧玉磬宮中生。", "下沈秋火激太清，天高地逈凝日晶，羽觴蕩漾何事傾。"]'),
('ee01573c-048a-4c12-9edd-d9525c9252f2','楊白花','柳宗元','唐','唐诗','tang','','[]','楊白花，風吹渡江水。',42,'全唐诗/poet.tang.18000.json','["楊白花，風吹渡江水。", "坐令宮樹無顏色，搖蕩春光千萬里。", "茫茫曉日下長秋，哀歌未斷城鴉起。"]'),
('51b1aeeb-9a66-412d-b15c-4afaa6c6b1d7','漁翁','柳宗元','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u5199\u4eba", "\u4e03\u8a00\u53e4\u8bd7", "\u5c71\u6c34"]','漁翁夜傍西巖宿，曉汲清湘燃楚竹。',50,'全唐诗/poet.tang.18000.json','["漁翁夜傍西巖宿，曉汲清湘燃楚竹。", "煙銷日出不見人，[欸]乃一聲山水綠。", "迴看天際下中流，巖上無心雲相逐。"]'),
('a356172a-b00b-48ca-ae06-2e6fa81d9817','飲酒','柳宗元','唐','唐诗','tang','','[]','今夕少愉樂，起坐開清尊。',96,'全唐诗/poet.tang.18000.json','["今夕少愉樂，起坐開清尊。", "舉觴酹先酒，爲我驅憂煩。", "須臾心自殊，頓覺天地暄。", "連山變幽晦，綠水函晏溫。", "藹藹南郭門，樹木一何繁。", "清陰可自庇，竟夕聞佳言。", "盡醉無復辭，偃臥有芳蓀。", "彼哉晉楚富，此道未必存。"]'),
('51c99f73-8a33-4c3b-b8b3-9e625e71805f','讀書','柳宗元','唐','唐诗','tang','','[]','幽沈謝世事，俛默窺唐虞。',168,'全唐诗/poet.tang.18000.json','["幽沈謝世事，俛默窺唐虞。", "上下觀古今，起伏千萬途。", "遇欣或自笑，感戚亦以吁。", "縹帙各舒散，前後互相逾。", "瘴痾擾靈府，日與往昔殊。", "臨文乍了了，徹卷兀若無。", "竟夕誰與言，但與竹素俱。", "倦極便倒臥，熟寐乃一蘇。", "欠伸展肢體，吟詠心自愉。", "得意適其適，非願爲世儒。", "道盡即閉口，蕭散捐囚拘。", "巧者爲我拙，智者爲我愚。", "書史足自悅，安用勤與劬。", "貴爾六尺軀，勿爲名所驅。"]'),
('276645b8-28df-46f9-9235-aea982772911','感遇二首 一','柳宗元','唐','唐诗','tang','','[]','西陸動涼氣，驚烏號北林。',120,'全唐诗/poet.tang.18000.json','["西陸動涼氣，驚烏號北林。", "棲息豈殊性，集枯安可任。", "鴻鵠去不返，勾吳阻且深。", "徒嗟日沈湎，丸鼓騖奇音。", "東海久搖蕩，南風已駸駸。", "坐使青天暮，小星愁太陰。", "衆情嗜姦利，居貨捐千金。", "危根一以振，齊斧來相尋。", "攬衣中夜起，感物涕盈襟。", "微霜衆所踐，誰念歲寒心。"]'),
('9b0f160b-13ae-4b9d-a7f2-0edce38709a5','感遇二首 二','柳宗元','唐','唐诗','tang','','[]','旭日照寒野，鸒斯起蒿萊。',48,'全唐诗/poet.tang.18000.json','["旭日照寒野，鸒斯起蒿萊。", "啁啾有餘樂，飛舞西陵隈。", "迴風旦夕至，零葉委陳荄。", "所棲不足恃，鷹隼縱橫來。"]'),
('83df3e51-a4a9-4fb7-a0fc-3478ff49f9cf','詠史','柳宗元','唐','唐诗','tang','','[]','燕有黃金臺，遠致望諸君。',96,'全唐诗/poet.tang.18000.json','["燕有黃金臺，遠致望諸君。", "嗛嗛事強怨，三歲有奇勳。", "悠哉辟疆理，東海漫浮雲。", "寧知世情異，嘉穀坐熇焚。", "致令委金石，誰願蠢蠕羣。", "風波歘潛構，遺恨意紛紜。", "豈不善圖後，交私非所聞。", "爲忠不顧內，晏子亦垂文。"]'),
('7bad2d2b-66f0-498a-849b-902355e11bf3','詠三良','柳宗元','唐','唐诗','tang','','["\u5148\u79e6\u81f3\u516d\u671d", "\u548f\u53f2\u6000\u53e4"]','束帶值明后，顧盼流輝光。',108,'全唐诗/poet.tang.18000.json','["束帶值明后，顧盼流輝光。", "一心在陳力，鼎列夸四方。", "款款效忠信，恩義皎如霜。", "生時亮同體，死沒寧分張。", "壯軀閉幽隧，猛志填黃腸。", "殉死禮所非，況乃用其良。", "霸基弊不振，晉楚更張皇。", "疾病命固亂，魏氏言有章。", "從邪陷厥父，吾欲討彼狂。"]'),
('3b67a24e-33da-4a40-941a-e7a42931b390','詠荆軻','柳宗元','唐','唐诗','tang','','["\u5148\u79e6\u81f3\u516d\u671d", "\u548f\u53f2\u6000\u53e4"]','燕秦不兩立，太子已爲虞。',192,'全唐诗/poet.tang.18000.json','["燕秦不兩立，太子已爲虞。", "千金奉短計，匕首荆卿趨。", "窮年徇所欲，兵勢且見屠。", "微言激幽憤，怒目辭燕都。", "朔風動易水，揮爵前長驅。", "函首致宿怨，獻田開版圖。", "炯然耀電光，掌握罔正夫。", "造端何其銳，臨事竟趑趄。", "長虹吐白日，倉卒反受誅。", "按劒赫憑怒，風雷助號呼。", "慈父斷子首，狂走無容軀。", "夷城芟七族，臺觀皆焚汙。", "始期憂患弭，卒動災禍樞。", "秦皇本詐力，事與桓公殊。", "奈何效曹子，實謂勇且愚。", "世傳故多謬，太史徵無且。"]'),
('1369c08e-0001-4134-897d-678dbdb42f69','掩役夫張進骸','柳宗元','唐','唐诗','tang','','[]','生死悠悠爾，一氣聚散之。',180,'全唐诗/poet.tang.18000.json','["生死悠悠爾，一氣聚散之。", "偶來紛喜怒，奄忽已復辭。", "爲役孰賤辱，爲貴非神奇。", "一朝纊息定，枯巧無妍媸。", "生平勤皂櫪，剉秣不告疲。", "既死給槥櫝，葬之東山基。", "奈何值崩湍，蕩析臨路垂。", "髐然暴百骸，散亂不復支。", "從者幸告余，睠之涓然悲。", "猫虎獲迎祭，犬馬有蓋帷。", "佇立唁爾魂，豈復識此爲。", "畚鍤載埋瘞，溝瀆護其危。", "我心得所安，不謂爾有知。", "掩骼著春令，茲焉適其時。", "及物非吾事，聊且顧爾私。"]'),
('2237377e-d00e-4e7a-9ce4-1ea09940c89c','省試觀慶雲圖詩','柳宗元','唐','唐诗','tang','','[]','設色既成象，卿雲示國都。',72,'全唐诗/poet.tang.18000.json','["設色既成象，卿雲示國都。", "九天開秘祉，百辟贊嘉謨。", "抱日依龍衮，非煙近御爐。", "高標連汗漫，逈望接虛無。", "裂素榮光發，舒華瑞色敷。", "恒將配堯德，垂慶代河圖。"]'),
('fb1a266b-a490-4cef-8446-5837e25a5c7f','春懷故園','柳宗元','唐','唐诗','tang','','[]','九扈鳴已晚，楚鄉農事春。',24,'全唐诗/poet.tang.18000.json','["九扈鳴已晚，楚鄉農事春。", "悠悠故池水，空待灌園人。"]'),
('7bf0a2a0-b7dc-4c56-8396-dcf54882cb22','團扇詩','劉禹錫','唐','唐诗','tang','','[]','團扇復團扇，奉君清暑殿。',48,'全唐诗/poet.tang.18000.json','["團扇復團扇，奉君清暑殿。", "秋風入庭樹，從此不相見。", "上有乘鸞女，蒼蒼蟲網遍。", "明年入懷袖，別是機中練。"]'),
('4c126cc6-4904-4d77-a178-e58b68cc45a5','宜城歌','劉禹錫','唐','唐诗','tang','','[]','野水繞空城，行塵起孤驛。',36,'全唐诗/poet.tang.18000.json','["野水繞空城，行塵起孤驛。", "荒臺側生樹，石碣陽鐫額。", "靡靡度行人，溫風吹宿麥。"]'),
('adba6369-f910-4b4d-9e1b-c4a4e174e9b7','順陽歌','劉禹錫','唐','唐诗','tang','','[]','朝辭官軍驛，前望順陽路。',48,'全唐诗/poet.tang.18000.json','["朝辭官軍驛，前望順陽路。", "野水齧荒墳，秋蟲鏤宮樹。", "曾聞天寶末，胡馬西南騖。", "城守魯將軍，拔城從此去。"]'),
('81738668-4372-4467-bea2-f9474e6616fb','莫猺歌','劉禹錫','唐','唐诗','tang','','[]','莫猺自生長，名字無符籍。',48,'全唐诗/poet.tang.18000.json','["莫猺自生長，名字無符籍。", "市易雜鮫人，婚姻通木客。", "星居占泉眼，火種開山脊。", "夜渡千仞谿，含沙不能射。"]'),
('4a862348-178c-4de0-856d-38dd13eadb51','度桂嶺歌','劉禹錫','唐','唐诗','tang','','[]','桂陽嶺，下下復高高。',34,'全唐诗/poet.tang.18000.json','["桂陽嶺，下下復高高。", "人稀鳥獸駭，地遠草木豪。", "寄言千金子，知余歌者勞。"]'),
('cc861eb1-384f-4048-8904-b3bbd290a37e','插田歌','劉禹錫','唐','唐诗','tang','','[]','岡頭花草齊，燕子東西飛。',192,'全唐诗/poet.tang.18000.json','["岡頭花草齊，燕子東西飛。", "田塍望如線，白水光參差。", "農婦白紵裙，農父綠蓑衣。", "齊唱郢中歌，嚶儜如竹枝。", "但聞怨響音，不辨俚語詞。", "時時一大笑，此必相嘲嗤。", "水平苗漠漠，煙火生墟落。", "黃犬往復還，赤雞鳴且啄。", "路旁誰家郎，烏帽衫袖長。", "自言上計吏，年幼離帝鄉。", "田夫語計吏，君家儂定諳。", "一來長安道，眼大不相參。", "計吏笑致辭，長安真大處。", "省門高軻峨，儂入無度數。", "昨來補衛士，唯用筒竹布。", "君看二三年，我作官人去。"]'),
('867efd8c-98d1-45c8-99bf-8635532444c0','葡萄歌','劉禹錫','唐','唐诗','tang','','[]','野田生葡萄，纏繞一枝高。',144,'全唐诗/poet.tang.18000.json','["野田生葡萄，纏繞一枝高。", "移來碧墀下，張王日日高。", "分岐浩繁縟，脩蔓蟠詰曲。", "揚翹向庭柯，意思如有屬。", "爲之立長檠，布濩當軒綠。", "米液溉其根，理疎看滲漉。", "繁葩組綬結，懸實珠璣蹙。", "馬乳帶輕霜，龍鱗曜初旭。", "有客汾陰至，臨堂瞪雙目。", "自言我晉人，種此如種玉。", "釀之成美酒，令人飲不足。", "爲君持一斗，往取涼州牧。"]'),
('cbffe2fa-ff43-4c02-aa8d-fb8208ba0967','蠻子歌','劉禹錫','唐','唐诗','tang','','[]','蠻語鉤輈音，蠻衣斑斕布。',48,'全唐诗/poet.tang.18000.json','["蠻語鉤輈音，蠻衣斑斕布。", "熏狸掘沙鼠，時節祠盤瓠。", "忽逢乘馬客，恍若驚麏顧。", "腰斧上高山，意行無舊路。"]'),
('4cb22c8a-88d6-44c1-8f31-3e2de9127945','馬嵬行','劉禹錫','唐','唐诗','tang','','[]','綠野扶風道，黃塵馬嵬驛。',192,'全唐诗/poet.tang.18000.json','["綠野扶風道，黃塵馬嵬驛。", "路邊楊貴人，墳高三四尺。", "乃問里中兒，皆言幸蜀時。", "軍家誅戚族，天子捨妖姬。", "羣吏伏門屏，貴人牽帝衣。", "低回轉美目，風日爲無暉。", "貴人飲金屑，倏忽舜英暮。", "平生服杏丹，顏色真如故。", "屬車塵已遠，里巷來窺覰。", "共愛宿妝妍，君王畫眉處。", "履綦無復有，履組光未滅。", "不見巖畔人，空見凌波襪。", "郵童愛踪跡，私手解鞶結。", "傳看千萬眼，縷絕香不歇。", "指環照骨明，首飾敵連城。", "將入咸陽市，猶得賈胡驚。"]'),
('e8d612ee-0090-4cab-a883-406f4520e195','百花行','劉禹錫','唐','唐诗','tang','','[]','長安百花時，風景宜輕薄。',120,'全唐诗/poet.tang.18000.json','["長安百花時，風景宜輕薄。", "無人不沽酒，何處不聞樂。", "春風連夜動，微雨凌曉濯。", "紅焰出牆頭，雪光映樓角。", "繁紫韻松竹，遠黃繞籬落。", "臨路不勝愁，輕煙去何託。", "滿庭蕩魂魄，照廡成丹渥。", "爛熳簇顛狂，飄零勸行樂。", "時節易晼晚，清陰覆池閣。", "唯有安石榴，當軒慰寂寞。"]'),
('51b1fbda-3484-45a7-ab12-efc1119c14ee','壯士行','劉禹錫','唐','唐诗','tang','','[]','陰風振寒郊，猛虎正咆哮。',96,'全唐诗/poet.tang.18000.json','["陰風振寒郊，猛虎正咆哮。", "徐行出燒地，連吼入黃茅。", "壯士走馬去，鐙前彎玉弰。", "叱之使人立，一發如鈹交。", "悍睛忽星墮，飛血濺林梢。", "彪炳爲我席，羶腥充我庖。", "里中欣害除，賀酒紛呶號。", "明日長橋上，傾城看斬蛟。"]'),
('ed7ef6eb-8c75-4ce9-8b03-2ad22ed6d8b0','苦雨行','劉禹錫','唐','唐诗','tang','','[]','悠悠飛走情，同樂在陽和。',48,'全唐诗/poet.tang.18000.json','["悠悠飛走情，同樂在陽和。", "歲中三百日，常恐風雨多。", "天人信遐遠，時節易蹉跎。", "洞房有明燭，無乃酣且歌。"]'),
('ea9d2b45-7a22-492a-9893-f1315219bda5','華山歌','劉禹錫','唐','唐诗','tang','','[]','洪罏作高山，元氣鼓其橐。',96,'全唐诗/poet.tang.18000.json','["洪罏作高山，元氣鼓其橐。", "俄然神功就，峻拔在寥廓。", "靈跡露指爪，殺氣見稜角。", "凡木不敢生，神僊聿來託。", "天資帝王宅，以我爲關鑰。", "能令下國人，一見換神骨。", "高山固無限，如此方爲嶽。", "丈夫無特達，雖貴猶碌碌。"]'),
('af352613-12f5-4a88-90b7-cc6ffc141997','拋毬樂詞 一','劉禹錫','唐','唐诗','tang','','[]','五綵繡團圓，登君玳瑁筵。',36,'全唐诗/poet.tang.18000.json','["五綵繡團圓，登君玳瑁筵。", "最宜紅燭下，偏稱落花前。", "上客如先起，應須贈一船。"]'),
('3a930bf4-38e2-4320-900f-3d9d17d99a58','拋毬樂詞 二','劉禹錫','唐','唐诗','tang','','[]','春早見花枝，朝朝恨發遲。',36,'全唐诗/poet.tang.18000.json','["春早見花枝，朝朝恨發遲。", "及看花落後，却憶未開時。", "幸有拋球樂，一杯君莫辭。"]'),
('efdb19c5-4ea9-4742-a22d-a201935a9495','華清詞','劉禹錫','唐','唐诗','tang','','[]','日出驪山東，裴回照溫泉。',96,'全唐诗/poet.tang.18000.json','["日出驪山東，裴回照溫泉。", "樓臺影玲瓏，稍稍開白煙。", "言昔太上皇，常居此祈年。", "風中聞清樂，往往來列仙。", "翠華入五雲，紫氣歸上玄。", "哀哀生人淚，泣盡弓劒前。", "聖道本自我，凡情徒顒然。", "小臣感玄化，一望青冥天。"]'),
('d8ebb16f-31c7-491b-bb3a-965c2da744dc','送春曲三首 一','劉禹錫','唐','唐诗','tang','','[]','春向晚，春晚思悠哉。',34,'全唐诗/poet.tang.18000.json','["春向晚，春晚思悠哉。", "風雲日已改，花葉自相摧。", "漠漠空中去，何時天際來。"]'),
('04cbe110-8003-4d0c-8b03-b15a1a154d5f','送春曲三首 二','劉禹錫','唐','唐诗','tang','','[]','春已暮，冉冉如人老。',34,'全唐诗/poet.tang.18000.json','["春已暮，冉冉如人老。", "映葉見殘花，連天是青草。", "可憐桃與李，從此同桑棗。"]'),
('6dba141f-3a7d-4102-8ccc-d0f1316c509a','送春曲三首 三','劉禹錫','唐','唐诗','tang','','[]','春景去，此去何時回。',34,'全唐诗/poet.tang.18000.json','["春景去，此去何時回。", "遊人千萬恨，落日上高臺。", "寂寞繁花盡，流鸎歸莫來。"]'),
('5f19b213-3290-42f4-a18e-a4abe5623253','初夏曲三首 一','劉禹錫','唐','唐诗','tang','','[]','銅壺方促夜，斗柄暫南回。',36,'全唐诗/poet.tang.18000.json','["銅壺方促夜，斗柄暫南回。", "稍嫌單衣重，初憐北戶開。", "西園花已盡，新月爲誰來。"]'),
('24b01880-dc52-4fc6-a3de-fcd0af996101','初夏曲三首 二','劉禹錫','唐','唐诗','tang','','[]','時節過繁華，陰陰千萬家。',36,'全唐诗/poet.tang.18000.json','["時節過繁華，陰陰千萬家。", "巢禽命子戲，園果墜枝斜。", "寂寞孤飛蝶，窺叢覓晚花。"]'),
('8bd83e81-1d93-4e02-90d9-a0cc53781f73','初夏曲三首 三','劉禹錫','唐','唐诗','tang','','[]','綠水風初暖，青林露早晞。',36,'全唐诗/poet.tang.18000.json','["綠水風初暖，青林露早晞。", "麥隴雉朝雊，桑野人暮歸。", "百舌悲花盡，平蕪來去飛。"]'),
('b439500e-b770-4ad5-a23e-cd6158cd4d03','擣衣曲','劉禹錫','唐','唐诗','tang','','[]','爽砧應秋律，繁杵含淒風。',96,'全唐诗/poet.tang.18000.json','["爽砧應秋律，繁杵含淒風。", "一一遠相續，家家音不同。", "戶庭凝露清，伴侶明月中。", "長裾委襞積，輕佩垂𤧚瓏。", "汗餘衫更馥，鈿移麝半空。", "報寒驚邊鴈，促思聞候蟲。", "天狼正芒角，虎落定相攻。", "盈篋寄何處，征人如轉蓬。"]'),
('87b2aaa6-533b-4792-8f8e-129aad0b84b8','畬田行','劉禹錫','唐','唐诗','tang','','[]','何處好畬田，團團縵山腹。',168,'全唐诗/poet.tang.18000.json','["何處好畬田，團團縵山腹。", "鑚龜得雨卦，上山燒臥木。", "驚麏走且顧，羣雉聲咿喔。", "紅焰遠成霞，輕煤飛入郭。", "風引上高岑，獵獵度青林。", "青林望靡靡，赤光低復起。", "照潭出老蛟，爆竹驚山鬼。", "夜色不見山，孤明星漢間。", "如星復如月，俱逐曉風滅。", "本從敲石光，遂至烘天熱。", "下種暖灰中，乘陽拆牙孽。", "蒼蒼一雨後，苕頴如雲發。", "巴人拱手吟，耕耨不關心。", "由來得地勢，徑寸有餘金。"]'),
('d6b2b649-2b2b-4c35-bb15-5681cbdd1775','鶗鴂吟','劉禹錫','唐','唐诗','tang','','[]','朝陽有鳴鳳，不聞千萬祀。',48,'全唐诗/poet.tang.18000.json','["朝陽有鳴鳳，不聞千萬祀。", "鶗鴂摧衆芳，晨間先入耳。", "秋風白露晞，從是爾啼時。", "如何上春日，唧唧滿庭飛。"]'),
('9b8940d5-7966-47ab-bbf9-55efadf169b3','觀雲篇','劉禹錫','唐','唐诗','tang','','[]','興雲感陰氣，疾足如見機。',48,'全唐诗/poet.tang.18000.json','["興雲感陰氣，疾足如見機。", "晴來意態行，有若功成歸。", "葱蘢含晚景，潔白凝秋暉。", "夜深度銀漢，漠漠仙人衣。"]'),
('113e7136-2be2-46a0-9e3b-25d3036d1d40','養鷙詞','劉禹錫','唐','唐诗','tang','','[]','養鷙非玩形，所資擊鮮力。',72,'全唐诗/poet.tang.18000.json','["養鷙非玩形，所資擊鮮力。", "少年昧其理，日日哺不息。", "探雛網黃口，旦暮有餘食。", "寧知下韝時，翅重飛不得。", "毰毸止林表，狡兔自南北。", "飲啄既已盈，安能勞羽翼。"]'),
('261fca31-93b2-4e5e-b6a8-65a79ac156dd','別友人後得書因以詩贈','劉禹錫','唐','唐诗','tang','','[]','前時送君去，揮手青門橋。',48,'全唐诗/poet.tang.18000.json','["前時送君去，揮手青門橋。", "路轉不相見，猶聞馬蕭蕭。", "今得出關書，行程日已遙。", "春還遲君至，共結芳蘭苕。"]'),
('8fc97122-a0f4-4483-b254-454821da29a1','送華陰尉張苕赴邕府使幕','劉禹錫','唐','唐诗','tang','','[]','昔忝南宮郎，往來東觀頻。',216,'全唐诗/poet.tang.18000.json','["昔忝南宮郎，往來東觀頻。", "嘗披燕公傳，聳若窺三辰。", "翊聖崇國本，像賢正朝倫。", "高視緬今古，清風敻無鄰。", "蘭錡照通衢，一家十朱輪。", "酇國嗣侯絕，韋卿世業貧。", "夫子承大名，少年振芳塵。", "青袍仙掌下，矯首凌煙旻。", "公冶本非罪，潘郎一爲民。", "風霜苦搖落，堅白無緇磷。", "一旦逢良時，天光燭幽淪。", "重爲長裾客，佐彼觀風臣。", "分野窮禹畫，人煙過虞巡。", "不言此行遠，所樂相知新。", "雨起巫山陽，鳥鳴湘水濱。", "離筵出蒼莽，別曲多悲辛。", "今朝一杯酒，明日千里人。", "從此孤舟去，悠悠天海春。"]'),
('61e77b5c-983a-4b10-afb5-a76563ba71ef','送湘陽熊判官孺登府罷歸鍾陵因寄呈江西裴中丞二十三兄','劉禹錫','唐','唐诗','tang','','["\u957f\u6c5f"]','射策志未就，從事歲云除。',240,'全唐诗/poet.tang.18000.json','["射策志未就，從事歲云除。", "篋留馬卿賦，袖有劉弘書。", "忽見夏木深，悵然憶吾廬。", "復持州民刺，歸謁專城居。", "君家誠易知，勝絕傾里閭。", "人言北郭生，門有卿相輿。", "鍾陵靄千里，帶郭西江水。", "朱檻照河宮，旗亭綠雲裏。", "前年初缺守，慎簡由宸扆。", "臨軒弄郡章，得人方付此。", "是時左馮翊，天下第一理。", "貴臣持牙璋，優詔發青紙。", "迎風姦吏免，先令疲人喜。", "何武劾腐儒，陳蕃禮高士。", "昔升君子堂，腰下綬猶黃。", "汾陰有寶氣，赤堇多奇鋩。", "束簡下曲臺，佩鞬來歷陽。", "綺筵陪一笑，蘭室襲餘芳。", "風水忽異勢，江湖遂相忘。", "因君倘借問，爲話老滄浪。"]'),
('92e10d9d-a268-4f67-a55f-07bc0334c08c','送韋秀才道沖赴制舉','劉禹錫','唐','唐诗','tang','','[]','驚禽一辭巢，棲息無少安。',264,'全唐诗/poet.tang.18000.json','["驚禽一辭巢，棲息無少安。", "秋扇一離手，流塵蔽霜紈。", "故侶不可追，涼風日已寒。", "遠逢杜陵士，別盡平生歡。", "逐客無印綬，楚江多芷蘭。", "因居暇時遊，長鋏不復彈。", "閱書南軒霽，絙瑟清夜闌。", "萬境身外寂，一杯腹中寬。", "伊昔玄宗朝，冬卿冠鴛鸞。", "肅穆升內殿，從容領儒冠。", "游夏無措詞，陽秋垂不刊。", "至今羣玉府，學者空縱觀。", "世人希德門，揭若攀峰巒。", "之子尚明訓，鏘如振琅玕。", "一旦西上書，斑衣拂征鞍。", "荆臺宿暮雨，漢水浮春瀾。", "君門起天中，多士如星攢。", "煙霞覆雙闕，抃舞羅千官。", "清漏滴銅壺，仙廚下雕槃。", "熒煌仰金榜，錯落濡飛翰。", "古來才傑士，所嗟遭時難。", "一鳴從此始，相望青雲端。"]'),
('a7965c42-0b1a-4fb9-97bd-1e5e375a819b','送李策秀才還湖南因寄幕中親故兼簡衡州呂八郎中','劉禹錫','唐','唐诗','tang','','["\u8861\u5c71"]','深春風日淨，晝長幽鳥鳴。',288,'全唐诗/poet.tang.18000.json','["深春風日淨，晝長幽鳥鳴。", "僕夫前致詞，門有白面生。", "攝衣相問訊，解帶坐南榮。", "端志見眉睫，苦言發精誠。", "因出懷中文，調孤詞亦清。", "悄如促柱弦，掩抑多不平。", "乃言本蜀士，世降岷山靈。", "前人秉藝文，高視來上京。", "曳綬司徒府，所從信國楨。", "析薪委寶林，善響繼家聲。", "何處翳附郭，幾人思郈成。", "雲天望喬木，風水悲流萍。", "前與計吏西，始列貢士名。", "森然就筆札，從試春官卿。", "帝城岐路多，萬足伺晨星。", "茫茫風塵中，工拙同有營。", "寒女勞夜織，山苗榮寸莖。", "侯門方擊鐘，衣褐誰將迎。", "弱羽果摧頹，壯心鬱怦怦。", "諒無蟠木容，聊復蓬累行。", "昨日訊靈龜，繇言利艱貞。", "當求捨拔中，必在審已明。", "誓將息薄遊，焦思窮筆精。", "蒔蘭在幽渚，安得揚芬馨。"]'),
('781aeee0-2331-4e7d-8f6c-d29b134c98a1','送張盥赴舉詩','劉禹錫','唐','唐诗','tang','','["\u5e90\u5c71"]','爾生始懸弧，我作座上賓。',216,'全唐诗/poet.tang.18000.json','["爾生始懸弧，我作座上賓。", "引箸舉湯餅，祝詞天麒麟。", "今成一丈夫，坎坷愁風塵。", "長裾來謁我，自號廬山人。", "道舊與撫孤，悄然傷我神。", "依依見眉睫，嘿嘿含悲辛。", "永懷同年友，追想出谷晨。", "三十二君子，齊飛凌煙旻。", "曲江一會時，後會已凋淪。", "況今三十載，閱世難重陳。", "盛時一已過，來者日日新。", "不如搖落樹，重有明年春。", "火後見琮璜，霜餘識松筠。", "肅風乃獨秀，武部亦絕倫。", "爾今持我詩，西見二重臣。", "成賢必念舊，保貴在安貧。", "清時爲丞郎，氣力侔陶鈞。", "乞取斗升水，因之雲漢津。"]'),
('cd292dd0-64dd-45dd-9755-f8bfac267b1f','和州送錢侍御自宣州幕拜官便於華州覲省','劉禹錫','唐','唐诗','tang','','[]','五綵繡衣裳，當年正相稱。',72,'全唐诗/poet.tang.18000.json','["五綵繡衣裳，當年正相稱。", "春風舊關路，歸去真多興。", "蘭陔行可採，蓮府猶回瞪。", "楊家紺幰迎，謝守瑤華贈。", "御街草泛灧，臺柏煙含凝。", "曾是平生遊，無因理歸乘。"]'),
('bb93206b-92a8-4440-aeb5-4cc3bbe596ea','送僧方及南謁柳員外','劉禹錫','唐','唐诗','tang','','["\u5e90\u5c71"]','昔事廬山遠，精舍虎溪東。',216,'全唐诗/poet.tang.18000.json','["昔事廬山遠，精舍虎溪東。", "朝陽照瀑水，樓閣虹霓中。", "騁望羨游雲，振衣若秋蓬。", "舊房閉松月，遠思吟江風。", "古寺歷頭陀，奇峰扳祝融。", "南登小桂嶺，却望歸塞鴻。", "衣裓貯文章，自言學雕蟲。", "搶榆念陵厲，覆簣圖穹崇。", "遠郡多暇日，有詩訪禪宮。", "石門聳峭絕，竹院含空濛。", "幽響滴巖溜，晴芳飄野叢。", "海雲懸颶母，山果屬狙公。", "忽憶吳興郡，白蘋正葱蘢。", "願言挹風采，邈若窺華嵩。", "桂水夏瀾急，火山宵焰紅。", "三衣濡菌露，一錫飛煙空。", "勿謂翻譯徒，不爲文雅雄。", "古來賞音者，燋爨得孤桐。"]'),
('5863daf6-9ae5-4f51-b3e0-f47679b47b27','送惟良上人','劉禹錫','唐','唐诗','tang','','[]','高齋灑寒水，是夕山僧至。',48,'全唐诗/poet.tang.18000.json','["高齋灑寒水，是夕山僧至。", "玄牝無關鎖，瓊書捨文字。", "燈明香滿室，月午霜凝地。", "語到不言時，世間人盡睡。"]'),
('4316a389-61fb-4994-ae88-83831c2ae90d','翠微寺有感','劉禹錫','唐','唐诗','tang','','[]','吾王昔遊幸，離宮雲際開。',48,'全唐诗/poet.tang.18000.json','["吾王昔遊幸，離宮雲際開。", "朱旗迎夏早，涼軒避暑來。", "湯餅賜都尉，寒冰頒上才。", "龍髯不可望，玉座生塵埃。"]'),
('e471da14-19ce-41bb-ab7e-0455aed83758','觀柘枝舞二首 一','劉禹錫','唐','唐诗','tang','','[]','胡服何葳蕤，僊僊登綺墀。',72,'全唐诗/poet.tang.18000.json','["胡服何葳蕤，僊僊登綺墀。", "神飆獵紅蕖，龍燭暎金枝。", "垂帶覆纖腰，安鈿當嫵眉。", "翹袖中繁鼓，傾眸遡華榱。", "燕秦有舊曲，淮南多冶詞。", "欲見傾城處，君看赴節時。"]'),
('b2404a4f-f825-4d29-ba99-f3807ca3951e','觀柘枝舞二首 二','劉禹錫','唐','唐诗','tang','','[]','山雞臨清鏡，石燕赴遙津。',48,'全唐诗/poet.tang.18000.json','["山雞臨清鏡，石燕赴遙津。", "何如上客會，長袖入華裀。", "體輕似無骨，觀者皆聳神。", "曲盡回身處，層波猶注人。"]'),
('e3c3efef-0365-4eda-8187-8890a0f407db','連州臘日觀莫徭臘西山','劉禹錫','唐','唐诗','tang','','[]','海天殺氣薄，蠻軍步伍囂。',96,'全唐诗/poet.tang.18000.json','["海天殺氣薄，蠻軍步伍囂。", "林紅葉盡變，原黑草初燒。", "圍合繁鉦息，禽興大斾搖。", "張羅依道口，嗾犬上山腰。", "猜鷹慮奮迅，驚鹿時跼跳。", "瘴雲四面起，臘雪半空消。", "箭頭餘鵠血，鞍傍見雉翹。", "日暮還城邑，金笳發麗譙。"]'),
('03209ef5-4294-43fa-aace-c03cd0f2fb6e','寄陝州姚中丞','劉禹錫','唐','唐诗','tang','','[]','八月天氣肅，二陵風雨收。',72,'全唐诗/poet.tang.18000.json','["八月天氣肅，二陵風雨收。", "旌旗闕下來，雲日關東秋。", "禹跡想前事，漢臺餘故丘。", "俳徊襟帶地，左右帝王州。", "留滯悲昔老，恩光榮徹侯。", "相思望棠樹，一寄商聲謳。"]'),
('f7bd65ca-4ccd-42db-82ec-b7115a53fc7c','奉酬湖州崔郎中見寄五韻','劉禹錫','唐','唐诗','tang','','[]','山陽昔相遇，灼灼晨葩鮮。',60,'全唐诗/poet.tang.18000.json','["山陽昔相遇，灼灼晨葩鮮。", "同遊翰墨場，和樂塤箎然。", "一落名宦途，浩如乘風船。", "行當衰暮日，臥理淮海邊。", "猶期謝病後，共樂桑榆年。"]'),
('1d74a45e-2147-4c0a-9356-57571cfc232a','學阮公體三首 一','劉禹錫','唐','唐诗','tang','','[]','少年負志氣，信道不從時。',48,'全唐诗/poet.tang.18000.json','["少年負志氣，信道不從時。", "只言繩自直，安知室可欺。", "百勝難慮敵，三折乃良醫。", "人生不失意，焉能慕知己。"]'),
('f8bfb247-859a-43e7-99fa-16f4eec18dc0','學阮公體三首 二','劉禹錫','唐','唐诗','tang','','[]','朔風悲老驥，秋霜動鷙禽。',48,'全唐诗/poet.tang.18000.json','["朔風悲老驥，秋霜動鷙禽。", "出門有遠道，平野多層陰。", "滅沒馳絕塞，振迅拂華林。", "不因感衰節，安能激壯心。"]'),
('b6a8ee98-9353-4283-9aed-dd14084ebced','學阮公體三首 三','劉禹錫','唐','唐诗','tang','','[]','昔賢多使氣，憂國不謀身。',48,'全唐诗/poet.tang.18000.json','["昔賢多使氣，憂國不謀身。", "目覽千載事，心交上古人。", "侯門有仁義，靈臺多苦辛。", "不學腰如磬，徒使甑生塵。"]'),
('4eac3d32-e1f3-4258-9938-26f828aaa26e','秋晚題湖城驛池上亭','劉禹錫','唐','唐诗','tang','','[]','秋次池上館，林塘照南榮。',48,'全唐诗/poet.tang.18000.json','["秋次池上館，林塘照南榮。", "塵衣紛未解，幽思浩已盈。", "風蓮墜故萼，露菊含晚英。", "恨爲一夕客，愁聽晨雞鳴。"]'),
('40cb2f52-4361-4f0d-9b37-519a7c0b0e74','賈客詞','劉禹錫','唐','唐诗','tang','','[]','賈客無定遊，所遊唯利幷。',132,'全唐诗/poet.tang.18000.json','["賈客無定遊，所遊唯利幷。", "眩俗雜良苦，乘時取重輕。", "心計析秋毫，搖鉤侔懸衡。", "錐刀既無棄，轉化日已盈。", "邀福禱波神，施財遊化城。", "妻約雕金釧，女垂貫珠纓。", "高貲比封君，奇貨通倖卿。", "趨時鷙鳥思，藏鏹盤龍形。", "大艑浮通川，高樓次旗亭。", "行止皆有樂，關梁自無征。", "農夫何爲者，辛苦事寒耕。"]'),
('089b5bfb-83e2-4d94-ab79-9b0dfdde3575','調瑟詞','劉禹錫','唐','唐诗','tang','','[]','調瑟在張弦，弦平音自足。',72,'全唐诗/poet.tang.18000.json','["調瑟在張弦，弦平音自足。", "朱弦二十五，缺一不成曲。", "美人愛高張，瑤軫再三促。", "上弦雖獨響，下應不相屬。", "日暮聲未和，寂寥一枯木。", "却顧膝上弦，流淚難相續。"]'),
('7d0dba7d-6ac7-46d2-b49d-ba4be9b7b66b','讀張曲江集作','劉禹錫','唐','唐诗','tang','','[]','聖言貴忠恕，至道重觀身。',48,'全唐诗/poet.tang.18000.json','["聖言貴忠恕，至道重觀身。", "法在何所恨，色相斯爲仁。", "良時難久恃，陰謫豈無因。", "寂寞韶陽廟，魂歸不見人。"]'),
('ed07986b-0256-4bcf-8b27-e633e3785ad2','偶作二首 一','劉禹錫','唐','唐诗','tang','','[]','終朝對尊酒，嗜興非嗜甘。',48,'全唐诗/poet.tang.18000.json','["終朝對尊酒，嗜興非嗜甘。", "終日偶衆人，縱言不縱談。", "世情閑靜見，藥性病多諳。", "寄謝嵇中散，予無甚不堪。"]'),
('bb874241-6d70-495b-91e1-2b24aadd8c9c','偶作二首 二','劉禹錫','唐','唐诗','tang','','["\u957f\u6c5f"]','萬卷堆牀書，學者識其真。',48,'全唐诗/poet.tang.18000.json','["萬卷堆牀書，學者識其真。", "萬里長江水，征夫渡要津。", "養生非但藥，悟佛不因人。", "燕石何須辨，逢時即至珍。"]'),
('31119bd8-3cf0-402d-8e6f-6ebfdda3c423','昏鏡詞','劉禹錫','唐','唐诗','tang','','[]','昏鏡非美金，漠然喪其晶。',72,'全唐诗/poet.tang.18000.json','["昏鏡非美金，漠然喪其晶。", "陋容多自欺，謂若他鏡明。", "瑕疵既不見，妍態隨意生。", "一日四五照，自言美傾城。", "飾帶以紋繡，裝匣以瓊瑛。", "秦宮豈不重，非適乃爲輕。"]'),
('0072b076-9763-4af6-8e62-36cd23362157','詠古二首有所寄 一','劉禹錫','唐','唐诗','tang','','[]','車音想轔轔，不見綦下塵。',48,'全唐诗/poet.tang.18000.json','["車音想轔轔，不見綦下塵。", "可憐平陽第，歌舞嬌青春。", "金屋容色在，文園詞賦新。", "一朝復得幸，應知失意人。"]'),
('5f95a0f0-b062-4734-98a4-9646fc613d73','詠古二首有所寄 二','劉禹錫','唐','唐诗','tang','','[]','寂寥照鏡臺，遺基古南陽。',48,'全唐诗/poet.tang.18000.json','["寂寥照鏡臺，遺基古南陽。", "真人昔來遊，翠鳳相隨翔。", "目成在桑野，志遂貯椒房。", "豈無三千女，初心不可忘。"]'),
('ebf7d326-1e94-4b70-a1e0-80419c25df45','磨鏡篇','劉禹錫','唐','唐诗','tang','','[]','流塵翳明鏡，歲久看如漆。',72,'全唐诗/poet.tang.18000.json','["流塵翳明鏡，歲久看如漆。", "門前負局人，爲我一磨拂。", "萍開綠池滿，暈盡金波溢。", "白日照空心，圓光走幽室。", "山神妖氣沮，野魅真形出。", "却思未磨時，瓦礫來唐突。"]'),
('93f9980c-8c38-4f07-a2e7-0ad9ec4e080f','登司馬錯古城','劉禹錫','唐','唐诗','tang','','[]','將軍將秦師，西南奠遐服。',96,'全唐诗/poet.tang.18000.json','["將軍將秦師，西南奠遐服。", "故壘清江上，蒼烟晦喬木。", "登臨直蕭辰，周覽壯前躅。", "塹平陳葉滿，墉高秋蔓綠。", "廢井抽寒菜，毀臺生魯穀。", "耕人得古器，宿雨多遺鏃。", "楚塞鬱重疊，蠻溪紛詰曲。", "留此數仞基，幾人傷遠目。"]'),
('3db77b89-08a0-4ae3-bf83-c5c1468c555d','謁柱山會禪師','劉禹錫','唐','唐诗','tang','','[]','我本山東人，平生多感慨。',192,'全唐诗/poet.tang.18000.json','["我本山東人，平生多感慨。", "弱冠遊咸京，上書金馬外。", "結交當世賢，馳聲溢四塞。", "勉修貴及早，狃捷不知退。", "錙銖揚芬馨，尋尺招瑕纇。", "淹留郢南都，摧頹羽翰碎。", "安能咎往事，且欲去沈痗。", "吾師得真如，寄在人寰內。", "哀我墮名網，有如翾飛輩。", "瞳瞳揭智燭，照使出昏昧。", "靜見玄關啓，歆然初心會。", "夙尚一何微，今得信可大。", "覺路明證入，便門通懺悔。", "悟理言自忘，處屯道猶泰。", "色身豈吾寶，慧性非形礙。", "思此靈山期，未卜何年載。"]'),
('4b6c65cd-f742-4c07-8da3-c815fcf6b9ab','臥病聞常山旋師策勳宥過王澤大洽因寄李六侍郎','劉禹錫','唐','唐诗','tang','','[]','寂寂重寂寂，病夫臥秋齋。',120,'全唐诗/poet.tang.18000.json','["寂寂重寂寂，病夫臥秋齋。", "夜蛩思幽壁，槁葉鳴空堦。", "南國異氣候，火旻尚昏霾。", "瘴煙跕飛羽，沴氣傷百骸。", "昨聞凱歌旋，飲至酒如淮。", "無戰陋丹水，垂仁輕槀街。", "清廟既策勳，圓丘俟燔柴。", "車書一以混，幽遠靡不懷。", "逐客顦顇久，故鄉雲雨乖。", "禽魚各有化，予欲問齊諧。"]'),
('20c8844d-531e-4037-8a64-54930a37939e','善卷壇下作','劉禹錫','唐','唐诗','tang','','[]','先生見堯心，相與去九有。',48,'全唐诗/poet.tang.18000.json','["先生見堯心，相與去九有。", "斯民既已治，我得安林藪。", "道爲自然貴，名是無窮壽。", "瑤壇在此山，識者常回首。"]'),
('7545d07f-17d2-47df-89d1-ed639aeff478','武陵觀火詩','劉禹錫','唐','唐诗','tang','','[]','楚鄉祝融分，炎火常爲虞。',288,'全唐诗/poet.tang.18000.json','["楚鄉祝融分，炎火常爲虞。", "是時直突煙，發自晨炊徒。", "盲風扇其威，白晝曛陽鳥。", "操綆不暇汲，循牆還避踰。", "怒如列缺光，迅與芬輪俱。", "聯延掩四遠，赫弈成洪鑪。", "洶疑雲濤翻，颯若鬼神趨。", "當前迎惞𨹮，是物同膏腴。", "金烏入梵天，赤龍遊玄都。", "騰煙透窻戶，飛燄生欒櫨。", "火山摧半空，星雨灑中衢。", "瑤壇被髹漆，寶樹攢珊瑚。", "光縣與琴焦，旗亭無酒濡。", "市人委百貨，邑令遺雙鳧。", "餘勢下隈隩，長熛烘舳艫。", "吹焚照水府，炙浪愁天吳。", "災罷雲日晚，心驚視聽殊。", "高灰辨廩庾，黑土連闉闍。", "衆燼合星羅，遊氛鑠人膚。", "厚地藏宿熱，遙林呈驟枯。", "火德資生人，庸可一日無。", "御之失其道，敲石彌天隅。", "晉庫走龍劒，吳宮傷燕雛。", "五行有沴氣，先哲垂訏謨。"]'),
('c70f3ee7-ba98-4fbd-a6af-46f4fa583e23','崔元受少府自貶所還遺山薑花以詩答之','劉禹錫','唐','唐诗','tang','','[]','故人博羅尉，遺我山薑花。',120,'全唐诗/poet.tang.18000.json','["故人博羅尉，遺我山薑花。", "採從碧海上，來自謫仙家。", "雲濤潤孤根，陰火照晨葩。", "靜搖扶桑日，豔對瀛洲霞。", "世人愛芳辛，搴擷忘幽遐。", "傳名入帝里，飛驛辭天涯。", "王濟本尚味，石崇方鬬奢。", "雕盤多不識，綺席乃增華。", "驛馬損筋骨，貴人滋齒牙。", "顧予藜藿士，持此重咨嗟。"]'),
('e5f6df2d-9c5b-460c-985c-c4f6513b40a9','途中早發','劉禹錫','唐','唐诗','tang','','[]','馬踏塵上霜，月明江頭路。',48,'全唐诗/poet.tang.18000.json','["馬踏塵上霜，月明江頭路。", "行人朝氣銳，宿鳥相辭去。", "流水隔遠村，縵山多紅樹。", "悠悠關塞內，往來無閑步。"]'),
('0f60d494-257c-43bf-b877-9088019bea69','和董庶中古散調詞贈尹果毅','劉禹錫','唐','唐诗','tang','','[]','昔聽東武吟，壯年心已悲。',288,'全唐诗/poet.tang.18000.json','["昔聽東武吟，壯年心已悲。", "如何今濩落，聞君辛苦辭。", "言有窮巷士，弱齡頗尚奇。", "讀得玄女符，生當事邊時。", "借名遊俠窟，結客幽幷兒。", "往來長楸間，能帶雙鞬馳。", "崩騰天寶末，塵暗燕南垂。", "爟火入咸陽，詔徵神武師。", "是時占軍幕，插羽揚金羈。", "萬夫列轅門，觀射中戟支。", "誓當雪國讐，親愛從此辭。", "中宵倚長劒，起視蚩尤旗。", "介馬晨蕭蕭，陣雲竟天涯。", "陰風獵白草，旗槊光參差。", "勇氣貫中腸，視身忽如遺。", "生擒白馬將，虜騎不敢追。", "貴臣上戰功，名姓隨意移。", "終歲肌骨苦，他人印纍纍。", "謁者既清宮，諸侯各罷戲。", "上將賜甲第，門戟不可窺。", "眥血下沾襟，天高問無期。", "却尋故鄉路，孤影空相隨。", "行逢里中舊，撲遬昔所嗤。", "一言合侯王，腰佩黃金龜。"]'),
('cf28f023-f007-48ac-8e71-96c1cce3bf53','望衡山','劉禹錫','唐','唐诗','tang','','["\u8861\u5c71"]','東南倚蓋卑，維嶽資柱石。',48,'全唐诗/poet.tang.18000.json','["東南倚蓋卑，維嶽資柱石。", "前當祝融居，上拂朱鳥翮。", "青冥結精氣，磅礴宣地脉。", "還聞膚寸陰，能致彌天澤。"]'),
('4c57a579-0494-41cf-a174-6472ac4f2e8e','遊桃源一百韻','劉禹錫','唐','唐诗','tang','','[]','沅江清悠悠，連山鬱岑寂。',288,'全唐诗/poet.tang.18000.json','["沅江清悠悠，連山鬱岑寂。", "回流抱絕巘，皎鏡含虛碧。", "昏旦遞明媚，煙嵐分委積。", "香蔓垂綠潭，暴龍照孤磧。", "淵明著前志，子驥思遠蹠。", "寂寂無何鄉，密爾天地隔。", "金行太元歲，漁者偶探賾。", "尋花得幽踪，窺洞穿闇隙。", "依微聞雞犬，豁達值阡陌。", "居人互將迎，笑語如平昔。", "廣樂雖交奏，海禽心不懌。", "揮手一來歸，故溪無處覓。", "綿綿五百載，市朝幾遷革。", "有路在壺中，無人知地脉。", "皇家感至道，聖祚自天錫。", "金闕傳本枝，玉函留寶曆。", "禁山開秘宇，復戶潔靈宅。", "蘂檢香氛氳，醮壇煙冪冪。", "我來塵外躅，瑩若朝星析。", "崖轉對翠屏，水窮留畫鷁。", "三休俯喬木，千級扳峭壁。", "旭日聞撞鐘，綵雲迎躡屐。", "遂登最高頂，縱目還楚澤。", "平湖見草青，遠岸連霞赤。"]'),
('099d1af5-6cb8-4e04-b199-2c6a7b4fca72','客有爲余話登天壇遇雨之狀因以賦之','劉禹錫','唐','唐诗','tang','','[]','清晨登天壇，半路逢陰晦。',168,'全唐诗/poet.tang.18000.json','["清晨登天壇，半路逢陰晦。", "疾行穿雨過，却立視雲背。", "白日照其上，風雷走於內。", "滉瀁雪海翻，槎牙玉山碎。", "蛟龍露鬐鬣，神鬼含變態。", "萬狀互生滅，百音以繁會。", "俯觀羣動靜，始覺天宇大。", "山頂自晶明，人間已霶霈。", "豁然重昏歛，渙若春冰潰。", "反照入松門，瀑流飛縞帶。", "遙光泛物色，餘韻吟天籟。", "洞府撞仙鐘，村墟起夕靄。", "却見山下侶，已如迷世代。", "問我何處來，我來雲雨外。"]'),
('c2c99e3f-9661-4fff-a6fd-28a591ff7e68','秋江早發','劉禹錫','唐','唐诗','tang','','[]','輕陰迎曉日，霞霽秋江明。',96,'全唐诗/poet.tang.18000.json','["輕陰迎曉日，霞霽秋江明。", "草樹含遠思，襟懷有餘清。", "凝睇萬象起，郎吟孤憤平。", "渚鴻未矯翼，而我已遐征。", "因思市朝人，方聽晨雞鳴。", "昏昏戀衾枕，安見元氣英。", "納爽耳目變，玩奇筋骨輕。", "滄洲有奇趣，浩然吾將行。"]'),
('da9d7556-8296-4658-8f9f-d05ed47f75b9','有僧言羅浮事因爲詩以寫之','劉禹錫','唐','唐诗','tang','','[]','君言羅浮上，容易見九垠。',216,'全唐诗/poet.tang.18000.json','["君言羅浮上，容易見九垠。", "漸高元氣壯，洶湧來翼身。", "夜宿最高峰，瞻望浩無鄰。", "海黑天宇曠，星辰來逼人。", "是時當朏魄，陰物恣騰振。", "日光吐鯨背，劒影開龍鱗。", "倏若萬馬馳，旌旗聳奫淪。", "又如廣樂奏，金石含悲辛。", "疑其有巨靈，怪物盡來賓。", "陰陽迭用事，乃俾夜作晨。", "咿喔天雞鳴，扶桑色昕昕。", "赤波千萬里，湧出黃金輪。", "下視生物息，霏如隙中塵。", "醯雞仰甕口，亦謂雲漢津。", "世人信耳目，方寸度大鈞。", "安知視聽外，怪愕不可陳。", "悠悠想大方，此乃桮水濱。", "知小天地大，安能識其真。"]'),
('0fb04b5e-76d3-4734-92a3-64194ad4f47e','裴祭酒尚書見示春歸城南青松塢別墅寄王左丞高侍郎之什命同作','劉禹錫','唐','唐诗','tang','','[]','蚤宦閱人事，晚懷生道機。',168,'全唐诗/poet.tang.18000.json','["蚤宦閱人事，晚懷生道機。", "時從學省出，獨望郊園歸。", "野彴度春水，山花映巖扉。", "石頭解金章，林下步綠薇。", "青松鬱成塢，脩竹盈尺圍。", "吟風起天籟，蔽日無炎威。", "危徑盤羊腸，連甍聳翬飛。", "幽谷響樵斧，澄潭環釣磯。", "因高見帝城，冠蓋揚光輝。", "白雲難持寄，清韻投所希。", "二公如長離，比翼翔太微。", "含情謝林壑，酬贈駢珠璣。", "顧予久郎潛，愁寂對芳菲。", "一聞丘中趣，再撫黃金徽。"]'),
('401979bb-d903-4216-a5f4-a6ad30066367','和河南裴尹侍郎宿齋天平寺詣九龍祠祈雨二十韻','劉禹錫','唐','唐诗','tang','','[]','有事九龍廟，潔齋梵王祠。',240,'全唐诗/poet.tang.18000.json','["有事九龍廟，潔齋梵王祠。", "玉簫何時絕，碧樹空涼颸。", "吏散埃𡏖息，月高庭宇宜。", "重城肅穆閉，澗水潺湲時。", "人希夜復閑，慮靜境亦隨。", "緬懷斷鰲足，凝想乘鸞姿。", "朱明盛農節，膏澤方愆期。", "瞻言五靈瑞，能救百穀萎。", "咿喔晨雞鳴，闌干斗柄垂。", "修容謁神像，注意陳正詞。", "驚飆起泓泉，若調雷雨師。", "黑煙聳鱗甲，灑液如棼絲。", "豐隆震天衢，列缺揮火旗。", "炎空忽淒緊，高霤懸綆縻。", "生物已霶霈，濕雲稍離披。", "丹霞啓南陸，白水含東菑。", "熙熙飛走適，藹藹草樹滋。", "浮光動宮觀，遠思盈川坻。", "吳公敏於政，謝守工爲詩。", "商山有病客，言賀舒龐眉。"]'),
('26f8cc2d-235a-4544-a87c-c8caee8665f8','冬夜宴河中李相公中堂命箏歌送酒','劉禹錫','唐','唐诗','tang','','[]','朗朗鵾雞弦，華堂夜多思。',48,'全唐诗/poet.tang.18000.json','["朗朗鵾雞弦，華堂夜多思。", "簾外雪已深，座中人半醉。", "翠蛾發清響，曲盡有餘意。", "酌我莫憂狂，老來無逸氣。"]'),
('310818b1-54a0-4da1-9d20-bd1e3264d10a','重至衡陽傷柳儀曹','劉禹錫','唐','唐诗','tang','','[]','憶昨與故人，湘江岸頭別。',48,'全唐诗/poet.tang.18000.json','["憶昨與故人，湘江岸頭別。", "我馬映林嘶，君帆轉山滅。", "馬嘶循古道，帆滅如流電。", "千里江蘺春，故人今不見。"]'),
('c172a642-3aa3-4760-a26a-0c85ad9d5a0e','謫居悼往二首 一','劉禹錫','唐','唐诗','tang','','[]','邑邑何邑邑，長沙地卑濕。',48,'全唐诗/poet.tang.18000.json','["邑邑何邑邑，長沙地卑濕。", "樓上見春多，花前恨風急。", "猿愁腸斷呌，鶴病翹趾立。", "牛衣獨自眠，誰哀仲卿泣。"]'),
('e005f7b5-b3ad-45de-90a8-4b78085e47cf','謫居悼往二首 二','劉禹錫','唐','唐诗','tang','','[]','鬱鬱何鬱鬱，長安遠如日。',48,'全唐诗/poet.tang.18000.json','["鬱鬱何鬱鬱，長安遠如日。", "終日念鄉關，燕來鴻復還。", "潘岳歲寒思，屈平顦顇顏。", "殷勤望歸路，無雨即登山。"]'),
('f22f1d6b-e5b0-402e-8c3a-16555badf9b7','有獺吟','劉禹錫','唐','唐诗','tang','','[]','有獺得嘉魚，自謂天見憐。',158,'全唐诗/poet.tang.18000.json','["有獺得嘉魚，自謂天見憐。", "先祭不敢食，捧鱗望青玄。", "人立寒沙上，心專眼悁悁。", "漁翁以爲妖，舉塊投其咽。", "呼兒貫魚歸，與獺同烹煎。", "關關黃金鶚，大[翅]搖江煙。", "下見盈尋魚，投身擘洪連。", "攫拏隱鱗去，哺雛林岳巔。", "鴟烏欲伺隙，遙噪莫敢前。", "長居青雲路，彈射無由緣。", "何地無江湖，何水無鮪鱣。", "天意不宰割，菲祭徒虔虔。", "空餘知禮重，載在淹中篇。"]'),
('71c65693-2472-41bb-ab62-dc408ae1de65','白太守行','劉禹錫','唐','唐诗','tang','','[]','聞有白太守，拋官歸舊谿。',96,'全唐诗/poet.tang.18000.json','["聞有白太守，拋官歸舊谿。", "蘇州十萬戶，盡作嬰兒啼。", "太守駐行舟，閶門草萋萋。", "揮袂謝啼者，依然兩眉低。", "朱戶非不崇，我心如重狴。", "華池非不清，意在寥廓栖。", "夸者竊所怪，賢者默思齊。", "我爲太守行，題在隱起珪。"]'),
('e5fc05cc-5bc0-4a5c-9008-687fe9b413c7','樂天寄洛下新詩兼喜微之欲到因以抒懷也','劉禹錫','唐','唐诗','tang','','[]','松間風未起，萬葉不自吟。',96,'全唐诗/poet.tang.18000.json','["松間風未起，萬葉不自吟。", "池上月未來，清輝同夕陰。", "宮徵不獨運，塤篪自相尋。", "一從別樂天，詩思日已沈。", "吟君洛中作，精絕百鍊金。", "乃知孤鶴情，月露爲知音。", "微之從東來，威鳳鳴歸林。", "羨君先相見，一豁平生心。"]'),
('3560e744-2c02-4f0c-b419-d665be2c9eff','月夜憶樂天兼寄微之','劉禹錫','唐','唐诗','tang','','[]','今宵帝城月，一望雪相似。',48,'全唐诗/poet.tang.18000.json','["今宵帝城月，一望雪相似。", "遙想洛陽城，清光正如此。", "知君當此夕，亦望鏡湖水。", "展轉相憶心，月明千萬里。"]'),
('ea84ab89-235d-47bb-a079-054a4155ed71','早夏郡中書事','劉禹錫','唐','唐诗','tang','','[]','水禽渡殘月，飛雨灑高城。',96,'全唐诗/poet.tang.18000.json','["水禽渡殘月，飛雨灑高城。", "華堂對嘉樹，簾廡含曉清。", "拂鏡整危冠，振衣步前楹。", "將吏儼成列，簿書紛來縈。", "言下辨曲直，筆端破交爭。", "虛懷詢病苦，懷律操剽輕。", "閽吏告無事，歸來解簪纓。", "高簾覆朱閣，忽爾聞調笙。"]'),
('ef112fc7-86a9-4f07-a14c-495af494e2a8','詶樂天七月一日夜即事見寄','劉禹錫','唐','唐诗','tang','','[]','夜樹風韻清，天河雲彩輕。',72,'全唐诗/poet.tang.18000.json','["夜樹風韻清，天河雲彩輕。", "故苑多露草，隔城聞鶴鳴。", "搖落從此始，別離含遠情。", "聞君當是夕，倚瑟吟商聲。", "外物豈不足，中懷向誰傾。", "秋來念歸去，同聽嵩陽笙。"]'),
('d3c3df89-405e-427d-8e67-d2c854c9bb9e','令狐相公見示贈竹二十韻仍命繼和','劉禹錫','唐','唐诗','tang','','[]','高人必愛竹，寄興良有以。',240,'全唐诗/poet.tang.18000.json','["高人必愛竹，寄興良有以。", "峻節可臨戎，虛心宜待士。", "衆芳信妍媚，威鳳難棲止。", "遂於鼙鼓間，移植東南美。", "封以梁國土，澆之浚泉水。", "得地色不移，凌空勢方起。", "新青排故葉，餘粉籠疎理。", "猶復隔牆藩，何因出塵滓。", "茲辰去前蔽，永日勞瞪視。", "槭槭林已成，熒熒玉相似。", "規摹起心匠，洗滌在頤指。", "曲直既瞭然，孤高何卓爾。", "垂梢覆內屏，迸笋侵前戺。", "妓席拂雲鬢，賓階蔭珠履。", "抱琴恣閑翫，執卷堪斜倚。", "露下懸明璫，風來韻清徵。", "堅貞貫四候，標格殊百卉。", "歲晚當自知，繁華豈云比。", "古詩無贈竹，高唱從此始。", "一聽清瑤音，崢然長在耳。"]'),
('9f93b8d3-e1c7-4de4-a55b-c203873beb6f','和令狐相公晚泛漢江書懷寄洋州崔侍郎閬州高舍人二曹長','劉禹錫','唐','唐诗','tang','','[]','雨過遠山出，江澄暮霞生。',120,'全唐诗/poet.tang.18000.json','["雨過遠山出，江澄暮霞生。", "因浮濟川舟，遂作適野行。", "郊樹映緹騎，水禽避紅旌。", "田夫捐畚鍤，織婦窺柴荆。", "古岸夏花發，遙林晚蟬清。", "沿洄方翫境，鼓角已登城。", "部內有良牧，望中寄深情。", "臨觴念佳期，泛瑟動離聲。", "寂寞一病士，夙昔接羣英。", "多謝謫仙侶，幾時還玉京。"]'),
('e2bbf79c-32ad-47f9-83a8-c5fdb3c7d3c7','和樂天洛城春齊梁體八韻','劉禹錫','唐','唐诗','tang','','[]','帝城宜春入，遊人喜意長。',96,'全唐诗/poet.tang.18000.json','["帝城宜春入，遊人喜意長。", "草生季倫谷，花出莫愁坊。", "斷雲發山色，輕風漾水光。", "樓前戲馬地，樹下鬬雞場。", "白頭自爲侶，綠酒亦滿觴。", "潘園觀種植，謝墅閱池塘。", "至閑似隱逸，過老不悲傷。", "相問焉功德，銀黃遊故鄉。"]'),
('1c570244-3e71-484b-86a7-d6ed74378cc3','洛中早春贈樂天','劉禹錫','唐','唐诗','tang','','[]','漠漠復靄靄，半晴將半陰。',84,'全唐诗/poet.tang.18000.json','["漠漠復靄靄，半晴將半陰。", "春來自何處，無迹日以深。", "韶嫩冰後木，輕盈煙際林。", "藤生欲有託，柳弱不自任。", "花意已含蓄，鳥言尚沈吟。", "期君當此時，與我恣追尋。", "翻愁爛熳後，春暮却傷心。"]'),
('5753f4b7-f085-4a30-8698-f3ae049f655d','和樂天讌李周美中丞宅池上賞櫻桃花','劉禹錫','唐','唐诗','tang','','[]','櫻桃千萬枝，照耀如雪天。',72,'全唐诗/poet.tang.18000.json','["櫻桃千萬枝，照耀如雪天。", "王孫讌其下，隔水疑神仙。", "宿露發清香，初陽動暄妍。", "妖姬滿髻插，酒客折枝傳。", "同此賞芳月，幾人有華筵。", "杯行勿遽辭，好醉逸三年。"]'),
('afe72329-d8ba-4812-aed2-0cac0af992ef','詶樂天聞新蟬見贈','劉禹錫','唐','唐诗','tang','','[]','碧樹鳴蟬後，煙雲改容光。',84,'全唐诗/poet.tang.18000.json','["碧樹鳴蟬後，煙雲改容光。", "瑟然引秋氣，芳草日夜黃。", "夾道喧古槐，臨池思垂楊。", "離人下憶淚，志士激剛腸。", "昔聞阻山川，今聽同匡牀。", "人情便所遇，音韻豈殊常。", "因之比笙竽，送我遊醉鄉。"]'),
('42a626db-68ab-4a41-8e85-f4d9f6cf7d94','和樂天秋涼閑臥','劉禹錫','唐','唐诗','tang','','[]','暑退人體輕，雨餘天色改。',48,'全唐诗/poet.tang.18000.json','["暑退人體輕，雨餘天色改。", "荷珠貫索斷，竹粉殘粧在。", "高僧掃室請，逸客登樓待。", "槐柳漸蕭疎，閑門少光彩。"]'),
('d90bc824-730a-4fb6-b910-28f4ad514141','詶樂天詠老見示','劉禹錫','唐','唐诗','tang','','["\u52b1\u5fd7"]','人誰不願老，老去有誰憐。',72,'全唐诗/poet.tang.18000.json','["人誰不願老，老去有誰憐。", "身瘦帶頻減，髪稀冠自偏。", "廢書緣惜眼，多炙爲隨年。", "經事還諳事，閱人如閱川。", "細思皆幸矣，下此便翛然。", "莫道桑榆晚，微霞尚滿天。"]'),
('e605a143-612c-4801-b1be-88601c88c648','歲夜詠懷','劉禹錫','唐','唐诗','tang','','["\u611f\u4f24", "\u6292\u6000", "\u6625\u8282"]','彌年不得意，新歲又如何。',48,'全唐诗/poet.tang.18000.json','["彌年不得意，新歲又如何。", "念昔同遊者，而今有幾多。", "以閑爲自在，將壽補蹉跎。", "春色無情故，幽居亦見過。"]'),
('0e29869e-9dda-4b25-a5f4-70496a04ac9e','詶牛相公獨飲偶醉寓言見示','劉禹錫','唐','唐诗','tang','','[]','宮漏夜丁丁，千門閉霜月。',72,'全唐诗/poet.tang.18000.json','["宮漏夜丁丁，千門閉霜月。", "華堂列紅燭，絲管靜中發。", "歌眉低有思，舞體輕無骨。", "主人啓酡顏，酣暢浹肌髪。", "猶思城外客，阡陌不可越。", "春意日夕深，此歡無斷絕。"]'),
('b334891f-03ed-4411-b8a5-206cfe5b60fa','萋兮吟','劉禹錫','唐','唐诗','tang','','[]','天涯浮雲生，爭蔽日月光。',72,'全唐诗/poet.tang.18000.json','["天涯浮雲生，爭蔽日月光。", "窮巷秋風起，先摧蘭蕙芳。", "萬貨列旗亭，恣心注明璫。", "名高毀所集，言巧智難防。", "勿謂行大道，斯須成太行。", "莫吟萋兮什，徒使君子傷。"]'),
('796c677d-66cc-47e2-886a-8cacb408f3ac','韓十八侍御見示岳陽樓別竇司直詩因令屬和重以自述故足成六十二韻','劉禹錫','唐','唐诗','tang','','["\u5cb3\u9633\u697c"]','楚望何蒼然，曾瀾七百里。',288,'全唐诗/poet.tang.18000.json','["楚望何蒼然，曾瀾七百里。", "孤城寄遠目，一寫無窮已。", "蕩漾浮天蓋，四環宣地理。", "積漲在三秋，混成非一水。", "冬遊見清淺，春望多洲沚。", "雲錦遠沙明，風煙青草靡。", "火星忽南見，月硤方東迤。", "雪波西山來，隱若長城起。", "獨專朝宗路，駛悍不可止。", "支川讓其威，蓄縮至南委。", "熊武走蠻落，瀟湘來奧鄙。", "炎蒸動泉源，積潦搜山趾。", "歸往無旦夕，包含通遠邇。", "行當白露時，眇視秋光裏。", "曙色未昭晰，露華遙斐舋。", "浩爾神骨清，如觀混元始。", "北風忽震盪，驚浪迷津涘。", "怒激鼓鏗訇，蹙成山巋硊。", "鵾鵬疑變化，罔象何恢詭。", "噓吸寫樓臺，騰驤露鬐尾。", "景移羣動息，波靜繁音弭。", "明月出中央，青天絕纖滓。", "素光淡無際，綠靜平如砥。", "空影渡鵷鴻，秋聲思蘆葦。"]'),
('2d658e8a-d266-4733-b8fe-acad101db2ad','和郴州楊侍郎翫郡齋紫薇花十四韻','劉禹錫','唐','唐诗','tang','','[]','幾年丹霄上，出入金華省。',170,'全唐诗/poet.tang.18000.json','["幾年丹霄上，出入金華省。", "暫別萬年枝，看花桂陽嶺。", "南方足奇樹，公府成佳境。", "綠陰交廣除，明豔透蕭屏。", "雨餘人吏散，燕語簾櫳靜。", "懿此含曉芳，翛然忘簿領。", "紫茸垂組縷，金[縷]攢鋒頴。", "露溽暗傳香，風輕徐就影。", "苒弱多意思，從容占光景。", "得地在侯家，移根近仙井。", "開尊好凝睇，倚瑟仍回頸。", "遊蜂駐綵冠，舞鶴迷煙頂。", "興生紅藥後，愛與甘棠並。", "不學夭桃姿，浮榮在俄頃。"]'),
('116dc987-3391-4e82-a01e-c452ee2ee523','春日寄楊八唐州二首 一','劉禹錫','唐','唐诗','tang','','[]','淮西春草長，淮水逶迤光。',36,'全唐诗/poet.tang.18000.json','["淮西春草長，淮水逶迤光。", "燕入新村落，人耕舊戰場。", "可憐行春守，立馬看斜桑。"]'),
('0933c1a1-20b9-4f6a-b8df-20435c9f52ad','春日寄楊八唐州二首 二','劉禹錫','唐','唐诗','tang','','[]','漠漠淮上春，莠苗生故壘。',36,'全唐诗/poet.tang.18000.json','["漠漠淮上春，莠苗生故壘。", "梨花方城路，荻笋蕭陂水。", "高齋有謫仙，坐嘯清風起。"]'),
('0444cedd-91f3-4952-9da9-b407658b5708','詶馮十七舍人宿衛贈別五韻','劉禹錫','唐','唐诗','tang','','[]','少年爲別日，隋宮楊柳陰。',60,'全唐诗/poet.tang.18000.json','["少年爲別日，隋宮楊柳陰。", "白首相逢處，巴江煙浪深。", "使星上三蜀，春雨霑衣襟。", "王程促速意，夜語殷勤心。", "却歸天上去，遺我雲間音。"]'),
('dbe87938-659f-4a87-b641-6fb3c0d5c956','詶湖州崔郎中見寄','劉禹錫','唐','唐诗','tang','','[]','風箏吟秋空，不肖指爪聲。',96,'全唐诗/poet.tang.18000.json','["風箏吟秋空，不肖指爪聲。", "高人靈府間，律呂伴咸英。", "昔年與兄遊，文似馬長卿。", "今來寄新詩，乃類陶淵明。", "磨礱老益智，吟詠閑彌精。", "豈非山水鄉，蕩漾神機清。", "渚煙蕙蘭動，溪雨虹蜺生。", "馮君虛上舍，待余乘興行。"]'),
('32355410-2319-4233-a69d-32f7a397a1df','秋日書懷寄河南王尹','劉禹錫','唐','唐诗','tang','','[]','公府想無事，西池秋水清。',48,'全唐诗/poet.tang.18000.json','["公府想無事，西池秋水清。", "去年爲狎客，永日奉高情。", "況有臺上月，如聞雲外笙。", "不知桑落酒，今歲與誰傾。"]'),
('38247dd3-e47b-4bbd-8763-e6e9da70062d','詶留守牛相公宮城早秋寓言見寄','劉禹錫','唐','唐诗','tang','','[]','曉月映宮樹，秋光起天津。',72,'全唐诗/poet.tang.18000.json','["曉月映宮樹，秋光起天津。", "涼風稍動葉，宿露未生塵。", "星氣尚芳麗，曠望感心神。", "揮毫成逸韻，開閤遲來賓。", "擺去將相印，漸爲逍遙身。", "如招後房宴，却要白頭人。"]'),
('5132c354-4f96-49e3-ba14-6a5a4da489ac','海陽十詠 吏隱亭','劉禹錫','唐','唐诗','tang','','[]','結構得奇勢，朱門交碧潯。',48,'全唐诗/poet.tang.18000.json','["結構得奇勢，朱門交碧潯。", "外來始一望，寫盡平生心。", "日軒漾波影，月砌鏤松陰。", "幾度欲歸去，回眸情更深。"]'),
('e995682a-7dd4-4ea8-8fe7-3436cb13581e','海陽十詠 切雲亭','劉禹錫','唐','唐诗','tang','','[]','逈破林煙出，俯窺石潭空。',48,'全唐诗/poet.tang.18000.json','["逈破林煙出，俯窺石潭空。", "波搖杏梁日，松韻碧窻風。", "隔水生別島，帶橋如斷虹。", "九疑南面事，盡入寸眸中。"]'),
('9283ad0c-0911-451f-8d27-771a345aa31f','海陽十詠 雲英潭','劉禹錫','唐','唐诗','tang','','[]','芳幄覆雲屏，石奩開碧鏡。',48,'全唐诗/poet.tang.18000.json','["芳幄覆雲屏，石奩開碧鏡。", "支流日飛灑，深處自疑瑩。", "潛去不見跡，清音常滿聽。", "有時病朝酲，來此心神醒。"]'),
('1008ad9b-afc3-47c8-9627-74cf7dcbae7a','海陽十詠 玄覽亭','劉禹錫','唐','唐诗','tang','','[]','瀟灑青林際，夤緣碧潭隈。',48,'全唐诗/poet.tang.18000.json','["瀟灑青林際，夤緣碧潭隈。", "淙流冒石下，輕波觸砌回。", "香風逼人度，幽花覆水開。", "故令無四壁，晴夜月光來。"]'),
('e173ac3f-ed84-41ad-b98d-586121353591','海陽十詠 裴溪','劉禹錫','唐','唐诗','tang','','[]','楚客憶關中，疏溪想汾水。',48,'全唐诗/poet.tang.18000.json','["楚客憶關中，疏溪想汾水。", "縈紆非一曲，意態如千里。", "倒影羅文動，微波笑顏起。", "君今賜環歸，何人承玉趾。"]'),
('4f7ea5ae-988e-4851-9346-a52c1278ed46','海陽十詠 飛練瀑','劉禹錫','唐','唐诗','tang','','[]','晶晶擲巖端，潔光如可把。',48,'全唐诗/poet.tang.18000.json','["晶晶擲巖端，潔光如可把。", "瓊枝曲不折，雲片晴猶下。", "石堅激清響，葉動承餘灑。", "前時明月中，見是銀河瀉。"]'),
('6fc46f47-97b2-4291-934b-ad1e5bffbd6a','海陽十詠 蒙池','劉禹錫','唐','唐诗','tang','','[]','瀠渟幽壁下，深淨如無力。',48,'全唐诗/poet.tang.18000.json','["瀠渟幽壁下，深淨如無力。", "風起不成文，月來同一色。", "地靈草木瘦，人遠煙霞逼。", "往往疑列仙，圍碁在巖側。"]'),
('260cc902-f037-49ce-8380-2d7ce420cdb2','海陽十詠 棼絲瀑','劉禹錫','唐','唐诗','tang','','[]','飛流透嵌隙，噴灑如絲棼。',48,'全唐诗/poet.tang.18000.json','["飛流透嵌隙，噴灑如絲棼。", "含暈迎初旭，翻光破夕曛。", "餘波遶石去，碎響隔溪聞。", "却望瓊沙際，逶迤見脉分。"]'),
('19b859e2-431b-4171-9221-99eabfd4068e','海陽十詠 雙溪','劉禹錫','唐','唐诗','tang','','[]','流水遶雙島，碧溪相並深。',48,'全唐诗/poet.tang.18000.json','["流水遶雙島，碧溪相並深。", "浮花擁曲處，遠影落中心。", "閑鷺久獨立，曝龜驚復沈。", "蘋風有時起，滿谷簫韶音。"]'),
('b5a4af38-32a5-4e3a-af05-bfa38302f854','海陽十詠 月窟','劉禹錫','唐','唐诗','tang','','[]','濺濺漱幽石，注入團圓處。',48,'全唐诗/poet.tang.18000.json','["濺濺漱幽石，注入團圓處。", "有如常滿杯，承彼清夜露。", "巖曲月斜照，林寒春晚煦。", "遊人不敢觸，恐有蛟龍護。"]'),
('0c26d1f0-4543-4b5b-a456-32639a1c73b2','武夫詞','劉禹錫','唐','唐诗','tang','','[]','武夫何洸洸，衣紫襲絳裳。',108,'全唐诗/poet.tang.18000.json','["武夫何洸洸，衣紫襲絳裳。", "借問胡爲爾，列校在鷹揚。", "依倚將軍勢，交結少年場。", "探丸害公吏，抽刃妒名倡。", "家產既不事，顧盼自生光。", "酣歌高樓上，袒裼大道傍。", "昔爲編戶人，秉耒甘哺糠。", "今來從軍樂，躍馬飫膏粱。", "猶思風塵起，無種取侯王。"]'),
('9a8bee71-a907-43c9-9b7c-9b575df2cac3','虎丘寺路宴','劉禹錫','唐','唐诗','tang','','[]','青林虎丘寺，林際翠微路。',144,'全唐诗/poet.tang.18000.json','["青林虎丘寺，林際翠微路。", "立見山僧來，遙從鳥飛處。", "茲峰淪寶玉，千載惟丘墓。", "埋劒人空傳，鑿山龍已去。", "捫蘿披翳薈，路轉夕陰遽。", "虎嘯崖谷寒，猿鳴松杉暮。", "徘徊北樓上，海江窮一顧。", "日映千里帆，鴉歸萬家樹。", "暫因愜所適，果得捐外慮。", "庭暗棲還雲，簷香滴甘露。", "久迷空寂理，多爲聲華故。", "永欲投此山，餘生豈能悞。"]'),
('08e7ade0-3403-406e-9d74-679e48d898c7','缺題','劉禹錫','唐','唐诗','tang','','[]','故人日已遠，窻下塵滿琴。',48,'全唐诗/poet.tang.18000.json','["故人日已遠，窻下塵滿琴。", "坐對一撙酒，恨多無力斟。", "幕疎螢色逈，露重月華深。", "萬境與羣籟，此時情豈任。"]'),
('1209f202-5321-4254-91ca-4477d547cfa2','晚步揚子游南塘望沙尾','劉禹錫','唐','唐诗','tang','','[]','淮海多夏雨，曉來天始晴。',108,'全唐诗/poet.tang.18000.json','["淮海多夏雨，曉來天始晴。", "蕭條長風至，千里孤雲生。", "卑濕久喧濁，搴開偶虛清。", "客遊廣陵郡，晚出臨江城。", "郊外綠楊陰，江中沙嶼明。", "歸帆翳盡日，去櫂聞遺聲。", "鄉國殊渺漫，羈心目懸旌。", "悠然京華意，悵望懷遠程。", "薄暮大山上，翩翩雙鳥征。"]'),
('08a8ab7b-fb84-4a05-8b4e-177f2728bdbf','和浙西李大夫晚下北固山喜徑松成陰悵然懷古偶題臨江亭幷浙東元相公所和依本韻','劉禹錫','唐','唐诗','tang','','[]','一辭溫室樹，幾見武昌柳。',240,'全唐诗/poet.tang.18000.json','["一辭溫室樹，幾見武昌柳。", "荀謝年何少，韋平望已久。", "種松夾石道，紆組臨沙阜。", "目覽帝王州，心存股肱守。", "葉動驚綵翰，波澄見頳首。", "晉宋齊梁都，千山萬江口。", "煙散隋宮出，濤來海門吼。", "風俗太伯餘，衣冠永嘉後。", "江長天作限，山固壤無朽。", "自古稱佳麗，非賢誰奄有。", "八元邦族盛，萬石門風厚。", "天柱揭東溟，文星照北斗。", "高亭一騁望，舉酒共爲壽。", "因賦詠懷詩，遠寄同心友。", "禁中晨夜直，江左東西偶。", "將手握兵符，儒腰盤貴綬。", "頒條風有自，立事言無苟。", "農野聞讓耕，軍人不使酒。", "用材當構廈，知道寧窺牖。", "誰謂青雲高，鵬飛終背負。"]'),
('d50762ec-f4d1-4b75-bc09-a29d6ff59ccc','始至雲安寄兵部韓侍郎中書白舍人二公近曾遠守故有屬焉','劉禹錫','唐','唐诗','tang','','[]','天外巴子國，山頭白帝城。',146,'全唐诗/poet.tang.18000.json','["天外巴子國，山頭白帝城。", "波清蜀[柹]盡，雲散楚臺傾。", "迅瀨下哮吼，兩岸勢爭衡。", "陰風鬼神過，暴雨蛟龍生。", "硤斷見孤邑，江流照飛甍。", "蠻軍擊嚴鼓，笮馬引雙旌。", "望闕遙拜舞，分庭備將迎。", "銅符一以合，文墨紛來縈。", "暮色四山起，愁猿數處聲。", "重關羣吏散，靜視寒燈明。", "故人青霞意，飛舞集蓬瀛。", "昔曾在池籞，應知魚鳥情。"]'),
('ee4d3074-c68a-4d86-9bef-b59cf2eb5c18','更衣曲','劉禹錫','唐','唐诗','tang','','["\u5bab\u5ef7", "\u751f\u6d3b", "\u4e50\u5e9c", "\u65b0\u4e50\u5e9c\u8f9e"]','博山炯炯吐香霧，紅燭引至更衣處。',64,'全唐诗/poet.tang.18000.json','["博山炯炯吐香霧，紅燭引至更衣處。", "夜如何其夜漫漫，鄰雞未鳴寒雁度。", "庭前雪壓松桂叢，廊下點點懸紗籠。", "滿堂醉客爭笑語，嘈囋琵琶青幕中。"]'),
('9a85b1aa-f7e3-46c6-9d47-c032a38ee885','桃源行','劉禹錫','唐','唐诗','tang','','[]','漁舟何招招，浮在武陵水。',204,'全唐诗/poet.tang.18000.json','["漁舟何招招，浮在武陵水。", "拖綸擲餌信流去，誤入桃源行數里。", "清源尋盡花綿綿，踏花覓徑至洞前。", "洞門蒼黑煙霧生，暗行數步逢虛明。", "俗人毛骨驚仙子，爭來致詞何至此。", "須臾皆破冰雪顏，笑言委曲問人間。", "因嗟隱身來種玉，不知人世如風燭。", "筵羞石髓勸客餐，燈爇松脂留客宿。", "雞聲犬聲遙相聞，曉色葱蘢開五雲。", "漁人振衣起出戶，滿庭無路花紛紛。", "翻然恐失鄉懸處，一息不肯桃源住。", "桃花滿溪水似鏡，塵心如垢洗不去。", "仙家一出尋無踪，至今流水山重重。"]'),
('039f4ee1-4354-458d-975a-53f6c9d98bd9','洞庭秋月行','劉禹錫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','洞庭秋月生湖心，層波萬頃如鎔金。',160,'全唐诗/poet.tang.18000.json','["洞庭秋月生湖心，層波萬頃如鎔金。", "孤輪徐轉光不定，遊氣濛濛隔寒鏡。", "是時白露三秋中，湖平月上天地空。", "岳陽樓頭暮角絕，蕩漾已過君山東。", "山城蒼蒼夜寂寂，水月逶迤繞城白。", "蕩槳巴童歌竹枝，連檣估客吹羗笛。", "勢高夜久陰力全，金氣肅肅開星躔。", "浮雲野馬歸四裔，遙望星斗當中天。", "天雞相呼曙霞出，歛影含光讓朝日。", "日出喧喧人不閑，夜來清景非人間。"]'),
('e0db86e9-c5a7-4390-a016-22a26d44043a','九華山歌','劉禹錫','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','奇峰一見驚魂魄，意想洪罏始開闢。',179,'全唐诗/poet.tang.18000.json','["奇峰一見驚魂魄，意想洪罏始開闢。", "疑是九龍夭矯欲攀天，忽逢霹靂一聲化爲石。", "不然何至今，悠悠億萬年，氣勢不死如騰仚。", "雲含幽兮月添冷，月凝暉兮江漾影。", "結根不得要路津，逈秀長在無人境。", "軒皇封禪登雲亭，大禹會寄臨東溟。", "乘樏不來廣樂絕，獨與猨鳥愁青熒。", "君不見敬亭之山黃索漠，兀如斷岸無稜角。", "宣城謝守一首詩，遂使聲名齊五岳。", "九華山，九華山。", "自是造化一尤物，焉能籍甚乎人間。"]'),
('72463bb5-a9de-40d1-b41a-30d873fcf1f9','泰娘歌','劉禹錫','唐','唐诗','tang','','[]','泰娘家本閶門西，門前綠水環金隄。',305,'全唐诗/poet.tang.18000.json','["泰娘家本閶門西，門前綠水環金隄。", "有時妝成好天氣，走上臯橋折花戲。", "風流太守韋尚書，路傍忽見停隼旟。", "斗量明珠鳥傳意，紺幰迎入專城居。", "長鬟如雲衣似霧，錦茵羅薦承輕步。", "舞學驚鴻水榭春，歌傳上客蘭堂暮。", "從郎西入帝城中，貴遊簪組香簾櫳。", "低鬟緩視抱明月，纖指破拔生胡風。", "繁華一旦有消歇，題劍無光履聲絕。", "洛陽舊宅生草萊，杜陵蕭蕭松柏哀。", "妝奩蟲網厚如繭，博山爐側傾寒灰。", "蘄州刺史張公子，白馬新到銅駝里。", "自言買笑擲黃金，月墮雲中從此始。", "安知鵩鳥座隅飛，寂寞旅魂招不歸。", "秦嘉鏡有前時結，韓壽香銷故篋衣。", "山城少人江水碧，斷鴈哀猨風雨夕。", "朱弦已絕爲知音，雲鬢未秋私自惜。", "舉目風煙非舊時，夢尋歸路鄉多參差。", "如何將此千行淚，更灑湘江斑竹枝。"]'),
('7b1e42d7-b559-4c0f-b568-b441d89b4d39','龍陽縣歌','劉禹錫','唐','唐诗','tang','','[]','縣門白日無塵土，百姓縣前挽魚罟。',64,'全唐诗/poet.tang.18000.json','["縣門白日無塵土，百姓縣前挽魚罟。", "主人引客登大隄，小兒縱觀黃犬怒。", "鷓鴣驚鳴繞籬落，橘柚垂芳照窗戶。", "沙平草綠見吏稀，寂歷斜陽照縣鼓。"]'),
('5bc37c7b-af6e-4a86-9d48-c558c25293a8','牆陰歌','劉禹錫','唐','唐诗','tang','','[]','白日左右浮天潢，朝晡影入東西牆。',112,'全唐诗/poet.tang.18000.json','["白日左右浮天潢，朝晡影入東西牆。", "昔爲兒童在陰戲，當時意小覺日長。", "東鄰侯家吹笙簧，隨陰促促移象牀。", "西鄰田舍乏糟糠，就影汲汲舂黃粱。", "因思九州四海外，家家只占牆陰內。", "莫言牆陰數尺間，老却主人如等閑。", "君看眼前光陰促，中心莫學太行山。"]'),
('9eb8766b-62b4-4026-b369-781c37d63957','踏潮歌','劉禹錫','唐','唐诗','tang','','[]','屯門積日無回飆，滄波不歸成踏潮。',144,'全唐诗/poet.tang.18000.json','["屯門積日無回飆，滄波不歸成踏潮。", "轟如鞭矻石且搖，亘空欲駕黿鼉橋。", "驚湍蹙縮悍而驕，大陵高岸失岧嶤。", "四邊無阻音響調，背負元氣掀重霄。", "介鯨得性方逍遙，仰鼻噓吸揚朱翹。", "海人狂顧迭相招，罽衣髽首聲嘵嘵。", "征南將軍登麗譙，赤旗指麾不敢囂。", "翌日風回沴氣消，歸濤納納景昭昭。", "烏泥白沙復滿海，海色不動如青瑤。"]'),
('2875908a-c8e1-4dc5-9048-625d430eb1a5','白鷺兒','劉禹錫','唐','唐诗','tang','','[]','白鷺兒，最高格。',48,'全唐诗/poet.tang.18000.json','["白鷺兒，最高格。", "毛衣新成雪不敵，衆禽喧呼獨凝寂。", "孤眠芊芊草，久立潺潺石。", "前山正無雲，飛去入遙碧。"]'),
('e0d148c2-0a75-4cf9-b3e7-e0532476db99','平齊行二首 一','劉禹錫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','胡塵昔起薊北門，河南地屬平盧軍。',192,'全唐诗/poet.tang.18000.json','["胡塵昔起薊北門，河南地屬平盧軍。", "貂裘代馬繞東岳，嶧陽孤桐削爲角。", "地形十二虜意驕，恩澤含容歷四朝。", "魯人皆解帶弓箭，齊人不復聞簫韶。", "今朝天子聖神武，手握玄符平九土。", "初哀狂童襲故事，文告不來方振怒。", "去秋詔下誅東平，官軍四合猶嬰城。", "春來羣烏噪且驚，氣如壞山墮其庭。", "牙門大將有劉生，夜半射落欃槍星。", "帳中虜血流滿地，門外三軍舞連臂。", "驛騎函首過黃河，城中無賊天氣和。", "朝廷侍郎來慰撫，耕夫滿野行人歌。"]'),
('bd285a68-be33-4ac0-b7ca-0dbd2b19b885','平齊行二首 二','劉禹錫','唐','唐诗','tang','','["\u6cf0\u5c71"]','泰山沈寇六十年，旅祭不享生愁煙。',128,'全唐诗/poet.tang.18000.json','["泰山沈寇六十年，旅祭不享生愁煙。", "今逢聖君欲封禪，神使陰兵來阻戰。", "妖氛掃盡河水清，日觀杲杲卿雲見。", "開元黃帝東封時，百神受職爭奔馳。", "千鈞猛簴順流下，洪波涵淡浮熊羆。", "侍臣燕公秉文筆，玉檢告天無媿詞。", "當今睿孫承聖祖，岳神望幸河宗舞。", "青門大道屬車塵，共待葳蕤翠華舉。"]'),
('73b23b38-fc4c-4aed-80ec-8da99789e13e','送裴處士應制舉詩','劉禹錫','唐','唐诗','tang','','[]','裴生久在風塵裏，氣勁言高少知己。',240,'全唐诗/poet.tang.18000.json','["裴生久在風塵裏，氣勁言高少知己。", "注書曾學鄭司農，歷國多於孔夫子。", "往年訪我到連州，無窮絕境終日遊。", "登山雨中試蠟屐，入洞夏裏披貂裘。", "白帝城邊又相遇，歛翼三年不飛去。", "忽然結束如秋蓬，自稱對策明光宮。", "人言策中說何事，掉頭不答看飛鴻。", "彤庭翠松迎曉日，鳳銜金榜雲間出。", "中貴腰鞭立傾酒，宰臣委佩觀搖筆。", "古稱射策如彎弧，一發偶中何時無。", "由來草澤無忌諱，努力滿挽當亨衢。", "憶得當年識君處，嘉禾驛後聯牆住。", "垂鉤釣得王餘魚，踏芳共登蘇小墓。", "此事今同夢想間，相看一笑且開顏。", "老大希逢舊鄰里，爲君扶病到方山。"]'),
('bf7821d0-4630-4e62-8462-c3e189277a4e','三鄉驛樓伏覩玄宗望女几山詩小臣斐然有感','劉禹錫','唐','唐诗','tang','','[]','開元天子萬事足，唯惜當時光景促。',64,'全唐诗/poet.tang.18000.json','["開元天子萬事足，唯惜當時光景促。", "三鄉陌上望仙山，歸作霓裳羽衣曲。", "仙心從此在瑤池，三清八景相追隨。", "天上忽乘白雲去，世間空有秋風詞。"]'),
('6aa0052e-eb21-4a5a-97d2-c90283c12aae','城西行','劉禹錫','唐','唐诗','tang','','[]','城西簇簇三叛族，叛者爲誰蔡吳蜀。',80,'全唐诗/poet.tang.18000.json','["城西簇簇三叛族，叛者爲誰蔡吳蜀。", "中使提刀出禁來，九衢車馬轟如雷。", "臨刑與酒杯未覆，讐家白官先請肉。", "守吏能然董卓臍，饑烏來覘桓玄目。", "城西人散泰階平，雨洗血痕春草生。"]'),
('944b70fa-7f5c-4558-b9e0-7b5688eaf601','武昌老人說笛歌','劉禹錫','唐','唐诗','tang','','["\u9ec4\u9e64\u697c"]','武昌老人七十餘，手把庾令相問書。',144,'全唐诗/poet.tang.18000.json','["武昌老人七十餘，手把庾令相問書。", "自言少小學吹笛，早事曹王曾賞激。", "往年鎮戍到蘄州，楚山蕭蕭笛竹秋。", "當時買材恣搜索，典却身上烏貂裘。", "古苔蒼蒼封老節，石上孤生飽風雪。", "商聲五音隨指發，水中龍應行雲絕。", "曾將黃鶴樓上吹，一聲占盡秋江月。", "如今老去語尤遲，音韻高低耳不知。", "氣力已微心尚在，時時一曲夢中吹。"]'),
('8aab2742-0f6f-4708-8db5-19a81dc35be1','西山蘭若試茶歌','劉禹錫','唐','唐诗','tang','','[]','山僧後檐茶數叢，春來映竹抽新茸。',208,'全唐诗/poet.tang.18000.json','["山僧後檐茶數叢，春來映竹抽新茸。", "宛然爲客振衣起，自傍芳叢摘鷹觜。", "斯須炒成滿室香，便酌砌下金沙水。", "驟雨松聲入鼎來，白雲滿盌花俳徊。", "悠揚噴鼻宿酲散，清峭徹骨煩襟開。", "陽崖陰嶺各殊氣，未若竹下莓苔地。", "炎帝雖嘗未解煎，桐君有籙那知味。", "新芽連拳半未舒，自摘至煎俄頃餘。", "木蘭霑露香微似，瑤草臨波色不如。", "僧言靈味宜幽寂，采采翹英爲嘉客。", "不辭緘封寄郡齋，甎井銅爐損標格。", "何況蒙山顧渚春，白泥赤印走風塵。", "欲知花乳清泠味，須是眠雲跂石人。"]'),
('acc05c3d-7f73-4966-9ef6-7893ba9d636a','聚蚊謠','劉禹錫','唐','唐诗','tang','','[]','沈沈夏夜蘭堂開，飛蚊伺暗聲如雷。',112,'全唐诗/poet.tang.18000.json','["沈沈夏夜蘭堂開，飛蚊伺暗聲如雷。", "嘈然歘起初駭聽，殷殷若自南山來。", "喧騰鼓舞喜昏黑，昧者不分聽者惑。", "露花滴瀝月上天，利觜迎人著不得。", "我軀七尺爾如芒，我孤爾衆能我傷。", "天生有時不可遏，爲爾設幄潛匡牀。", "清商一來秋日曉，羞爾微形飼丹鳥。"]'),
('b08422c8-4123-4327-a69e-32f21f2dce00','百舌吟','劉禹錫','唐','唐诗','tang','','[]','曉星寥落春雲低，初聞百舌間關啼。',176,'全唐诗/poet.tang.18000.json','["曉星寥落春雲低，初聞百舌間關啼。", "花樹滿空迷處所，搖動繁英墜紅雨。", "笙簧百囀音韻多，黃鸝吞聲燕無語。", "東方朝日遲遲升，迎風弄景如自矜。", "數聲不盡又飛去，何許相逢綠楊路。", "綿蠻宛轉似娛人，一心百舌何紛紛。", "酡顏俠少停歌聽，墜珥妖姬和睡聞。", "可憐光景何時盡，誰能低回避鷹隼。", "廷尉張羅自不關，潘郎挾彈無情損。", "天生羽族爾何微，舌端萬變乘春暉。", "南方朱鳥一朝見，索漠無言蒿下飛。"]'),
('06c80145-5ba1-4266-badf-d498cacff961','飛鳶操','劉禹錫','唐','唐诗','tang','','[]','鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。',192,'全唐诗/poet.tang.18000.json','["鳶飛杳杳青雲裏，鳶鳴蕭蕭風四起。", "旗尾飄揚勢漸高，箭頭砉劃聲相似。", "長空悠悠霽日懸，六翮不動凝風煙。", "遊鵾翔鴈出其下，慶雲清景相回旋。", "忽聞饑烏一噪聚，瞥下雲中爭腐鼠。", "騰音礪吻相喧呼，仰天大嚇疑鵷鶵。", "畏人避犬投高處，俛啄無聲猶屢顧。", "青鳥自愛玉山禾，仙禽徒貴華亭露。", "樸遬危巢向暮時，毰毸飽腹蹲枯枝。", "遊童挾彈一麾肘，臆碎羽分人不悲。", "天生衆禽各有類，威鳳文章在仁義。", "鷹隼儀形螻蟻心，雖能戾天何足貴。"]'),
('fa308cb2-c342-4a5f-a110-e48d22ba22e0','秋螢引','劉禹錫','唐','唐诗','tang','','[]','漢陵秦苑遙蒼蒼，陳根腐葉秋螢光。',192,'全唐诗/poet.tang.18000.json','["漢陵秦苑遙蒼蒼，陳根腐葉秋螢光。", "夜空寥寂金氣淨，千門九陌飛悠揚。", "紛綸暉映互明滅，金爐星噴鐙花發。", "露華洗濯清風吹，低昂不定招搖垂。", "高麗罘罳照蛛網，斜歷璇題舞羅幌。", "曝衣樓上拂香帬，承露臺前轉仙掌。", "槐市諸生夜讀書，北窗分明辨魯魚。", "行子東山起征思，中郎騎省悲秋氣。", "銅雀人歸自入簾，長門帳開來照淚。", "誰言向晦常自明，兒童走步嬌女爭。", "天生有光非自衒，遠近低昂暗中見。", "撮蚊妖鳥亦夜起，翅如車輪而已矣。"]'),
('37cb8473-c572-4fa0-95f2-dfc8ad04d1c8','傷秦姝行','劉禹錫','唐','唐诗','tang','','[]','長安二月花滿城，插花女兒彈銀箏。',290,'全唐诗/poet.tang.18000.json','["長安二月花滿城，插花女兒彈銀箏。", "南宮仙郎下朝晚，曲頭駐馬聞新聲。", "馬蹄逶遲心蕩漾，高樓已遠猶頻望。", "此時意重千金輕，鳥傳消息紺輪迎。", "芳筵銀燭一相見，淺笑低鬟初目成。", "蜀弦錚摐指如玉，皇帝弟子韋家曲。", "青牛文梓赤金簧，玫瑰寶柱秋鴈行。", "歛蛾收[袂]凝清光，抽弦緩調怨且長。", "八鸞鏘鏘渡銀漢，九雛威鳳鳴朝陽。", "曲終韻盡意不足，餘思悄絕愁空堂。", "從郎鎮南別城闕，樓船理曲瀟湘月。", "馮夷蹁躚舞淥波，鮫人出聽停綃梭。", "北池含煙瑤草短，萬松亭下清風滿。", "秦聲一曲此時聞，嶺泉嗚咽南雲斷。", "來自長陵小市東，蕣華零落瘴江風。", "侍兒掩泣收銀甲，鸚鵡不言愁玉籠。", "博山爐中香自滅，鏡奩塵暗同心結。", "從此東山非昔遊，長嗟人與弦俱絕。"]'),
('30704557-6ff6-482b-aa1d-b98e5295546f','競渡曲','劉禹錫','唐','唐诗','tang','','[]','沅江五月平堤流，邑人相將浮綵舟。',160,'全唐诗/poet.tang.18000.json','["沅江五月平堤流，邑人相將浮綵舟。", "靈均何年歌已矣，哀謠振檝從此起。", "楊桴擊節雷闐闐，亂流齊進聲轟然。", "蛟龍得雨鬐鬛動，螮蝀飲河形影聯。", "刺史臨流褰翠幃，揭竿命爵分雄雌。", "先鳴餘勇爭鼓舞，未至銜枚顏色沮。", "百勝本自有前期，一飛由來無定所。", "風俗如狂重此時，縱觀雲委江之湄。", "綵旂夾岸照蛟室，羅襪凌波呈水嬉。", "曲終人散空愁暮，招屈亭前水東注。"]'),
('c8fe387c-8c72-416e-9923-e72a07241a74','翰林白二十二學士見寄詩一百篇因以答貺','劉禹錫','唐','唐诗','tang','','[]','吟君遺我百篇詩，使我獨坐形神馳。',64,'全唐诗/poet.tang.18000.json','["吟君遺我百篇詩，使我獨坐形神馳。", "玉琴清夜人不語，琪樹春朝風正吹。", "郢人斤斵無痕跡，仙人衣裳棄刀尺。", "世人方內欲相尋，行盡四維無處覓。"]'),
('41bb21a6-136e-40c7-8a74-cd23630f8740','憶春草','劉禹錫','唐','唐诗','tang','','[]','憶春草，處處多情洛陽道。',92,'全唐诗/poet.tang.18000.json','["憶春草，處處多情洛陽道。", "金谷園中見日遲，銅駝陌上迎風早。", "河南大尹頻出難，只得池塘十步看。", "府門閉後滿街月，幾處遊人草頭歇。", "館娃宮外姑蘇臺，鬱鬱芊芊撥不開。", "無風自偃君知否，西子帬裾曾拂來。"]'),
('fe0ab8e8-3cda-465a-9bc6-bafd8c39ae39','樂天寄憶舊遊因作報白君以答','劉禹錫','唐','唐诗','tang','','[]','報白君，別來已渡江南春。',168,'全唐诗/poet.tang.18000.json','["報白君，別來已渡江南春。", "江南春色何處好，燕子雙飛故官道。", "春城三百七十橋，夾岸朱樓隔柳條。", "丫頭小兒蕩畫槳，長袂女郎簪翠翹。", "郡齋北軒卷羅幕，碧池逶迤遶畫閣。", "池邊綠竹桃李花，花下舞筵鋪彩霞。", "吳娃足情言語黠，越客有酒巾冠斜。", "坐中皆言白太守，不負風光向杯酒。", "酒酣襞牋飛逸韻，至今傳在人人口。", "報白君，相思空望嵩丘雲。", "其奈錢塘蘇小小，憶君淚點石榴帬。"]'),
('3eff1157-2720-48bc-b75a-79cf04a087f7','兩如何詩謝裴令公贈別二首 一','劉禹錫','唐','唐诗','tang','','[]','一言一顧重，重何如。',26,'全唐诗/poet.tang.18000.json','["一言一顧重，重何如。", "今日陪遊清洛苑，昔年別入承明廬。"]'),
('83e1f2ff-46ab-4e68-b5b8-a1dc7b38554c','兩如何詩謝裴令公贈別二首 二','劉禹錫','唐','唐诗','tang','','[]','一東一西別，別何如。',26,'全唐诗/poet.tang.18000.json','["一東一西別，別何如。", "終期大冶再熔鍊，願託扶搖翔碧虛。"]'),
('891701e1-57c1-4d2a-82c0-253c1e6e934b','唐侍御寄遊道林嶽麓二寺詩幷沈中丞姚員外所和見徵繼作','劉禹錫','唐','唐诗','tang','','["\u957f\u6c5f"]','湘西古剎雙蹲蹲，羣峰朝拱如駿奔。',208,'全唐诗/poet.tang.18000.json','["湘西古剎雙蹲蹲，羣峰朝拱如駿奔。", "青松步障深五里，龍宮黯黯神爲閽。", "高殿呀然壓蒼巘，俯瞰長江疑欲吞。", "橘洲泛浮金實動，水郭繚繞朱樓騫。", "語餘百響入天籟，衆奇引步輕翩翻。", "泉清石布博棋子，蘿密鳥韻如簧言。", "回廊架險高且曲，新徑穿林明復昏。", "淺流忽濁山獸過，古木半空天火痕。", "星使雙飛出禁垣，元侯餞之遊石門。", "紫髯翼從紅袖舞，竹風松雪香溫黁。", "遠持清瑣照巫峽，一戞驚斷三聲猨。", "靈山會中身不預，吟想峭絕愁精魂。", "恨無黃金千萬餅，布地買取爲丘園。"]'),
('b0b06a9e-8464-4cf4-9fb3-d986dfc388ff','將赴汝州途出浚下留辭李相公','劉禹錫','唐','唐诗','tang','','[]','長安舊遊四十載，鄂渚一別十四年。',160,'全唐诗/poet.tang.18000.json','["長安舊遊四十載，鄂渚一別十四年。", "後來富貴已零落，歲寒松柏猶依然。", "初逢貞元尚文主，雲闕天池共翔舞。", "相看却數六朝臣，屈指如今無四五。", "夷門天下之咽喉，昔時往往生瘡疣。", "聯翩舊相來鎮壓，四海吐納皆通流。", "久別凡經幾多事，何由說得平生意。", "千思萬慮盡如空，一笑一言真可貴。", "世間何事最殷勤，白頭將相逢故人。", "功成名遂會歸老，請問東山爲近鄰。"]'),
('32bc7df7-81de-4db7-b425-eade43f5e593','平蔡州三首 一','劉禹錫','唐','唐诗','tang','','[]','蔡州城中衆心死，妖星夜落照壕水。',96,'全唐诗/poet.tang.18000.json','["蔡州城中衆心死，妖星夜落照壕水。", "漢家飛將下天來，馬箠一揮門洞開。", "賊徒崩騰望旗拜，有若羣蟄驚春雷。", "狂童面縛登檻車，太白夭矯垂捷書。", "相公從容來鎮撫，常侍郊迎負文弩。", "四人歸業閭里閑，小兒跳浪健兒舞。"]'),
('3fc03d87-be07-4e07-b260-781c6d428f30','平蔡州三首 二','劉禹錫','唐','唐诗','tang','','[]','汝南晨雞喔喔鳴，城頭鼓角音和平。',64,'全唐诗/poet.tang.18000.json','["汝南晨雞喔喔鳴，城頭鼓角音和平。", "路傍老人憶舊事，相與感激皆涕零。", "老人收泣前致辭，官軍入城人不知。", "忽驚元和十二載，重見天寶承平時。"]'),
('1c61235e-e714-4033-9ba5-34ef1dda7ebb','平蔡州三首 三','劉禹錫','唐','唐诗','tang','','[]','九衢車馬渾渾流，使臣來獻淮西囚。',80,'全唐诗/poet.tang.18000.json','["九衢車馬渾渾流，使臣來獻淮西囚。", "四夷聞風失匕筯，天子受賀登高樓。", "妖童擢髪不足數，血污城西一抔土。", "南峯無火楚澤閑，夜行不鎖穆陵關。", "策勳禮畢天下泰，猛士按劒看恒山。"]'),
('a23157ca-918b-4f3e-a209-ea155dafb11c','送僧仲剬東遊兼寄呈靈澈上人','劉禹錫','唐','唐诗','tang','','[]','釋子道成神氣閑，住持曾上清涼山。',208,'全唐诗/poet.tang.18000.json','["釋子道成神氣閑，住持曾上清涼山。", "晴空禮拜見真像，金毛五髻卿雲間。", "西遊長安隸僧籍，本寺門前曲江碧。", "松間白月照寶書，竹下香泉灑瑤席。", "前時學得經論成，奔馳象馬開禪扃。", "高筵談柄一麾拂，講下門徒如醉醒。", "舊聞南方多長老，次第來入荆門道。", "荆州本自重彌天，南朝塔廟猶依然。", "宴坐東陽枯樹下，經行居止故臺邊。", "忽憶遺民社中客，爲我衡陽駐飛錫。", "講罷同尋相鶴經，閑來共蠟登山屐。", "一旦揚眉望沃州，自言王謝許同遊。", "憑將雜擬三十首，寄與江南湯慧休。"]'),
('34351239-a415-44df-9131-f7f1cc55612b','觀棋歌送儇師西遊','劉禹錫','唐','唐诗','tang','','[]','長沙男子東林師，閑讀藝經工弈棋。',240,'全唐诗/poet.tang.18000.json','["長沙男子東林師，閑讀藝經工弈棋。", "有時凝思如入定，暗覆一局誰能知。", "今年訪予來小桂，方袍袖中貯新勢。", "山人無事秋日長，白晝懵懵眠匡牀。", "因君臨局看鬬智，不覺遲景沈西牆。", "自從仙人遇樵子，直到開元王長史。", "前身後身付餘習，百變千化無窮已。", "初疑磊落曙天星，次見搏擊三秋兵。", "鴈行布陳衆未曉，虎穴得子人皆驚。", "行盡三湘不逢敵，終日饒人損機格。", "自言臺閣有知音，悠然遠起西遊心。", "商山夏木陰寂寂，好處俳徊駐飛錫。", "忽思爭道畫平沙，獨笑無言心有適。", "藹藹京城在九天，貴遊豪士足華筵。", "此時一行出人意，賭取聲名不要錢。"]'),
('bdf49a1c-c6fe-4239-8607-8007bc43bc24','吐綬鳥詞','劉禹錫','唐','唐诗','tang','','[]','越山有鳥翔寥廓，嗉中天綬光若若。',240,'全唐诗/poet.tang.18000.json','["越山有鳥翔寥廓，嗉中天綬光若若。", "越人偶見而奇之，因名吐綬江南知。", "四明天姥神仙地，朱鳥星精鍾異氣。", "赤玉彫成彪炳毛，紅綃翦出玲瓏翅。", "湖煙始開山日高，迎風吐綬盤花絛。", "臨波似染瑯琊草，映葉疑開阿母桃。", "花紅草綠人間事，未若靈禽自然貴。", "鶴吐明珠暫報恩，鵲銜金印空爲瑞。", "春和秋霽野花開，翫景尋芳處處來。", "翠幕雕籠非所慕，珠丸柘彈莫相猜。", "棲月啼煙凌縹緲，高林先見金霞曉。", "三山仙路寄遙情，刷羽揚翹欲上征。", "不學碧雞依井絡，願隨青鳥向層城。", "太液池中有黃鵠，憐君長向高枝宿。", "如何一借羊角風，來聽簫韶九成曲。"]'),
('12f2af31-9401-4281-a410-55843039d6b1','八月十五日夜桃源翫月','劉禹錫','唐','唐诗','tang','','["\u4e2d\u79cb\u8282", "\u4e2d\u79cb", "\u6e38\u4ed9", "\u6292\u6000"]','塵中見月心亦閑，況是清秋仙府間。',128,'全唐诗/poet.tang.18000.json','["塵中見月心亦閑，況是清秋仙府間。", "凝光悠悠寒露墜，此時立在最高山。", "碧虛無雲風不起，山上長松山下水。", "羣動翛然一顧中，天高地平千萬里。", "少君引我昇玉壇，禮空遙請真仙官。", "雲軿欲下星斗動，天樂一聲肌骨寒。", "金霞昕昕漸東上，輪欹影促猶頻望。", "絕景良時難再幷，他年此日應惆悵。"]'),
('df7ccf42-3d7d-4927-a388-43ec90d7ec7b','送鴻舉遊江[西]','劉禹錫','唐','唐诗','tang','','["\u5e90\u5c71"]','禪客學禪兼學文，出山初似無心雲。',160,'全唐诗/poet.tang.18000.json','["禪客學禪兼學文，出山初似無心雲。", "從風卷舒來何處，繚繞巴山不得去。", "山州古寺好閑居，讀盡龍王宮裏書。", "使君灘頭揀石硯，白帝城邊尋野蔬。", "忽然登高心瞥起，又欲浮杯信流水。", "煙波浩淼魚鳥情，東去三千三百里。", "荆門峽斷無盤渦，湘平漢闊清光多。", "廬山霧開見瀑布，江西月淨聞漁歌。", "鍾陵八郡多名守，半是西方社中友。", "與師相見便談空，想得高齋獅子吼。"]'),
('ba8cd1f5-00f4-4926-a69e-8eedcd3465c6','採菱行','劉禹錫','唐','唐诗','tang','','[]','白馬湖平秋日光，紫菱如錦彩鴛翔。',160,'全唐诗/poet.tang.18000.json','["白馬湖平秋日光，紫菱如錦彩鴛翔。", "蕩舟遊女滿中央，採菱不顧馬上郎。", "爭多逐勝紛相向，時轉蘭橈破輕浪。", "長鬟弱袂動參差，釵影釧文浮蕩漾。", "笑語哇咬顧晚暉，蓼花緣岸扣舷歸。", "歸來共到市橋步，野蔓繫船萍滿衣。", "家家竹樓臨廣陌，下有連檣多估客。", "攜觴薦芰夜經過，醉踏大隄相應歌。", "屈平祠下沅江水，月照寒波白煙起。", "一曲南音此地聞，長安北望三千里。"]'),
('81e71dc4-6fb5-4335-bb83-93166ef970aa','和牛相公溪醉歌見寄','劉禹錫','唐','唐诗','tang','','["\u592a\u6e56"]','脫屣將相守沖謙，唯於山水獨不廉。',240,'全唐诗/poet.tang.18000.json','["脫屣將相守沖謙，唯於山水獨不廉。", "枕伊背洛得勝地，鳴臯少室來軒簷。", "相形面勢默指畫，言下變化隨顧瞻。", "清池曲榭人所致，野趣幽芳天與添。", "有時轉入潭島間，珍木如幄藤爲簾。", "忽然便有江湖思，沙礫平淺草纖纖。", "怪石釣出太湖底，珠樹移自天台尖。", "崇蘭迎風綠泛豔，坼蓮含露紅𧞋襜。", "脩廊架空遠岫入，弱柳覆檻流波霑。", "渚蒲抽芽劒脊動，岸荻迸笋錐頭銛。", "攜觴命侶極永日，此會雖數心無厭。", "人皆置莊身不到，富貴難與逍遙兼。", "唯公出處得自在，決就放曠辭炎炎。", "座賓盡歡恣談謔，媿我掉頭還奮髯。", "能令商於多病客，亦覺自適非沈潛。"]'),
('a86f9164-209f-4467-8335-0dc990241eff','和浙西李大夫霜夜對月聽小童吹觱篥歌依本韻','劉禹錫','唐','唐诗','tang','','["\u957f\u6c5f"]','海門雙青暮煙歇，萬頃金波湧明月。',192,'全唐诗/poet.tang.18000.json','["海門雙青暮煙歇，萬頃金波湧明月。", "侯家小兒能觱篥，對此清光天性發。", "長江凝練樹無風，瀏慄一聲霄漢中。", "涵胡畫角怨邊草，蕭瑟清蟬吟野叢。", "沖融頓挫心使指，雄吼如風轉如水。", "思婦多情珠淚垂，仙禽欲舞雙翅起。", "郡人寂聽衣滿霜，江城月斜樓影長。", "纔驚指下繁韻息，已見樹杪明星光。", "謝公高齋吟激楚，戀闕心同在羈旅。", "一奏荆人白雪歌，如聞雒客扶風鄔。", "吳門水驛按山陰，文字殷勤寄意深。", "欲識陽陶能絕處，少年榮貴道傷心。"]'),
('045f4f0f-2b75-495a-a1db-987d6900874e','歎水別白二十二','劉禹錫','唐','唐诗','tang','','[]','水，至清，盡美。',68,'全唐诗/poet.tang.18000.json','["水，至清，盡美。", "從一勺，至千里。", "利人利物，時行時止。", "道性淨皆然，交情淡如此。", "君遊金谷堤上，我在石渠署裏。", "兩心相憶似流波，潺湲日夜無窮已。"]'),
('46119a54-3e3f-4f72-963e-b53fd23b4d84','同留守王僕射各賦春中一物從一韻至七','劉禹錫','唐','唐诗','tang','','[]','鶯，能語，多情。',68,'全唐诗/poet.tang.18000.json','["鶯，能語，多情。", "春將半，天欲明。", "始逢南陌，復集東城。", "林疎時見影，花密但聞聲。", "營中緣催短笛，樓上來定哀箏。", "千門萬戶垂楊裏，百轉如簧煙景晴。"]'),
('784ead6f-4847-40d7-8d1a-a1c0eedc0066','傷我馬詞','劉禹錫','唐','唐诗','tang','','[]','生於磧礰善馳走，萬里南來困丘阜。',48,'全唐诗/poet.tang.18000.json','["生於磧礰善馳走，萬里南來困丘阜。", "青菰寒菽非適口，病聞北風猶舉首。", "金臺已平骨空朽，投之龍淵從爾友。"]'),
('ff7a5220-ab0f-455f-bce6-33d84a12d0b1','清湘詞二首 一','劉禹錫','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u6292\u6000", "\u548f\u7269", "\u5a49\u7ea6"]','湘水流，湘水流，九疑雲物至今愁。',32,'全唐诗/poet.tang.18000.json','["湘水流，湘水流，九疑雲物至今愁。", "君問二妃何處所，零陵香草雨中收。"]'),
('6038218e-598f-426c-b7c6-6f3493876bc7','清湘詞二首 二','劉禹錫','唐','唐诗','tang','','["\u6000\u53e4", "\u548f\u7269", "\u54c0\u6028", "\u5377\u4e00\u00b7\u5510\u4e94\u4ee3\u8bcd", "\u548f\u7269\u8bd7", "\u5b8b\u8bcd\u4e09\u767e\u9996"]','斑竹枝，斑竹枝，淚痕點點寄相思。',32,'全唐诗/poet.tang.18000.json','["斑竹枝，斑竹枝，淚痕點點寄相思。", "楚客欲聞瑤瑟怨，瀟湘深夜月明時。"]'),
('7ff97b0c-62c9-47c7-a828-c76a04c0bdbb','和樂天春詞依憶江南曲拍爲句 一','劉禹錫','唐','唐诗','tang','','[]','春去也，多謝洛城人。',32,'全唐诗/poet.tang.18000.json','["春去也，多謝洛城人。", "弱柳從風疑舉袂，叢蘭裛露似霑巾，獨坐亦含嚬。"]'),
('cb372fbc-a9b2-48a7-8d49-23ff0b695a85','和樂天春詞依憶江南曲拍爲句 二','劉禹錫','唐','唐诗','tang','','[]','春過也，笑惜豔陽年。',32,'全唐诗/poet.tang.18000.json','["春過也，笑惜豔陽年。", "猶有桃花流水上，無辭竹葉醉樽前，惟待見青天。"]'),
('f6116503-3328-441c-85b4-bf2d1d9ee882','澤宮詩 一','劉禹錫','唐','唐诗','tang','','[]','秩秩澤宮，有的維鵠。',20,'全唐诗/poet.tang.18000.json','["秩秩澤宮，有的維鵠。", "祁祁庶士，於以干祿。"]'),
('4cf3337d-44fc-4b4a-a44b-03f0f80463aa','澤宮詩 二','劉禹錫','唐','唐诗','tang','','[]','彼鵠斯微，若止若翔。',20,'全唐诗/poet.tang.18000.json','["彼鵠斯微，若止若翔。", "千里之差，起於毫芒。"]'),
('604c8586-7abd-41ed-b5be-3240efa688c3','澤宮詩 三','劉禹錫','唐','唐诗','tang','','[]','我矢既直，我弓既良。',20,'全唐诗/poet.tang.18000.json','["我矢既直，我弓既良。", "依於高墉，因我不臧。"]'),
('cade1a7a-3f1c-4594-9fb0-42eaeab32e17','澤宮詩 四','劉禹錫','唐','唐诗','tang','','[]','高墉伊何，維器與時。',20,'全唐诗/poet.tang.18000.json','["高墉伊何，維器與時。", "視之以心，誰謂鵠微。"]'),
('8fbcb3d0-f752-4276-9e20-971e82b36b3e','酬令狐相公六言見寄','劉禹錫','唐','唐诗','tang','','[]','已嗟別離太遠，更被光陰苦催。',56,'全唐诗/poet.tang.18000.json','["已嗟別離太遠，更被光陰苦催。", "吳苑燕辭人去，汾川鴈帶書來。", "愁吟月落猶望，憶夢天明未回。", "今日便令歌者，唱兄詩送一杯。"]'),
('bd46e20e-7309-4695-935d-8a90c4f6a0db','荅樂天臨都驛見贈','劉禹錫','唐','唐诗','tang','','[]','北固山邊波浪，東都城裏風塵。',28,'全唐诗/poet.tang.18000.json','["北固山邊波浪，東都城裏風塵。", "世事不同心事，新人何似故人。"]'),
('226c0600-b0d9-44bc-9992-042ac9579e97','再贈樂天','劉禹錫','唐','唐诗','tang','','[]','一政政官軋軋，一年年老駸駸。',28,'全唐诗/poet.tang.18000.json','["一政政官軋軋，一年年老駸駸。", "身外名何足算，別來詩且同吟。"]'),
('e89ae7e3-795f-464c-9b6b-bd8a6ad653e3','酬楊侍郎憑見寄','劉禹錫','唐','唐诗','tang','','[]','十年毛羽催頹，一旦天書召回。',28,'全唐诗/poet.tang.18000.json','["十年毛羽催頹，一旦天書召回。", "看看瓜時欲到，故侯也好歸來。"]'),
('7c76a826-8bf3-44ee-840b-c3c67231a6fe','春有情篇','劉禹錫','唐','唐诗','tang','','[]','爲問遊春侶，春情何處尋。',48,'全唐诗/poet.tang.18000.json','["爲問遊春侶，春情何處尋。", "花含欲語意，草有鬬生心。", "雨頻催發色，雲輕不作陰。", "縱令無月夜，芳興暗中深。"]'),
('01d2faf1-f9c9-4fc3-bc7b-9b1e72d59f2d','七夕二首 一','劉禹錫','唐','唐诗','tang','','[]','河鼓靈旗動，嫦娥破鏡斜。',48,'全唐诗/poet.tang.18000.json','["河鼓靈旗動，嫦娥破鏡斜。", "滿空天是幕，徐轉斗爲車。", "機罷猶安石，橋成不礙槎。", "誰知觀津女，竟夕望雲涯。"]'),
('f28dfaa3-ff90-42e3-923d-63a5635afab8','七夕二首 二','劉禹錫','唐','唐诗','tang','','[]','天衢啓雲帳，神馭上星橋。',48,'全唐诗/poet.tang.18000.json','["天衢啓雲帳，神馭上星橋。", "初喜渡河漢，頻驚轉斗杓。", "餘霞張錦幛，輕電閃紅綃。", "非是人間世，還悲後會遙。"]'),
('be69c8f7-40a1-4f39-a1a5-e9abe30a24c1','邊風行','劉禹錫','唐','唐诗','tang','','[]','邊馬蕭蕭鳴，邊風滿磧生。',48,'全唐诗/poet.tang.18000.json','["邊馬蕭蕭鳴，邊風滿磧生。", "暗添弓箭力，斗上鼓鼙聲。", "襲月寒暈起，吹雲陰陣成。", "將軍占氣候，出號夜翻營。"]'),
('309e6aa0-2139-4c70-a935-9f98b0bbb56c','送工部蕭郎中刑部李郎中並以本官兼中丞分命充京西京北覆糧使','劉禹錫','唐','唐诗','tang','','[]','霜簡映金章，相輝同舍郎。',48,'全唐诗/poet.tang.18000.json','["霜簡映金章，相輝同舍郎。", "天威巡虎落，星使出鴛行。", "尊俎成全策，京坻閱見糧。", "歸來虜塵滅，畫地奏明光。"]'),
('39679101-7fdc-45ae-a58c-80099b8e007a','送太常蕭博士棄官歸養赴東都','劉禹錫','唐','唐诗','tang','','[]','兄弟盡鴛鸞，歸心切問安。',48,'全唐诗/poet.tang.18000.json','["兄弟盡鴛鸞，歸心切問安。", "貪榮五綵服，遂掛兩梁冠。", "侍膳曾調鼎，循陔更握蘭。", "從今別君後，長憶德星看。"]'),
('f37014d2-3c5d-43ac-a441-6832ae1d89bf','送河南皇甫少尹赴絳州','劉禹錫','唐','唐诗','tang','','[]','祖帳臨周道，前旌指晉城。',48,'全唐诗/poet.tang.18000.json','["祖帳臨周道，前旌指晉城。", "午橋羣吏散，亥字老人迎。", "詩酒同行樂，別離方見情。", "從此洛陽社，吟詠屬書生。"]'),
('8db19185-3753-4e89-8a9d-6c4fbe40b98f','發華州留別張侍御','劉禹錫','唐','唐诗','tang','','[]','束簡下延閣，買符驅短轅。',48,'全唐诗/poet.tang.18000.json','["束簡下延閣，買符驅短轅。", "同人惜分袂，結念醉芳樽。", "切切別弦急，蕭蕭征騎煩。", "臨岐無限意，相視却忘言。"]'),
('dbb8df67-b1cb-4b86-8ea4-ad63fc4bfe97','奉送家兄歸王屋山隱居二首 一','劉禹錫','唐','唐诗','tang','','[]','洛陽天壇上，依稀似玉京。',48,'全唐诗/poet.tang.18000.json','["洛陽天壇上，依稀似玉京。", "夜分先見日，月靜遠聞笙。", "雲路將雞犬，丹臺有姓名。", "古來成道者，兄弟亦同行。"]'),
('74a0da61-9487-417a-ac6a-e468c35114a9','奉送家兄歸王屋山隱居二首 二','劉禹錫','唐','唐诗','tang','','[]','春來山事好，歸去亦逍遙。',48,'全唐诗/poet.tang.18000.json','["春來山事好，歸去亦逍遙。", "水淨苔莎色，露香芝朮苗。", "登臺吸瑞景，飛步翼神飆。", "願薦塤篪曲，相將學玉簫。"]'),
('2be36bb1-fc64-4a1c-b627-ceb6eb84a047','送王師魯協律赴湖南使幕','劉禹錫','唐','唐诗','tang','','[]','翩翩馬上郎，驅傳渡三湘。',48,'全唐诗/poet.tang.18000.json','["翩翩馬上郎，驅傳渡三湘。", "橘樹沙洲暗，松醪酒肆香。", "素風傳竹帛，高價聘琳瑯。", "楚水多蘭芷，何人事搴芳。"]'),
('52119dc8-6af9-49b7-9905-9da1c39360fd','送趙中丞自司金郎轉官參山南令狐僕射幕府','劉禹錫','唐','唐诗','tang','','[]','綠樹滿褒斜，西南蜀路賒。',48,'全唐诗/poet.tang.18000.json','["綠樹滿褒斜，西南蜀路賒。", "驛門臨白草，縣道入黃花。", "相府開油幕，門生逐絳紗。", "行看布政後，還從入京華。"]'),
('377feb9c-f041-4601-bb90-03c23352a86f','送盧處士歸嵩山別業','劉禹錫','唐','唐诗','tang','','[]','世業嵩山隱，雲深無四鄰。',48,'全唐诗/poet.tang.18000.json','["世業嵩山隱，雲深無四鄰。", "藥爐燒姹女，酒甕貯賢人。", "晚日華陰霧，秋風函谷塵。", "送君從此去，鈴閣少談賓。"]'),
('98a63a38-a99e-4c6d-8a82-efcc5008768e','洛中送崔司業使君扶侍赴唐州','劉禹錫','唐','唐诗','tang','','[]','綠野芳城路，殘春柳絮飛。',48,'全唐诗/poet.tang.18000.json','["綠野芳城路，殘春柳絮飛。", "風鳴驌驦馬，日照老萊衣。", "洛苑魚書至，江村鴈戶歸。", "相思望淮水，雙鯉不應稀。"]'),
('dfda74a7-9e96-48ed-bbd6-b7bcc1af85df','送李友路秀才赴舉','劉禹錫','唐','唐诗','tang','','[]','誰憐相門子，不語望秋山。',48,'全唐诗/poet.tang.18000.json','["誰憐相門子，不語望秋山。", "生長綺紈內，辛勤筆硯間。", "榮親在名字，好學棄官班。", "佇俟明年桂，高堂開笑顏。"]'),
('9f78dbd2-d34c-414c-b29d-65656729231a','送從弟郎中赴浙西','劉禹錫','唐','唐诗','tang','','[]','銜命出尚書，新恩換使車。',48,'全唐诗/poet.tang.18000.json','["銜命出尚書，新恩換使車。", "漢庭無右者，梁苑重歸歟。", "又食建業水，曾依京口居。", "共經何限事，賓主兩如初。"]'),
('b85e18f3-6951-49f8-a5f7-6a78f35e37f8','送元上人歸稽亭','劉禹錫','唐','唐诗','tang','','[]','重疊稽亭路，山僧歸獨行。',48,'全唐诗/poet.tang.18000.json','["重疊稽亭路，山僧歸獨行。", "遠峰斜日影，本寺舊鐘聲。", "徒侶問新事，煙雲愴別情。", "應誇乞食處，踏遍鳳凰城。"]'),
('d7d05fac-c532-4b7e-9b00-ff54216c5df3','贈別君素上人詩','劉禹錫','唐','唐诗','tang','','[]','窮巷唯秋草，高僧獨扣門。',48,'全唐诗/poet.tang.18000.json','["窮巷唯秋草，高僧獨扣門。", "相歡如舊識，問法到無言。", "水爲風生浪，珠非塵可昏。", "悟來皆是道，此別不銷魂。"]'),
('d4b6647b-265f-41c2-ab67-ec867eb5e03a','送深法師遊南岳','劉禹錫','唐','唐诗','tang','','[]','師在白雲鄉，名登善法堂。',48,'全唐诗/poet.tang.18000.json','["師在白雲鄉，名登善法堂。", "十方傳句偈，八部會壇場。", "飛錫無定所，寶書留舊房。", "唯應銜果鴈，相送至衡陽。"]'),
('df751ccc-0157-467b-b525-01c8ee9c0693','贈別約師','劉禹錫','唐','唐诗','tang','','["\u5e90\u5c71"]','師逢吳興守，相伴住禪扃。',48,'全唐诗/poet.tang.18000.json','["師逢吳興守，相伴住禪扃。", "春雨同栽樹，秋燈對講經。", "廬山曾結社，桂水遠揚舲。", "話舊還惆悵，天南望柳星。"]'),
('757a180d-55eb-4931-9f10-c71649f6a06d','秋日過鴻舉法師寺院便送歸江陵','劉禹錫','唐','唐诗','tang','','[]','看畫長廊遍，尋僧一徑幽。',48,'全唐诗/poet.tang.18000.json','["看畫長廊遍，尋僧一徑幽。", "小池兼鶴淨，古木帶蟬秋。", "客至茶煙起，禽歸講席收。", "浮杯明日去，相望水悠悠。"]'),
('bba0e13e-b062-4234-bcec-fe616bceb769','春日退朝','劉禹錫','唐','唐诗','tang','','[]','紫陌夜來雨，南山朝下看。',48,'全唐诗/poet.tang.18000.json','["紫陌夜來雨，南山朝下看。", "戟枝迎日動，閣影助松寒。", "瑞氣轉綃縠，遊光泛波瀾。", "御溝新柳色，處處拂歸鞍。"]'),
('2f37297b-77d5-412b-bc73-105bfa4d011d','蜀先主廟','劉禹錫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2\u6000\u53e4", "\u4e94\u8a00\u5f8b\u8bd7"]','天地英雄氣，千秋尚凜然。',48,'全唐诗/poet.tang.18000.json','["天地英雄氣，千秋尚凜然。", "勢分三足鼎，業復五銖錢。", "得相能開國，生兒不象賢。", "淒涼蜀故妓，來舞魏宮前。"]'),
('5df40321-e858-4c40-a91b-c97dc443eb5a','經東都安國觀九仙公主舊院作','劉禹錫','唐','唐诗','tang','','[]','仙院御溝東，今來事不同。',48,'全唐诗/poet.tang.18000.json','["仙院御溝東，今來事不同。", "門開青草日，樓閉綠楊風。", "將犬昇天路，披雲赴月宮。", "武皇曾駐蹕，親問主人翁。"]'),
('6bfa0919-c33a-4fd2-a1ee-67cf7f0c4e83','觀八陣圖','劉禹錫','唐','唐诗','tang','','[]','軒皇傳上略，蜀相運神機。',48,'全唐诗/poet.tang.18000.json','["軒皇傳上略，蜀相運神機。", "水落龍蛇出，沙平鵝鸛飛。", "波濤無動勢，鱗介避餘威。", "會有知兵者，臨流指是非。"]'),
('477ee8be-062e-41d1-97c3-301165ef61bb','八月十五日夜翫月','劉禹錫','唐','唐诗','tang','','[]','天將今夜月，一遍洗寰瀛。',48,'全唐诗/poet.tang.18000.json','["天將今夜月，一遍洗寰瀛。", "暑退九霄淨，秋澄萬景清。", "星辰讓光彩，風露發晶英。", "能變人間世，翛然是玉京。"]'),
('ae2ea063-a899-442d-9a59-27eef726f78f','太和戊申歲大有年詔賜百僚出城觀秋稼謹書盛事以俟采詩者','劉禹錫','唐','唐诗','tang','','[]','長安銅雀鳴，秋稼與雲平。',48,'全唐诗/poet.tang.18000.json','["長安銅雀鳴，秋稼與雲平。", "玉燭調寒暑，金風報順成。", "川原呈上瑞，恩澤賜閑行。", "欲反重城掩，猶聞歌吹聲。"]'),
('7d9dad77-234d-4ba2-8402-206d9d7bca67','金陵懷古','劉禹錫','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u666f", "\u548f\u53f2\u6000\u53e4"]','潮滿冶城渚，日斜征虜亭。',48,'全唐诗/poet.tang.18000.json','["潮滿冶城渚，日斜征虜亭。", "蔡洲新草綠，幕府舊煙青。", "興廢由人事，山川空地形。", "後庭花一曲，幽怨不堪聽。"]'),
('fdf4338a-51dc-44af-90ef-bbe1e30cd759','晝居池上亭獨吟','劉禹錫','唐','唐诗','tang','','[]','日午樹陰正，獨吟池上亭。',48,'全唐诗/poet.tang.18000.json','["日午樹陰正，獨吟池上亭。", "靜看蜂教誨，閒想鶴儀形。", "法酒調神氣，清琴入性靈。", "浩然機已息，几杖復何銘。"]'),
('2fd099d5-42b1-471c-a22d-4f50be11b73e','分司東都蒙襄陽李司徒相公書問因以奉寄','劉禹錫','唐','唐诗','tang','','[]','早忝金馬客，晚爲商洛翁。',48,'全唐诗/poet.tang.18000.json','["早忝金馬客，晚爲商洛翁。", "知名四海內，多病一生中。", "舉世往還盡，何人心事同。", "幾時登峴首，恃舊揖三公。"]'),
('cc80d1dc-739b-44cf-a1be-7c017455432c','門下相公榮加册命天下同歡忝沐眷私輒感申賀','劉禹錫','唐','唐诗','tang','','[]','冊命出宸衷，官儀自古崇。',48,'全唐诗/poet.tang.18000.json','["冊命出宸衷，官儀自古崇。", "特膺平土拜，光贊格天功。", "再佩扶陽印，常乘鮑氏驄。", "七賢遺老在，猶得詠清風。"]'),
('3de21225-e6fd-4a26-be65-fe25d6ea5e53','病中一二禪客見問因以謝之','劉禹錫','唐','唐诗','tang','','[]','勞動諸賢者，同來問病夫。',48,'全唐诗/poet.tang.18000.json','["勞動諸賢者，同來問病夫。", "添爐烹雀舌，灑水淨龍鬚。", "身是芭蕉喻，行須筇竹扶。", "醫王有妙藥，能乞一丸無。"]'),
('b64829f8-7516-4872-8439-08a28558ed95','秋江晚泊','劉禹錫','唐','唐诗','tang','','[]','長泊起秋色，空江涵霽暉。',48,'全唐诗/poet.tang.18000.json','["長泊起秋色，空江涵霽暉。", "暮霞千萬狀，賓鴻次第飛。", "古戍見旗逈，荒村聞犬稀。", "軻峨艑上客，勸酒夜相依。"]'),
('18134617-3a61-4d5a-a0c2-3d80b54099f6','步出武陵東亭臨江寓望','劉禹錫','唐','唐诗','tang','','[]','鷹至感風候，霜餘變林麓。',48,'全唐诗/poet.tang.18000.json','["鷹至感風候，霜餘變林麓。", "孤颿帶日來，寒江轉沙曲。", "戍搖旗影動，津晚櫓聲促。", "月上彩霞收，漁歌遠相續。"]'),
('fca5d8bf-885f-487c-85ad-89bebff8e289','秋日送客至潛水驛','劉禹錫','唐','唐诗','tang','','[]','候吏立沙際，田家連竹溪。',48,'全唐诗/poet.tang.18000.json','["候吏立沙際，田家連竹溪。", "楓林社日鼓，茅屋午時雞。", "鵲噪晚禾地，蝶飛秋草畦。", "驛樓宮樹近，疲馬再三嘶。"]'),
('8291399e-7492-4563-964b-5da69a8358d6','湖州崔郎中曹長寄三癖詩自言癖在詩與琴酒其詞逸而高吟詠不足昔柳吳興亭臯隴首之句王融書之白團扇故爲四韻以謝之','劉禹錫','唐','唐诗','tang','','[]','視事畫屏中，自稱三癖翁。',48,'全唐诗/poet.tang.18000.json','["視事畫屏中，自稱三癖翁。", "管弦泛春渚，旌斾拂晴虹。", "酒對青山月，琴韻白蘋風。", "會書團扇上，知君文字工。"]'),
('dfc9c57a-a65f-464d-aa59-b10ab8922873','爲郎分司寄上都同舍','劉禹錫','唐','唐诗','tang','','[]','籍通金馬門，家在銅駞陌。',48,'全唐诗/poet.tang.18000.json','["籍通金馬門，家在銅駞陌。", "省闥晝無塵，宮樹朝凝碧。", "荒街淺深轍，古渡潺湲石。", "唯有嵩丘雲，堪誇早朝客。"]'),
('a17a8071-b012-4749-87ae-34f1ceff1304','登陝州北樓却憶京師親友','劉禹錫','唐','唐诗','tang','','[]','獨上百尺樓，目窮思亦愁。',48,'全唐诗/poet.tang.18000.json','["獨上百尺樓，目窮思亦愁。", "初日徧露草，野田荒悠悠。", "塵息長道白，林清宿煙收。", "回首雲深處，永懷鄉舊遊。"]'),
('69ff1ba3-3359-48cb-81de-aa79ea8e8206','途中早發','劉禹錫','唐','唐诗','tang','','[]','中庭望啓明，促促事晨征。',48,'全唐诗/poet.tang.18000.json','["中庭望啓明，促促事晨征。", "寒樹鳥初動，霜橋人未行。", "水流白煙起，日上彩霞生。", "隱士應高枕，無人問姓名。"]'),
('651722dd-f3fc-479a-9392-5c09c55c513e','陝州河亭陪韋五大夫雪後眺望因以留別與韋有布衣之舊一別二紀經遷貶而歸','劉禹錫','唐','唐诗','tang','','[]','雪霽太陽津，城池表裏春。',48,'全唐诗/poet.tang.18000.json','["雪霽太陽津，城池表裏春。", "河流添馬頰，原色動龍鱗。", "萬里獨歸客，一杯逢故人。", "登高向西望，關路正飛塵。"]'),
('a154e82e-209c-43b1-8f31-dc81252bc17a','城東閑遊','劉禹錫','唐','唐诗','tang','','[]','借問池臺主，多居要路津。',48,'全唐诗/poet.tang.18000.json','["借問池臺主，多居要路津。", "千金買絕境，永日屬閑人。", "竹徑縈紆入，花林委曲巡。", "斜陽衆客散，空鎖一園春。"]'),
('affaf4b2-bac5-4b35-b1c6-67dbd0176844','罷郡歸洛陽閑居','劉禹錫','唐','唐诗','tang','','[]','十年江海守，旦夕有歸心。',48,'全唐诗/poet.tang.18000.json','["十年江海守，旦夕有歸心。", "及此西還日，空成東武吟。", "花間數杯酒，月下一張琴。", "聞說功名事，依前惜寸陰。"]'),
('0dc5ae3a-b7b8-4d31-bdbd-f423e81d63fe','晚泊牛渚','劉禹錫','唐','唐诗','tang','','[]','蘆葦晚風起，秋江鱗甲生。',48,'全唐诗/poet.tang.18000.json','["蘆葦晚風起，秋江鱗甲生。", "殘霞忽變色，遊雁有餘聲。", "戍鼓音響絕，漁家燈火明。", "無人能詠史，獨自月中行。"]'),
('bd3a0a24-fd2c-4aa9-86d9-ff08f158bb61','宿誠禪師山房題贈二首 一','劉禹錫','唐','唐诗','tang','','[]','宴坐白雲端，清江直下看。',48,'全唐诗/poet.tang.18000.json','["宴坐白雲端，清江直下看。", "來人望金剎，講席繞香壇。", "虎嘯夜林動，鼉鳴秋澗寒。", "衆音徒起滅，心在淨中觀。"]'),
('ccd37b05-c9c1-4085-b280-bf755a2b93bd','宿誠禪師山房題贈二首 二','劉禹錫','唐','唐诗','tang','','[]','不出孤峰上，人間四十秋。',48,'全唐诗/poet.tang.18000.json','["不出孤峰上，人間四十秋。", "視身如傳舍，閱世似東流。", "法爲因緣立，心從次第修。", "中宵問真偈，有住是吾憂。"]'),
('cf3fdab8-8806-4955-94fc-b6c7c2fa2714','贈澧州高大夫司馬霞[寓]','劉禹錫','唐','唐诗','tang','','[]','前年牧錦城，馬蹋血泥行。',48,'全唐诗/poet.tang.18000.json','["前年牧錦城，馬蹋血泥行。", "千里追戎首，三軍許勇名。", "殘兵疑鶴唳，空壘辯烏聲。", "一誤雲中級，南遊湘水清。"]'),
('1e702c6f-2cdb-4070-8e93-0f4396404340','聞董評事疾因以書贈','劉禹錫','唐','唐诗','tang','','[]','繁露傳家學，青蓮譯梵書。',48,'全唐诗/poet.tang.18000.json','["繁露傳家學，青蓮譯梵書。", "火風乖四大，文字廢三餘。", "欹枕晝眠靜，折巾秋鬢疎。", "武皇思視草，誰許茂陵居。"]'),
('cbdd1bd4-58ea-4bd4-a64c-40654f818387','詠庭梅寄人','劉禹錫','唐','唐诗','tang','','[]','蚤花常犯寒，繁實常苦酸。',48,'全唐诗/poet.tang.18000.json','["蚤花常犯寒，繁實常苦酸。", "何事上春日，坐令芳意闌。", "夭桃定相笑，遊妓肯回看。", "君問調金鼎，方知正味難。"]'),
('52efece3-c660-4d9f-9f29-6f22f94cfdc0','德宗神武孝文皇帝挽歌二首 一','劉禹錫','唐','唐诗','tang','','[]','出震清多難，乘時播大鈞。',48,'全唐诗/poet.tang.18000.json','["出震清多難，乘時播大鈞。", "操弦調六氣，揮翰動三辰。", "運偶升天日，哀深率土人。", "瑤池無轍迹，誰見屬車塵。"]'),
('57dd887c-0f37-4c92-99d0-8adc6af9f64e','德宗神武孝文皇帝挽歌二首 二','劉禹錫','唐','唐诗','tang','','[]','鳳翣擁銘旌，威遲異吉行。',48,'全唐诗/poet.tang.18000.json','["鳳翣擁銘旌，威遲異吉行。", "漢儀陳祕器，楚挽咽繁聲。", "駐綍辭清廟，凝笳背直城。", "唯應留內傳，知是向蓬瀛。"]'),
('9350c47a-7dd4-4190-9fde-9bb9610b6a90','敬宗睿武昭愍孝皇帝挽歌三首 一','劉禹錫','唐','唐诗','tang','','[]','寶曆方無限，仙期忽有涯。',48,'全唐诗/poet.tang.18000.json','["寶曆方無限，仙期忽有涯。", "事親崇漢禮，傳聖法殷家。", "晚出芙蓉闕，春歸棠棣華。", "玉輪今日動，不是畫雲車。"]'),
('84c3e8ec-51c4-408a-b93f-a56ad1360586','敬宗睿武昭愍孝皇帝挽歌三首 二','劉禹錫','唐','唐诗','tang','','[]','任賢勞夢寐，登位富春秋。',48,'全唐诗/poet.tang.18000.json','["任賢勞夢寐，登位富春秋。", "欲遂東人幸，寧虞杞國憂。", "長楊收羽騎，太液泊龍舟。", "惟有衣冠在，年年愴月遊。"]'),
('33d1a0e5-d26e-4ce3-b35c-79be07c28450','敬宗睿武昭愍孝皇帝挽歌三首 三','劉禹錫','唐','唐诗','tang','','[]','講學金華殿，親畊鉤盾田。',48,'全唐诗/poet.tang.18000.json','["講學金華殿，親畊鉤盾田。", "侍臣容諫獵，方士信求仙。", "虹影俄侵日，龍髯不上天。", "空餘水銀海，長照夜燈前。"]'),
('9bbc2f50-f732-42f4-b416-7f70d5c5734b','文宗元聖昭獻孝皇帝挽歌三首','劉禹錫','唐','唐诗','tang','','[]','繼體三才理，承顏九族親。',48,'全唐诗/poet.tang.18000.json','["繼體三才理，承顏九族親。", "禹功留海內，殷曆付天倫。", "調露曲常在，秋風詞尚新。", "本支方百代，先讓棣華春。"]'),
('882882b6-5458-402b-af71-7cc2de48e0af','文宗元聖昭獻孝皇帝挽歌三首 二','劉禹錫','唐','唐诗','tang','','[]','月落宮車動，風淒儀杖閑。',48,'全唐诗/poet.tang.18000.json','["月落宮車動，風淒儀杖閑。", "路唯瞻鳳翣，人尚想龍顏。", "御宇方無事，乘雲遂不還。", "聖情悲望處，沈日下西山。"]'),
('a5edf990-6bc6-48a5-a0c9-79c2c963297f','文宗元聖昭獻孝皇帝挽歌三首 三','劉禹錫','唐','唐诗','tang','','[]','享國十五載，升天千萬年。',48,'全唐诗/poet.tang.18000.json','["享國十五載，升天千萬年。", "龍鑣仙路遠，騎吹禮容全。", "日下初陵外，人悲舊劒前。", "周南有遺老，掩淚望秦川。"]'),
('7c280b65-7f21-4058-933e-dc644e22f2a6','故相國燕國公于司空挽歌二首 一','劉禹錫','唐','唐诗','tang','','[]','彫弓封舊國，黑弰繼前功。',48,'全唐诗/poet.tang.18000.json','["彫弓封舊國，黑弰繼前功。", "十年鎮南雍，九命作司空。", "池臺樂事盡，簫鼓葬儀雄。", "一代英豪氣，曉散白楊風。"]'),
('0a83ef72-79a5-4bcd-b4a9-bae51a497714','故相國燕國公于司空挽歌二首 二','劉禹錫','唐','唐诗','tang','','[]','陰山貴公子，來葬五陵西。',48,'全唐诗/poet.tang.18000.json','["陰山貴公子，來葬五陵西。", "前馬悲無主，猶帶朔風嘶。", "漢水晉山郭，襄楊白銅鞮。", "至今有遺愛，日暮人悽悽。"]'),
('3a5d127e-39f7-4383-806b-6f19581136e4','傷丘中丞','劉禹錫','唐','唐诗','tang','','[]','鄴下殺才子，蒼茫冤氣凝。',48,'全唐诗/poet.tang.18000.json','["鄴下殺才子，蒼茫冤氣凝。", "枯楊映漳水，野火上西陵。", "馬鬣今無所，龍門昔共登。", "何人爲弔客，唯是有青蠅。"]'),
('b5ba89b2-38fe-4f53-a229-99f1448e1ae8','河南觀察使故相國袁公挽歌三首 一','劉禹錫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','五驅龍虎節，一入鳳凰池。',48,'全唐诗/poet.tang.18000.json','["五驅龍虎節，一入鳳凰池。", "令尹自無喜，羊公人不疑。", "天歸京兆日，葉下洞庭時。", "湘水秋風至，淒涼吹素旗。"]'),
('2d01c7b7-2e9e-432b-a818-46db0490b207','河南觀察使故相國袁公挽歌三首 二','劉禹錫','唐','唐诗','tang','','[]','丹旐發江臯，人悲雁亦號。',48,'全唐诗/poet.tang.18000.json','["丹旐發江臯，人悲雁亦號。", "湘南罷亥市，漢上改詞曹。", "表墓雙碑立，尊名一字褒。", "嘗聞平楚獄，爲報里門高。"]'),
('43a39cc2-6a8c-45ff-97ee-e40f2f21bcc0','河南觀察使故相國袁公挽歌三首 三','劉禹錫','唐','唐诗','tang','','[]','返葬三千里，荆衡達帝畿。',48,'全唐诗/poet.tang.18000.json','["返葬三千里，荆衡達帝畿。", "逢人即故吏，拜奠盡沾衣。", "地得青烏相，賓驚白鶴飛。", "五公碑尚在，今日亦同歸。"]'),
('808c6e7d-e6cd-4d42-b249-9a5f8353cf18','哭王僕射相公','劉禹錫','唐','唐诗','tang','','[]','子侯一日病，滕公千載歸。',48,'全唐诗/poet.tang.18000.json','["子侯一日病，滕公千載歸。", "門庭愴已變，風物澹無輝。", "羣吏謁新府，舊賓沾素衣。", "歌堂忽暮哭，賀雀盡驚飛。"]'),
('40e0ee9c-cf5c-4c1e-a189-1d8dc67b71a5','傷韋賓客','劉禹錫','唐','唐诗','tang','','[]','韋公八十餘，位至六尚書。',48,'全唐诗/poet.tang.18000.json','["韋公八十餘，位至六尚書。", "五福唯無富，一生誰得如。", "桂枝攀最久，蘭省出仍初。", "海內時流盡，何人動素車。"]'),
('a29d1e76-453c-4d3a-85f4-17c9d2f8f1fb','再經故元九相公宅池上作','劉禹錫','唐','唐诗','tang','','[]','故池春又至，一到一傷情。',48,'全唐诗/poet.tang.18000.json','["故池春又至，一到一傷情。", "雁鶩羣猶下，蛙螟衣已生。", "竹叢身後長，臺勢雨來傾。", "六尺孤安在，人間未有名。"]'),
('3153881d-954a-4daa-a62e-ce93e15f1405','請告東歸發灞橋却寄諸僚友','劉禹錫','唐','唐诗','tang','','[]','征徒出灞涘，回首傷如何。',48,'全唐诗/poet.tang.18000.json','["征徒出灞涘，回首傷如何。", "故人雲雨散，滿目山川多。", "行車無停軌，流景同迅波。", "前歡漸成昔，感歎益勞歌。"]'),
('8cc26a48-6f8a-44f9-8183-6b1a9859fd2d','初至長安','劉禹錫','唐','唐诗','tang','','[]','左遷凡二紀，重見帝城春。',48,'全唐诗/poet.tang.18000.json','["左遷凡二紀，重見帝城春。", "老大歸朝客，平安出嶺人。", "每行經舊處，却想似前身。", "不改南山色，其餘事事新。"]'),
('03f1917c-1bd3-4e31-a444-8fdb6b408f0f','歲杪將發楚州呈樂天','劉禹錫','唐','唐诗','tang','','[]','楚澤雪初霽，楚城春欲歸。',48,'全唐诗/poet.tang.18000.json','["楚澤雪初霽，楚城春欲歸。", "清淮變寒色，遠樹含清暉。", "原野已多思，風霜潛減威。", "與君同旅雁，北向刷毛衣。"]'),
('2e6a8523-3ce5-4647-93f9-136b9ac18cba','鶴歎二首 一','劉禹錫','唐','唐诗','tang','','[]','寂寞一雙鶴，主人在西京。',48,'全唐诗/poet.tang.18000.json','["寂寞一雙鶴，主人在西京。", "故巢吳苑樹，深院洛陽城。", "徐引竹間步，遠含雲外情。", "誰憐好風月，鄰舍夜吹笙。"]'),
('ca7f10d2-31f1-47f5-a043-ed93b15c951c','鶴歎二首 二','劉禹錫','唐','唐诗','tang','','[]','丹頂宜承日，霜翎不染泥。',48,'全唐诗/poet.tang.18000.json','["丹頂宜承日，霜翎不染泥。", "愛池能久立，看月未成棲。", "一院春草長，三山歸路迷。", "主人朝謁早，貪養汝南雞。"]'),
('bb68efa3-9758-4ac2-927c-a0985c84acad','答白刑部聞新蟬','劉禹錫','唐','唐诗','tang','','[]','蟬聲未發前，已自感流年。',48,'全唐诗/poet.tang.18000.json','["蟬聲未發前，已自感流年。", "一入淒涼耳，如聞斷續弦。", "晴清依露葉，晚急畏霞天。", "何事秋卿詠，逢時亦悄然。"]'),
('ead35b67-5ff2-46d8-92bf-c93eae090b11','和裴相公寄白侍郎求雙鶴','劉禹錫','唐','唐诗','tang','','[]','皎皎華亭鶴，來隨太守船。',48,'全唐诗/poet.tang.18000.json','["皎皎華亭鶴，來隨太守船。", "青雲意長在，滄海別經年。", "留滯清洛苑，裴回明月天。", "何如鳳池上，雙舞入祥煙。"]'),
('aaf62ace-7464-47ef-a354-f952b9e2d2a9','終南秋雪','劉禹錫','唐','唐诗','tang','','[]','南嶺見秋雪，千門生早寒。',48,'全唐诗/poet.tang.18000.json','["南嶺見秋雪，千門生早寒。", "閑時駐馬望，高處卷簾看。", "霧散瓊枝出，日斜鉛粉殘。", "偏宜曲江上，倒影入清瀾。"]'),
('447b1e07-20c7-4af4-ac7d-4e2c8168f37c','和樂天早寒','劉禹錫','唐','唐诗','tang','','[]','雨引苔侵壁，風驅葉擁堦。',48,'全唐诗/poet.tang.18000.json','["雨引苔侵壁，風驅葉擁堦。", "久留閑客話，宿請老僧齋。", "酒甕新陳接，書籤次第排。", "翛然自有處，搖落不傷懷。"]'),
('b8a38448-cb8f-4fed-8ee5-d1f77ad3ac17','曲江春望','劉禹錫','唐','唐诗','tang','','[]','鳳城煙雨歇，萬象含佳氣。',48,'全唐诗/poet.tang.18000.json','["鳳城煙雨歇，萬象含佳氣。", "酒後人倒狂，花時天似醉。", "三春車馬客，一代繁華地。", "何事獨傷懷，少年曾得意。"]'),
('d109931b-6121-42ea-80d9-f8c53c0cef04','同樂天和微之深春二十首 一','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深萬乘家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深萬乘家。", "宮門皆映柳，輦路盡穿花。", "池色連天漢，城形象帝車。", "旌旗暖風裏，獵獵向西斜。"]'),
('23b288e3-01d9-4688-8f00-8572431a2819','同樂天和微之深春二十首 二','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深阿母家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深阿母家。", "瑤池長不夜，珠樹正開花。", "橋峻通星渚，樓暄近日車。", "層城十二闕，相對日西斜。"]'),
('7da7530a-7033-43b3-90e3-f37c6baa5bd8','同樂天和微之深春二十首 三','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深執政家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深執政家。", "恩光貪捧日，貴重不看花。", "玉饌堂交印，沙隄柱礙車。", "多門一已閉，直道更無斜。"]'),
('8534811a-5ddc-4cb6-aca7-74939e9c2676','同樂天和微之深春二十首 四','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深大鎮家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深大鎮家。", "前旌光照日，後騎蹙成花。", "節院收衙隊，毬場簇看車。", "廣筵歌舞散，書號夕陽斜。"]'),
('3317e361-b45c-40b1-82e6-ce523ee6d424','同樂天和微之深春二十首 五','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深貴戚家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深貴戚家。", "櫪嘶無價馬，庭發有名花。", "欲進宮人食，先薰命婦車。", "晚歸長帶酒，冠蓋任傾斜。"]'),
('db700e6b-5b2f-4354-9295-aafa4fdac50e','同樂天和微之深春二十首 六','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深恩澤家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深恩澤家。", "爐添龍腦炷，綬結虎頭花。", "賓客珠成履，嬰孩錦縛車。", "畫堂簾幕外，來去燕飛斜。"]'),
('beb2f202-2c2e-429e-bada-58d23707883f','同樂天和微之深春二十首 七','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深京兆家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深京兆家。", "人眉新柳葉，馬色醉桃花。", "盜息無鳴鼓，朝回自走車。", "能令帝城外，不敢逕由斜。"]'),
('72a19fe4-7b5e-4285-9bf8-4d2812f89675','同樂天和微之深春二十首 八','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深刺史家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深刺史家。", "夜闌猶命樂，雨甚亦尋花。", "傲客多憑酒，新姬苦上車。", "公門吏散後，風擺戟衣斜。"]'),
('72ea76eb-c624-4e9d-b791-4b8438c18605','同樂天和微之深春二十首 九','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深羽客家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深羽客家。", "芝田繞舍色，杏樹滿山花。", "雲是淮王宅，風爲列子車。", "古壇操簡處，一逕入林斜。"]'),
('cdf6e3ff-c80d-438c-9d6d-a03d4b5d6230','同樂天和微之深春二十首 十','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深小隱家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深小隱家。", "芟庭留野菜，撼樹去狂花。", "醉酒一千日，貯書三十車。", "雉衣從露體，不敢有餘斜。"]'),
('68bab652-e497-471f-8e4e-eb48eb6fb6ee','同樂天和微之深春二十首 十一','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深富室家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深富室家。", "唯多貯金帛，不擬負鶯花。", "國樂呼連轡，行廚載滿車。", "歸來看理曲，燈下寶釵斜。"]'),
('243fae53-1b7d-41c1-a052-1f8daa6d7e48','同樂天和微之深春二十首 十二','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深豪士家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深豪士家。", "多沽味濃酒，貴買色深花。", "已臂鷹隨馬，連催妓上車。", "城南踏青處，村落逐原斜。"]'),
('61e989b9-18bd-491a-abbc-a64c45061b27','同樂天和微之深春二十首 十三','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深貴胄家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深貴胄家。", "迎呼偏熟客，揀選最多花。", "飲饌開華幄，笙歌出鈿車。", "興酣罇易罄，連瀉酒瓶斜。"]'),
('19cd6d1c-fd8c-4d74-a79d-6177b72c1b3e','同樂天和微之深春二十首 十四','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深唱第家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深唱第家。", "名傳一紙榜，興管九衢花。", "薦聽諸侯樂，來隨計吏車。", "杏園拋曲處，揮袖向風斜。"]'),
('a7ec76b2-0a7d-4769-828a-451d5775f2bf','同樂天和微之深春二十首 十五','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深少婦家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深少婦家。", "能偷新禁曲，自剪入時花。", "追逐同遊伴，平章貴價車。", "從來不墮馬，故譴髻鬟斜。"]'),
('d842e734-ca12-43de-a4ea-b7b48c2ff1fd','同樂天和微之深春二十首 十六','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深幼女家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深幼女家。", "雙鬟梳頂髻，兩面繡帬花。", "妝壞頻臨鏡，身輕不占車。", "鞦韆爭次第，牽拽綵繩斜。"]'),
('379d9a4d-c126-44e6-b632-f4d45ad8111f','同樂天和微之深春二十首 十七','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深蘭若家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深蘭若家。", "當香收柏葉，養蜜近梨花。", "野逕宜行樂，遊人盡駐車。", "菜園籬落短，遙見桔槔斜。"]'),
('e7c21de5-b9f7-40e9-9e86-4a6bb501ad72','同樂天和微之深春二十首 十八','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深老宿家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深老宿家。", "小欄圍蕙草，高架引藤花。", "四字香書印，三乘壁畫車。", "遲回聽句偈，雙樹晚陰斜。"]'),
('c6af1ead-26f2-4762-9cea-bd841de31686','同樂天和微之深春二十首 十九','劉禹錫','唐','唐诗','tang','','[]','何處深春好，春深種蒔家。',48,'全唐诗/poet.tang.18000.json','["何處深春好，春深種蒔家。", "分畦十字水，接樹兩般花。", "櫛比栽籬槿，咿啞轉井車。", "可憐高處望，棊布不曾斜。"]'),
('80ce1d3d-d35a-427f-b85b-db8923949c05','同樂天和微之深春二十首 二十','劉禹錫','唐','唐诗','tang','','[]','何處春深好，春深稚子家。',48,'全唐诗/poet.tang.18000.json','["何處春深好，春深稚子家。", "爭騎一竿竹，偷折四鄰花。", "笑擊羊皮鼓，行牽犢頷車。", "中庭貪夜戲，不覺玉繩斜。"]'),
('6d7e40d7-86c3-49dd-9949-dc6291a41185','贈眼醫婆羅門僧','劉禹錫','唐','唐诗','tang','','[]','三秋傷望眼，終日哭途窮。',48,'全唐诗/poet.tang.18000.json','["三秋傷望眼，終日哭途窮。", "兩目今先暗，中年似老翁。", "看朱漸成碧，羞日不禁風。", "師有金篦術，如何爲發蒙。"]'),
('1ab5e94e-0af0-4eb7-aebe-94952155bc06','海門潮別浩初師','劉禹錫','唐','唐诗','tang','','[]','前日過蕭寺，看師上講筵。',48,'全唐诗/poet.tang.18000.json','["前日過蕭寺，看師上講筵。", "都人禮白足，施者散金錢。", "方便無非教，經行不廢禪。", "還知習居士，發論侍彌天。"]'),
('0780e393-42ed-4de4-9a7d-a5c501420b47','始聞蟬有懷白賓客去歲白有聞蟬見寄詩云秖應催我老兼遣報君知之句','劉禹錫','唐','唐诗','tang','','[]','蟬韻極清切，始聞何處悲。',48,'全唐诗/poet.tang.18000.json','["蟬韻極清切，始聞何處悲。", "人含不平意，景值欲秋時。", "此歲方晼晚，誰家無別離。", "君言催我老，已是去年詩。"]'),
('2e308a55-cbe9-4a84-809c-a02db184bcbc','贈樂天','劉禹錫','唐','唐诗','tang','','[]','一別舊遊盡，相逢俱涕零。',48,'全唐诗/poet.tang.18000.json','["一別舊遊盡，相逢俱涕零。", "在人雖晚達，於樹似冬青。", "痛飲連宵醉，狂吟滿坐聽。", "終期拋印綬，共占少微星。"]'),
('58ca8b46-9f12-44d1-a31a-6ec77c001a8d','到郡未浹日登西樓見樂天題詩因即事因寄','劉禹錫','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','湖上收宿雨，城中無晝塵。',48,'全唐诗/poet.tang.18000.json','["湖上收宿雨，城中無晝塵。", "樓依新柳貴，池帶亂苔春。", "雲水正一望，簿書來繞身。", "烟波洞庭路，愧彼扁舟人。"]'),
('471b85aa-25ec-415f-b305-f22f35249b13','秋夕不寐寄樂天','劉禹錫','唐','唐诗','tang','','[]','洞戶夜簾卷，華堂秋簟清。',48,'全唐诗/poet.tang.18000.json','["洞戶夜簾卷，華堂秋簟清。", "螢飛過池影，蛩思繞階聲。", "老枕知將雨，高窗報欲明。", "何人諳此景，遠問白先生。"]'),
('b8125932-c457-4eed-9772-311144659aed','冬日晨興寄樂天','劉禹錫','唐','唐诗','tang','','[]','庭樹曉禽動，郡樓殘點聲。',48,'全唐诗/poet.tang.18000.json','["庭樹曉禽動，郡樓殘點聲。", "燈挑紅燼落，酒煖白光生。", "髪少嫌梳利，顏衰恨鏡明。", "獨吟誰應和，須寄洛陽城。"]'),
('d3d914d8-b1a9-4911-9b9c-52d27471dd12','答樂天見憶','劉禹錫','唐','唐诗','tang','','[]','與老無期約，到來如等閑。',51,'全唐诗/poet.tang.18000.json','["與老無期約，到來如等閑。", "偏傷朋友盡，移興子孫間。", "筆底心無毒，杯前膽不{犭豖}。", "唯餘憶君夢，飛過武牢關。"]'),
('12f10b51-3e41-441a-9249-f68d07f4fa63','和樂天誚失婢牓者','劉禹錫','唐','唐诗','tang','','[]','把鏡朝猶在，添香夜不歸。',48,'全唐诗/poet.tang.18000.json','["把鏡朝猶在，添香夜不歸。", "鴛鴦拂瓦去，鸚鵡透籠飛。", "不逐張公子，即隨劉武威。", "新知正相樂，從此脫青衣。"]'),
('b8fc5f39-46b6-4b4f-a8fc-015229c25da9','八月十五日夜半雲開然後翫月因書一時之景寄呈樂天','劉禹錫','唐','唐诗','tang','','[]','半夜碧雲收，中天素月流。',48,'全唐诗/poet.tang.18000.json','["半夜碧雲收，中天素月流。", "開城邀好客，置酒賞清秋。", "影透衣香潤，光凝歌黛愁。", "斜輝猶可翫，移宴上西樓。"]'),
('044d7c1c-3445-430c-aa4d-800f5904ac77','秋日書懷寄白賓客','劉禹錫','唐','唐诗','tang','','[]','州遠雄無益，年高健亦衰。',48,'全唐诗/poet.tang.18000.json','["州遠雄無益，年高健亦衰。", "興情逢酒在，筋力上樓知。", "蟬噪芳意盡，鴈來愁望時。", "商山紫芝客，應不向秋悲。"]'),
('0f444611-635b-4274-92d1-a9a33efd32b0','詶樂天初冬早寒見寄','劉禹錫','唐','唐诗','tang','','[]','乍起衣猶冷，微吟帽半欹。',48,'全唐诗/poet.tang.18000.json','["乍起衣猶冷，微吟帽半欹。", "霜凝南屋瓦，雞唱後園枝。", "洛水碧雲曉，吳宮黃葉時。", "兩傳千里意，書札不如詩。"]'),
('d862e17f-e7da-43f5-a1f8-e537e482e953','和令狐相公郡齋對紫薇花','劉禹錫','唐','唐诗','tang','','[]','明麗碧天霞，丰茸紫綬花。',48,'全唐诗/poet.tang.18000.json','["明麗碧天霞，丰茸紫綬花。", "香聞荀令宅，豔入孝王家。", "幾歲自榮樂，高情方歎嗟。", "有人移上苑，猶足占年華。"]'),
('1ea6fac3-e3d7-4be0-9a91-da96abf23fda','令狐相公俯贈篇章斐然仰謝','劉禹錫','唐','唐诗','tang','','[]','鄂渚臨流別，梁園衝雪來。',48,'全唐诗/poet.tang.18000.json','["鄂渚臨流別，梁園衝雪來。", "旅愁隨凍釋，歡意待花開。", "城曉烏頻起，池春鴈欲回。", "飲和心自醉，何必管弦催。"]'),
('9015a136-058d-4c3b-9540-6cf29ff7b899','酬令狐相公早秋見寄','劉禹錫','唐','唐诗','tang','','[]','公來第四秋，樂國號無愁。',48,'全唐诗/poet.tang.18000.json','["公來第四秋，樂國號無愁。", "軍士遊書肆，商人占酒樓。", "熊羆交黑矟，賓客滿青油。", "今日文章主，梁王不姓劉。"]'),
('51ce1f0a-705f-44c9-9e1c-db211c181238','和令狐相公入潼關','劉禹錫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','寒光照旌節，關路曉無塵。',48,'全唐诗/poet.tang.18000.json','["寒光照旌節，關路曉無塵。", "吏謁前丞相，山迎舊主人。", "東瞻軍府靜，西望敕書頻。", "心共黃河水，同昇天漢津。"]'),
('5fb59324-2136-41f0-82a7-a517efa537b2','和令狐相公尋白閣老見留小飲因贈','劉禹錫','唐','唐诗','tang','','[]','傲士更逢酒，樂天仍對花。',48,'全唐诗/poet.tang.19000.json','["傲士更逢酒，樂天仍對花。", "文章管星曆，情興占年華。", "宦達翻思退，名高却不誇。", "惟存浩然氣，相共賞煙霞。"]'),
('5aeb8ff1-73e4-49a5-b67c-e91b98a5d350','酬令狐相公雪中遊玄都見憶','劉禹錫','唐','唐诗','tang','','[]','好雪動高情，心期在玉京。',48,'全唐诗/poet.tang.19000.json','["好雪動高情，心期在玉京。", "人披鶴氅出，馬踏象筵行。", "照耀樓臺變，淋漓松桂清。", "玄都留五字，使入步虛聲。"]'),
('e0ee9fcf-9538-4402-9fe5-14f63b7e4016','和令狐相公以司空裴相見招南亭看雪四韻','劉禹錫','唐','唐诗','tang','','[]','重門不下關，樞務有餘閑。',48,'全唐诗/poet.tang.19000.json','["重門不下關，樞務有餘閑。", "上客同看雪，高亭盡見山。", "瑞呈霄漢外，興入笑言間。", "知是平陽會，人人帶酒還。"]'),
('3449103e-496f-47f2-aa5b-b81e3c7fd38b','和鄆州令狐相公春晚對花','劉禹錫','唐','唐诗','tang','','[]','朱門退公後，高興對花枝。',48,'全唐诗/poet.tang.19000.json','["朱門退公後，高興對花枝。", "望闕無窮思，看書欲盡時。", "含芳朝競發，凝豔晚相宜。", "人意殷勤惜，狂風豈得知。"]'),
('c880958c-a496-4906-bce3-fb6d1960e0d7','酬令狐相公春日言懷見寄','劉禹錫','唐','唐诗','tang','','[]','前陪看花處，鄰里近王昌。',48,'全唐诗/poet.tang.19000.json','["前陪看花處，鄰里近王昌。", "今想臨戎地，旌旗出汶陽。", "營飛柳絮雪，門耀戟枝霜。", "東望清河水，心隨艑上郎。"]'),
('fc2ca839-a75e-419b-b10b-48aa5b39df86','途次大梁雪中奉天平令狐相公書問兼示新什因思曩歲從此拜辭形於短篇以申仰謝','劉禹錫','唐','唐诗','tang','','[]','遠守宦情薄，故人書信來。',48,'全唐诗/poet.tang.19000.json','["遠守宦情薄，故人書信來。", "共曾花下別，今獨雪中回。", "紙尾得新什，眉頭還暫開。", "此時同鴈鶩，池上一徘徊。"]'),
('cc3a7980-f399-4fa0-af1e-a5adc1d5b7a1','酬令狐相公秋懷見寄','劉禹錫','唐','唐诗','tang','','[]','寂寞蟬聲靜，差池燕羽回。',48,'全唐诗/poet.tang.19000.json','["寂寞蟬聲靜，差池燕羽回。", "秋風憐越絕，朔氣想臺駘。", "相去數千里，無因同一杯。", "殷勤望飛鴈，新自塞垣來。"]'),
('7db3cfe0-60e9-4dd0-82fc-32046acb82a0','酬[太]原令狐相公見寄','劉禹錫','唐','唐诗','tang','','[]','書信來天外，瓊瑤滿匣中。',48,'全唐诗/poet.tang.19000.json','["書信來天外，瓊瑤滿匣中。", "衣冠南渡遠，旌節北門雄。", "鶴唳華亭月，馬嘶榆塞風。", "山川幾千里，惟有兩心同。"]'),
('b0614f11-4d88-4c60-ac6c-82a31f577cca','酬令狐相公歲暮遠懷見寄','劉禹錫','唐','唐诗','tang','','[]','別侶孤鶴怨，沖天威鳳歸。',48,'全唐诗/poet.tang.19000.json','["別侶孤鶴怨，沖天威鳳歸。", "容光一以間，夢想是耶非。", "芳訊遠彌重，知音老更稀。", "不如湖上鴈，北向整毛衣。"]'),
('dea7fe90-dc97-4928-bccb-93cbf47eb991','酬令狐相公親仁郭家花下即事見寄','劉禹錫','唐','唐诗','tang','','[]','荀令園林好，山公遊賞頻。',48,'全唐诗/poet.tang.19000.json','["荀令園林好，山公遊賞頻。", "豈無花下侶，遠望眼中人。", "斜日漸移影，落英紛委塵。", "一吟相思曲，惆悵江南春。"]'),
('b2bc6a4c-5762-41fb-823c-8ef063558d4a','酬令狐相公首夏閑居書懷見寄','劉禹錫','唐','唐诗','tang','','[]','蕙草芳未歇，綠槐陰已成。',48,'全唐诗/poet.tang.19000.json','["蕙草芳未歇，綠槐陰已成。", "金罍唯獨酌，瑤瑟有離聲。", "翔泳各殊勢，篇章空寄情。", "應憐三十載，未變使君名。"]'),
('e4417fb7-c663-4f78-a4c5-ff279a5a5579','酬令狐相公庭前白菊花謝偶書所懷見寄','劉禹錫','唐','唐诗','tang','','[]','數叢如雪色，一旦冒霜開。',48,'全唐诗/poet.tang.19000.json','["數叢如雪色，一旦冒霜開。", "寒蘂差池落，清香斷續來。", "思深含別怨，芳謝惜年催。", "千里難同賞，看看又早梅。"]'),
('9fa51844-e14e-4b31-9f86-d56b660b009c','酬令狐相公季冬南郊宿齋見寄','劉禹錫','唐','唐诗','tang','','[]','壇下雪初霽，南城凍欲生。',48,'全唐诗/poet.tang.19000.json','["壇下雪初霽，南城凍欲生。", "齋心祠上帝，高步領名卿。", "沐浴含芳澤，周旋聽佩聲。", "猶憐廣平守，寂寞竟何成。"]'),
('a3c13747-6de4-4110-92dc-114999ae6cae','貞元中侍郎舅氏牧華州時余再忝科第前後由華覲謁陪登伏毒寺屢焉亦曾賦詩題於梁棟今典馮詡暇日登樓南望三峰浩然生思追想昔年之事因成篇題舊寺','劉禹錫','唐','唐诗','tang','','[]','曾作關中客，頻經伏毒巖。',48,'全唐诗/poet.tang.19000.json','["曾作關中客，頻經伏毒巖。", "晴煙沙苑樹，晚日渭川帆。", "昔是青春貌，今悲白雪髯。", "郡樓空一望，含意卷高簾。"]'),
('201c5d1c-900e-4772-950b-7462b0927cdf','酬令狐相公杏園花下飲有懷見寄','劉禹錫','唐','唐诗','tang','','[]','年年曲江望，花發即經過。',48,'全唐诗/poet.tang.19000.json','["年年曲江望，花發即經過。", "未飲心先醉，臨風思倍多。", "三春看又盡，兩地欲如何。", "日望長安道，空成勞者歌。"]'),
('f4613fb0-ddac-4218-8e28-73ff327fee9d','令狐相公見示題洋州崔侍郎宅雙木瓜花頃接侍郎同舍陪宴樹下吟翫來什輒成和章','劉禹錫','唐','唐诗','tang','','[]','金牛蜀樓遠，玉樹帝城春。',48,'全唐诗/poet.tang.19000.json','["金牛蜀樓遠，玉樹帝城春。", "榮耀生華館，逢迎欠主人。", "簾前疑小雪，牆外麗行塵。", "來去皆回首，情深是德鄰。"]'),
('62c3f011-7cbc-4ff2-a87c-95486d6b391a','和令狐相公春早朝回鹽鐵使院中作','劉禹錫','唐','唐诗','tang','','[]','柳動御溝清，威遲堤上行。',48,'全唐诗/poet.tang.19000.json','["柳動御溝清，威遲堤上行。", "城隅日未過，山色雨初晴。", "鶯避傳呼起，花臨府署明。", "簿書盈几案，要自有高情。"]'),
('1f3d32bb-da81-4169-b71f-62f9c2144551','和令狐僕射相公題龍回寺','劉禹錫','唐','唐诗','tang','','[]','茲地回鑾日，皇家禪聖時。',48,'全唐诗/poet.tang.19000.json','["茲地回鑾日，皇家禪聖時。", "路無胡馬跡，人識漢官儀。", "天子旌旗度，法王龍象隨。", "知懷去家歎，經此益遲遲。"]'),
('9d9d35f7-b9dc-44cd-9a31-30d7fabfab49','令狐相公頻示新什早春南望遐想漢中因抒短章以寄情愫','劉禹錫','唐','唐诗','tang','','[]','軍城臨漢水，旌斾起春風。',48,'全唐诗/poet.tang.19000.json','["軍城臨漢水，旌斾起春風。", "遠思見江草，歸心看塞鴻。", "野花沿古道，新葉映行宮。", "惟有詩兼酒，朝朝兩不同。"]'),
('2d7b793a-4237-41b6-b357-b3448d6f37ac','和令狐相公詠梔子花','劉禹錫','唐','唐诗','tang','','[]','蜀國花已盡，越桃今已開。',48,'全唐诗/poet.tang.19000.json','["蜀國花已盡，越桃今已開。", "色疑瓊樹倚，香似玉京來。", "且賞同心處，那憂別葉催。", "佳人如擬詠，何必待寒梅。"]'),
('918f6ea4-5bec-49fb-ab5d-5ff4b8971153','詶令狐相公新蟬見寄','劉禹錫','唐','唐诗','tang','','[]','相去三千里，聞蟬同此時。',48,'全唐诗/poet.tang.19000.json','["相去三千里，聞蟬同此時。", "清吟曉露葉，愁噪夕陽枝。", "忽爾弦斷絕，俄聞管參差。", "洛橋碧雲晚，西望佳人期。"]'),
('df15aeb6-d2f4-47a9-a294-fc080f860c03','詶樂天閑臥見寄','劉禹錫','唐','唐诗','tang','','[]','散誕向陽眠，將閑敵地仙。',48,'全唐诗/poet.tang.19000.json','["散誕向陽眠，將閑敵地仙。", "詩情茶助爽，藥力酒能宣。", "風碎竹間日，露明池底天。", "同年未同隱，緣欠買山錢。"]'),
('0fae33d9-b8de-436c-a742-b769de12af9a','詶樂天小亭寒夜有懷','劉禹錫','唐','唐诗','tang','','[]','寒夜陰雲起，疎林宿鳥驚。',48,'全唐诗/poet.tang.19000.json','["寒夜陰雲起，疎林宿鳥驚。", "斜風閃燈影，迸雪打窗聲。", "竟夕不能寐，同年知此情。", "漢皇無奈老，何況本書生。"]'),
('929aa3d8-e82f-4905-81fa-2842256e9863','將之官留辭裴令公留守','劉禹錫','唐','唐诗','tang','','[]','祖帳臨伊水，前旌指渭河。',48,'全唐诗/poet.tang.19000.json','["祖帳臨伊水，前旌指渭河。", "風煙里數少，雲雨別情多。", "重疊受恩久，邅回如命何。", "東山與東閣，終異再經過。"]'),
('946dc59e-313f-4094-80e1-4edd39a8215f','詶喜相遇同州與樂天替代','劉禹錫','唐','唐诗','tang','','[]','舊託松心契，新交竹使符。',48,'全唐诗/poet.tang.19000.json','["舊託松心契，新交竹使符。", "行年同甲子，筋力羨丁夫。", "別後詩成帙，攜來酒滿壺。", "今朝停五馬，不獨爲羅敷。"]'),
('664a1587-6f6d-4d23-aa2b-14193018d5a3','閒坐憶樂天以詩問酒熟未','劉禹錫','唐','唐诗','tang','','[]','案頭開縹帙，肘後檢青囊。',48,'全唐诗/poet.tang.19000.json','["案頭開縹帙，肘後檢青囊。", "唯有達生理，應無治老方。", "減書存眼力，省事養心王。", "君酒何時熟，相攜入醉鄉。"]'),
('7037f3d3-652f-48d9-ba29-dd44893ea77e','秋中暑退贈樂天','劉禹錫','唐','唐诗','tang','','[]','暑服宜秋著，清琴入夜彈。',48,'全唐诗/poet.tang.19000.json','["暑服宜秋著，清琴入夜彈。", "人情皆向菊，風意欲摧蘭。", "歲稔貧心泰，天涼病體安。", "相逢取次第，却甚少年歡。"]'),
('0a96850c-2e49-4c26-879d-a84eae5d8b9e','樂天池館夏景方妍白蓮初開綵舟空泊唯邀緇侶因以戲之','劉禹錫','唐','唐诗','tang','','[]','池館今正好，主人何寂然。',48,'全唐诗/poet.tang.19000.json','["池館今正好，主人何寂然。", "白蓮方出水，碧樹未鳴蟬。", "靜室宵聞磬，齋廚晚絕煙。", "蕃僧如共載，應不是神仙。"]'),
('207b8904-f16a-48db-84db-6659d74aa2f7','詶樂天感秋涼見寄','劉禹錫','唐','唐诗','tang','','[]','庭晚初辨色，林秋微有聲。',48,'全唐诗/poet.tang.19000.json','["庭晚初辨色，林秋微有聲。", "槿衰猶強笑，蓮逈却多情。", "簷燕歸心動，韝鷹俊氣生。", "閑人占閑景，酒熟且同傾。"]'),
('0e34f769-0796-4076-a958-9a10f3962202','秋晚新晴夜月如練有懷樂天','劉禹錫','唐','唐诗','tang','','[]','雨歇晚霞明，風調夜景清。',48,'全唐诗/poet.tang.19000.json','["雨歇晚霞明，風調夜景清。", "月高微暈散，雲薄細鱗生。", "露草百蟲思，秋林千葉聲。", "相望一步地，脉脉萬重情。"]'),
('3848e473-6f18-469a-be75-1b1cc4dfc9fb','新秋對月寄樂天','劉禹錫','唐','唐诗','tang','','[]','月露發光彩，此時方見秋。',48,'全唐诗/poet.tang.19000.json','["月露發光彩，此時方見秋。", "夜涼金氣應，天靜火星流。", "蛩響偏依井，螢飛直過樓。", "相知盡白首，清景復追遊。"]'),
('3934e725-f7e9-4639-9677-0e9abd8fbd0d','詶樂天小臺晚坐見憶','劉禹錫','唐','唐诗','tang','','[]','小臺堪遠望，獨上清秋時。',48,'全唐诗/poet.tang.19000.json','["小臺堪遠望，獨上清秋時。", "有酒無人勸，看山秖自知。", "幽禽囀新竹，孤蓮落靜池。", "高門勿遽掩，好客無前期。"]'),
('7108fd3d-d932-4c04-b672-95a23970fee8','早秋雨後寄樂天','劉禹錫','唐','唐诗','tang','','[]','夜雲起河漢，朝雨灑高林。',48,'全唐诗/poet.tang.19000.json','["夜雲起河漢，朝雨灑高林。", "梧葉先風落，草蟲迎濕吟。", "簟涼扇恩薄，室靜琴思深。", "且喜炎前別，安能懷寸陰。"]'),
('030c6a82-4216-4e52-b1b8-15b91b764680','秋晚病中樂天以詩見問力疾奉酬','劉禹錫','唐','唐诗','tang','','[]','耳虛多聽遠，展傳晨雞鳴。',48,'全唐诗/poet.tang.19000.json','["耳虛多聽遠，展傳晨雞鳴。", "一室背燈臥，中宵掃葉聲。", "蘭芳經雨敗，鶴病得秋輕。", "肯踏衡門草，唯應是友生。"]'),
('9d784de3-ecc1-42d9-889c-404ff5302614','和樂天燒藥不成命酒獨醉','劉禹錫','唐','唐诗','tang','','[]','九轉欲成就，百神應主持。',48,'全唐诗/poet.tang.19000.json','["九轉欲成就，百神應主持。", "嬰啼鼎上去，老貌鏡前悲。", "却顧空丹竈，回心向酒巵。", "醺然耳熱後，暫似少年時。"]'),
('c4e45aca-6a1a-4cdb-a334-f95d7cbfe76e','元日樂天見過因舉酒爲賀','劉禹錫','唐','唐诗','tang','','[]','漸入有年數，喜逢新歲來。',48,'全唐诗/poet.tang.19000.json','["漸入有年數，喜逢新歲來。", "震方天籟動，寅位帝車回。", "門巷掃殘雪，林園驚早梅。", "與君同甲子，壽酒讓先杯。"]'),
('550bc038-417f-4cb7-b36f-9583aa468185','詶馬大夫以愚獻通草茇葜酒感通拔二字因而寄別之作','劉禹錫','唐','唐诗','tang','','[]','泥沙難振拔，誰復問窮通。',48,'全唐诗/poet.tang.19000.json','["泥沙難振拔，誰復問窮通。", "莫訝提壺贈，家傳枕麴風。", "成謠獨酌後，深意片言中。", "不進終無已，應須荀令公。"]'),
('cc26a82f-14b4-4928-89ed-cc9b47c5b173','奉和司空裴相公中書即事通簡舊僚之作','劉禹錫','唐','唐诗','tang','','[]','譚笑在巖廊，人人盡所長。',48,'全唐诗/poet.tang.19000.json','["譚笑在巖廊，人人盡所長。", "儀形見山立，文字動星光。", "日運丹青筆，時看赤白囊。", "佇聞戎馬息，入賀領鴛行。"]'),
('7630b188-5b47-4f80-83cd-7f1066c4b876','微之鎮武昌中路見寄藍橋懷舊之作悽然繼和兼寄安平','劉禹錫','唐','唐诗','tang','','[]','今日油幢引，他年黃紙追。',48,'全唐诗/poet.tang.19000.json','["今日油幢引，他年黃紙追。", "同爲三楚客，獨有九霄期。", "宿草恨長在，傷禽飛尚遲。", "武昌應已到，新柳映紅旗。"]'),
('2bb83070-1196-4468-8e88-f7076973c04e','將赴蘇州途出洛陽留守李相公累申宴餞寵行話舊形於篇章謹抒下情以申仰謝','劉禹錫','唐','唐诗','tang','','[]','歲杪風物動，雪餘宮苑晴。',48,'全唐诗/poet.tang.19000.json','["歲杪風物動，雪餘宮苑晴。", "兔園賓客至，金谷管弦聲。", "洛水故人別，吳宮新燕迎。", "越郎憂不淺，懷袖有瓊英。"]'),
('6bc87011-6c1e-4b95-9c3b-d905d6210560','牛相公留守見示城外新墅有溪竹秋月親情多往宿遊恨不得去因成四韻兼簡洛中親故之什兼命同作','劉禹錫','唐','唐诗','tang','','[]','別墅洛城外，月明村野通。',48,'全唐诗/poet.tang.19000.json','["別墅洛城外，月明村野通。", "光輝滿地上，絲管發舟中。", "堤豔菊花露，島涼松葉風。", "高情限清禁，寒漏滴深宮。"]'),
('e08df5bb-2624-4182-907c-90bca0177c84','牛相公林亭雨後偶成','劉禹錫','唐','唐诗','tang','','[]','飛雨過池閣，浮光生草樹。',48,'全唐诗/poet.tang.19000.json','["飛雨過池閣，浮光生草樹。", "新竹開粉奩，初蓮爇香注。", "野花無時節，水鳥自來去。", "若問知境人，人間第一處。"]'),
('648e9ce0-1c9e-4fc0-8139-b6284232ae34','詶滑州李尚書秋日見寄','劉禹錫','唐','唐诗','tang','','[]','一入石渠署，三聞宮樹蟬。',48,'全唐诗/poet.tang.19000.json','["一入石渠署，三聞宮樹蟬。", "丹霄未得路，白髮又添年。", "雙節外臺貴，孤簫中禁傳。", "徵黃在旦夕，早晚發南燕。"]'),
('9ad03d65-0953-4326-8d85-9e69bb02b4de','和西川李尚書漢州微月遊房太尉西湖','劉禹錫','唐','唐诗','tang','','["\u897f\u6e56"]','木落漢川夜，西湖懸玉鈎。',48,'全唐诗/poet.tang.19000.json','["木落漢川夜，西湖懸玉鈎。", "旌旗環水次，舟檝泛中流。", "目極想前事，神交如共遊。", "瑤琴久已絕，松韻自悲秋。"]'),
('dea59950-cccb-4045-9d92-68d5fdecbb74','和重題','劉禹錫','唐','唐诗','tang','','[]','林端落照盡，湖上遠嵐清。',48,'全唐诗/poet.tang.19000.json','["林端落照盡，湖上遠嵐清。", "水榭芝蘭室，仙舟魚鳥情。", "人琴久寂寞，煙月若平生。", "一泛釣璜處，再吟鏘玉聲。"]'),
('10c8d216-301d-46e2-b91c-1d660e31f920','酬李相公喜歸鄉國自鞏縣夜泛洛水見寄','劉禹錫','唐','唐诗','tang','','[]','鞏樹煙月上，清光含碧流。',48,'全唐诗/poet.tang.19000.json','["鞏樹煙月上，清光含碧流。", "且無三已色，猶泛五湖州。", "鵬息風還起，鳳歸林正秋。", "雖攀小山桂，此地不淹留。"]'),
('4ea737f1-64a6-450b-9fec-1e8dc45a551a','和李相公平泉潭上喜見初月','劉禹錫','唐','唐诗','tang','','[]','家山見初月，林壑悄無塵。',48,'全唐诗/poet.tang.19000.json','["家山見初月，林壑悄無塵。", "幽境此何夕，清光如爲人。", "潭空破鏡入，風動翠蛾嚬。", "會向瑣窗望，追思伊洛濱。"]'),
('2d616ff7-6752-47e6-913d-b14d7240724c','和李相公初歸平泉過龍門南嶺遙望山居即事','劉禹錫','唐','唐诗','tang','','[]','暫別明庭去，初隨優詔還。',48,'全唐诗/poet.tang.19000.json','["暫別明庭去，初隨優詔還。", "曾爲鵬鳥賦，喜過鑿龍山。", "新墅煙火起，野程泉石間。", "巖廊人望在，只得片時閑。"]'),
('3fc2ef47-7eb6-4a85-90fd-29bf2499b691','和李相公以平泉新墅獲方外之名因爲詩以報洛中士君子兼見寄之什','劉禹錫','唐','唐诗','tang','','[]','業繼韋平後，家依崑閬間。',48,'全唐诗/poet.tang.19000.json','["業繼韋平後，家依崑閬間。", "恩華辭北第，瀟灑愛東山。", "滿室圖書在，入門松菊閑。", "垂天雖暫息，一舉出人寰。"]'),
('e33f2321-34c7-4328-99cc-99e0ad299663','發蘇州後登武丘寺望海樓','劉禹錫','唐','唐诗','tang','','[]','獨宿望海樓，夜深珍木冷。',48,'全唐诗/poet.tang.19000.json','["獨宿望海樓，夜深珍木冷。", "僧房已閉戶，山月方出嶺。", "碧池涵劒彩，寶剎搖星影。", "却憶郡齋中，虛眠此時景。"]'),
('14ae1987-b0e2-4b19-a5c0-4357d11b1d4b','松江送處州奚使君','劉禹錫','唐','唐诗','tang','','[]','吳越古今路，滄波朝夕流。',48,'全唐诗/poet.tang.19000.json','["吳越古今路，滄波朝夕流。", "從來別離地，能使管弦愁。", "江草帶煙暮，海雲含雨秋。", "知君五陵客，不樂石門遊。"]'),
('f7532cc0-cfc6-45f3-bc59-19fd20dae9fa','題報恩寺','劉禹錫','唐','唐诗','tang','','[]','雲外支硎寺，名聲敵虎丘。',48,'全唐诗/poet.tang.19000.json','["雲外支硎寺，名聲敵虎丘。", "石文留馬跡，峰勢聳牛頭。", "泉眼潛通海，松門預帶秋。", "遲回好風景，王謝昔曾遊。"]'),
('fbc554bf-3f39-417a-8dfc-13df26ea897d','罷郡姑蘇北歸渡楊子津 一','劉禹錫','唐','唐诗','tang','','[]','幾歲悲南國，今朝賦北征。',48,'全唐诗/poet.tang.19000.json','["幾歲悲南國，今朝賦北征。", "歸心渡江勇，病體得秋輕。", "海闊石門小，城高粉堞明。", "金山舊遊寺，過岸聽鐘聲。"]'),
('504c8b34-934f-4cf4-825e-7c21367cc600','罷郡姑蘇北歸渡楊子津 二','劉禹錫','唐','唐诗','tang','','[]','故國荒臺在，前臨震澤波。',48,'全唐诗/poet.tang.19000.json','["故國荒臺在，前臨震澤波。", "綺羅隨世盡，麋鹿古時多。", "築用金鎚力，摧因石鼠窠。", "昔年雕輦路，唯有采樵歌。"]'),
('b14970ed-be35-4978-a51a-2d7b2d2b1e0f','尋汪道士不遇','劉禹錫','唐','唐诗','tang','','[]','仙子東南秀，泠然善馭風。',48,'全唐诗/poet.tang.19000.json','["仙子東南秀，泠然善馭風。", "笙歌五雲裏，天地一壺中。", "受籙金華洞，焚香玉帝宮。", "我來君閉戶，應是向崆峒。"]'),
('fbcc4fc7-4bd6-4797-8c43-9fecb5e3d344','謝柳子厚寄疊石硯','劉禹錫','唐','唐诗','tang','','[]','常時同硯席，寄硯感離羣。',48,'全唐诗/poet.tang.19000.json','["常時同硯席，寄硯感離羣。", "清越敲寒玉，參差疊碧雲。", "烟嵐馀斐亹，水墨兩氛氳。", "好與陶貞白，松窻寫紫文。"]'),
('612e9207-ea91-44c1-aa45-1eeae0285734','元日感懷','劉禹錫','唐','唐诗','tang','','["\u8282\u65e5", "\u6625\u5929"]','振蟄春潛至，湘南人未歸。',48,'全唐诗/poet.tang.19000.json','["振蟄春潛至，湘南人未歸。", "身加一日長，心覺去年非。", "燎火委虛燼，兒童衒彩衣。", "異鄉無舊識，車馬到門稀。"]'),
('960c39b7-c199-40df-8d25-e782c8a7b85b','謝宣州崔相公賜馬','劉禹錫','唐','唐诗','tang','','[]','浮雲金絡膝，昨日別朱輪。',48,'全唐诗/poet.tang.19000.json','["浮雲金絡膝，昨日別朱輪。", "銜草如懷戀，嘶風尚意頻。", "曾將此君子，不是換佳人。", "從此西歸路，應容躡後塵。"]'),
('fc74e687-ef60-4bba-a32c-2563eb75dab6','南中書來','劉禹錫','唐','唐诗','tang','','[]','君書問風俗，此地接炎州。',48,'全唐诗/poet.tang.19000.json','["君書問風俗，此地接炎州。", "淫祀多青鬼，居人少白頭。", "旅情偏在夜，鄉思豈唯秋。", "每羨朝宗水，門前盡日流。"]'),
('74e89e85-382e-46c4-9fa8-f7e49bd13d8f','題招隱寺','劉禹錫','唐','唐诗','tang','','[]','隱士遺塵在，高僧精舍開。',48,'全唐诗/poet.tang.19000.json','["隱士遺塵在，高僧精舍開。", "地形臨渚斷，江勢觸山回。", "楚野花多思，南禽聲例哀。", "殷勤最高頂，閑即望鄉來。"]'),
('1ae3b53e-bcc3-4734-b9d1-3db497fff9c7','思歸寄山中友人','劉禹錫','唐','唐诗','tang','','[]','蕭條對秋色，相憶在雲泉。',48,'全唐诗/poet.tang.19000.json','["蕭條對秋色，相憶在雲泉。", "木落病身死，潮平歸思懸。", "涼鐘山頂寺，暝火渡頭船。", "此地非吾土，閑留又一年。"]'),
('7ee01859-bb0e-4169-8606-97d76c221205','有感','劉禹錫','唐','唐诗','tang','','[]','死且不自覺，其餘安可論。',48,'全唐诗/poet.tang.19000.json','["死且不自覺，其餘安可論。", "昨宵鳳池客，今日雀羅門。", "騎吏塵未息，銘旌風已翻。", "平生紅粉愛，惟解哭黃昏。"]'),
('439a098e-5c3d-4b0d-a1d1-c1805d631c28','途次敷水驛伏覩華州舅氏昔日行縣題詩處潸然有感','劉禹錫','唐','唐诗','tang','','[]','昔日股肱守，朱輪茲地遊。',48,'全唐诗/poet.tang.19000.json','["昔日股肱守，朱輪茲地遊。", "繁華日已謝，章句此空留。", "蔓草佳城閉，故林棠樹秋。", "今來重垂淚，不忍過西州。"]'),
('0b24c2da-6ef2-4bd7-860f-73eace37d8be','奉和鄭相公以考功十弟山薑花俯賜篇詠','劉禹錫','唐','唐诗','tang','','[]','採擷黃薑蘂，封題青瑣闈。',48,'全唐诗/poet.tang.19000.json','["採擷黃薑蘂，封題青瑣闈。", "共聞調膳日，正是退朝歸。", "響爲纖筵發，情隨綵翰飛。", "故將天下寶，萬里與光輝。"]'),
('7364c048-390a-4738-8531-784ad5f1214e','題淳于髠墓','劉禹錫','唐','唐诗','tang','','[]','生爲齊贅壻，死作楚先賢。',48,'全唐诗/poet.tang.19000.json','["生爲齊贅壻，死作楚先賢。", "應以客卿葬，故臨官道邊。", "寓言本多興，放意能合權。", "我有一石酒，置君墳樹前。"]'),
('e67c329e-9b04-4df6-8da3-e1dcdcf0a7df','送春詞','劉禹錫','唐','唐诗','tang','','[]','昨來樓上迎春處，今日登樓又送歸。',64,'全唐诗/poet.tang.19000.json','["昨來樓上迎春處，今日登樓又送歸。", "蘭蘂殘妝含露泣，柳條長袖向風揮。", "佳人對鏡容顏改，楚客臨江心事違。", "萬古至今同此恨，無如一醉盡忘機。"]'),
('58c193c7-8a99-4873-a2a6-7511c329a47c','送李尚書鎮滑州','劉禹錫','唐','唐诗','tang','','["\u9ec4\u6cb3"]','南徐報政入文昌，東郡須才別建章。',64,'全唐诗/poet.tang.19000.json','["南徐報政入文昌，東郡須才別建章。", "視草名高同蜀客，擁旄年少勝荀郎。", "黃河一曲當城下，緹騎千重照路傍。", "自古相門還出相，如今人望在巖廊。"]'),
('98df5092-0327-4427-a188-19cc9decf46a','送渾大夫赴豐州','劉禹錫','唐','唐诗','tang','','[]','鳳銜新詔降恩華，又見旌旗出渾家。',64,'全唐诗/poet.tang.19000.json','["鳳銜新詔降恩華，又見旌旗出渾家。", "故吏來辭辛屬國，精兵願逐李輕車。", "氈裘君長迎風馭，錦帶酋豪踏雪衙。", "其奈明年好春日，無人喚看牡丹花。"]'),
('0ebfb8a6-9d9f-4150-bd83-ee21e72141c4','送源中丞充新羅冊立使','劉禹錫','唐','唐诗','tang','','[]','相門才子稱華簪，持節東行捧德音。',64,'全唐诗/poet.tang.19000.json','["相門才子稱華簪，持節東行捧德音。", "身帶霜威辭鳳闕，口傳天語到雞林。", "煙開鰲背千尋碧，日浴鯨波萬頃金。", "想見扶桑受恩處，一時西拜盡傾心。"]'),
('d77c5ac8-e977-4729-b491-8399d1702c86','送王司馬之陝州','劉禹錫','唐','唐诗','tang','','[]','暫輟清齋出太常，空攜詩卷赴甘棠。',64,'全唐诗/poet.tang.19000.json','["暫輟清齋出太常，空攜詩卷赴甘棠。", "府公既有朝中舊，司馬應容酒後狂。", "案牘來時唯署字，風煙入興便成章。", "兩京大道多遊客，每遇詞人戰一場。"]'),
('09a848fe-755b-4938-81e5-9fa442d45d35','洛中送楊處厚入關便遊蜀','劉禹錫','唐','唐诗','tang','','[]','洛陽秋日正淒淒，君去西秦更向西。',64,'全唐诗/poet.tang.19000.json','["洛陽秋日正淒淒，君去西秦更向西。", "舊學三冬今轉富，曾傷六翮養初齊。", "王城曉入窺丹鳳，蜀路晴來見碧雞。", "早識臥龍應有分，不妨從此躡丹梯。"]'),
('6806f014-1b0c-45a7-a647-684b3a42a7ab','送周使君罷渝州歸郢州別墅','劉禹錫','唐','唐诗','tang','','[]','君思郢上吟歸去，故自渝南擲郡章。',64,'全唐诗/poet.tang.19000.json','["君思郢上吟歸去，故自渝南擲郡章。", "野戍岸邊留畫舸，綠蘿陰下到山莊。", "池荷雨後依香起，庭草春深綬帶長。", "只恐鳴騶催上道，不容待得晚菘嘗。"]'),
('68febad0-9314-4bea-b54b-45487325eba4','奉送浙西李僕射相公赴鎮','劉禹錫','唐','唐诗','tang','','[]','建節東行是舊遊，歡聲喜氣滿吳州。',64,'全唐诗/poet.tang.19000.json','["建節東行是舊遊，歡聲喜氣滿吳州。", "郡人重得黃丞相，童子爭迎郭細侯。", "詔下初辭溫室樹，夢中先到景陽樓。", "自憐不識平津閣，遙望旌旗汝水頭。"]'),
('77827c6e-9ac8-4050-8a45-0bfcfe22948d','重送浙西李相公頃廉問江南已經七載後歴滑臺劍南兩鎮遂入相今復領舊地新加旌旄','劉禹錫','唐','唐诗','tang','','[]','江北萬人看玉節，江南千騎引金鐃。',64,'全唐诗/poet.tang.19000.json','["江北萬人看玉節，江南千騎引金鐃。", "鳳從池上遊滄海，鶴到遼東識舊巢。", "城下清波含百谷，窻中遠岫列三茅。", "碧雞白馬回翔久，却憶朱方是樂郊。"]'),
('ad9f94e9-3bfc-4ef1-912c-efd6fe4b7567','送前進士蔡京赴學究科','劉禹錫','唐','唐诗','tang','','[]','耳聞戰鼓帶經鋤，振發聲名自里閭。',64,'全唐诗/poet.tang.19000.json','["耳聞戰鼓帶經鋤，振發聲名自里閭。", "已是世間能賦客，更攻窻下絕編書。", "朱門達者誰能識，絳帳書生盡不如。", "幸遇天官舊丞相，知君無翼上空虛。"]'),
('246a2fc7-2c76-4d6d-93ba-86e6ff082352','送唐舍人出鎮閩中','劉禹錫','唐','唐诗','tang','','[]','暫辭鴛鷺出蓬瀛，忽擁貔貅鎮粤城。',64,'全唐诗/poet.tang.19000.json','["暫辭鴛鷺出蓬瀛，忽擁貔貅鎮粤城。", "閩嶺夏雲迎皂蓋，建溪秋樹映紅旌。", "山川遠地由來好，富貴當年別有情。", "了却人間婚嫁事，復歸朝右作公卿。"]'),
('be954dd8-282b-4452-8240-6869382e5008','送李中丞赴楚州','劉禹錫','唐','唐诗','tang','','[]','緹騎朱旗入楚城，士林皆賀振家聲。',64,'全唐诗/poet.tang.19000.json','["緹騎朱旗入楚城，士林皆賀振家聲。", "兒童但喜迎賓守，故吏猶應記姓名。", "萬頃水田連郭秀，四時烟月映淮清。", "憶君初得崑山玉，同向揚州攜手行。"]'),
('daf11f65-5c4a-43d7-96e1-8e48646e9475','奉送李戶部侍郎自河南尹再除本官歸闕','劉禹錫','唐','唐诗','tang','','[]','昔年內署振雄詞，今日東都結去思。',64,'全唐诗/poet.tang.19000.json','["昔年內署振雄詞，今日東都結去思。", "宮女猶傳洞簫賦，國人先詠衮衣詩。", "華星却復文昌位，別鶴重歸太乙池。", "想到金閨待通籍，一時驚喜見風儀。"]'),
('10e5d9aa-2a60-41f7-897a-1e4fd193492e','送蘄州李郎中赴任','劉禹錫','唐','唐诗','tang','','[]','楚關蘄水路非賒，東望雲山日夕佳。',64,'全唐诗/poet.tang.19000.json','["楚關蘄水路非賒，東望雲山日夕佳。", "薤葉照人呈夏簟，松花滿盌試新茶。", "樓中飲興因明月，江上詩情爲晚霞。", "北地交親長引領，早將玄鬢到京華。"]'),
('f6c50738-bff4-41a3-b593-f22cc276a159','送國子令狐博士赴興元覲省','劉禹錫','唐','唐诗','tang','','[]','相門才子高陽族，學省清資五品官。',64,'全唐诗/poet.tang.19000.json','["相門才子高陽族，學省清資五品官。", "諫院過時榮棣萼，謝庭歸去踏芝蘭。", "山中花帶煙嵐晚，棧底江涵雪水寒。", "伯仲到家人盡賀，柳營蓮府遞相歡。"]'),
('e364378d-e457-45b4-80c5-e76d755915a7','送李二十九兄員外赴邠寧使幕','劉禹錫','唐','唐诗','tang','','[]','家襲韋平身業文，素風清白至今貧。',64,'全唐诗/poet.tang.19000.json','["家襲韋平身業文，素風清白至今貧。", "南宮通籍新郎吏，西候從戎舊主人。", "城外草黃秋有雪，烽頭煙靜虜無塵。", "鼎門爲別霜天曉，賸把離殤三五巡。"]'),
('9d1e406b-2674-4099-8478-d8e9ac756c6c','送分司陳郎中秖召直史館重修三聖實録','劉禹錫','唐','唐诗','tang','','[]','蟬鳴官樹引行車，言自成周赴玉除。',64,'全唐诗/poet.tang.19000.json','["蟬鳴官樹引行車，言自成周赴玉除。", "遠取南朝貴公子，重修東觀帝王書。", "常時載筆窺金匱，暇日登樓到石渠。", "若問舊人劉子政，如今白首在南徐。"]'),
('bdd10dd8-c113-4f6f-a304-bcb500230553','送慧則法師歸上都因呈廣宣上人','劉禹錫','唐','唐诗','tang','','[]','昨日東林看講時，都人象馬蹋琉璃。',64,'全唐诗/poet.tang.19000.json','["昨日東林看講時，都人象馬蹋琉璃。", "雪山童子應前世，金粟如來是本師。", "一錫言歸九城路，三衣曾拂萬年枝。", "休公久別如相問，楚客逢秋心更悲。"]'),
('1ef50bf2-b4d2-4dce-b23a-188cd3b1d920','送義舟師却還黔南','劉禹錫','唐','唐诗','tang','','[]','黔江秋水浸雲霓，獨泛慈航路不迷。',64,'全唐诗/poet.tang.19000.json','["黔江秋水浸雲霓，獨泛慈航路不迷。", "猨狖窺齋林葉動，蛟龍聞咒浪花低。", "如蓮半偈心常悟，問菊新詩手自攜。", "常說摩圍似靈鷲，却將山屐上丹梯。"]'),
('616a784a-d942-4cf1-b0b3-9a2f98cfad8f','送景玄師東歸','劉禹錫','唐','唐诗','tang','','[]','東林寺裏一沙彌，心愛當時才子詩。',64,'全唐诗/poet.tang.19000.json','["東林寺裏一沙彌，心愛當時才子詩。", "山下偶隨流水出，秋來却赴白雲期。", "灘頭躡屐挑沙菜，路上停舟讀古碑。", "想到舊房拋錫杖，小松應有過簷枝。"]'),
('c9b7f6d9-8bac-4d85-a9bc-ddf7045fa9e7','漢壽城春望','劉禹錫','唐','唐诗','tang','','[]','漢壽城邊野草春，荒祠古墓對荆榛。',64,'全唐诗/poet.tang.19000.json','["漢壽城邊野草春，荒祠古墓對荆榛。", "田中牧豎燒芻狗，陌上行人看石麟。", "華表半空經霹靂，碑文纔見滿埃塵。", "不知何日東瀛變，此地還成要路津。"]'),
('17e143e7-b869-498b-a5ad-a667674afa5d','荆門道懷古','劉禹錫','唐','唐诗','tang','','[]','南國山川舊帝畿，宋臺梁館尚依稀。',64,'全唐诗/poet.tang.19000.json','["南國山川舊帝畿，宋臺梁館尚依稀。", "馬嘶古道行人歇，麥秀空城野雉飛。", "風吹落葉填宮井，火入荒陵化寶衣。", "徒使詞臣庾開府，咸陽終日苦思歸。"]'),
('29053389-2e59-46f7-b7c2-5ff91010224b','朗州竇員外見示與澧州元郎中郡齋贈答長句二篇因以繼和','劉禹錫','唐','唐诗','tang','','[]','鴛鷺差池出建章，綵旗朱戶蔚相望。',64,'全唐诗/poet.tang.19000.json','["鴛鷺差池出建章，綵旗朱戶蔚相望。", "新恩共理犬牙地，昨日同含雞舌香。", "白芷江邊分驛路，山桃蹊外接甘棠。", "應憐一罷金閨籍，枉渚逢春十度傷。"]'),
('519a0538-e33a-48a5-bb44-85000b3a5c5f','早春對雪奉寄澧州元郎中','劉禹錫','唐','唐诗','tang','','[]','新賜魚書墨未乾，賢人暫出遠人安。',64,'全唐诗/poet.tang.19000.json','["新賜魚書墨未乾，賢人暫出遠人安。", "朝驅旌斾行時令，夜見星辰憶舊官。", "梅蘂覆堦鈴閣暖，雪峰當戶戟枝寒。", "寧知楚客思公子，北望長吟澧有蘭。"]'),
('3fc8c4c3-b3a0-459b-a497-3b0f2ecfed57','竇朗州見示與澧州元郎中早秋贈荅命同作','劉禹錫','唐','唐诗','tang','','[]','鄰境諸侯同舍郎，芷江蘭浦恨無梁。',64,'全唐诗/poet.tang.19000.json','["鄰境諸侯同舍郎，芷江蘭浦恨無梁。", "秋風門外旌旗動，曉露庭中橘柚香。", "玉簟微涼宜白晝，金笳入暮應清商。", "騷人昨夜聞鶗鴂，不歎流年惜衆芳。"]'),
('b235d33a-c1c9-4009-b479-1491a607d9ab','松滋渡望峽中','劉禹錫','唐','唐诗','tang','','[]','渡頭輕雨灑寒梅，雲際溶溶雪水來。',64,'全唐诗/poet.tang.19000.json','["渡頭輕雨灑寒梅，雲際溶溶雪水來。", "夢渚草長迷楚望，夷陵土黑有秦灰。", "巴人淚應猿聲落，蜀客船從鳥道回。", "十二碧峰何處所，永安宮外是荒臺。"]'),
('d70bbc60-e7da-4754-b41f-35a8f9582596','衢州徐員外使君遺以縞紵兼竹書箱因成一篇用答佳貺','劉禹錫','唐','唐诗','tang','','[]','爛柯山下舊仙郎，列宿來添婺女光。',64,'全唐诗/poet.tang.19000.json','["爛柯山下舊仙郎，列宿來添婺女光。", "遠放歌聲分白紵，知傳家學與青箱。", "水朝滄海何時去，蘭在幽林亦自芳。", "聞說天台有遺愛，人將琪樹比甘棠。"]'),
('4db3331a-9825-49c5-8400-ea554a91180e','唐秀才贈端州紫石硯以詩答之','劉禹錫','唐','唐诗','tang','','[]','端州石硯人間重，贈我因知正草玄。',64,'全唐诗/poet.tang.19000.json','["端州石硯人間重，贈我因知正草玄。", "闕里廟堂空舊物，開方竈下豈天然。", "玉蜍吐水霞光靜，綵翰搖風絳錦鮮。", "此日傭工記名姓，因君數到墨池前。"]'),
('33c6012b-f14a-46e8-a869-8ed41271c3a1','覽董評事思歸之什因以詩贈','劉禹錫','唐','唐诗','tang','','[]','幾年油幕佐征東，却泛滄浪狎釣童。',64,'全唐诗/poet.tang.19000.json','["幾年油幕佐征東，却泛滄浪狎釣童。", "欹枕醉眠成戲蝶，抱琴閑望送歸鴻。", "文儒自襲膠西相，倚伏能齊塞上翁。", "更說扁舟動鄉思，青菰已熟奈秋風。"]'),
('9c1b6fde-6b08-458a-89d9-81676dcd6adb','謝寺雙檜','劉禹錫','唐','唐诗','tang','','[]','雙檜蒼然古貌奇，含煙吐霧鬱參差。',64,'全唐诗/poet.tang.19000.json','["雙檜蒼然古貌奇，含煙吐霧鬱參差。", "晚依禪客當金殿，初對將軍映畫旗。", "龍象界中成寶蓋，鴛鴦瓦上出高枝。", "長明燈是前朝焰，曾照青青年少時。"]'),
('9957348f-3e45-48cb-ac2e-f159fc56a9ba','寄楊八壽州','劉禹錫','唐','唐诗','tang','','[]','風獵紅旗入壽春，滿城歌舞向朱輪。',64,'全唐诗/poet.tang.19000.json','["風獵紅旗入壽春，滿城歌舞向朱輪。", "八公山下清淮水，千騎塵中白面人。", "桂嶺雨餘多鶴迹，茗園晴望似龍鱗。", "聖朝方用敢言者，次第應須舊諫臣。"]'),
('cce9f281-cd32-4689-beb4-5357c715bf54','洛中寺北樓見賀監草書題詩','劉禹錫','唐','唐诗','tang','','[]','高樓賀監昔曾登，壁上筆蹤龍虎騰。',64,'全唐诗/poet.tang.19000.json','["高樓賀監昔曾登，壁上筆蹤龍虎騰。", "中國書流尚皇象，北朝文士重徐陵。", "偶因獨見空驚目，恨不同時便伏膺。", "唯恐塵埃轉磨滅，再三珍重囑山僧。"]'),
('299c9713-fcdd-489e-93b0-24891e497314','聞韓賓擢第歸覲以詩美之兼賀韓十五曹長時韓牧永州','劉禹錫','唐','唐诗','tang','','[]','零陵香草滿郊坰，丹穴雛飛入翠屏。',64,'全唐诗/poet.tang.19000.json','["零陵香草滿郊坰，丹穴雛飛入翠屏。", "孝若歸來成畫讚，孟陽別後有山銘。", "蘭陔舊地花纔結，桂樹新枝色更青。", "爲報儒林丈人道，如今從此鬢星星。"]'),
('e8a3e9fe-ed3b-4150-8d31-cda06d9bfae2','宣上人遠寄和禮部王侍郎放榜後詩因而繼和','劉禹錫','唐','唐诗','tang','','[]','禮闈新榜動長安，九陌人人走馬看。',64,'全唐诗/poet.tang.19000.json','["禮闈新榜動長安，九陌人人走馬看。", "一日聲名遍天下，滿城桃李屬春官。", "自吟白雪詮詞賦，指示青雲借羽翰。", "借問至公誰印可，支郎天眼定中觀。"]'),
('9a7d146f-7fa2-4507-a7d8-420cdee2aaf2','贈東嶽張鍊師','劉禹錫','唐','唐诗','tang','','["\u6cf0\u5c71"]','東嶽真人張鍊師，高情雅淡世間稀。',64,'全唐诗/poet.tang.19000.json','["東嶽真人張鍊師，高情雅淡世間稀。", "堪爲列女書青簡，久事元君住翠微。", "金縷機中拋錦字，玉清臺上著霓衣。", "雲衢不要吹簫伴，只擬乘鸞獨自飛。"]'),
('a13ae539-59e5-41b2-9271-96901b39efad','秘書山崔少監見示墜馬長句因而和之','劉禹錫','唐','唐诗','tang','','[]','麟臺少[監]舊仙郎，洛水橋邊墜馬傷。',66,'全唐诗/poet.tang.19000.json','["麟臺少[監]舊仙郎，洛水橋邊墜馬傷。", "塵污腰間青襞綬，風飄掌上紫遊韁。", "上車著作應來問，折臂三公定送方。", "猶賴德全如醉者，不妨吟詠入篇章。"]'),
('002063b6-841e-48b8-a1d8-292bb68860b0','寄楊虢州與之舊姻','劉禹錫','唐','唐诗','tang','','[]','避地江湖知幾春，今來本郡擁朱輪。',64,'全唐诗/poet.tang.19000.json','["避地江湖知幾春，今來本郡擁朱輪。", "阮郎無復里中舊，楊僕却爲關外人。", "各繫一官難命駕，每懷前好易沾巾。", "玉城山裏多靈藥，擺落功名且養神。"]'),
('4b2dd846-576c-4d6d-9222-95b21061da58','秋日題竇員外崇德里新居','劉禹錫','唐','唐诗','tang','','[]','長愛街西風景閑，到君居處暫開顏。',64,'全唐诗/poet.tang.19000.json','["長愛街西風景閑，到君居處暫開顏。", "清光門外一渠水，秋色牆頭數點山。", "疎種碧松通月朗，多栽紅藥待春還。", "莫言堆案無餘地，認得詩人在此間。"]'),
('a4f2c1c8-8a89-46c2-a969-1a140915a270','蒙恩轉儀曹郎依前充集賢學士舉韓潮州自代因寄七言','劉禹錫','唐','唐诗','tang','','[]','翔鸞闕下謝恩初，通籍由來在石渠。',64,'全唐诗/poet.tang.19000.json','["翔鸞闕下謝恩初，通籍由來在石渠。", "暫入南宮判祥瑞，還歸內殿閱圖書。", "故人猶在三江外，同病凡經二紀餘。", "今日薦君嗟久滯，不惟文體似相如。"]'),
('5f171af4-d334-4709-ae5e-8c4dff073dd7','途次華州陪錢大夫登城北樓春望因覩李崔令狐三相國唱和之什翰林舊侶繼踵華城山水清高鸞鳳翔集皆忝宿眷遂題此詩','劉禹錫','唐','唐诗','tang','','[]','城樓四望出風塵，見盡關西渭北春。',64,'全唐诗/poet.tang.19000.json','["城樓四望出風塵，見盡關西渭北春。", "百二山河雄上國，一雙旌斾委名臣。", "壁中今日題詩處，天上同時草詔人。", "莫怪老郎呈濫吹，宦途雖別舊情親。"]'),
('8250a2b0-8b01-477c-b2ec-741ab9639f07','始聞秋風','劉禹錫','唐','唐诗','tang','','["\u52b1\u5fd7", "\u5199\u98ce", "\u79cb\u5929", "\u98ce"]','昔看黃菊與君別，今聽玄蟬我却回。',64,'全唐诗/poet.tang.19000.json','["昔看黃菊與君別，今聽玄蟬我却回。", "五夜颼飀枕前覺，一年顏狀鏡中來。", "馬思邊草拳毛動，雕眄青雲睡眼開。", "天地肅清堪四望，爲君扶病上高臺。"]'),
('9a00cce8-1114-4504-ada3-659321e53036','洛中初冬拜表有懷上京故人','劉禹錫','唐','唐诗','tang','','[]','鳳樓南面控三條，拜表郎官早渡橋。',64,'全唐诗/poet.tang.19000.json','["鳳樓南面控三條，拜表郎官早渡橋。", "清洛曉光鋪碧簟，上陽霜葉剪紅綃。", "省門簪組初成列，雲路鴛鸞想退朝。", "寄謝慇懃九天侶，搶榆水擊各逍遙。"]'),
('4a7a16f4-2af8-4e2f-b961-c0fb97cea449','尉遲郎中見示自南遷牽復却至洛城東舊居之作因以和之','劉禹錫','唐','唐诗','tang','','[]','曾遭飛語十年謫，新受恩光萬里還。',64,'全唐诗/poet.tang.19000.json','["曾遭飛語十年謫，新受恩光萬里還。", "朝服不妨遊洛浦，郊園依舊看嵩山。", "竹含天籟清商樂，水遶庭臺碧玉環。", "留作功成退身地，如今只是暫時閑。"]'),
('ecb62f6d-a038-4cc9-bfad-209e350bc553','洛中詶福建陳判官見贈','劉禹錫','唐','唐诗','tang','','[]','潦倒聲名擁腫材，一生多故苦邅迴。',64,'全唐诗/poet.tang.19000.json','["潦倒聲名擁腫材，一生多故苦邅迴。", "南宮舊籍遙相管，東洛閑門晝未開。", "靜對道流論藥石，偶逢詞客與瓊瑰。", "怪君近日文鋒利，新向延平看劒來。"]'),
('70b0526c-45fb-4932-b4a7-ebfbc8641ed8','和蘇十郎中謝病閑居時嚴常侍蕭給事同過訪歎初有二毛之作','劉禹錫','唐','唐诗','tang','','[]','清羸隱几望雲空，左掖鴛鸞到室中。',64,'全唐诗/poet.tang.19000.json','["清羸隱几望雲空，左掖鴛鸞到室中。", "一卷素書消永日，數莖斑髪對秋風。", "菱花照後容雖改，蓍草占來命已通。", "莫怪人人驚早白，緣君尚是黑頭翁。"]'),
('7b333c7c-9d52-40ee-bb01-92b0835a5d41','酬淮南廖參謀秋夕見過之作','劉禹錫','唐','唐诗','tang','','[]','揚州從事夜相尋，無限新詩月下吟。',64,'全唐诗/poet.tang.19000.json','["揚州從事夜相尋，無限新詩月下吟。", "初服已驚玄髪長，高情猶向碧雲深。", "語餘時舉一杯酒，坐久方聞四處砧。", "不逐繁華訪閑散，知君擺落俗人心。"]'),
('6ec78a65-18c4-42cb-9f6c-2529c1488e20','題王郎中宣義里新居','劉禹錫','唐','唐诗','tang','','[]','愛君新買街西宅，客到如遊鄠杜間。',64,'全唐诗/poet.tang.19000.json','["愛君新買街西宅，客到如遊鄠杜間。", "雨後退朝貪種樹，申時出省趂看山。", "門前巷陌三條近，牆內池亭萬境閑。", "見擬移居作鄰里，不論時節請開關。"]'),
('969c4162-0ee7-494f-a621-e077143fa371','酬朗州崔員外與任十四兄侍御同過鄙人舊居見懷之什時守吳郡','劉禹錫','唐','唐诗','tang','','[]','昔日居鄰招屈亭，楓林橘樹鷓鴣聲。',64,'全唐诗/poet.tang.19000.json','["昔日居鄰招屈亭，楓林橘樹鷓鴣聲。", "一辭御苑青門去，十見蠻江白芷生。", "自此曾沾宣室召，如今又守闔閭城。", "何人萬里能相憶，同舍仙郎與外兄。"]'),
('3ef5cd66-b496-4c17-b95a-af9b40cfe940','劉駙馬水亭避暑','劉禹錫','唐','唐诗','tang','','[]','千竿竹翠數蓮紅，水閣虛涼玉簟空。',64,'全唐诗/poet.tang.19000.json','["千竿竹翠數蓮紅，水閣虛涼玉簟空。", "琥珀琖紅疑漏酒，水晶簾瑩更通風。", "賜冰滿盌沈朱實，法饌盈盤覆碧籠。", "盡日逍遙避煩暑，再三珍重主人翁。"]'),
('1e289182-9ae3-4f90-ba93-4334c439f2cd','述舊賀遷寄陝虢孫常侍','劉禹錫','唐','唐诗','tang','','[]','南宮幸襲芝蘭後，左輔曾交印綬來。',64,'全唐诗/poet.tang.19000.json','["南宮幸襲芝蘭後，左輔曾交印綬來。", "多病未離清洛苑，新恩已歷望仙臺。", "關頭古塞桃林靜，城下長河竹箭回。", "聞說隨車有零雨，此時偏動子荆才。"]'),
('5403f872-7e74-4c22-b39a-7a94196e9839','江陵嚴司空見示與成都武相公唱和因命同作','劉禹錫','唐','唐诗','tang','','[]','南荆西蜀大行臺，幕府旌門相對開。',64,'全唐诗/poet.tang.19000.json','["南荆西蜀大行臺，幕府旌門相對開。", "名重三司平水土，威雄八陣役風雷。", "彩雲朝望青城起，錦浪秋經白帝來。", "不是郢中清唱發，誰當丞相掞天才。"]'),
('1121aee0-197f-40eb-8046-5c60ab4ac301','廟庭偃松詩','劉禹錫','唐','唐诗','tang','','[]','勢軋枝偏根已危，高情一見與扶持。',64,'全唐诗/poet.tang.19000.json','["勢軋枝偏根已危，高情一見與扶持。", "忽從顦顇有生意，却爲離披無俗姿。", "影入巖廊行樂處，韻含天籟宿齋時。", "謝公莫道東山去，待取陰成滿鳳池。"]'),
('b6ccd052-5e40-4a04-9ddc-aaad79a695e0','贈致仕滕庶子先輩','劉禹錫','唐','唐诗','tang','','[]','朝服歸來晝錦榮，登科記上更無兄。',66,'全唐诗/poet.tang.19000.json','["朝服歸來晝錦榮，登科記上更無兄。", "壽觴每使曾孫獻，勝境長攜衆妓行。", "[矍]鑠據鞍時騁健，殷勤把酒尚多情。", "凌寒却向山陰去，衣繡郎君雪裏行。"]'),
('f6e94fa5-3a8a-4b2b-abbb-50d1755ee354','哭呂衡州時予方謫居','劉禹錫','唐','唐诗','tang','','[]','一夜霜風凋玉芝，蒼生望絕士林悲。',64,'全唐诗/poet.tang.19000.json','["一夜霜風凋玉芝，蒼生望絕士林悲。", "空懷濟世安人略，不見男婚女嫁時。", "遺草一函歸太史，旅墳三尺近要離。", "朔方徙歲行當滿，欲爲君刊第二碑。"]'),
('080d5239-4ac7-4c20-95b9-b60f78669025','夔州竇員外使君見示悼妓詩顧余嘗識之因命同作','劉禹錫','唐','唐诗','tang','','[]','前年曾見兩鬟時，今日驚吟悼妓詩。',64,'全唐诗/poet.tang.19000.json','["前年曾見兩鬟時，今日驚吟悼妓詩。", "鳳管學成知有籍，龍媒欲換歎無期。", "空廊月照常行地，後院花開舊折枝。", "寂寞魚山青草裏，何人更立智瓊祠。"]'),
('085886a9-c80b-4405-87c3-7b95fac67561','竇夔州見寄寒食日憶故姬小紅吹笙因和之','劉禹錫','唐','唐诗','tang','','[]','鸞聲窈眇管參差，清韻初調衆樂隨。',64,'全唐诗/poet.tang.19000.json','["鸞聲窈眇管參差，清韻初調衆樂隨。", "幽院妝成花下弄，高樓月好夜深吹。", "忽驚暮雨飄零盡，唯有朝雲夢想期。", "聞道今年寒食日，東山舊路獨行遲。"]'),
('1551eb29-69d8-4057-8238-541627f551b4','哭龐京兆','劉禹錫','唐','唐诗','tang','','[]','俊骨英才氣褎然，策名飛步冠羣賢。',64,'全唐诗/poet.tang.19000.json','["俊骨英才氣褎然，策名飛步冠羣賢。", "逢時已自致高位，得疾還因倚少年。", "天上別歸京兆府，人間空數茂陵阡。", "今朝穗帳哭君處，前日見鋪歌舞筵。"]'),
('71536ef1-bcdf-4637-9536-47c2467dfdfa','送李庚先輩赴選','劉禹錫','唐','唐诗','tang','','[]','一家何啻十朱輪，諸父雙飛秉大鈞。',64,'全唐诗/poet.tang.19000.json','["一家何啻十朱輪，諸父雙飛秉大鈞。", "曾脫素衣參幕客，却爲精舍讀書人。", "離筵雒水侵杯色，征路函關向晚塵。", "今日山公舊賓主，知君不負帝城春。"]'),
('63e361b2-ef5d-4c55-908b-bccca46c33cc','陽山廟觀賽神','劉禹錫','唐','唐诗','tang','','[]','漢家都尉舊征蠻，血食如今配此山。',64,'全唐诗/poet.tang.19000.json','["漢家都尉舊征蠻，血食如今配此山。", "曲蓋幽深蒼檜下，洞簫愁絕翠屏間。", "荆巫脉脉傳神語，野老娑娑起醉顏。", "日落風生廟門外，幾人連蹋竹歌還。"]'),
('6c784bb2-ed8b-4421-9b8d-21075fafd808','送僧元暠東遊','劉禹錫','唐','唐诗','tang','','[]','寶書翻譯學初成，振錫如飛白足輕。',64,'全唐诗/poet.tang.19000.json','["寶書翻譯學初成，振錫如飛白足輕。", "彭澤因家凡幾世，靈山預會是前生。", "傳燈已悟無爲理，濡露猶懷罔極情。", "從此多逢大居士，何人不願解珠瓔。"]'),
('c5c6019d-59f8-49fe-aaf0-6180c3eced96','赠日本僧智藏','劉禹錫','唐','唐诗','tang','','[]','浮杯萬里過滄溟，遍禮名山適性靈。',64,'全唐诗/poet.tang.19000.json','["浮杯萬里過滄溟，遍禮名山適性靈。", "深夜降龍潭水黑，新秋放鶴野田青。", "身無彼我那懷土，心會真如不讀經。", "爲問中華學道者，幾人雄猛得寧馨。"]'),
('9d9f9643-c363-413f-8b97-868a4dd77bdd','送元簡上人適越','劉禹錫','唐','唐诗','tang','','[]','孤雲出岫本無依，勝境名山即是歸。',64,'全唐诗/poet.tang.19000.json','["孤雲出岫本無依，勝境名山即是歸。", "久向吳門遊好寺，還思越水洗塵機。", "浙江濤驚獅子吼，稽嶺峰疑靈鷲飛。", "更入天台石橋去，垂珠璀璨拂三衣。"]'),
('9abf8f00-28ba-467b-8a5d-735b11898f55','送宗密上人歸南山草堂寺因謁河南尹白侍郎','劉禹錫','唐','唐诗','tang','','["\u9001\u522b"]','宿習修來得慧根，多聞第一却忘言。',64,'全唐诗/poet.tang.19000.json','["宿習修來得慧根，多聞第一却忘言。", "自從七祖傳心印，不要三乘入便門。", "東泛滄江尋古跡，西歸紫閣出塵喧。", "河南白尹大檀越，好把真經相對翻。"]'),
('80beb8cc-8338-44d4-8b96-7f9d32133c97','西塞山懷古','劉禹錫','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u548f\u53f2\u6000\u53e4"]','西晉樓船下益州，金陵王氣黯然收。',64,'全唐诗/poet.tang.19000.json','["西晉樓船下益州，金陵王氣黯然收。", "千尋鐵鎖沈江底，一片降旛出石頭。", "人世幾回傷往事，山形依舊枕江流。", "今逢四海爲家日，故壘蕭蕭蘆荻秋。"]'),
('05c73555-f579-404f-bdc9-4a2582e2f343','廣宣上人寄在蜀與韋令公唱和詩卷因以令公手扎荅詩示之','劉禹錫','唐','唐诗','tang','','[]','碧雲佳句久傳芳，曾向成都住草堂。',56,'全唐诗/poet.tang.19000.json','["碧雲佳句久傳芳，曾向成都住草堂。", "振錫常過長者宅，披衣猶帶令公香。", "一時風景添詩思，八部人天入道塲。", "吾家本自有柴桑。"]'),
('e8d821b6-2576-467b-a3f0-4578331e11b6','白舍人自杭州寄新詩有柳色春藏蘇小家之句因而戲酬兼寄浙東元相公','劉禹錫','唐','唐诗','tang','','[]','錢塘山水有奇聲，暫謫仙官領百城。',64,'全唐诗/poet.tang.19000.json','["錢塘山水有奇聲，暫謫仙官領百城。", "女妓還聞名小小，使君誰許喚卿卿。", "鼇驚震海風雷起，蜃鬬噓天樓閣成。", "莫道騷人在三楚，文星今向斗牛明。"]'),
('63442237-5430-48e6-a3e6-2efc5e5b1b95','春日書懷寄東洛白二十二楊八二庶子','劉禹錫','唐','唐诗','tang','','[]','曾向空門學坐禪，如今萬事盡忘筌。',64,'全唐诗/poet.tang.19000.json','["曾向空門學坐禪，如今萬事盡忘筌。", "眼前名利同春夢，醉裏風情敵少年。", "野草芳菲紅錦地，遊絲撩亂碧羅天。", "心知洛下閑才子，不作詩魔即酒顛。"]'),
('70109909-89e3-4aa8-aeca-a6b3a41cb013','白舍人見酬拙詩因以寄謝','劉禹錫','唐','唐诗','tang','','[]','雖陪三品散班中，資歷從來事不同。',64,'全唐诗/poet.tang.19000.json','["雖陪三品散班中，資歷從來事不同。", "名姓也曾鐫石柱，詩篇未得上屏風。", "甘陵舊黨凋零盡，魏闕新知禮數崇。", "煙水五湖如有伴，猶應堪作釣魚翁。"]'),
('37d6286a-c1fb-4958-b186-6e862cc8f585','白舍人曹長寄新詩有遊宴之盛因以戲酬','劉禹錫','唐','唐诗','tang','','[]','蘇州刺史例能詩，西掖今來替左司。',64,'全唐诗/poet.tang.19000.json','["蘇州刺史例能詩，西掖今來替左司。", "二八城門開道路，五千兵馬引旌旗。", "水通山寺笙歌去，騎過虹橋劒戟隨。", "若共吳王鬬百草，不如應是欠西施。"]'),
('488acecf-66b8-4744-8956-adeeaf875a89','蘇州白舍人寄新詩有歎早白無兒之句因以贈之','劉禹錫','唐','唐诗','tang','','[]','莫嗟華髪與無兒，却是人間久遠期。',64,'全唐诗/poet.tang.19000.json','["莫嗟華髪與無兒，却是人間久遠期。", "雪裏高山頭白早，海中仙果子生遲。", "于公必有高門慶，謝守何煩曉鏡悲。", "幸免如新分非淺，祝君長詠夢熊詩。"]'),
('9c955427-5806-4e78-949e-0cff513bc8e7','酬樂天揚州初逢席上見贈','劉禹錫','唐','唐诗','tang','','["\u8d2c\u8c2a", "\u54f2\u7406", "\u516b\u5e74\u7ea7\u4e0b\u518c(\u8bfe\u5185)", "\u521d\u4e2d\u53e4\u8bd7", "\u52b1\u5fd7"]','巴山楚水淒涼地，二十三年棄置身。',64,'全唐诗/poet.tang.19000.json','["巴山楚水淒涼地，二十三年棄置身。", "懷舊空吟聞篴賦，到鄉翻似爛柯人。", "沈舟側畔千帆過，病樹前頭萬木春。", "今日聽君歌一曲，暫憑杯酒長精神。"]'),
('641ed438-78bc-4b61-a023-7fe34fed2ef4','罷郡歸洛途次山陽留辭郭中丞使君','劉禹錫','唐','唐诗','tang','','[]','自到山陽不許辭，高齋日夜有佳期。',64,'全唐诗/poet.tang.19000.json','["自到山陽不許辭，高齋日夜有佳期。", "管弦正合看書院，語笑方酣各詠詩。", "銀漢雪晴褰翠幕，清淮月影落金巵。", "洛陽歸客明朝去，容趂城東花發時。"]'),
('601bbaae-8b53-4ae8-aa24-deec5f03defb','楚州開元寺北院枸杞臨井繁茂可觀羣賢賦詩因以繼和','劉禹錫','唐','唐诗','tang','','[]','僧房藥樹依寒井，井有香泉樹有靈。',64,'全唐诗/poet.tang.19000.json','["僧房藥樹依寒井，井有香泉樹有靈。", "翠黛葉生籠石甃，殷紅子熟照銅瓶。", "枝繁本是仙人杖，根老新成瑞犬形。", "上品功能甘露味，還知一勺可延齡。"]'),
('2965e4a0-84db-4909-975e-50a1ef0e0ae4','和樂天鸚鵡','劉禹錫','唐','唐诗','tang','','[]','養來鸚鵡觜初紅，宜在朱樓繡戶中。',64,'全唐诗/poet.tang.19000.json','["養來鸚鵡觜初紅，宜在朱樓繡戶中。", "頻學喚人緣性慧，偏能識主爲情通。", "歛毛睡足難銷日，嚲翅愁時願見風。", "誰遣聰明好顏色，事須安置入深籠。"]'),
('94b593ad-722b-4c80-a3a8-3a1d9be89f68','洛中逢白監同話遊梁之樂因寄宣武令狐相公','劉禹錫','唐','唐诗','tang','','[]','曾經謝病各遊梁，今日相逢憶孝王。',64,'全唐诗/poet.tang.19000.json','["曾經謝病各遊梁，今日相逢憶孝王。", "少有一身兼將相，更能四面占文章。", "開顏坐上催飛盞，廻首庭中看舞槍。", "借問風前兼月下，不知何客對胡牀。"]'),
('fe1397dd-d7fb-4869-bed9-17ea0cfd5014','河南王少尹宅燕張常侍白舍人兼呈盧郎中李員外二副使','劉禹錫','唐','唐诗','tang','','[]','將星夜落使星來，三省清臣到外臺。',64,'全唐诗/poet.tang.19000.json','["將星夜落使星來，三省清臣到外臺。", "事重各銜天子詔，禮成同把故人盃。", "捲簾松竹雪初霽，滿院池塘春欲回。", "第一林亭迎好客，殷勤莫惜玉山頹。"]'),
('d82dbecf-289e-427b-8f98-26016acc7b1f','和宣武令狐相公郡齋對新竹','劉禹錫','唐','唐诗','tang','','[]','新竹翛翛韻曉風，隔囱依砌尚蒙籠。',64,'全唐诗/poet.tang.19000.json','["新竹翛翛韻曉風，隔囱依砌尚蒙籠。", "數間素壁初開後，一段清光入坐中。", "欹枕閑看知自適，含毫朗詠與誰同。", "此君若欲長相見，政事堂東有舊叢。"]'),
('c4f56f54-865b-497a-b0f3-f78f5b863ddf','和樂天送鶴上裴相公別鶴之作','劉禹錫','唐','唐诗','tang','','[]','昨日看成送鶴詩，高籠提出白雲司。',64,'全唐诗/poet.tang.19000.json','["昨日看成送鶴詩，高籠提出白雲司。", "朱門乍入應迷路，玉樹容棲莫揀枝。", "雙舞庭中花落處，數聲池上月明時。", "三山碧海不歸去，且向人間呈羽儀。"]'),
('cf9fc808-ee9a-464d-ba02-b59163cc8086','闕下待傳點呈諸同舍','劉禹錫','唐','唐诗','tang','','[]','禁漏晨鐘聲欲絕，旌旗組綬影相交。',64,'全唐诗/poet.tang.19000.json','["禁漏晨鐘聲欲絕，旌旗組綬影相交。", "殿含佳氣當龍首，閣倚晴天見鳳巢。", "山色葱籠丹檻外，霞光泛灧翠松梢。", "多慙再入金門籍，不敢爲文學解嘲。"]'),
('98ce42a0-d71c-4604-b9bc-90a1f6d73752','和樂天以鏡換酒','劉禹錫','唐','唐诗','tang','','[]','把取菱花百鍊鏡，換他竹葉十旬杯。',64,'全唐诗/poet.tang.19000.json','["把取菱花百鍊鏡，換他竹葉十旬杯。", "嚬眉厭老終難去，蘸甲須歡便到來。", "妍醜太分迷忌諱，松喬俱傲絕嫌猜。", "校量功力相千萬，好去從空白玉臺。"]'),
('abf46c97-4770-4e6b-bd01-b4c4ad49c552','同樂天送河南馮尹學士','劉禹錫','唐','唐诗','tang','','[]','可憐五馬風流地，暫輟金貂侍從才。',64,'全唐诗/poet.tang.19000.json','["可憐五馬風流地，暫輟金貂侍從才。", "閣上掩書劉向去，門前修刺孔融來。", "崤陵路靜寒無雨，洛水橋長晝起雷。", "共羨府中棠棣好，先於城外百花開。"]'),
('a86e1f74-25be-409e-bc40-23c5c588d7db','同白二十二贈王山人','劉禹錫','唐','唐诗','tang','','[]','愛名之世忘名客，多事之時無事身。',64,'全唐诗/poet.tang.19000.json','["愛名之世忘名客，多事之時無事身。", "古老相傳見來久，歲年雖變貌常新。", "飛章上達三清路，受籙平交五嶽神。", "笑聽鼕鼕朝暮鼓，只能催得市朝人。"]'),
('137bed02-ce9e-4354-aa9b-8aa64f003a01','題集賢閣','劉禹錫','唐','唐诗','tang','','[]','鳳池西畔圖書府，玉樹玲瓏景氣閑。',64,'全唐诗/poet.tang.19000.json','["鳳池西畔圖書府，玉樹玲瓏景氣閑。", "長聽餘風送天樂，時登高閣望人寰。", "青山雲繞欄干外，紫殿香來步武間。", "曾是先賢翔集地，每看壁記一慙顏。"]'),
('280be731-30c8-49ab-bbd1-784133f1ae61','和令狐相公初歸京國賦詩言懷','劉禹錫','唐','唐诗','tang','','[]','凌雲羽翮掞天才，揚歷中樞與外臺。',64,'全唐诗/poet.tang.19000.json','["凌雲羽翮掞天才，揚歷中樞與外臺。", "相印昔辭東閣去，將星還拱北辰來。", "殿庭捧日彯纓入，閣道看山曳履回。", "口不言功心自適，吟詩釀酒待花開。"]'),
('8ad08293-0114-4150-b8dc-b555bcda6d35','和樂天南園試小樂','劉禹錫','唐','唐诗','tang','','[]','閑步南園煙雨晴，遙聞絲竹出牆聲。',64,'全唐诗/poet.tang.19000.json','["閑步南園煙雨晴，遙聞絲竹出牆聲。", "欲拋丹筆三川去，先教清商一部成。", "花木手栽偏有興，歌詞自作別生情。", "多才遇景皆能詠，當日人傳滿鳳城。"]'),
('204ea4e4-ee44-4d7a-8466-9530131e9c7c','答樂天戲贈','劉禹錫','唐','唐诗','tang','','[]','才子聲名白侍郎，風流雖老尚難當。',64,'全唐诗/poet.tang.19000.json','["才子聲名白侍郎，風流雖老尚難當。", "詩情逸似陶彭澤，齋日多如周太常。", "矻矻將心求淨法，時時偷眼看春光。", "知君技癢思歡讌，欲倩天魔破道塲。"]'),
('d2713cdb-0b94-4cc2-9673-567c21766154','同樂天送令狐相公赴東都留守','劉禹錫','唐','唐诗','tang','','[]','尚書劒履出明光，居守旌旗赴洛陽。',64,'全唐诗/poet.tang.19000.json','["尚書劒履出明光，居守旌旗赴洛陽。", "世上功名兼將相，人間聲價是文章。", "衙門曉闢分天仗，賓幕初開辟省郎。", "從發坡頭向東望，春風處處有甘棠。"]'),
('41c270ce-4044-47ff-8562-7628ee3711f1','刑部白侍郎謝病長告改賓客分司以詩贈別','劉禹錫','唐','唐诗','tang','','[]','鼎食華軒到眼前，拂衣高謝豈徒然。',64,'全唐诗/poet.tang.19000.json','["鼎食華軒到眼前，拂衣高謝豈徒然。", "九霄路上辭朝客，四皓叢中作少年。", "他日臥龍終得雨，今朝放鶴且沖天。", "洛陽舊有衡茆在，亦擬抽身伴地仙。"]'),
('04ef203f-e582-4ac6-ad7a-2b1c73d1debe','和留守令狐相公答白賓客','劉禹錫','唐','唐诗','tang','','[]','麥隴和風吹樹枝，商山逸客出關時。',64,'全唐诗/poet.tang.19000.json','["麥隴和風吹樹枝，商山逸客出關時。", "身無拘束起長晚，路足交親行自遲。", "官拂象筵終日待，私將雞黍幾人期。", "君來不用飛書報，萬戶先從紙貴知。"]'),
('fb0c278e-28be-4192-b9eb-0403efeb7fbf','酬鄆州令狐相公官舍言懷見寄兼呈樂天','劉禹錫','唐','唐诗','tang','','[]','詞人各在一涯居，聲味雖同跡自疎。',64,'全唐诗/poet.tang.19000.json','["詞人各在一涯居，聲味雖同跡自疎。", "佳句傳因多好事，尺題稀爲不便書。", "已通戎略逢黃石，仍占星文耀碧虛。", "聞說朝天在來歲，霸陵春色待行車。"]'),
('c3f1653d-075b-44a3-b213-feac85e3c0e4','吟白樂天哭崔兒二篇愴然寄贈','劉禹錫','唐','唐诗','tang','','[]','吟君苦調我霑纓，能使無情盡有情。',64,'全唐诗/poet.tang.19000.json','["吟君苦調我霑纓，能使無情盡有情。", "四望車中心未釋，千秋亭下賦初成。", "庭梧已有棲雛處，池鶴今無子和聲。", "從此期君比瓊樹，一枝吹折一枝生。"]'),
('4067dec0-483d-47cc-b14c-db0545be278a','答樂天所寄詠懷且釋其枯樹之歎','劉禹錫','唐','唐诗','tang','','[]','衙前有樂饌常精，宅內連池酒任傾。',64,'全唐诗/poet.tang.19000.json','["衙前有樂饌常精，宅內連池酒任傾。", "自是官高無狎客，不論年長少歡情。", "驪龍頷被探珠去，老蚌胚還應月生。", "莫羨三春桃與李，桂花成實向秋榮。"]'),
('feb122e4-3555-4678-a0ca-e5d43c72e6b7','赴蘇州酬別樂天','劉禹錫','唐','唐诗','tang','','[]','吳郡魚書下紫宸，長安廄吏送朱輪。',64,'全唐诗/poet.tang.19000.json','["吳郡魚書下紫宸，長安廄吏送朱輪。", "二南風化承遺愛，八詠聲名躡後塵。", "梁氏夫妻爲寄客，陸家兄弟是州民。", "江城春日追遊處，共憶東歸舊主人。"]'),
('fabcd3b0-ac3e-4199-9592-cd1d59ba92b0','福先寺雪中酬別樂天','劉禹錫','唐','唐诗','tang','','[]','龍門賓客會龍宮，東去旌旗駐上東。',64,'全唐诗/poet.tang.19000.json','["龍門賓客會龍宮，東去旌旗駐上東。", "二八笙歌雲幕下，三千世界雪花中。", "離堂未暗排紅燭，別曲含淒颺晚風。", "才子從今一分散，便將詩詠向吳儂。"]'),
('9e488f48-94e4-4141-abb9-04d4d8f8c546','和樂天耳順吟兼寄敦詩','劉禹錫','唐','唐诗','tang','','[]','吟君新什慰蹉跎，屈指同登耳順科。',64,'全唐诗/poet.tang.19000.json','["吟君新什慰蹉跎，屈指同登耳順科。", "鄧禹功成三紀事，孔融書就八年多。", "已經將相誰能爾，拋却丞郎爭奈何。", "獨恨長洲數千里，且隨魚鳥泛煙波。"]'),
('9d460f1e-1f99-418e-be2c-fa8bc51b7e20','和白侍郎送令狐相公鎮太原','劉禹錫','唐','唐诗','tang','','[]','十萬天兵貂錦衣，晉城風日斗生輝。',64,'全唐诗/poet.tang.19000.json','["十萬天兵貂錦衣，晉城風日斗生輝。", "行臺僕射深恩重，從事中郎舊路歸。", "疊鼓蹙成汾水浪，閃旗驚斷塞鴻飛。", "邊庭自此無烽火，擁節還來坐紫微。"]'),
('b53e5527-17d7-44c9-b4fb-17cc910ceafe','酬樂天見寄','劉禹錫','唐','唐诗','tang','','[]','元君後輩先零落，崔相同年不少留。',64,'全唐诗/poet.tang.19000.json','["元君後輩先零落，崔相同年不少留。", "華屋坐來能幾日，夜臺歸去便千秋。", "背時猶自居三品，得老終須卜一丘。", "若使吾徒還早達，亦應簫鼓入松楸。"]'),
('df67ae37-52c4-4ada-b878-7d25be62e47a','樂天寄重和晚達冬青一篇因成再答','劉禹錫','唐','唐诗','tang','','[]','風雲變化饒年少，光景蹉跎屬老夫。',64,'全唐诗/poet.tang.19000.json','["風雲變化饒年少，光景蹉跎屬老夫。", "秋隼得時凌汗漫，寒龜飲氣受泥塗。", "東隅有失誰能免，北叟之言豈便無。", "振臂猶堪呼一擲，爭知掌下不成盧。"]'),
('e4dc9fac-1160-45b6-8182-51829ac15f72','河南白尹有喜崔賓客歸洛兼見懷長句因而繼和','劉禹錫','唐','唐诗','tang','','[]','幾年侍從作名臣，却向青雲索得身。',64,'全唐诗/poet.tang.19000.json','["幾年侍從作名臣，却向青雲索得身。", "朝士忽爲方外士，主人仍是眼中人。", "雙鸞遊處天京好，五馬行時海嶠春。", "遙羨光陰不虛擲，肯令絲竹暫生塵。"]'),
('e24c31b7-e6cb-4d9b-9046-02856aa0506c','和楊師臯給事傷小姬英英','劉禹錫','唐','唐诗','tang','','[]','見學胡琴見藝成，今朝追想幾傷情。',64,'全唐诗/poet.tang.19000.json','["見學胡琴見藝成，今朝追想幾傷情。", "撚弦花下呈新曲，放撥燈前謝改名。", "但是好花皆易落，從來尤物不長生。", "鸞臺夜直衣衾冷，雲雨無因入禁城。"]'),
('267ee733-10b5-4a73-86da-c9b7f2b9f366','和樂天洛下醉吟寄太原令狐相公兼見懷長句','劉禹錫','唐','唐诗','tang','','[]','舊相臨戎非稱意，詞人作尹本多情。',64,'全唐诗/poet.tang.19000.json','["舊相臨戎非稱意，詞人作尹本多情。", "從容自使邊塵靜，談笑不聞桴鼓聲。", "章句新添塞下曲，風流舊占洛陽城。", "昨來亦有吳趨詠，惟寄東都與北京。"]'),
('5263a0dc-06dc-431c-9cfe-cd9fc6b8dfa1','郡齋書懷寄江南白尹兼簡分司崔賓客','劉禹錫','唐','唐诗','tang','','[]','謾讀圖書三十車，年年爲郡老天涯。',64,'全唐诗/poet.tang.19000.json','["謾讀圖書三十車，年年爲郡老天涯。", "一生不得文章力，百口空爲飽煖家。", "綺季衣冠稱鬢面，吳公政事副詞華。", "還思謝病吟歸去，同醉城東桃李花。"]'),
('cb7adcbc-17c9-4fb4-8bca-b22c64894652','題于家公主舊宅','劉禹錫','唐','唐诗','tang','','[]','樹繞荒臺葉滿池，簫聲一絕草蟲悲。',64,'全唐诗/poet.tang.19000.json','["樹繞荒臺葉滿池，簫聲一絕草蟲悲。", "鄰家猶學宮人髻，園客爭偷御果枝。", "馬埒蓬蒿藏狡兔，鳳樓煙雨嘯愁鴟。", "何郎獨在無恩澤，不似當初傅粉時。"]'),
('5231b666-804b-4db2-a24d-3a6e4e0dfaae','酬樂天貽賀金紫之什','劉禹錫','唐','唐诗','tang','','[]','久學文章含白鳳，却因政事賜金魚。',64,'全唐诗/poet.tang.19000.json','["久學文章含白鳳，却因政事賜金魚。", "郡人未識聞謠詠，天子知名與詔書。", "珍重賀詩呈錦繡，願言歸計竝園廬。", "舊來詞客多無位，金紫同遊誰得如。"]'),
('4ad777ea-a470-4adc-9af3-a9f6bb22cc10','樂天見示傷微之敦詩晦叔三君子皆有深分因成是詩以寄','劉禹錫','唐','唐诗','tang','','["\u54f2\u7406", "\u6292\u6000", "\u53cb\u60c5"]','吟君歎逝雙絕句，使我傷懷奏短歌。',64,'全唐诗/poet.tang.19000.json','["吟君歎逝雙絕句，使我傷懷奏短歌。", "世上空驚故人少，集中惟覺祭文多。", "芳林新葉催陳葉，流水前波讓後波。", "萬古到今同此恨，聞琴淚盡欲如何。"]'),
('271f81bf-71b9-4571-8b98-1fa9f6e82467','和樂天柘枝','劉禹錫','唐','唐诗','tang','','[]','柘枝本出楚王家，玉面添嬌舞態奢。',64,'全唐诗/poet.tang.19000.json','["柘枝本出楚王家，玉面添嬌舞態奢。", "鬆鬢改梳鸞鳳髻，新衫別識鬬雞紗。", "鼓催殘拍腰身軟，汗透羅衣雨點花。", "畫筵曲罷辭歸去，便隨王母上煙霞。"]'),
('1a680d46-3a13-42c1-9e08-83b4b8beea86','和樂天題真娘墓','劉禹錫','唐','唐诗','tang','','[]','薝蔔林中黃土堆，羅襦繡黛已成灰。',64,'全唐诗/poet.tang.19000.json','["薝蔔林中黃土堆，羅襦繡黛已成灰。", "芳魂雖死人不怕，蔓草逢春花自開。", "幡蓋向風疑舞袖，鏡燈臨曉似妝臺。", "吳王嬌女墳相近，一片行雲應往來。"]'),
('3b6cb900-0574-4d96-a0f9-4b95d87736d6','客有話汴州新政書事寄令狐相公','劉禹錫','唐','唐诗','tang','','[]','天下咽喉今大寧，軍城喜氣徹青冥。',64,'全唐诗/poet.tang.19000.json','["天下咽喉今大寧，軍城喜氣徹青冥。", "庭前劒戟朝迎日，筆底文章夜應星。", "三省壁中題姓字，萬人頭上見儀形。", "汴州忽復承平事，正月看燈戶不扃。"]'),
('c563fc3a-402f-4955-848e-c344c03b0bcf','令狐相公見示河中楊少尹贈答兼命繼之','劉禹錫','唐','唐诗','tang','','[]','兩首新詩百字餘，朱弦玉磬韻難如。',64,'全唐诗/poet.tang.19000.json','["兩首新詩百字餘，朱弦玉磬韻難如。", "漢家丞相重徵後，梁苑仁風一變初。", "四面諸侯瞻節制，八方通貨溢河渠。", "自從却縠爲元帥，大將歸來盡把書。"]'),
('7f6710f4-2571-48cb-9be7-7b07744d788e','和令狐相公送趙常盈鍊師與中貴人同拜嶽及天台投龍畢却赴京','劉禹錫','唐','唐诗','tang','','[]','銀璫謁者引蜺旌，霞帔仙官到赤城。',64,'全唐诗/poet.tang.19000.json','["銀璫謁者引蜺旌，霞帔仙官到赤城。", "白鶴迎來天樂動，金龍擲下海神驚。", "元君伏奏歸中禁，武帝親齋禮上清。", "何事夷門請詩送，梁王文字上聲名。"]'),
('0664da46-e8c9-4188-9319-202172487d77','酬令狐相公贈別','劉禹錫','唐','唐诗','tang','','[]','越聲長苦有誰聞，老向湘山與楚雲。',64,'全唐诗/poet.tang.19000.json','["越聲長苦有誰聞，老向湘山與楚雲。", "海嶠新辭永嘉守，夷門重見信陵君。", "田園松菊今迷路，霄漢鴛鴻久絕羣。", "幸遇甘泉尚詞賦，不知何客薦雄文。"]'),
('d29a2c26-d43c-498f-bfd2-031fe83c9888','酬令狐相公寄賀遷拜之什','劉禹錫','唐','唐诗','tang','','[]','邅廻二紀重爲郎，洛下遙分列宿光。',64,'全唐诗/poet.tang.19000.json','["邅廻二紀重爲郎，洛下遙分列宿光。", "不見當關呼早起，曾無侍史與焚香。", "三花秀色通春幌，十字清波遶宅牆。", "白髮青衫誰比數，相憐只是有梁王。"]'),
('9b280d97-b3f7-479d-a32f-20af06f06aee','夏日寄宣武令狐相公','劉禹錫','唐','唐诗','tang','','[]','長憶梁王逸興多，西園花盡興如何。',64,'全唐诗/poet.tang.19000.json','["長憶梁王逸興多，西園花盡興如何。", "近來溽暑侵亭館，應覺清談勝綺羅。", "境入篇章高韻發，風穿號令衆心和。", "承明欲謁先相報，願拂朝衣逐曉珂。"]'),
('a72b456c-821f-4e84-871a-35f0111fb922','酬令狐留守巡內至集賢院見寄','劉禹錫','唐','唐诗','tang','','[]','仙院文房隔舊宮，當時盛事盡成空。',64,'全唐诗/poet.tang.19000.json','["仙院文房隔舊宮，當時盛事盡成空。", "墨池半在頹垣下，書帶猶生蔓草中。", "巡內因經九重苑，裁詩又繼二南風。", "爲兄手寫殷勤句，遍歷三台各一通。"]'),
('71226e9d-622d-4c06-86fc-3c916c9bbe9e','和令狐相公言懷寄河中楊少尹','劉禹錫','唐','唐诗','tang','','[]','章句慙非第一流，世間才子昔陪遊。',64,'全唐诗/poet.tang.19000.json','["章句慙非第一流，世間才子昔陪遊。", "吳宮已歎芙蓉死，邊月空悲蘆管秋。", "任向洛陽稱傲吏，苦教河上領諸侯。", "石渠甘對圖書老，關外楊公安穩不。"]'),
('fa80cfd3-946e-4c04-adaf-2a6eb47c6da2','令狐相公自天平移鎮太原以詩申賀','劉禹錫','唐','唐诗','tang','','[]','北都留守將天兵，出入香街宿禁扃。',64,'全唐诗/poet.tang.19000.json','["北都留守將天兵，出入香街宿禁扃。", "鼙鼓夜聞驚朔鴈，旌旗曉動拂參星。", "孔璋舊檄家家有，叔度新歌處處聽。", "夷落遙知真漢相，爭來屈膝看儀刑。"]'),
('223db032-430d-496f-ae7d-8f67efdcf712','重酬前寄','劉禹錫','唐','唐诗','tang','','[]','邊烽寂寂盡收兵。',64,'全唐诗/poet.tang.19000.json','["邊烽寂寂盡收兵。", "宮樹蒼蒼靜掩扃，戎羯歸心如內地。", "天狼無角比凡星，新成麗句開緘後。", "便入清歌滿坐聽，吳苑晉祠遙望處。", "可憐南北太相形。"]'),
('d9815a1d-03a0-4a0b-bc06-43fe3fd2519b','令狐相公自太原累示新詩因以酬寄','劉禹錫','唐','唐诗','tang','','[]','飛蓬卷盡塞雲寒，戰馬閑嘶漢地寬。',64,'全唐诗/poet.tang.19000.json','["飛蓬卷盡塞雲寒，戰馬閑嘶漢地寬。", "萬里胡天無警急，一籠烽火報平安。", "燈前妓樂留賓宴，雪後山河出獵看。", "珍重新詩遠相寄，風情不似四登壇。"]'),
('68ed7633-dcd0-4e67-a738-f866cd945145','酬令狐相公使宅別齋初栽桂樹見懷之作','劉禹錫','唐','唐诗','tang','','[]','清淮南岸家山樹，黑水東邊第一栽。',64,'全唐诗/poet.tang.19000.json','["清淮南岸家山樹，黑水東邊第一栽。", "影近畫梁迎曉日，香隨綠酒入金杯。", "根留本土依江潤，葉起寒稜映月開。", "早晚陰城比梧竹，九霄還放綵雛來。"]'),
('530fc885-8391-4349-ae49-5e7bb5378c89','酬令狐相公見寄','劉禹錫','唐','唐诗','tang','','[]','才兼文武播雄名，遺愛芳塵滿洛城。',64,'全唐诗/poet.tang.19000.json','["才兼文武播雄名，遺愛芳塵滿洛城。", "身在行臺爲僕射，書來甪里訪先生。", "閑遊占得嵩山色，醉臥高聽洛水聲。", "千里相思難命駕，七言詩裏寄深情。"]'),
('c28e9e75-5bb1-4058-aec3-e7c63be76a99','郡內書情獻裴侍中留守','劉禹錫','唐','唐诗','tang','','[]','功成頻獻乞身章，擺落襄陽鎮洛陽。',64,'全唐诗/poet.tang.19000.json','["功成頻獻乞身章，擺落襄陽鎮洛陽。", "萬乘旌旗分一半，八方風雨會中央。", "兵符今奉黃公略，書殿曾隨翠鳳翔。", "心寄華亭一雙鶴，曰陪高步繞池塘。"]'),
('08e6af46-ffa6-477c-a1c5-fa7b9fe5bb7c','酬樂天衫酒見寄','劉禹錫','唐','唐诗','tang','','[]','酒法衆傳吳米好，舞衣偏尚越羅輕。',64,'全唐诗/poet.tang.19000.json','["酒法衆傳吳米好，舞衣偏尚越羅輕。", "動搖浮蟻香濃甚，裝束輕鴻意態生。", "閱曲定知能自適，舉杯應歎不同傾。", "終朝相憶終年別，對景臨風無限情。"]'),
('7a4908a5-c491-4b93-9704-5f8a18b0d769','自左馮歸洛下酬樂天兼呈裴令公','劉禹錫','唐','唐诗','tang','','[]','新恩通籍在龍樓，分務神都近舊丘。',64,'全唐诗/poet.tang.19000.json','["新恩通籍在龍樓，分務神都近舊丘。", "自有園公紫芝侶，仍追少傅赤松遊。", "華林霜葉紅霞晚，伊水晴光碧玉秋。", "更接東山文酒會，始知江左未風流。"]'),
('f60c816b-3acb-474b-9be8-c930f14a1ea5','秋齋獨坐寄樂天兼呈吳方之大夫','劉禹錫','唐','唐诗','tang','','[]','空齋寂寂不生塵，藥物方書繞病身。',64,'全唐诗/poet.tang.19000.json','["空齋寂寂不生塵，藥物方書繞病身。", "纖草數莖勝靜地，幽禽忽至似佳賓。", "世間憂喜雖無定，釋氏銷磨盡有因。", "同向洛陽閑度日，莫教風景屬他人。"]'),
('1a6eec81-a0c4-4cb7-a777-8840be55be57','和樂天齋戒月滿夜對道場偶懷詠','劉禹錫','唐','唐诗','tang','','[]','常修清淨去繁華，人識王城長者家。',64,'全唐诗/poet.tang.19000.json','["常修清淨去繁華，人識王城長者家。", "案上香煙鋪貝葉，佛前燈焰透蓮花。", "持齋已滿招閑客，理曲先聞命小娃。", "明日若過方丈室，還應問爲法來邪。"]'),
('47eff951-59c2-4c6f-bd0e-d3025cf15ac3','吳方之見示獨酌小醉首篇樂天續有詶答皆含戲謔極至風流兩篇之中竝蒙見屬輒呈濫吹益美來章','劉禹錫','唐','唐诗','tang','','[]','閑門共寂任張羅，靜室同虛養太和。',64,'全唐诗/poet.tang.19000.json','["閑門共寂任張羅，靜室同虛養太和。", "塵世歡娛開意少，醉鄉風景獨遊多。", "散金疏傅尋常樂，枕麴劉生取次歌。", "計會雪中爭挈榼，鹿裘鶴氅遞相過。"]'),
('b3ff17ef-526a-4563-9d76-787965ea4d5f','酬樂天齋滿日裴令公置宴席上戲贈','劉禹錫','唐','唐诗','tang','','[]','一月道場齋戒滿，今朝華幄管弦迎。',64,'全唐诗/poet.tang.19000.json','["一月道場齋戒滿，今朝華幄管弦迎。", "銜杯本自多狂態，事佛無妨有佞名。", "酒力半酣愁已散，文鋒未鈍老猶爭。", "平陽不獨容賓醉，聽取喧呼吏舍聲。"]'),
('bc622dc2-bead-4741-a807-dc8640173cff','酬樂天偶題酒甕見寄','劉禹錫','唐','唐诗','tang','','[]','從君勇斷拋名後，世路榮枯見幾回。',64,'全唐诗/poet.tang.19000.json','["從君勇斷拋名後，世路榮枯見幾回。", "門外紅塵人自走，甕頭清酒我初開。", "三冬學任胸中有，萬戶侯須骨上來。", "何幸相招同醉處，洛陽城裏好池臺。"]'),
('a58a0828-9669-4171-ad0c-ce6ae0fad3b1','酬樂天請裴令公開春加宴','劉禹錫','唐','唐诗','tang','','[]','高名大位能兼有，恣意遨遊是特恩。',64,'全唐诗/poet.tang.19000.json','["高名大位能兼有，恣意遨遊是特恩。", "二室煙霞成步障，三川風物是家園。", "晨窺苑樹韶光動，晚度河橋春思繁。", "弦管常調客常滿，但逢花處即開樽。"]'),
('dfed425d-bd3d-438a-86d2-3932ee7bba21','樂天示過敦詩舊宅有感一篇吟之泫然追想昔事因成繼和以寄苦懷','劉禹錫','唐','唐诗','tang','','[]','淒涼同到故人居，門枕寒流古木疎。',64,'全唐诗/poet.tang.19000.json','["淒涼同到故人居，門枕寒流古木疎。", "向秀心中嗟棟宇，蕭何身後散圖書。", "本營歸計非無意，唯算生涯尚有餘。", "忽憶前言更惆悵，丁寧相約速懸車。"]'),
('8886c089-8837-4faa-a4ef-ca293307dcc5','寄和東川楊尚書慕巢兼寄西川繼之二公近從弟兄情分偏睦早忝遊舊因成是詩','劉禹錫','唐','唐诗','tang','','[]','太華蓮峰降嶽靈，兩川棠樹接郊坰。',64,'全唐诗/poet.tang.19000.json','["太華蓮峰降嶽靈，兩川棠樹接郊坰。", "政同兄弟人人樂，曲奏塤篪處處聽。", "楊葉百穿榮會府，芝泥五色耀天庭。", "各拋筆硯誇旄鉞，莫遣文星讓將星。"]'),
('50dddeca-2601-4924-8a34-12b1df6931ad','和樂天洛下雪中宴集寄汴州李尚書','劉禹錫','唐','唐诗','tang','','[]','洛城無事足杯盤，風雪相和歲欲蘭。',64,'全唐诗/poet.tang.19000.json','["洛城無事足杯盤，風雪相和歲欲蘭。", "樹上因依見寒鳥，坐中收拾盡閑官。", "笙歌要請頻何爽，笑語忘機拙更歡。", "遙想兔園今日會，瓊林滿眼映旂竿。"]'),
('ad9c4a44-e929-4e25-9680-7099ac93da17','和牛相公遊南莊醉後寓言戲贈樂天兼見示','劉禹錫','唐','唐诗','tang','','[]','城外園林初夏天，就中野趣在西偏。',64,'全唐诗/poet.tang.19000.json','["城外園林初夏天，就中野趣在西偏。", "薔薇亂發多臨水，鸂鶒雙遊不避船。", "水底遠山雲似雪，橋邊平岸草如煙。", "白家唯有杯觴興，欲把頭盤打少年。"]'),
('8fc1b3ff-50cc-4767-814f-541e521d38ae','樂天以愚相訪沽酒致歡因成七言聊以奉答','劉禹錫','唐','唐诗','tang','','[]','少年曾醉酒旗下，同輩黃衣頷亦黃。',64,'全唐诗/poet.tang.19000.json','["少年曾醉酒旗下，同輩黃衣頷亦黃。", "蹴踏青雲尋入仕，蕭條白髮且飛觴。", "令徵古事歡生雅，客喚閑人興任狂。", "猶勝獨居荒草院，蟬聲聽盡到寒螿。"]');
